// One Rust stub per C++ function found by code-complexity-comparator.
pub fn conf_to_char1(conf: f64) -> char {
    assert!((0.0..=1.0).contains(&conf));
    let tenth = (conf * 10.0) as uint;
    assert!(tenth <= 10);
    if tenth == 10 {
        '+'
    } else {
        char::from(b'0' + tenth as byte)
    }
}

pub fn conf_to_char2(conf: f64) -> char {
    assert!((0.0..=1.0).contains(&conf));
    let h = (conf * 100.0) as uint;
    assert!(h <= 100);
    if h == 100 {
        '+'
    } else {
        char::from(b'0' + (h % 10) as byte)
    }
}

pub fn conf_to_char_1(conf: f64) -> char {
    assert!((0.0..=1.0).contains(&conf));
    let tenth = (conf * 10.0) as usize;
    assert!(tenth <= 10);
    char::from(b"___.,/:=@*^"[tenth])
}

#[track_caller]
pub fn do1(confidences: &[f64], conf_label: &str, dec: i32) -> String {
    let mut conf_seq = String::new();
    for conf in confidences {
        let c = match dec {
            -1 => conf_to_char_1(*conf),
            1 => conf_to_char1(*conf),
            2 => conf_to_char2(*conf),
            _ => panic!("invalid confidence decimal mode {dec}"),
        };
        conf_seq.push(c);
    }
    format!(">{conf_label}\n{conf_seq}\n")
}

#[track_caller]
pub fn cmd_addconfseq(
    input_file_name: &str,
    output_file_name: &str,
    ref_file_name: Option<&str>,
    conf_label: Option<&str>,
    confseq1: bool,
) -> String {
    let conf_label = conf_label.unwrap_or("_conf_");

    let mut ref_msa = ref_file_name.map(msa_from_fasta_file_preserve_case);

    let mut e = Ensemble::default();
    ensemble_from_file(&mut e, input_file_name);
    if let Some(ref mut ref_msa) = ref_msa {
        ensemble_sort_msa(&e, ref_msa);
    }

    let msa_count = e.msas.len() as uint;
    let seq_count = ensemble_get_seq_count(&e);
    let mut out = String::new();
    for msa_index in 0..msa_count {
        let msa_name = ensemble_get_msa_name(&e, msa_index);
        out.push('<');
        out.push_str(msa_name);
        out.push('\n');
        let m = ensemble_get_msa(&e, msa_index);

        let col_count = multi_sequence_get_col_count(m);
        let msa_seq_count = m.seqs.len() as uint;
        assert_eq!(msa_seq_count, seq_count);

        let confidences = (0..col_count)
            .map(|col_index| ensemble_get_conf_msa_col(&e, msa_index, col_index))
            .collect::<Vec<_>>();
        if confseq1 {
            out.push_str(&do1(&confidences, conf_label, -1));
        } else {
            out.push_str(&do1(&confidences, conf_label, 1));
            out.push_str(&do1(&confidences, &format!("{conf_label}2"), 2));
        }

        for seq_index in 0..seq_count {
            let seq = &m.seqs[seq_index as usize];
            out.push('>');
            out.push_str(&seq.label);
            out.push('\n');
            for col in 0..col_count {
                out.push(seq.char_vec[col as usize]);
            }
            out.push('\n');
        }
    }

    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, &out).expect("failed to write addconfseq output");
    }
    out
}

pub fn make_replicate_file_name(pattern: &str, tp: TREEPERM, perturb_seed: uint) -> String {
    let pos = pattern
        .find('@')
        .unwrap_or_else(|| panic!("'@' not found in '{}'", pattern));
    let mut file_name = String::new();
    file_name.push_str(&pattern[..pos]);
    file_name.push_str(&format!("{}.{}", treeperm_to_str(tp), perturb_seed));
    file_name.push_str(&pattern[pos + 1..]);
    file_name
}

#[track_caller]
pub fn align<FCmdLineUpdate, FRunMpc>(
    m: &mut MPCFlat,
    input_seqs: &MultiSequence,
    perturb_seed: uint,
    tp: TREEPERM,
    write_efa_hdr: bool,
    output_enabled: bool,
    mut cmd_line_update: FCmdLineUpdate,
    mut run_mpc: FRunMpc,
) -> (HMMParams, String)
where
    FCmdLineUpdate: FnMut(&mut HMMParams),
    FRunMpc: FnMut(&mut MPCFlat, &MultiSequence) -> MultiSequence,
{
    let nucleo = ALPHA_STATE.lock().unwrap().alpha == ALPHA::ALPHA_Nucleo;
    let mut hp = hmm_params_from_defaults(nucleo);
    if !output_enabled {
        return (hp, String::new());
    }

    cmd_line_update(&mut hp);
    if perturb_seed > 0 {
        reset_rand(perturb_seed);
        hmm_params_perturb_probs(&mut hp, perturb_seed);
    }
    hmm_params_to_pair_hmm(&hp);

    m.tree_perm = tp;
    let msa = run_mpc(m, input_seqs);
    m.msa = Some(msa);
    let msa = m.msa.as_ref().expect("Align missing MSA");

    let mut out = String::new();
    if write_efa_hdr {
        out.push_str(&format!("<{}.{}\n", treeperm_to_str(tp), perturb_seed));
    }
    out.push_str(&msa_to_fasta_file_l112(msa));
    (hp, out)
}

#[track_caller]
pub fn cmd_align<FCmdLineUpdate, FRunMpc, FRunSuper5>(
    input_file_name: &str,
    output_pattern: &str,
    minsuper: Option<uint>,
    consistency_iter_count: Option<uint>,
    refine_iter_count: Option<uint>,
    stratified: bool,
    diversified: bool,
    replicates: Option<uint>,
    perturb_seed: Option<uint>,
    tree_perm: Option<TREEPERM>,
    mut cmd_line_update: FCmdLineUpdate,
    mut run_mpc: FRunMpc,
    mut run_super5: FRunSuper5,
) -> (MPCFlat, Vec<String>, String)
where
    FCmdLineUpdate: FnMut(&mut HMMParams),
    FRunMpc: FnMut(&mut MPCFlat, &MultiSequence) -> MultiSequence,
    FRunSuper5: FnMut(uint) -> (Vec<String>, String),
{
    let mut input_seqs = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut input_seqs, input_file_name, true);
    set_global_input_ms(&input_seqs);
    set_global_input_ms(&input_seqs);
    let input_seq_count = input_seqs.seqs.len() as uint;

    if let Some(minsuper) = minsuper {
        if input_seq_count >= minsuper {
            multi_sequence_clear(&mut input_seqs);
            let mut out = format!("{input_seq_count} seqs, running Super5 algorithm\n");
            let (files, super5_log) = run_super5(input_seq_count);
            out.push_str(&super5_log);
            return (MPCFlat::default(), files, out);
        }
    }

    let mut log = String::new();
    if input_seq_count > 1000 {
        log.push_str(&warning(
            ">1k sequences, may be slow or use excessive memory, consider using -super5",
        ));
    }

    if output_pattern.is_empty() {
        die("Must set -output");
    }

    let output_wildcard = output_pattern.contains('@');
    let is_nucleo = multi_sequence_guess_is_nucleo(&input_seqs);
    set_alpha_l209(if is_nucleo {
        ALPHA::ALPHA_Nucleo
    } else {
        ALPHA::ALPHA_Amino
    });

    let mut m = MPCFlat::default();
    if let Some(consistency_iter_count) = consistency_iter_count {
        m.consistency_iter_count = consistency_iter_count;
    }
    if let Some(refine_iter_count) = refine_iter_count {
        m.refine_iter_count = refine_iter_count;
    }

    if stratified && diversified {
        die("Cannot set both -stratified and -diversified");
    }
    if stratified || diversified {
        if tree_perm.is_some() || perturb_seed.is_some() {
            die("Cannot set -perm or -perturb with -stratified or -diversified");
        }
    }

    let mut rep_count = 1;
    if stratified {
        rep_count = 4;
    } else if diversified {
        rep_count = 100;
    }
    if let Some(replicates) = replicates {
        rep_count = replicates;
    }

    let mut output_file_names = Vec::new();
    if rep_count == 1 {
        let perturb_seed = perturb_seed.unwrap_or(0);
        let tp = tree_perm.unwrap_or(TREEPERM::TP_None);
        if tp == TREEPERM::TP_All {
            die("-perm all not supported, use -stratified");
        }
        let output_file_name = if output_wildcard {
            make_replicate_file_name(output_pattern, tp, perturb_seed)
        } else {
            output_pattern.to_string()
        };
        let (_hp, out) = align(
            &mut m,
            &input_seqs,
            perturb_seed,
            tp,
            false,
            true,
            |hp| cmd_line_update(hp),
            |mpc, input_seqs| run_mpc(mpc, input_seqs),
        );
        std::fs::write(&output_file_name, out).expect("failed to write align output");
        output_file_names.push(output_file_name);
        return (m, output_file_names, log);
    }

    let mut stratified_reps = false;
    if stratified {
        stratified_reps = true;
        rep_count *= 4;
        if tree_perm.is_some() {
            die("Cannot set both -perm and -stratified");
        }
        assert!(rep_count > 0);
    }

    let mut combined_out = String::new();
    for rep_index in 0..rep_count {
        let perturb_seed = if stratified_reps {
            rep_index / 4
        } else {
            rep_index
        };
        let tp = tree_perm.unwrap_or(match rep_index % 4 {
            0 => TREEPERM::TP_None,
            1 => TREEPERM::TP_ABC,
            2 => TREEPERM::TP_ACB,
            3 => TREEPERM::TP_BCA,
            _ => unreachable!(),
        });
        log.push_str(&format!(
            "Replicate {}/{}, {}.{}\n",
            rep_index + 1,
            rep_count,
            treeperm_to_str(tp),
            perturb_seed
        ));
        let write_efa_header = !output_wildcard;
        let (_hp, out) = align(
            &mut m,
            &input_seqs,
            perturb_seed,
            tp,
            write_efa_header,
            true,
            |hp| cmd_line_update(hp),
            |mpc, input_seqs| run_mpc(mpc, input_seqs),
        );
        if output_wildcard {
            let output_file_name = make_replicate_file_name(output_pattern, tp, perturb_seed);
            std::fs::write(&output_file_name, out).expect("failed to write align output");
            output_file_names.push(output_file_name);
        } else {
            combined_out.push_str(&out);
        }
    }

    if !output_wildcard {
        std::fs::write(output_pattern, combined_out).expect("failed to write align output");
        output_file_names.push(output_pattern.to_string());
    }
    (m, output_file_names, log)
}

#[track_caller]
pub fn align_ms_as_by_cols(
    x: &MultiSequence,
    y: &MultiSequence,
    cols_x: &[uint],
    cols_y: &[uint],
    path: &mut String,
    merge_map: &mut Vec<uint>,
    x2: &mut MultiSequence,
    y2: &mut MultiSequence,
) {
    multi_sequence_clear(x2);
    multi_sequence_clear(y2);
    merge_map.clear();
    let nc = cols_x.len();
    assert_eq!(cols_y.len(), nc);
    assert!(nc > 0);
    for i in 1..nc {
        assert!(cols_x[i] > cols_x[i - 1]);
        assert!(cols_y[i] > cols_y[i - 1]);
    }

    let col_count_x = multi_sequence_get_col_count(x);
    let col_count_y = multi_sequence_get_col_count(y);
    let mut col_x = 0_u32;
    let mut col_y = 0_u32;
    let first_col_x = cols_x[0];
    let first_col_y = cols_y[0];
    if first_col_x < first_col_y {
        for _ in 0..first_col_y - first_col_x {
            path.push('y');
            col_y += 1;
        }
    } else if first_col_y < first_col_x {
        for _ in 0..first_col_x - first_col_y {
            path.push('x');
            col_x += 1;
        }
    }
    while col_x < first_col_x {
        path.push('m');
        col_x += 1;
        col_y += 1;
    }
    assert_eq!(col_x, first_col_x);
    assert_eq!(col_y, first_col_y);
    merge_map.push(path.len() as uint);
    path.push('M');

    for i in 1..nc {
        let next_col_x = cols_x[i];
        let next_col_y = cols_y[i];
        assert!(col_x < next_col_x);
        assert!(col_y < next_col_y);
        let nx = next_col_x - col_x;
        let ny = next_col_y - col_y;
        if nx < ny {
            for _ in 0..ny - nx {
                path.push('y');
                col_y += 1;
            }
        } else if ny < nx {
            for _ in 0..nx - ny {
                path.push('x');
                col_x += 1;
            }
        }
        while col_x + 1 < next_col_x {
            path.push('m');
            col_x += 1;
            col_y += 1;
        }
        assert_eq!(col_x + 1, next_col_x);
        assert_eq!(col_y + 1, next_col_y);
        merge_map.push(path.len() as uint);
        path.push('M');
        col_x = next_col_x;
        col_y = next_col_y;
    }

    col_x += 1;
    col_y += 1;
    while col_x < col_count_x && col_y < col_count_y {
        path.push('m');
        col_x += 1;
        col_y += 1;
    }
    while col_x < col_count_x {
        path.push('x');
        col_x += 1;
    }
    while col_y < col_count_y {
        path.push('y');
        col_y += 1;
    }

    let mut nx = 0_u32;
    let mut ny = 0_u32;
    for c in path.chars() {
        match c {
            'm' | 'M' => {
                nx += 1;
                ny += 1;
            }
            'x' => nx += 1,
            'y' => ny += 1,
            _ => panic!("Invalid AlignMSAsByCols path char '{c}'"),
        }
    }
    assert_eq!(nx, col_count_x);
    assert_eq!(ny, col_count_y);

    let pl = path.len();
    for seq in &x.seqs {
        let mut col = 0usize;
        let mut out_seq = Sequence {
            label: seq.label.clone(),
            char_vec: Vec::with_capacity(pl),
        };
        for c in path.chars() {
            match c {
                'm' | 'M' | 'x' => {
                    out_seq.char_vec.push(seq.char_vec[col]);
                    col += 1;
                }
                'y' => out_seq.char_vec.push('.'),
                _ => panic!("Invalid AlignMSAsByCols path char '{c}'"),
            }
        }
        x2.seqs.push(out_seq);
        x2.owners.push(true);
    }

    for seq in &y.seqs {
        let mut col = 0usize;
        let mut out_seq = Sequence {
            label: seq.label.clone(),
            char_vec: Vec::with_capacity(pl),
        };
        for c in path.chars() {
            match c {
                'm' | 'M' | 'y' => {
                    out_seq.char_vec.push(seq.char_vec[col]);
                    col += 1;
                }
                'x' => out_seq.char_vec.push('.'),
                _ => panic!("Invalid AlignMSAsByCols path char '{c}'"),
            }
        }
        y2.seqs.push(out_seq);
        y2.owners.push(true);
    }
}

#[track_caller]
pub fn align_pair_flat_sparse_post(
    label1: &str,
    label2: &str,
    sparse_post: Option<&mut MySparseMx>,
) -> (f32, String) {
    let l1 = get_seq_length_by_global_label(label1);
    let l2 = get_seq_length_by_global_label(label2);
    let post = calc_post(label1, label2);
    let mut dp_rows = alloc_dp_rows(l1, l2);
    let mut tb = alloc_tb(l1, l2);
    let (score, path) = calc_aln_flat(&post, l1, l2, &mut dp_rows, &mut tb);
    if let Some(sparse) = sparse_post {
        my_sparse_mx_from_post(sparse, &post, l1, l2);
    }

    assert!(l1 > 0 && l2 > 0);
    let ea = score / l1.min(l2) as f32;
    (ea, path)
}

#[track_caller]
pub fn align_pair_flat(label1: &str, label2: &str) -> (f32, String) {
    align_pair_flat_sparse_post(label1, label2, None)
}

#[track_caller]
pub fn get_fb_size(lx: uint, ly: uint) -> uint64 {
    uint64::from(lx + 1) * uint64::from(ly + 1) * HMMSTATE_COUNT
}

#[track_caller]
pub fn get_post_size(lx: uint, ly: uint) -> uint64 {
    let size64 = uint64::from(lx) * uint64::from(ly);
    assert_eq!(uint64::from(size64 as uint), size64);
    size64
}

#[track_caller]
pub fn get_dp_rows_size(_lx: uint, ly: uint) -> uint64 {
    let size64 = 2 * uint64::from(ly + 1);
    assert_eq!(uint64::from(size64 as uint), size64);
    size64
}

#[track_caller]
pub fn get_tb_size(lx: uint, ly: uint) -> uint64 {
    let size64 = uint64::from(lx + 1) * uint64::from(ly + 1);
    assert_eq!(uint64::from(size64 as uint), size64);
    size64
}

#[track_caller]
pub fn alloc_fb(lx: uint, ly: uint) -> Vec<f32> {
    if f64::from(lx) * f64::from(ly) * 5.0 + 100.0 > f64::from(i32::MAX) {
        panic!("Sequences length {lx}, {ly} overflow HMM buffers");
    }
    vec![0.0; get_fb_size(lx, ly) as usize]
}

#[track_caller]
pub fn alloc_post(lx: uint, ly: uint) -> Vec<f32> {
    vec![0.0; get_post_size(lx, ly) as usize]
}

#[track_caller]
pub fn alloc_dp_rows(lx: uint, ly: uint) -> Vec<f32> {
    vec![0.0; get_dp_rows_size(lx, ly) as usize]
}

#[track_caller]
pub fn alloc_tb(lx: uint, ly: uint) -> Vec<i8> {
    vec![0; get_tb_size(lx, ly) as usize]
}

#[track_caller]
pub fn mpc_flat_align_alns(
    mpc: &mut MPCFlat,
    msa1: &MultiSequence,
    msa2: &MultiSequence,
) -> (MultiSequence, f32, String) {
    let seq_count1 = msa1.seqs.len() as uint;
    let seq_count2 = msa2.seqs.len() as uint;
    let col_count1 = multi_sequence_get_col_count(msa1);
    let col_count2 = multi_sequence_get_col_count(msa2);

    let seq_count = mpc_flat_get_seq_count(mpc);
    if mpc.weights.len() != seq_count as usize {
        mpc.weights = vec![1.0; seq_count as usize];
    }

    let post = mpc_flat_build_post(mpc, msa1, msa2);
    let mut dp_rows = alloc_dp_rows(col_count1, col_count2);
    let mut tb = alloc_tb(col_count1, col_count2);
    let (score, path) = calc_aln_flat(&post, col_count1, col_count2, &mut dp_rows, &mut tb);

    let mut result = MultiSequence::default();
    for seq_index1 in 0..seq_count1 {
        let input_row = &msa1.seqs[seq_index1 as usize];
        let aligned_row = sequence_add_gaps_path(input_row, &path, 'X');
        result.seqs.push(aligned_row);
        result.owners.push(true);
    }
    for seq_index2 in 0..seq_count2 {
        let input_row = &msa2.seqs[seq_index2 as usize];
        let aligned_row = sequence_add_gaps_path(input_row, &path, 'Y');
        result.seqs.push(aligned_row);
        result.owners.push(true);
    }
    (result, score, path)
}

#[track_caller]
pub fn align_two_ms_as_given_path(
    msa_a: &MultiSequence,
    msa_b: &MultiSequence,
    path: &str,
    msa2: &mut MultiSequence,
) {
    multi_sequence_clear(msa2);
    let seq_count_a = msa_a.seqs.len();
    let seq_count_b = msa_b.seqs.len();
    for seq_index_a in 0..seq_count_a {
        let input_row = &msa_a.seqs[seq_index_a];
        let aligned_row = sequence_add_gaps_path(input_row, path, 'D');
        msa2.seqs.push(aligned_row);
        msa2.owners.push(true);
    }

    for seq_index_b in 0..seq_count_b {
        let input_row = &msa_b.seqs[seq_index_b];
        let aligned_row = sequence_add_gaps_path(input_row, path, 'I');
        msa2.seqs.push(aligned_row);
        msa2.owners.push(true);
    }
}

#[track_caller]
pub fn p_prog_align_ms_as_flat(
    progress_str: &str,
    msa1: &MultiSequence,
    msa2: &MultiSequence,
    target_pair_count: uint,
    path: &mut String,
) -> f32 {
    let seq_count1 = msa1.seqs.len() as uint;
    let seq_count2 = msa2.seqs.len() as uint;
    assert!(seq_count1 > 0);
    assert!(seq_count2 > 0);

    let col_count1 = multi_sequence_get_col_count(msa1);
    let col_count2 = multi_sequence_get_col_count(msa2);
    let (seq_indexes1, seq_indexes2) = get_pairs(seq_count1, seq_count2, target_pair_count);
    assert_eq!(seq_indexes1.len(), seq_indexes2.len());

    let mut sparse_mxs = Vec::new();
    let avg_ea = p_prog_get_post_pairs_aligned_flat(
        progress_str,
        msa1,
        msa2,
        &seq_indexes1,
        &seq_indexes2,
        &mut sparse_mxs,
    );

    let mut post = alloc_post(col_count1, col_count2);
    calc_posterior_flat3(
        msa1,
        msa2,
        &seq_indexes1,
        &seq_indexes2,
        &sparse_mxs,
        &mut post,
    );
    let mut dp_rows = alloc_dp_rows(col_count1, col_count2);
    let mut tb = alloc_tb(col_count1, col_count2);
    let (_score, aln_path) = calc_aln_flat(&post, col_count1, col_count2, &mut dp_rows, &mut tb);
    *path = aln_path;
    avg_ea
}

