#[track_caller]
pub fn mpc_flat_calc_posterior(mpc: &mut MPCFlat, pair_index: uint) {
    let (seq_index_x, seq_index_y) = mpc_flat_get_pair(mpc, pair_index);
    let lx = mpc_flat_get_seq_length(mpc, seq_index_x);
    let ly = mpc_flat_get_seq_length(mpc, seq_index_y);
    if f64::from(lx) * f64::from(ly) * 5.0 + 100.0 > f64::from(i32::MAX) {
        panic!("HMM overflow, sequence lengths {lx}, {ly} (max ~21k)");
    }

    let label_x = mpc_flat_get_label(mpc, seq_index_x);
    let label_y = mpc_flat_get_label(mpc, seq_index_y);
    let gsix = get_gsi_by_label(&label_x);
    let gsiy = get_gsi_by_label(&label_y);
    assert_eq!(get_seq_length_by_gsi(gsix), lx);
    assert_eq!(get_seq_length_by_gsi(gsiy), ly);

    let post = calc_post(&label_x, &label_y);
    let x = mpc_flat_get_byte_ptr(mpc, seq_index_x);
    let y = mpc_flat_get_byte_ptr(mpc, seq_index_y);
    {
        let sparse_post = mpc_flat_get_sparse_post(mpc, pair_index);
        my_sparse_mx_from_post(sparse_post, &post, lx, ly);
        sparse_post.x = Some(x);
        sparse_post.y = Some(y);
    }

    let mut dp_rows = alloc_dp_rows(lx, ly);
    let score = calc_aln_score_flat(&post, lx, ly, &mut dp_rows);
    let ea = score / lx.min(ly) as f32;
    assert!((seq_index_x as usize) < mpc.dist_mx.len());
    assert!((seq_index_y as usize) < mpc.dist_mx.len());
    mpc.dist_mx[seq_index_x as usize][seq_index_y as usize] = ea;
    mpc.dist_mx[seq_index_y as usize][seq_index_x as usize] = ea;
}

#[track_caller]
pub fn clustal_weights_run(cw: &mut ClustalWeights, ms: &MultiSequence, t: &Tree) -> Vec<f32> {
    let root = t.root_node_index;
    let node_count = t.node_count;
    let seq_count = ms.seqs.len() as uint;
    let mut weights = vec![f32::MAX; seq_count as usize];

    cw.node_to_subtree_size.clear();
    cw.node_to_subtree_size.resize(node_count as usize, 0);

    let root_subtree_size = clustal_weights_set_subtree_size(cw, t, root);
    let leaf_count = (0..node_count)
        .filter(|node| {
            let i = *node as usize;
            t.node_count == 1
                || (t.neighbor2[i] == NULL_NEIGHBOR && t.neighbor3[i] == NULL_NEIGHBOR)
        })
        .count() as uint;
    assert_eq!(root_subtree_size, leaf_count);

    cw.node_to_strength.clear();
    cw.node_to_strength.reserve(node_count as usize);
    for node in 0..node_count {
        if node == t.root_node_index {
            cw.node_to_strength.push(0.0);
            continue;
        }
        let parent = t.neighbor1[node as usize];
        let mut length = tree_get_edge_length(t, node, parent) as f32;
        if length < 0.05 {
            length = 0.05;
        }
        let leaf_count = cw.node_to_subtree_size[node as usize];
        let strength = length / leaf_count as f32;
        cw.node_to_strength.push(strength);
    }

    let mut sum_weights = 0.0_f32;
    for node in 0..node_count {
        let i = node as usize;
        if !(t.node_count == 1
            || (t.neighbor2[i] == NULL_NEIGHBOR && t.neighbor3[i] == NULL_NEIGHBOR))
        {
            continue;
        }
        let seq_index = tree_get_leaf_id(t, node);
        assert!((seq_index as usize) < weights.len() && weights[seq_index as usize] == f32::MAX);
        let path = tree_get_path_to_root(t, node);
        let mut weight = 0.0_f32;
        for node2 in path {
            weight += cw.node_to_strength[node2 as usize];
        }
        weights[seq_index as usize] = weight;
        sum_weights += weight;
    }

    for seq_index in 0..seq_count {
        weights[seq_index as usize] /= sum_weights;
    }
    weights
}

#[track_caller]
pub fn clustal_weights_set_subtree_size(cw: &mut ClustalWeights, t: &Tree, node: uint) -> uint {
    let i = node as usize;
    if t.node_count == 1 || (t.neighbor2[i] == NULL_NEIGHBOR && t.neighbor3[i] == NULL_NEIGHBOR) {
        cw.node_to_subtree_size[i] = 1;
        return 1;
    }
    let left = t.neighbor2[i];
    let right = t.neighbor3[i];
    let size = clustal_weights_set_subtree_size(cw, t, left)
        + clustal_weights_set_subtree_size(cw, t, right);
    cw.node_to_subtree_size[i] = size;
    size
}

#[track_caller]
pub fn cmd_batch<FRunMuscle3>(
    batch_file_name: &str,
    input_dir: &str,
    output_dir: &str,
    ap: &M3AlnParams,
    mut run_muscle3: FRunMuscle3,
) -> Vec<String>
where
    FRunMuscle3: FnMut(&mut Muscle3, &M3AlnParams, &MultiSequence) -> MultiSequence,
{
    let names = read_strings_from_file(batch_file_name);
    let mut input_dir = input_dir.to_string();
    let mut output_dir = output_dir.to_string();
    dirize(&mut input_dir);
    dirize(&mut output_dir);

    let thread_count = get_requested_thread_count();
    let mut m3s = Vec::<Muscle3>::new();
    for _ in 0..thread_count {
        m3s.push(Muscle3::default());
    }
    if m3s.is_empty() {
        m3s.push(Muscle3::default());
    }

    let mut output_file_names = Vec::<String>::new();
    for name in &names {
        let fasta_file_name = format!("{input_dir}{name}");
        let mut ms = MultiSequence::default();
        multi_sequence_load_mfa_l8(&mut ms, &fasta_file_name, true);

        let output_file_name = format!("{output_dir}{name}");
        let final_msa = run_muscle3(&mut m3s[0], ap, &ms);
        msa_to_fasta_file_l103(&final_msa, &output_file_name);
        output_file_names.push(output_file_name);
    }
    output_file_names
}

#[track_caller]
pub fn cmd_bench<FRunCase>(
    input_file_name: &str,
    ref_dir: &str,
    tsv_out_file_name: &str,
    ap: &M3AlnParams,
    run_case: FRunCase,
) -> (Bench, String)
where
    FRunCase: FnMut(&M3AlnParams, &str, &MultiSequence, &MultiSequence, bool) -> (f64, f64),
{
    let mut bench = Bench::default();
    let mut ref_dir = ref_dir.to_string();
    dirize(&mut ref_dir);
    bench_load(&mut bench, input_file_name, &ref_dir);
    bench.show_progress = true;
    let msa_count = bench.inputs.len() as uint;

    bench_run(&mut bench, ap, false, run_case);
    bench_t_cs_to_file(&bench, tsv_out_file_name);

    let log = format!(
        "AvgQ={:.3} AvgTC={:.3} N={}\n",
        bench.mean_q, bench.mean_tc, msa_count
    );
    (bench, log)
}

#[track_caller]
pub fn cmd_bench_blosums<FRunCase>(
    input_file_name: &str,
    ref_dir: &str,
    tsv_out_file_name: &str,
    mut run_case: FRunCase,
) -> (Bench, String, Option<String>)
where
    FRunCase: FnMut(&M3AlnParams, &str, &MultiSequence, &MultiSequence, bool) -> (f64, f64),
{
    let mut bench = Bench::default();
    let mut ref_dir = ref_dir.to_string();
    dirize(&mut ref_dir);
    bench_load(&mut bench, input_file_name, &ref_dir);
    bench.show_progress = true;
    let msa_count = bench.inputs.len() as uint;

    let mut tsv = String::new();
    if !tsv_out_file_name.is_empty() {
        tsv.push_str("BLOSUM\tParamSet\tQ\tTC\tPerturbSeed\tDelta\n");
    }
    let mut log = String::new();
    let format_g3 = |x: f32| -> String {
        if x == 0.0 {
            return "0".to_string();
        }
        let ax = x.abs();
        let mut s = if (0.001..1000.0).contains(&ax) {
            format!("{x:.3}")
        } else {
            format!("{x:.3e}")
        };
        if let Some(dot) = s.find('.') {
            let exp = s.find('e').unwrap_or(s.len());
            let mut mant = s[..exp].to_string();
            while mant.ends_with('0') {
                mant.pop();
            }
            if mant.ends_with('.') {
                mant.pop();
            }
            s = if exp < s.len() {
                format!("{}{}", mant, &s[exp..])
            } else {
                mant
            };
            let _ = dot;
        }
        s
    };

    for perturb_seed in 0..6 {
        let delta = 0.05_f32 * perturb_seed as f32;
        for pct_id in [90_u32, 80, 70, 62] {
            for n in 0..4 {
                let mut ap = M3AlnParams::default();
                m3_aln_params_set_blosum(
                    &mut ap,
                    pct_id,
                    n,
                    f32::MAX,
                    f32::MAX,
                    perturb_seed,
                    delta,
                    delta,
                    delta,
                );
                bench_run(&mut bench, &ap, false, &mut run_case);

                let delta_s = format_g3(delta);
                log.push_str(&format!(
                    "BLOSUM{pct_id}:{n}  perturb={perturb_seed} delta={delta_s:>7} AvgQ={:.4} AvgTC={:.4} N={msa_count}\n",
                    bench.mean_q, bench.mean_tc
                ));
                if !tsv_out_file_name.is_empty() {
                    tsv.push_str(&format!(
                        "{pct_id}\t{n}\t{:.5}\t{:.5}\t{perturb_seed}\t{delta_s}\n",
                        bench.mean_q, bench.mean_tc
                    ));
                }
            }
        }
    }

    let tsv_written = if tsv_out_file_name.is_empty() {
        None
    } else {
        std::fs::write(tsv_out_file_name, &tsv).expect("failed to write BLOSUM bench TSV");
        Some(tsv)
    };
    (bench, log, tsv_written)
}

pub fn hsv_to_rgb(h: f64, s: f64, v: f64) -> (byte, byte, byte) {
    let h_i = (h * 6.0) as uint;
    let f = h * 6.0 - f64::from(h_i);
    let p = v * (1.0 - s);
    let q = v * (1.0 - f * s);
    let t = v * (1.0 - (1.0 - f) * s);

    let (r, g, b) = if h_i == 0 {
        (v, t, p)
    } else if h_i == 1 {
        (q, v, p)
    } else if h_i == 2 {
        (p, v, t)
    } else if h_i == 3 {
        (p, q, v)
    } else if h_i == 4 {
        (t, p, v)
    } else if h_i == 5 {
        (v, p, q)
    } else {
        panic!("invalid hue sector");
    };

    let r = (r * 256.0) as uint;
    let g = (g * 256.0) as uint;
    let b = (b * 256.0) as uint;
    assert!(r < 256);
    assert!(g < 256);
    assert!(b < 256);
    (r as byte, g as byte, b as byte)
}

pub fn get_random_color() -> uint {
    let mut state = CMP_MSA_COLOR_STATE.lock().unwrap();
    if state.h == f64::MAX {
        state.h = f64::from(randu32() % 1000) / 1000.0;
    }

    state.h += 0.618_033_988_749_895;
    state.h %= 1.0;
    let (r, g, b) = hsv_to_rgb(state.h, 0.5, 0.95);
    let color = (uint::from(r) << 16) | (uint::from(g) << 8) | uint::from(b);
    assert!(color <= 0x00ff_ffff);
    color
}

pub fn darken(color: uint, factor: f64) -> uint {
    assert!((0.0..=1.0).contains(&factor));
    let mut r = (color >> 16) as byte;
    let mut g = ((color >> 8) % 0xff) as byte;
    let mut b = (color % 0xff) as byte;

    r = (f64::from(r) * factor) as byte;
    g = (f64::from(g) * factor) as byte;
    b = (f64::from(b) * factor) as byte;
    (uint::from(r) << 16) | (uint::from(g) << 8) | uint::from(b)
}

pub fn get_color(ref_col: uint) -> String {
    let mut state = CMP_MSA_COLOR_STATE.lock().unwrap();
    if ref_col as usize >= state.colors.len() {
        let n = state.colors.len();
        let new_len = ref_col as usize + 100;
        state.colors.resize(new_len, 0);
        for i in n..new_len {
            if i % 4 == 0 {
                if state.h == f64::MAX {
                    state.h = f64::from(randu32() % 1000) / 1000.0;
                }
                state.h += 0.618_033_988_749_895;
                state.h %= 1.0;
                let (r, g, b) = hsv_to_rgb(state.h, 0.5, 0.95);
                let color = (uint::from(r) << 16) | (uint::from(g) << 8) | uint::from(b);
                assert!(color <= 0x00ff_ffff);
                state.prev_random_color = color;
                state.colors[i] = state.prev_random_color;
            }
            let k = i % 4;
            assert!(k < 4);
            state.colors[i] = darken(state.prev_random_color, (4 - k) as f64 / 4.0);
        }
    }
    let hex_color = state.colors[ref_col as usize];
    format!("#{hex_color:06x}")
}

#[track_caller]
pub fn cmd_cmp_msa(test_file_name: &str, ref_file_name: &str, output_file_name: &str) -> QScorer {
    let name = get_base_name(ref_file_name);

    let mut test = MultiSequence::default();
    let mut ref_msa = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut test, test_file_name, false);
    multi_sequence_load_mfa_l8(&mut ref_msa, ref_file_name, false);

    let mut qs = QScorer::default();
    q_scorer_run_l337(&mut qs, &name, &test, &ref_msa);

    let test_seq_count = test.seqs.len() as uint;
    let test_col_count = multi_sequence_get_col_count(&test);
    let mut test_seq_index_to_ref_cols = vec![Vec::<uint>::new(); test_seq_count as usize];

    let mut out = String::new();
    out.push_str("<html>\n");
    out.push_str("<body>\n");
    out.push_str("<span style=\"font-size:16px\">");
    out.push_str("<pre>");

    let label_count = qs.labels.len();
    assert_eq!(qs.test_seq_indexes.len(), label_count);
    assert_eq!(qs.ref_seq_indexes.len(), label_count);

    for label_index in 0..label_count {
        let test_seq_index = qs.test_seq_indexes[label_index];
        let ref_seq_index = qs.ref_seq_indexes[label_index];
        if test_seq_index == uint::MAX || ref_seq_index == uint::MAX {
            continue;
        }
        let pos_to_ref_col = &qs.pos_to_ref_col_vec[label_index];

        let ref_cols = &mut test_seq_index_to_ref_cols[test_seq_index as usize];
        ref_cols.resize(test_col_count as usize, uint::MAX);
        let label = &test.seqs[test_seq_index as usize].label;
        let mut pos = 0usize;
        for test_col in 0..test_col_count {
            let tc = msa_get_char(&test, test_seq_index, test_col);
            if !msa_is_gap(&test, test_seq_index, test_col) {
                let ref_col = pos_to_ref_col[pos];
                let rc = msa_get_char(&ref_msa, ref_seq_index, ref_col);
                let ok =
                    rc.is_ascii_alphabetic() && rc.to_ascii_uppercase() == tc.to_ascii_uppercase();
                if !ok {
                    die(&format!(
                        "!Ok\nTest label >{label}\n Ref label >{}\n     Pos {}\nTest col {}\n Ref col {}\nTest seq {}\n Ref seq {}\ntc '{}'\nrc '{}'",
                        ref_msa.seqs[ref_seq_index as usize].label,
                        pos,
                        test_col,
                        ref_col,
                        test_seq_index,
                        ref_seq_index,
                        tc,
                        rc
                    ));
                }
                assert_ne!(ref_col, uint::MAX);
                assert_eq!(ref_cols[test_col as usize], uint::MAX);
                if rc.is_ascii_uppercase() {
                    ref_cols[test_col as usize] = ref_col;
                }
                pos += 1;
            }
        }
    }

    const ROWLEN: uint = 100;
    let block_count = (test_col_count + ROWLEN - 1) / ROWLEN;
    for block_index in 0..block_count {
        let from = block_index * ROWLEN;
        let mut to = from + ROWLEN;
        if to >= test_col_count {
            to = test_col_count;
        }
        for test_seq_index in 0..test_seq_count {
            if test_seq_index_to_ref_cols[test_seq_index as usize].is_empty() {
                continue;
            }
            out.push_str("   ");
            let label = &test.seqs[test_seq_index as usize].label;
            for test_col in from..to {
                let tc = msa_get_char(&test, test_seq_index, test_col);
                let ref_col =
                    test_seq_index_to_ref_cols[test_seq_index as usize][test_col as usize];

                if ref_col == uint::MAX {
                    out.push_str(&format!("<span style=\"color:gray\">{tc}</span>"));
                } else {
                    let color = if tc.is_ascii_lowercase() {
                        "gray".to_string()
                    } else {
                        get_color(ref_col)
                    };
                    out.push_str(&format!(
                        "<span style=\"color:white;background-color:{color}\">{tc}</span>"
                    ));
                }
            }
            for _ in to..ROWLEN {
                out.push(' ');
            }
            out.push_str(&format!(
                "  <span style=\"color:black\">{label}   </span>\n"
            ));
        }
        out.push_str("\n\n");
    }
    out.push_str("</pre>");
    out.push_str("</span>");
    out.push_str("</body>");
    out.push_str("</html>\n");

    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, out).expect("failed to write cmp_msa HTML");
    }
    qs
}

#[track_caller]
pub fn cmd_m3ensemble(
    input_file_name: &str,
    output_file_name: &str,
    replicates: Option<uint>,
) -> String {
    assert!(!output_file_name.is_empty());
    let mut input_seqs = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut input_seqs, input_file_name, true);
    set_global_input_ms(&input_seqs);

    let replicates = replicates.unwrap_or(16);
    assert!(replicates > 0);
    let delta = 0.1_f32;
    let mut out = String::new();
    let format_g3 = |d: f32| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let d64 = f64::from(d);
        let exp = d64.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 3 {
            let raw = format!("{d64:.2e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (2 - exp).max(0) as usize;
            format!("{d64:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };
    for ii in 0..replicates {
        let perturb_seed = ii / 4;
        let param_group = if replicates == 4 { 0 } else { (ii * 7) % 4 };
        let pct_id = match ii % 4 {
            0 => 90,
            1 => 80,
            2 => 70,
            3 => 62,
            _ => unreachable!(),
        };

        let mut ap = M3AlnParams {
            linkage: "min".to_string(),
            tree_iters: 1,
            kmer_dist: "66".to_string(),
            ..M3AlnParams::default()
        };
        m3_aln_params_set_blosum(
            &mut ap,
            pct_id,
            param_group,
            f32::MAX,
            f32::MAX,
            perturb_seed,
            delta,
            delta,
            delta,
        );
        ap.linkage = "min".to_string();
        ap.tree_iters = 1;
        ap.kmer_dist = "66".to_string();

        let mut m3 = Muscle3::default();
        let final_msa = muscle3_run(
            &mut m3,
            &ap,
            &input_seqs,
            |u, linkage, tree| upgma5_run_l75(u, linkage, tree),
            |pp, input, weights, tree| {
                p_prog3_run(
                    pp,
                    input,
                    weights,
                    tree,
                    |cm, prof_a, prof_b| nw_small3(cm, prof_a, prof_b).1,
                    |prof_a, weight_a, prof_b, weight_b, subst_mx_letter, gap_open, path| {
                        align_two_profs_given_path(
                            prof_a,
                            weight_a,
                            prof_b,
                            weight_b,
                            subst_mx_letter,
                            gap_open,
                            path,
                        )
                    },
                );
                pp.msa.clone()
            },
        );
        out.push_str(&format!(
            "<blosum{pct_id}:{param_group}.perturb{perturb_seed}.delta{}\n",
            format_g3(delta)
        ));
        out.push_str(&msa_to_fasta_file_l112(&final_msa));
    }
    std::fs::write(output_file_name, &out).expect("failed to write M3 ensemble output");
    out
}

#[track_caller]
pub fn cmd_muscle3<FRun, FRunRo>(
    input_file_name: &str,
    output_file_name: &str,
    guide_tree_out_file_name: Option<&str>,
    random_order: bool,
    ap: &M3AlnParams,
    mut run: FRun,
    mut run_ro: FRunRo,
) -> (MultiSequence, Option<Tree>)
where
    FRun: FnMut(&M3AlnParams, &MultiSequence) -> (MultiSequence, Tree),
    FRunRo: FnMut(&M3AlnParams, &MultiSequence) -> MultiSequence,
{
    let mut input_seqs = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut input_seqs, input_file_name, false);
    let is_nucleo = multi_sequence_guess_is_nucleo(&input_seqs);
    set_alpha_l209(if is_nucleo {
        ALPHA::ALPHA_Nucleo
    } else {
        ALPHA::ALPHA_Amino
    });

    let (final_msa, guide_tree) = if random_order {
        (run_ro(ap, &input_seqs), None)
    } else {
        let (msa, tree) = run(ap, &input_seqs);
        if let Some(file_name) = guide_tree_out_file_name {
            tree_to_file_l13(&tree, file_name);
        }
        (msa, Some(tree))
    };
    msa_to_fasta_file_l103(&final_msa, output_file_name);
    (final_msa, guide_tree)
}

#[track_caller]
pub fn cmd_mustang_core(input_file_name: &str, output_file_name: &str) -> String {
    const MINCORECOLS: uint = 10;

    let input_msa = msa_from_fasta_file_preserve_case(input_file_name);
    let seq_count = input_msa.seqs.len() as uint;
    let col_count = multi_sequence_get_col_count(&input_msa);

    let mut aligned_col_count = 0;
    let mut labels = Vec::new();
    for seq in &input_msa.seqs {
        labels.push(seq.label.clone());
    }
    let mut tmp_rows = vec![String::new(); seq_count as usize];
    for col in 0..col_count {
        let aligned = msa_get_gap_count(&input_msa, col) == 0;
        if aligned {
            aligned_col_count += 1;
        }
        for seq_index in 0..seq_count {
            let mut c = msa_get_char(&input_msa, seq_index, col);
            if aligned {
                if c == '-' || c == '.' {
                    c = '-';
                } else if c.is_ascii_alphabetic() {
                    c = c.to_ascii_uppercase();
                }
            } else if c == '-' || c == '.' {
                c = '.';
            } else if c.is_ascii_alphabetic() {
                c = c.to_ascii_lowercase();
            }
            tmp_rows[seq_index as usize].push(c);
        }
    }

    let mut tmp_msa = MultiSequence::default();
    multi_sequence_from_strings(&mut tmp_msa, &labels, &tmp_rows);
    let out_msa = squeeze_inserts(&tmp_msa);
    assert_eq!(out_msa.seqs.len() as uint, seq_count);
    let new_col_count = multi_sequence_get_col_count(&out_msa) as usize;

    if aligned_col_count < MINCORECOLS {
        return format!("WARNING: {aligned_col_count} aligned cols < {MINCORECOLS}\n");
    }

    let mut out = String::new();
    for seq in &out_msa.seqs {
        let mut label = seq.label.clone();
        if label.ends_with(".pdb") {
            label.truncate(label.len() - 4);
        }
        out.push('>');
        out.push_str(&label);
        out.push('\n');
        let mut n = 0usize;
        while n < new_col_count {
            let end = std::cmp::min(n + 60, new_col_count);
            for col in n..end {
                out.push(seq.char_vec[col]);
            }
            out.push('\n');
            n = end;
        }
    }
    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, &out).expect("failed to write MUSTANG core output");
    }
    out
}

pub fn contains_pf_exactly_once(dom_str: &str, pf: &str) -> bool {
    let fields = split(dom_str, '_');
    let mut n = 0;
    for field in fields {
        if field == pf {
            n += 1;
        }
    }
    n == 1
}

pub fn dom_str_has_done_pf(dom_str: &str, done_pfs: &[String]) -> bool {
    let pfs = split(dom_str, '_');
    for pf in pfs {
        if done_pfs.iter().any(|done| done == &pf) {
            return true;
        }
    }
    false
}

#[track_caller]
pub fn output_dom_str(
    dom_str_to_lines: &std::collections::BTreeMap<String, Vec<String>>,
    up_to_seq_index: &std::collections::BTreeMap<String, uint>,
    seqs: &MultiSequence,
    dom_str: &str,
    done_labels: &mut std::collections::BTreeSet<String>,
) -> (String, String) {
    let lines = dom_str_to_lines
        .get(dom_str)
        .unwrap_or_else(|| panic!("OutputDomStr({dom_str})"));
    let mut fa = String::new();
    let mut tsv = String::new();
    let seq_count_this_dom_str = lines.len();
    for line in lines.iter().take(seq_count_this_dom_str) {
        let mut up = String::new();
        for c in line.chars() {
            if c == '\t' {
                break;
            }
            up.push(c);
        }

        if done_labels.contains(&up) {
            continue;
        }
        done_labels.insert(up.clone());

        let seq_index = *up_to_seq_index
            .get(&up)
            .unwrap_or_else(|| panic!("OutputDomStr label not found {up}"));
        let seq = sequence_get_seq_as_string(&seqs.seqs[seq_index as usize]);
        fa.push_str(&seq_to_fasta_l2561(&seq, &up));
        tsv.push_str(&format!("{dom_str}\t{line}\n"));
    }
    (fa, tsv)
}

#[track_caller]
pub fn do_dom_strs(
    pf: &str,
    arg_dom_strs: &std::collections::BTreeSet<String>,
    dom_str_to_lines: &std::collections::BTreeMap<String, Vec<String>>,
    up_to_seq_index: &std::collections::BTreeMap<String, uint>,
    seqs: &MultiSequence,
    done_pfs: &mut std::collections::BTreeSet<String>,
) -> Option<(String, String, String)> {
    if done_pfs.contains(pf) {
        return None;
    }

    let mut dom_strs = Vec::new();
    let done_pf_vec: Vec<String> = done_pfs.iter().cloned().collect();
    for dom_str in arg_dom_strs {
        if dom_str_has_done_pf(dom_str, &done_pf_vec) {
            continue;
        }
        if !contains_pf_exactly_once(dom_str, pf) {
            continue;
        }
        dom_strs.push(dom_str.clone());
    }
    if dom_strs.len() < 2 {
        return None;
    }

    let mut size = 0;
    for dom_str in &dom_strs {
        let lines = dom_str_to_lines
            .get(dom_str)
            .unwrap_or_else(|| panic!("DoDomStrs({pf}) missing {dom_str}"));
        size += lines.len();
    }
    if size < 10 {
        return None;
    }

    let name = format!("{pf}_local");
    let mut done_labels = std::collections::BTreeSet::new();
    let mut fa = String::new();
    let mut tsv = String::new();
    for dom_str in &dom_strs {
        for dom_str2 in &dom_strs {
            let _ = dom_str2;
            let (fa_part, tsv_part) = output_dom_str(
                dom_str_to_lines,
                up_to_seq_index,
                seqs,
                dom_str,
                &mut done_labels,
            );
            fa.push_str(&fa_part);
            tsv.push_str(&tsv_part);
        }
    }

    let mut pf_set = std::collections::BTreeSet::new();
    for dom_str in &dom_strs {
        let pfs = split(dom_str, '_');
        for pf2 in pfs {
            pf_set.insert(pf2);
        }
    }

    for pf2 in pf_set {
        assert!(!done_pfs.contains(&pf2));
        done_pfs.insert(pf2);
    }
    Some((name, fa, tsv))
}

#[track_caller]
pub fn do_dom_str(
    dom_str: &str,
    min_size: uint,
    dom_str_to_lines: &std::collections::BTreeMap<String, Vec<String>>,
    up_to_seq_index: &std::collections::BTreeMap<String, uint>,
    seqs: &MultiSequence,
) -> Option<(String, String)> {
    let lines = dom_str_to_lines
        .get(dom_str)
        .unwrap_or_else(|| panic!("DoDomStr({dom_str})"));
    let seq_count_this_dom_str = lines.len() as uint;

    if seq_count_this_dom_str < min_size {
        return None;
    }

    let mut done_labels = std::collections::BTreeSet::new();
    let (fa, tsv) = output_dom_str(
        dom_str_to_lines,
        up_to_seq_index,
        seqs,
        dom_str,
        &mut done_labels,
    );
    Some((fa, tsv))
}

pub fn parse_line(line: &str) -> (String, Vec<String>) {
    let fields = split(line, '\t');
    let field_count = fields.len() as uint;
    assert!(field_count >= 7);
    let pf_count = str_to_uint_l1278(&fields[3], false);
    assert_eq!(field_count, 3 * pf_count + 4);

    let mut dom_str = String::new();
    let mut pfs = Vec::new();
    for i in 0..pf_count as usize {
        let pf = &fields[4 + 3 * i];
        assert!(pf.starts_with("PF"));
        pfs.push(pf.clone());
        if i > 0 {
            dom_str.push('_');
        }
        dom_str.push_str(pf);
    }
    (dom_str, pfs)
}

#[track_caller]
pub fn cmd_newbench_pfamgroups(
    select_pfams_file_name: &str,
    input_file_name: &str,
    out_dir_fa: &str,
    out_dir_tsv: &str,
    min_size: uint,
) -> std::collections::BTreeMap<String, (String, String)> {
    let mut seqs = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut seqs, input_file_name, true);
    let seq_count = seqs.seqs.len() as uint;
    let mut up_to_seq_index = std::collections::BTreeMap::<String, uint>::new();
    for i in 0..seq_count {
        let up = seqs.seqs[i as usize].label.clone();
        up_to_seq_index.insert(up, i);
    }

    let mut lines = Vec::new();
    let mut pf_to_dom_strs =
        std::collections::BTreeMap::<String, std::collections::BTreeSet<String>>::new();
    let mut dom_str_to_lines = std::collections::BTreeMap::<String, Vec<String>>::new();
    let mut max_dom_strs_per_pf = 0usize;
    for line in std::fs::read_to_string(select_pfams_file_name)
        .expect("failed to read newbench PFAM groups input")
        .lines()
    {
        if line.is_empty() {
            continue;
        }
        let line = line.to_string();
        lines.push(line.clone());
        let (dom_str, pfs) = parse_line(&line);
        for pf in pfs {
            let dom_strs = pf_to_dom_strs.entry(pf).or_default();
            dom_strs.insert(dom_str.clone());
            max_dom_strs_per_pf = max_dom_strs_per_pf.max(dom_strs.len());
        }
        dom_str_to_lines.entry(dom_str).or_default().push(line);
    }

    let mut out_dir_fa_s = out_dir_fa.to_string();
    let mut out_dir_tsv_s = out_dir_tsv.to_string();
    dirize(&mut out_dir_fa_s);
    dirize(&mut out_dir_tsv_s);
    std::fs::create_dir_all(&out_dir_fa_s).expect("failed to create FASTA output dir");
    std::fs::create_dir_all(&out_dir_tsv_s).expect("failed to create TSV output dir");

    let mut done_pfs = std::collections::BTreeSet::<String>::new();
    let mut outputs = std::collections::BTreeMap::<String, (String, String)>::new();
    for dom_strs_per_pf in (2..=max_dom_strs_per_pf).rev() {
        for (pf, dom_strs) in &pf_to_dom_strs {
            if dom_strs.len() != dom_strs_per_pf {
                continue;
            }
            if let Some((name, fa, tsv)) = do_dom_strs(
                pf,
                dom_strs,
                &dom_str_to_lines,
                &up_to_seq_index,
                &seqs,
                &mut done_pfs,
            ) {
                std::fs::write(format!("{out_dir_fa_s}{name}"), &fa)
                    .expect("failed to write PFAM group FASTA");
                std::fs::write(format!("{out_dir_tsv_s}{name}"), &tsv)
                    .expect("failed to write PFAM group TSV");
                outputs.insert(name, (fa, tsv));
            }
        }
    }

    for dom_str in dom_str_to_lines.keys() {
        let pfs = split(dom_str, '_');
        let mut done = false;
        let mut pf_set = std::collections::BTreeSet::<String>::new();
        for pf2 in pfs {
            if done_pfs.contains(&pf2) {
                done = true;
                break;
            }
            pf_set.insert(pf2);
        }
        if done {
            continue;
        }

        if let Some((fa, tsv)) = do_dom_str(
            dom_str,
            min_size,
            &dom_str_to_lines,
            &up_to_seq_index,
            &seqs,
        ) {
            std::fs::write(format!("{out_dir_fa_s}{dom_str}"), &fa)
                .expect("failed to write PFAM domstr FASTA");
            std::fs::write(format!("{out_dir_tsv_s}{dom_str}"), &tsv)
                .expect("failed to write PFAM domstr TSV");
            outputs.insert(dom_str.clone(), (fa, tsv));
        }

        for pf2 in pf_set {
            assert!(!done_pfs.contains(&pf2));
            done_pfs.insert(pf2);
        }
    }

    outputs
}

#[track_caller]
pub fn get_ungapped_seq_length(seq_index: uint) -> uint {
    let seqs = NEWBENCH_UNGAPPED_SEQS.lock().unwrap();
    assert!((seq_index as usize) < seqs.len());
    seqs[seq_index as usize].len() as uint
}

#[track_caller]
pub fn get_p_fix(pf: &str, new_ok: bool) -> uint {
    let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    if let Some(pfix) = state.pf_to_pfix.get(pf) {
        return *pfix;
    }
    if !new_ok {
        panic!("GetPFix({pf}) not found");
    }

    let pfix = state.unique_pfs.len() as uint;
    state.unique_pfs.push(pf.to_string());
    state.pf_to_pfix.insert(pf.to_string(), pfix);
    assert_eq!(state.pfix_to_regionixs.len(), pfix as usize);
    state.pfix_to_regionixs.push(Vec::new());
    pfix
}

#[track_caller]
pub fn get_upix(up: &str, new_ok: bool) -> uint {
    let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    if let Some(upix) = state.up_to_upix.get(up) {
        return *upix;
    }
    if !new_ok {
        panic!("GetUpix({up}) not found");
    }

    let upix = state.unique_ups.len() as uint;
    assert_eq!(state.upix_to_regionixs.len(), upix as usize);
    state.unique_ups.push(up.to_string());
    state.up_to_upix.insert(up.to_string(), upix);
    state.upix_to_regionixs.push(Vec::new());
    upix
}

#[track_caller]
pub fn read_pfam_regions(file_name: &str) {
    let contents = std::fs::read_to_string(file_name).expect("failed to read PFAM regions TSV");
    for line in contents.lines() {
        let fields = split(line, '\t');
        assert_eq!(fields.len(), 6);

        let up = &fields[0];
        let sp = &fields[1];
        let pf = &fields[2];
        let lo = str_to_uint_l1278(&fields[3], false);
        let hi = str_to_uint_l1278(&fields[4], false);
        let l = str_to_uint_l1278(&fields[5], false);
        assert!(lo < hi);
        assert!(hi <= l);

        {
            let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
            if let Some(sp2) = state.up_to_sp.get(up) {
                assert_eq!(sp2, sp);
            } else {
                state.up_to_sp.insert(up.clone(), sp.clone());
            }
        }

        get_p_fix(pf, true);
        let upix = get_upix(up, true);
        let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
        let regionix = state.ups.len() as uint;
        state.ups.push(up.clone());
        state.sps.push(sp.clone());
        state.pfs.push(pf.clone());
        state.los.push(lo);
        state.his.push(hi);
        state.ls.push(l);
        assert!((upix as usize) < state.upix_to_regionixs.len());
        state.upix_to_regionixs[upix as usize].push(regionix);
    }
}

#[track_caller]
pub fn has_primary_pf_repeat(aln: &MultiSequence) -> bool {
    let state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    let seq_count = aln.seqs.len();
    assert_eq!(state.aln_regionix_vec.len(), seq_count);
    for seq_index in 0..seq_count {
        let mut primary_count = 0;
        let regionixs = &state.aln_regionix_vec[seq_index];
        for regionix in regionixs {
            assert!((*regionix as usize) < state.pfs.len());
            let pf = &state.pfs[*regionix as usize];
            if pf == &state.primary_pf {
                primary_count += 1;
            }
        }
        assert!(primary_count > 0);
        if primary_count > 1 {
            return true;
        }
    }
    false
}

#[track_caller]
pub fn get_mean_primary_domain_length(aln: &MultiSequence) -> f64 {
    let state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    let seq_count = aln.seqs.len();
    assert_eq!(state.aln_regionix_vec.len(), seq_count);
    let mut sum_primary_length = 0;
    for seq_index in 0..seq_count {
        let regionixs = &state.aln_regionix_vec[seq_index];
        for regionix in regionixs {
            assert!((*regionix as usize) < state.pfs.len());
            let pf = &state.pfs[*regionix as usize];
            if pf == &state.primary_pf {
                let lo = state.los[*regionix as usize];
                let hi = state.his[*regionix as usize];
                assert!(lo < hi);
                sum_primary_length += hi - lo + 1;
            }
        }
    }
    (sum_primary_length / seq_count as uint) as f64
}

#[track_caller]
pub fn set_aln_regions(aln: &MultiSequence) {
    const MIN_DOM_FRACT: f64 = 0.1;
    const MIN_COVERAGE_GLOBAL: f64 = 0.8;
    let seq_count = aln.seqs.len();
    let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    state.aln_regionix_vec.clear();
    state.aln_pfixs.clear();
    state.aln_pfix_to_char.clear();
    state.dom_str_to_count.clear();
    state.dom_strs.clear();
    state.dom_coverages.clear();
    state.aln_pfix_to_char.insert(uint::MAX, '.');

    let ungapped_seqs = NEWBENCH_UNGAPPED_SEQS.lock().unwrap();
    for seq_index in 0..seq_count {
        let up = aln.seqs[seq_index].label.clone();
        let upix = *state
            .up_to_upix
            .get(&up)
            .unwrap_or_else(|| panic!("GetUpix({up}) not found"));
        let up2 = &state.unique_ups[upix as usize];
        assert_eq!(up2, &up);

        let _sp = state
            .up_to_sp
            .get(&up)
            .unwrap_or_else(|| panic!("Swissprot label not found for {up}"))
            .clone();

        assert!((upix as usize) < state.upix_to_regionixs.len());
        let regionixs = state.upix_to_regionixs[upix as usize].clone();
        state.aln_regionix_vec.push(regionixs.clone());

        let mut dom_str = String::new();
        let n = regionixs.len();
        let mut sum_dom_lens = 0;
        for regionix in regionixs.iter().take(n) {
            assert!((*regionix as usize) < state.ups.len());
            assert!((*regionix as usize) < state.sps.len());
            assert!((*regionix as usize) < state.pfs.len());
            assert!((*regionix as usize) < state.los.len());
            assert!((*regionix as usize) < state.his.len());
            assert!((*regionix as usize) < state.ls.len());

            let up3 = state.ups[*regionix as usize].clone();
            let pf = state.pfs[*regionix as usize].clone();
            let lo = state.los[*regionix as usize];
            let hi = state.his[*regionix as usize];
            let l = state.ls[*regionix as usize];
            let dom_len = hi - lo + 1;
            if dom_len as f64 / l as f64 >= MIN_DOM_FRACT {
                sum_dom_lens += dom_len;
                if !dom_str.is_empty() {
                    dom_str.push('+');
                }
                dom_str.push_str(&pf);
            }
            let pfix = *state
                .pf_to_pfix
                .get(&pf)
                .unwrap_or_else(|| panic!("GetPFix({pf}) not found"));

            if !state.aln_pfix_to_char.contains_key(&pfix) {
                let i = state.aln_pfixs.len() as uint;
                state.aln_pfixs.push(pfix);
                if pfix == state.primary_pfix {
                    state.aln_pfix_to_char.insert(pfix, '@');
                } else {
                    state
                        .aln_pfix_to_char
                        .insert(pfix, (b'A' + i as u8) as char);
                }
            }

            assert_eq!(up3, up);
        }

        if dom_str.is_empty() {
            dom_str = "-".to_string();
        }
        assert!(seq_index < ungapped_seqs.len());
        let l = ungapped_seqs[seq_index].len() as uint;
        if sum_dom_lens >= l {
            sum_dom_lens = l;
        }
        let dom_coverage = sum_dom_lens as f64 / l as f64;
        state.dom_strs.push(dom_str.clone());
        state.dom_coverages.push(dom_coverage);
        *state.dom_str_to_count.entry(dom_str).or_insert(0) += 1;
    }

    assert_eq!(state.dom_strs.len(), seq_count);
    assert_eq!(state.dom_coverages.len(), seq_count);

    state.dom_str_to_count.clear();
    for dom_str in state.dom_strs.clone() {
        *state.dom_str_to_count.entry(dom_str).or_insert(0) += 1;
    }
    state.unique_dom_strs.clear();
    state.unique_dom_str_counts.clear();
    let dom_counts = state
        .dom_str_to_count
        .iter()
        .map(|(dom_str, count)| (dom_str.clone(), *count))
        .collect::<Vec<_>>();
    for (dom_str, count) in dom_counts {
        state.unique_dom_strs.push(dom_str);
        state.unique_dom_str_counts.push(count);
    }
    let n = state.unique_dom_strs.len();
    let mut order = (0..n).collect::<Vec<_>>();
    order.sort_by(|a, b| {
        state.unique_dom_str_counts[*b]
            .cmp(&state.unique_dom_str_counts[*a])
            .then_with(|| a.cmp(b))
    });

    state.unique_dom_min_coverages.clear();
    let mut _global_found = false;
    for k in 0..n {
        let i = order[k];
        let dom_str = &state.unique_dom_strs[i];
        let count = state.unique_dom_str_counts[i];
        let mut min_cvg = f64::MAX;
        for seq_index in 0..seq_count {
            if &state.dom_strs[seq_index] == dom_str {
                let dom_cvg = state.dom_coverages[seq_index];
                min_cvg = min_cvg.min(dom_cvg);
            }
        }
        state.unique_dom_min_coverages.push(min_cvg);
        if k == 0 && n == 1 && min_cvg >= MIN_COVERAGE_GLOBAL {
            _global_found = true;
        }
        let _ = count;
    }

    let top = order[0];
    assert!(top < state.unique_dom_strs.len());
    assert!(top < state.unique_dom_str_counts.len());
    assert!(top < state.unique_dom_min_coverages.len());
    let top_count = state.unique_dom_str_counts[top];
    assert!(top_count <= seq_count as uint);
    let top_fract = top_count as f64 / seq_count as f64;
    let top_min_cvg = state.unique_dom_min_coverages[top];
    state.globalness = top_fract * top_min_cvg;
}

#[track_caller]
pub fn get_before_after_p_fs(_aln: &MultiSequence, seq_index: uint) -> (String, String) {
    let state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    let mut before = ".".to_string();
    let mut after = ".".to_string();
    assert!((seq_index as usize) < state.aln_regionix_vec.len());
    let regionixs = &state.aln_regionix_vec[seq_index as usize];
    let n = regionixs.len();
    for i in 0..n {
        let regionix = regionixs[i];
        assert!((regionix as usize) < state.pfs.len());
        let region_pf = &state.pfs[regionix as usize];
        if region_pf == &state.primary_pf {
            if i > 0 {
                let before_regionix = regionixs[i - 1];
                assert!((before_regionix as usize) < state.pfs.len());
                before = state.pfs[before_regionix as usize].clone();
            }
            if i + 1 < n {
                let after_regionix = regionixs[i + 1];
                assert!((after_regionix as usize) < state.pfs.len());
                after = state.pfs[after_regionix as usize].clone();
            }
        }
    }
    (before, after)
}

#[track_caller]
pub fn set_before_after_p_fs(aln: &MultiSequence) -> f64 {
    {
        let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
        state.before_primary_pfs.clear();
        state.after_primary_pfs.clear();
    }
    let seq_count = aln.seqs.len();
    for seq_index in 0..seq_count {
        let (before, after) = get_before_after_p_fs(aln, seq_index as uint);
        let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
        state.before_primary_pfs.push(before);
        state.after_primary_pfs.push(after);
    }

    let state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    let mut before_count_map = std::collections::BTreeMap::<String, uint>::new();
    let mut after_count_map = std::collections::BTreeMap::<String, uint>::new();
    for before in &state.before_primary_pfs {
        *before_count_map.entry(before.clone()).or_insert(0) += 1;
    }
    for after in &state.after_primary_pfs {
        *after_count_map.entry(after.clone()).or_insert(0) += 1;
    }
    let before_top_count = before_count_map.values().copied().max().unwrap_or(0);
    let after_top_count = after_count_map.values().copied().max().unwrap_or(0);
    before_top_count as f64 * after_top_count as f64 / (seq_count * seq_count) as f64
}

#[track_caller]
pub fn set_aln_labels(aln: &mut MultiSequence) {
    let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    state.aln_ups.clear();
    state.aln_sps.clear();
    for seq in &mut aln.seqs {
        let label = seq.label.clone();
        assert!(label.ends_with(".pdb"));
        let up = label[..label.len() - 4].to_string();
        let Some(upix) = state.up_to_upix.get(&up).copied() else {
            continue;
        };
        seq.label = up.clone();
        let up2 = &state.unique_ups[upix as usize];
        assert_eq!(up2, &up);
        let sp = state
            .up_to_sp
            .get(&up)
            .unwrap_or_else(|| panic!("Swissprot label not found for {up}"))
            .clone();
        state.aln_ups.push(up);
        state.aln_sps.push(sp);
    }
}

#[track_caller]
pub fn set_aln_case(aln: &mut MultiSequence) {
    let state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    let col_count = multi_sequence_get_col_count(aln);
    assert_eq!(state.annot_row.len(), col_count as usize);
    for col_index in 0..col_count as usize {
        let has_gap = aln
            .seqs
            .iter()
            .any(|seq| matches!(seq.char_vec[col_index], '-' | '.'));
        let c = state.annot_row.as_bytes()[col_index] as char;
        let is_core_col = c != '~';
        if is_core_col {
            assert!(!has_gap);
        }
        for seq in &mut aln.seqs {
            let mut c = seq.char_vec[col_index];
            if c.is_ascii_alphabetic() {
                c = if is_core_col {
                    c.to_ascii_uppercase()
                } else {
                    c.to_ascii_lowercase()
                };
            }
            seq.char_vec[col_index] = c;
        }
    }
}

#[track_caller]
pub fn set_pos_to_col_vec(aln: &MultiSequence) {
    let seq_count = aln.seqs.len();
    let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    state.pos_to_col_vec.clear();
    state.pos_to_col_vec.resize(seq_count, Vec::new());
    for seq_index in 0..seq_count {
        let row = sequence_get_seq_as_string(&aln.seqs[seq_index]);
        state.pos_to_col_vec[seq_index] = sequence_get_pos_to_col(&row);
    }
}

#[track_caller]
pub fn set_pos_to_p_fix_vec(aln: &MultiSequence) -> uint {
    let seq_count = aln.seqs.len();
    let mut overlap_count = 0;
    let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    state.pos_to_pfix_vec.clear();
    state.pos_to_pfix_vec.resize(seq_count, Vec::new());
    for seq_index in 0..seq_count {
        assert!(seq_index < state.aln_regionix_vec.len());
        let l = get_ungapped_seq_length(seq_index as uint);
        let mut pos_to_pfix = vec![uint::MAX; l as usize];
        let regionixs = &state.aln_regionix_vec[seq_index];
        for regionix in regionixs {
            assert!((*regionix as usize) < state.ups.len());
            assert!((*regionix as usize) < state.sps.len());
            assert!((*regionix as usize) < state.pfs.len());
            assert!((*regionix as usize) < state.los.len());
            assert!((*regionix as usize) < state.his.len());
            assert!((*regionix as usize) < state.ls.len());
            let pf = &state.pfs[*regionix as usize];
            let lo = state.los[*regionix as usize];
            let hi = state.his[*regionix as usize];
            let l2 = state.ls[*regionix as usize];
            assert_eq!(l2, l);
            let pfix = *state
                .pf_to_pfix
                .get(pf)
                .unwrap_or_else(|| panic!("GetPFix({pf}) not found"));
            assert!(lo > 0);
            assert!(lo < hi);
            assert!(hi <= l);
            for pos in lo..=hi {
                let pfix2 = pos_to_pfix[pos as usize - 1];
                if pfix2 != uint::MAX {
                    overlap_count += 1;
                    if pfix2 != state.primary_pfix {
                        pos_to_pfix[pos as usize - 1] = pfix;
                    }
                } else {
                    pos_to_pfix[pos as usize - 1] = pfix;
                }
            }
        }
        state.pos_to_pfix_vec[seq_index] = pos_to_pfix;
    }
    overlap_count
}

#[track_caller]
pub fn set_col_to_p_fix_vec(aln: &MultiSequence) -> Vec<String> {
    let seq_count = aln.seqs.len();
    let col_count = multi_sequence_get_col_count(aln);
    let mut rows = Vec::new();
    let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    state.col_to_pfix_vec.clear();
    state.col_to_pfix_vec.resize(seq_count, Vec::new());
    for seq_index in 0..seq_count {
        assert!(seq_index < state.aln_regionix_vec.len());
        let l = get_ungapped_seq_length(seq_index as uint);
        let pos_to_pfix = &state.pos_to_pfix_vec[seq_index];
        let pos_to_col = &state.pos_to_col_vec[seq_index];
        assert_eq!(pos_to_pfix.len(), l as usize);
        assert_eq!(pos_to_col.len(), l as usize);
        let mut col_to_pfix = vec![uint::MAX; col_count as usize];
        for pos in 0..l as usize {
            let col = pos_to_col[pos];
            assert!(col < col_count);
            let pfix = pos_to_pfix[pos];
            col_to_pfix[col as usize] = pfix;
        }

        let mut row = String::new();
        for pfix in &col_to_pfix {
            let c = state
                .aln_pfix_to_char
                .get(pfix)
                .unwrap_or_else(|| panic!("PFix char not found: {pfix}"));
            row.push(*c);
        }
        state.col_to_pfix_vec[seq_index] = col_to_pfix;
        rows.push(row);
    }
    rows
}

#[track_caller]
pub fn set_ungapped_seqs(aln: &MultiSequence) {
    let mut seqs = NEWBENCH_UNGAPPED_SEQS.lock().unwrap();
    seqs.clear();
    for seq in &aln.seqs {
        let mut ungapped = String::new();
        for c in &seq.char_vec {
            if *c != '-' && *c != '.' {
                ungapped.push(*c);
            }
        }
        seqs.push(ungapped);
    }
}

#[track_caller]
pub fn get_consensus_pf(aln: &MultiSequence, col: uint) -> uint {
    let state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    let seq_count = aln.seqs.len();
    let col_count = multi_sequence_get_col_count(aln);
    assert!(col < col_count);
    assert_eq!(state.col_to_pfix_vec.len(), seq_count);
    let mut consensus_pfix = uint::MAX;
    for seq_index in 0..seq_count {
        let col_to_pfix = &state.col_to_pfix_vec[seq_index];
        assert_eq!(col_to_pfix.len(), col_count as usize);
        let pfix = col_to_pfix[col as usize];
        if pfix == uint::MAX {
            return uint::MAX;
        }
        if seq_index == 0 {
            consensus_pfix = pfix;
        } else if pfix != consensus_pfix {
            return uint::MAX;
        }
    }
    consensus_pfix
}

#[track_caller]
pub fn set_col_annots(aln: &MultiSequence) {
    {
        let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
        state.core_count = 0;
        state.core_primary_count = 0;
        state.core_other_count = 0;
        state.annot_row.clear();
    }
    let col_count = multi_sequence_get_col_count(aln);
    for col in 0..col_count {
        let pfix = get_consensus_pf(aln, col);
        let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
        if pfix == uint::MAX {
            state.annot_row.push('~');
            continue;
        }
        if pfix == state.primary_pfix {
            state.core_primary_count += 1;
            state.annot_row.push('^');
        } else {
            state.core_other_count += 1;
            state.annot_row.push(':');
        }
    }
    let mut state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    state.core_count = state.core_primary_count + state.core_other_count;
}

#[track_caller]
pub fn get_primary_col_lo_hi(aln: &MultiSequence, seq_index: uint) -> (uint, uint) {
    let state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    assert!((seq_index as usize) < state.col_to_pfix_vec.len());
    let col_to_pfix = &state.col_to_pfix_vec[seq_index as usize];
    let col_count = multi_sequence_get_col_count(aln);
    assert_eq!(col_to_pfix.len(), col_count as usize);
    let mut primary_col_lo = uint::MAX;
    let mut primary_col_hi = uint::MAX;
    for col in 0..col_count {
        let pfix = col_to_pfix[col as usize];
        if pfix == state.primary_pfix {
            if primary_col_lo == uint::MAX {
                primary_col_lo = col;
            }
            primary_col_hi = col;
        }
    }
    assert_ne!(primary_col_lo, uint::MAX);
    assert_ne!(primary_col_hi, uint::MAX);
    assert!(primary_col_lo < primary_col_hi);
    (primary_col_lo, primary_col_hi)
}

#[track_caller]
pub fn trim(aln: &MultiSequence) -> MultiSequence {
    let seq_count = aln.seqs.len();
    let col_count = multi_sequence_get_col_count(aln);
    let mut tmp_aln = aln.clone();
    assert_eq!(tmp_aln.seqs.len(), seq_count);
    assert_eq!(multi_sequence_get_col_count(&tmp_aln), col_count);

    for seq_index in 0..seq_count {
        let (primary_col_lo, primary_col_hi) = get_primary_col_lo_hi(aln, seq_index as uint);
        for col in 0..primary_col_lo as usize {
            tmp_aln.seqs[seq_index].char_vec[col] = '.';
        }
        for col in primary_col_hi as usize + 1..col_count as usize {
            tmp_aln.seqs[seq_index].char_vec[col] = '.';
        }
    }
    squeeze_inserts(&tmp_aln)
}

#[track_caller]
pub fn get_annot_coverage(up_region_ixs: &[uint]) -> f64 {
    let n = up_region_ixs.len();
    assert!(n > 0);
    let mut l = uint::MAX;
    let mut upix = uint::MAX;
    let state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    for (i, regionix) in up_region_ixs.iter().enumerate() {
        assert!((*regionix as usize) < state.los.len());
        assert!((*regionix as usize) < state.his.len());
        assert!((*regionix as usize) < state.ls.len());

        let up = &state.ups[*regionix as usize];
        let upix2 = *state
            .up_to_upix
            .get(up)
            .unwrap_or_else(|| panic!("GetUpix({up}) not found"));
        let _sp = &state.sps[*regionix as usize];
        let _pf = &state.pfs[*regionix as usize];
        let _lo = state.los[*regionix as usize];
        let _hi = state.his[*regionix as usize];
        let l2 = state.ls[*regionix as usize];
        let _dom_len = _hi - _lo + 1;
        if i == 0 {
            l = l2;
            upix = upix2;
        } else {
            assert_eq!(l2, l);
            assert_eq!(upix2, upix);
        }
    }
    0.0
}

#[track_caller]
pub fn select_up(upix: uint) -> Option<String> {
    const MINCVG: f64 = 0.9;
    const MINFRACT: f64 = 0.1;
    let state = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap();
    let up = &state.unique_ups[upix as usize];
    assert!((upix as usize) < state.upix_to_regionixs.len());
    let regionixs = &state.upix_to_regionixs[upix as usize];
    let n = regionixs.len();
    let mut pfs = Vec::new();
    let mut los = Vec::new();
    let mut his = Vec::new();
    let mut l = uint::MAX;
    let mut sp = String::new();
    let mut sum_dom_len = 0;
    for i in 0..n {
        let regionix = regionixs[i] as usize;
        let pf = &state.pfs[regionix];
        let up2 = &state.ups[regionix];
        let sp2 = &state.sps[regionix];
        let lo = state.los[regionix];
        let hi = state.his[regionix];
        let l2 = state.ls[regionix];

        if i == 0 {
            l = l2;
        } else {
            assert_eq!(l2, l);
        }
        assert_eq!(up2, up);
        if i == 0 {
            sp = sp2.clone();
        } else {
            assert_eq!(sp2, &sp);
        }

        assert!(lo > 0);
        assert!(lo < hi);
        assert!(hi <= l);
        let dom_len = hi - lo + 1;
        let fract = dom_len as f64 / l as f64;
        if fract >= MINFRACT {
            for j in 0..pfs.len() {
                if get_overlap(los[j], his[j], lo, hi) > 0 {
                    return None;
                }
            }
            sum_dom_len += dom_len;
            pfs.push(pf.clone());
            los.push(lo);
            his.push(hi);
        }
    }
    let coverage = sum_dom_len as f64 / l as f64;
    assert!(coverage <= 1.0);
    if coverage < MINCVG {
        return None;
    }

    let mut order = (0..los.len()).collect::<Vec<_>>();
    order.sort_by_key(|i| los[*i]);
    let mut row = String::new();
    row.push_str(up);
    row.push('\t');
    row.push_str(&sp);
    row.push('\t');
    row.push_str(&l.to_string());
    row.push('\t');
    row.push_str(&los.len().to_string());
    for i in order {
        row.push('\t');
        row.push_str(&pfs[i]);
        row.push('\t');
        row.push_str(&los[i].to_string());
        row.push('\t');
        row.push_str(&his[i].to_string());
    }
    row.push('\n');
    Some(row)
}

#[track_caller]
pub fn cmd_newbench_selectpfams(
    pfam_regions_tsv_file_name: &str,
    output_file_name: &str,
) -> String {
    read_pfam_regions(pfam_regions_tsv_file_name);
    let up_count = NEWBENCH_SELECT_PFAMS_STATE.lock().unwrap().unique_ups.len() as uint;
    let mut out = String::new();
    for upix in 0..up_count {
        if let Some(row) = select_up(upix) {
            out.push_str(&row);
        }
    }
    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, &out).expect("failed to write selected PFAM rows");
    }
    out
}

#[track_caller]
pub fn get_insert_lo_his(als: &[bool]) -> (Vec<uint>, Vec<uint>) {
    let mut los = Vec::new();
    let mut his = Vec::new();
    let mut start = uint::MAX;
    let col_count = als.len() as uint;
    for col in 0..col_count {
        if als[col as usize] {
            if start != uint::MAX {
                los.push(start);
                his.push(col - 1);
                start = uint::MAX;
            }
        } else if start == uint::MAX {
            start = col;
        }
    }
    if start != uint::MAX {
        los.push(start);
        his.push(col_count - 1);
    }
    (los, his)
}

#[track_caller]
pub fn get_msa_col_is_aligned(aln: &MultiSequence, col: uint) -> bool {
    let seq_count = aln.seqs.len();
    if seq_count == 0 {
        return false;
    }

    let mut upper_count = 0;
    let mut lower_count = 0;
    for seq in &aln.seqs {
        let c = seq.char_vec[col as usize];
        if c == '-' || c == '.' {
        } else if c.is_ascii_uppercase() {
            upper_count += 1;
        } else if c.is_ascii_lowercase() {
            lower_count += 1;
        } else {
            panic!("Unexpected sequence char '{c}'");
        }
    }
    if upper_count > 0 && lower_count > 0 {
        panic!("Mixed-case col");
    }
    upper_count > 0
}

#[track_caller]
pub fn get_msa_col_aligned_vec(aln: &MultiSequence) -> Vec<bool> {
    let col_count = multi_sequence_get_col_count(aln);
    let mut aligned_vec = Vec::new();
    for col in 0..col_count {
        let al = get_msa_col_is_aligned(aln, col);
        aligned_vec.push(al);
    }
    aligned_vec
}

#[track_caller]
pub fn squeeze_inserts(aln: &MultiSequence) -> MultiSequence {
    let seq_count = aln.seqs.len();
    let col_count = multi_sequence_get_col_count(aln);

    let mut ungapped_seqs = Vec::new();
    for seq_index in 0..seq_count {
        let mut ungapped_seq = String::new();
        for c in &aln.seqs[seq_index].char_vec {
            if *c != '-' && *c != '.' {
                ungapped_seq.push(*c);
            }
        }
        ungapped_seqs.push(ungapped_seq);
    }

    let als = get_msa_col_aligned_vec(aln);
    let (los, his) = get_insert_lo_his(&als);
    let range_count = los.len();
    if range_count == 0 {
        return aln.clone();
    }

    assert_eq!(his.len(), range_count);
    let mut new_rows = vec![String::new(); seq_count];
    let mut prev_hi = uint::MAX;
    for range_index in 0..range_count {
        let lo = los[range_index];
        let hi = his[range_index];
        assert!(lo <= hi);
        if range_index > 0 {
            assert!(lo > prev_hi);
        }

        let from = if prev_hi == uint::MAX { 0 } else { prev_hi + 1 };
        for col in from..lo {
            for seq_index in 0..seq_count {
                let mut c = aln.seqs[seq_index].char_vec[col as usize];
                if als[col as usize] {
                    c = c.to_ascii_uppercase();
                } else {
                    c = c.to_ascii_lowercase();
                }
                new_rows[seq_index].push(c);
            }
        }

        let mut max_ins_l = 0usize;
        let mut inserts = Vec::new();
        for seq_index in 0..seq_count {
            let mut insert = String::new();
            for col in lo..=hi {
                let c = aln.seqs[seq_index].char_vec[col as usize];
                if c != '-' && c != '.' {
                    insert.push(c.to_ascii_lowercase());
                }
            }
            let l = insert.len();
            if l > max_ins_l {
                max_ins_l = l;
            }
            inserts.push(insert);
        }
        for seq_index in 0..seq_count {
            let insert = &inserts[seq_index];
            let ins_l = insert.len();
            let mut n = 0usize;
            let dots = max_ins_l - ins_l;
            let mut dots1 = dots / 2;
            if from == 0 {
                dots1 = dots;
            } else if range_index + 1 == range_count {
                dots1 = 0;
            }
            while n < dots1 {
                new_rows[seq_index].push('.');
                n += 1;
            }
            new_rows[seq_index].push_str(insert);
            assert!(ins_l <= max_ins_l);
            while n < dots {
                new_rows[seq_index].push('.');
                n += 1;
            }
        }
        for seq_index in 0..seq_count {
            assert_eq!(new_rows[seq_index].len(), new_rows[0].len());
        }

        prev_hi = hi;
    }

    let from = if prev_hi == uint::MAX { 0 } else { prev_hi + 1 };
    for col in from..col_count {
        for seq_index in 0..seq_count {
            new_rows[seq_index].push(aln.seqs[seq_index].char_vec[col as usize]);
        }
    }
    for seq_index in 0..seq_count {
        assert_eq!(new_rows[seq_index].len(), new_rows[0].len());
    }

    let labels = aln
        .seqs
        .iter()
        .map(|seq| seq.label.clone())
        .collect::<Vec<_>>();
    let mut s = MultiSequence::default();
    multi_sequence_from_strings(&mut s, &labels, &new_rows);

    for seq_index in 0..seq_count {
        let mut ungapped_seq = String::new();
        for c in &s.seqs[seq_index].char_vec {
            if *c != '-' && *c != '.' {
                ungapped_seq.push(*c);
            }
        }
        if ungapped_seq != ungapped_seqs[seq_index] {
            panic!("UngappedSeq != UngappedSeqs[SeqIndex]");
        }
    }
    s
}

#[track_caller]
pub fn cmd_squeeze_inserts(input_file_name: &str, output_file_name: &str) -> MultiSequence {
    let input_msa = msa_from_fasta_file_preserve_case(input_file_name);
    let out_msa = squeeze_inserts(&input_msa);
    msa_to_fasta_file_l103(&out_msa, output_file_name);
    out_msa
}

pub fn get_q_char(q: f64) -> char {
    assert!((0.0..=1.0).contains(&q));
    if q == 1.0 {
        '|'
    } else if q >= 0.9 {
        ':'
    } else if q >= 0.5 {
        '.'
    } else if q > 0.0 {
        '@'
    } else {
        '*'
    }
}

#[track_caller]
pub fn cmd_cmp_ref_msas(
    test_file_name: &str,
    ref_file_name: &str,
    max_gap_fract: f64,
) -> (QScorer, String) {
    let name = get_base_name(test_file_name);

    let test = msa_from_fasta_file_preserve_case(test_file_name);
    let ref_msa = msa_from_fasta_file_preserve_case(ref_file_name);

    let mut qs = QScorer {
        max_gap_fract,
        ..QScorer::default()
    };
    q_scorer_cmp_ref_ms_as(&mut qs, &name, &test, &ref_msa, false);

    let nc = qs.ref_msas_compared_col_count;
    let mut out = format!(
        "@CMP_REF_MSAs test={test_file_name} ref={ref_file_name} name={name} cols={nc} Q={:.4}\n",
        qs.ref_msas_q
    );
    if nc == 0 {
        return (qs, out);
    }
    let qs_col_qs = qs.ref_msas_col_qs.clone();
    let test_cols = qs.ref_msas_test_cols.clone();
    let ref_cols = qs.ref_msas_ref_cols.clone();
    assert_eq!(test_cols.len(), nc as usize);
    assert_eq!(ref_cols.len(), nc as usize);
    assert_eq!(qs_col_qs.len(), nc as usize);
    let test_seq_indexes = qs.test_seq_indexes.clone();
    let ref_seq_indexes = qs.ref_seq_indexes.clone();
    let ns = test_seq_indexes.len();
    assert_eq!(ref_seq_indexes.len(), ns);
    for i in 0..nc as usize {
        let test_col = test_cols[i];
        let ref_col = ref_cols[i];
        let mut test_col_str = String::new();
        let mut ref_col_str = String::new();
        for j in 0..ns {
            test_col_str.push(msa_get_char(&test, test_seq_indexes[j], test_col));
            ref_col_str.push(msa_get_char(&ref_msa, ref_seq_indexes[j], ref_col));
        }
        out.push_str(&format!(
            "{test_col_str}  {ref_col_str}  {:6.4}\n",
            qs_col_qs[i]
        ));
    }

    out.push('\n');
    let anc = test_cols.len();
    assert!(anc > 0);
    let mut fixed_test_cols = vec![test_cols[0]];
    let mut fixed_ref_cols = vec![ref_cols[0]];
    let mut fixed_qs = vec![qs_col_qs[0]];
    for i in 1..anc {
        let col_x = test_cols[i];
        let col_y = ref_cols[i];
        if col_x > *fixed_test_cols.last().unwrap() && col_y > *fixed_ref_cols.last().unwrap() {
            fixed_test_cols.push(col_x);
            fixed_ref_cols.push(col_y);
            fixed_qs.push(qs_col_qs[i]);
        }
    }
    let nf = fixed_test_cols.len();
    assert_eq!(fixed_ref_cols.len(), nf);
    assert!(nf > 0);

    let test_subset = msa_from_seq_subset(&test, &test_seq_indexes);
    let ref_subset = msa_from_seq_subset(&ref_msa, &ref_seq_indexes);
    let mut test2 = MultiSequence::default();
    let mut ref2 = MultiSequence::default();
    let mut path = String::new();
    let mut merge_map = Vec::new();
    align_ms_as_by_cols(
        &test_subset,
        &ref_subset,
        &fixed_test_cols,
        &fixed_ref_cols,
        &mut path,
        &mut merge_map,
        &mut test2,
        &mut ref2,
    );
    let col_count2 = path.len() as uint;
    assert_eq!(multi_sequence_get_col_count(&test2), col_count2);
    assert_eq!(multi_sequence_get_col_count(&ref2), col_count2);
    assert_eq!(merge_map.len(), nf);

    let mut all_gaps = Vec::new();
    for i in 0..col_count2 {
        all_gaps.push(msa_is_gap_column(&test2, i) && msa_is_gap_column(&ref2, i));
    }

    let mut first_m = uint::MAX;
    let mut last_m = uint::MAX;
    for (i, c) in path.bytes().enumerate() {
        if c == b'M' {
            if first_m == uint::MAX {
                first_m = i as uint;
            }
            last_m = i as uint;
        }
    }

    let mut annot = vec!['_'; col_count2 as usize];
    for i in 0..nf {
        let k = merge_map[i] as usize;
        let q = fixed_qs[i];
        assert!(k < annot.len());
        annot[k] = if q == 1.0 {
            '|'
        } else if q >= 0.9 {
            ':'
        } else if q >= 0.5 {
            '.'
        } else if q > 0.0 {
            '@'
        } else {
            '*'
        };
    }

    for i in 0..test2.seqs.len() as uint {
        let label = msa_get_seq_label(&test2, i);
        let ref_label = msa_get_seq_label(&ref2, i);
        let row = msa_get_row_str(&test2, i);
        let row_bytes = row.as_bytes();
        let mut row_m = String::new();
        for j in first_m..=last_m {
            if !all_gaps[j as usize] {
                row_m.push(row_bytes[j as usize] as char);
            }
        }
        out.push_str(&format!("{row_m}  >{label} (={ref_label})\n"));
    }
    out.push('\n');

    let mut annot_m = String::new();
    for j in first_m..=last_m {
        if !all_gaps[j as usize] {
            annot_m.push(annot[j as usize]);
        }
    }
    out.push_str(&format!("{annot_m}\n\n"));

    for i in 0..ref2.seqs.len() as uint {
        let label = msa_get_seq_label(&ref2, i);
        let row = msa_get_row_str(&ref2, i);
        let row_bytes = row.as_bytes();
        let mut row_m = String::new();
        for j in first_m..=last_m {
            if !all_gaps[j as usize] {
                row_m.push(row_bytes[j as usize] as char);
            }
        }
        out.push_str(&format!("{row_m}  >{label}\n"));
    }
    (qs, out)
}

pub fn get_bin(conf: f64) -> uint {
    assert!(conf > 0.0 && conf <= 1.0);
    if conf == 1.0 {
        return 10;
    }
    let bin = (conf * 10.0) as uint;
    assert!(bin < 10);
    bin
}

#[track_caller]
pub fn cmd_colscore_efa(
    efa_file_name: &str,
    ref_file_name: &str,
    output_file_name: &str,
    max_gap_fract: f64,
) -> String {
    const MAXBIN: usize = 10;
    let mut e = Ensemble::default();
    ensemble_from_file(&mut e, efa_file_name);

    let mut ref_msa = msa_from_fasta_file_preserve_case(ref_file_name);
    ensemble_sort_msa(&e, &mut ref_msa);

    let ref_unique_ixs = ensemble_get_ref_unique_ixs(&e, &ref_msa, max_gap_fract);
    let ref_upper_col_count = (0..multi_sequence_get_col_count(&ref_msa))
        .filter(|&ref_col_index| msa_col_is_upper(&ref_msa, ref_col_index, max_gap_fract))
        .count() as uint;
    let ref_pos_set = ensemble_get_ref_pos_set(&e, &ref_msa, max_gap_fract);

    let msa_count = e.msas.len() as uint;
    let mut bin_to_count = vec![0_u32; MAXBIN + 1];
    let mut bin_to_correct_count = vec![0_u32; MAXBIN + 1];
    let mut sum_tc = 0.0;
    for msa_index in 0..msa_count {
        let (test_unique_ixs, confs) = ensemble_get_test_unique_ixs(&e, msa_index, &ref_pos_set);

        let test_ix_count = test_unique_ixs.len();
        let mut correct_count = 0_u32;
        for i in 0..test_ix_count {
            let test_unique_ix = test_unique_ixs[i];
            let conf = confs[i];
            let bin = get_bin(conf) as usize;
            assert!(bin <= MAXBIN);
            bin_to_count[bin] += 1;
            let correct = ref_unique_ixs.contains(&test_unique_ix);
            if correct {
                correct_count += 1;
                bin_to_correct_count[bin] += 1;
            }
        }
        let tc = f64::from(correct_count) / f64::from(ref_upper_col_count);
        sum_tc += tc;
    }
    let mean_tc = sum_tc / f64::from(msa_count);

    let mut out = String::new();
    out.push_str(&format!("meantc\t{mean_tc:.4}\n"));
    for bin in 0..=MAXBIN {
        let count = bin_to_count[bin];
        let correct_count = bin_to_correct_count[bin];
        assert!(correct_count <= count);
        let mut p = 0.0;
        if count > 0 {
            p = f64::from(correct_count) / f64::from(count);
        }
        out.push_str(&format!("bin\t{bin}\t{count}\t{correct_count}\t{p:.4}\n"));
    }
    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, &out).expect("failed to write colscore_efa output");
    }
    out
}

#[track_caller]
pub fn mpc_flat_cons_iter<FConsPair>(mpc: &mut MPCFlat, _iter: uint, mut cons_pair: FConsPair)
where
    FConsPair: FnMut(&mut MPCFlat, uint),
{
    let pair_count = mpc.pairs.len() as uint;
    assert!(pair_count > 0);
    for pair_index in 0..pair_count {
        cons_pair(mpc, pair_index);
    }
    std::mem::swap(&mut mpc.sparse_posts1, &mut mpc.sparse_posts2);
}

#[track_caller]
pub fn mpc_flat_cons_pair(mpc: &mut MPCFlat, pair_index: uint) {
    let (seq_index_x, seq_index_y) = mpc_flat_get_pair(mpc, pair_index);
    let sparse_post_xy = mpc.sparse_posts1[pair_index as usize]
        .as_ref()
        .unwrap_or_else(|| panic!("missing sparse post {pair_index}"))
        .clone();

    let lx = mpc_flat_get_seq_length(mpc, seq_index_x);
    let ly = mpc_flat_get_seq_length(mpc, seq_index_y);
    assert_eq!(sparse_post_xy.lx, lx);
    assert_eq!(sparse_post_xy.ly, ly);

    let mut post = my_sparse_mx_to_post(&sparse_post_xy);
    for p in &mut post {
        *p *= 2.0;
    }

    let seq_count = mpc_flat_get_seq_count(mpc);
    assert!(seq_index_x < seq_index_y);
    for seq_index_z in 0..seq_count {
        if seq_index_z == seq_index_x || seq_index_z == seq_index_y {
            continue;
        }
        let _ = mpc.weights[seq_index_z as usize];
        let weight_z = 1.0_f32;

        if seq_index_z < seq_index_x {
            assert!(seq_index_z < seq_index_y);
            let pair_index_zx = mpc_flat_get_pair_index(mpc, seq_index_z, seq_index_x);
            let pair_index_zy = mpc_flat_get_pair_index(mpc, seq_index_z, seq_index_y);
            let zx = mpc.sparse_posts1[pair_index_zx as usize]
                .as_ref()
                .unwrap_or_else(|| panic!("missing sparse post {pair_index_zx}"))
                .clone();
            let zy = mpc.sparse_posts1[pair_index_zy as usize]
                .as_ref()
                .unwrap_or_else(|| panic!("missing sparse post {pair_index_zy}"))
                .clone();
            relax_flat_zx_zy(&zx, &zy, weight_z, &mut post);
        } else if seq_index_z > seq_index_x && seq_index_z < seq_index_y {
            let pair_index_xz = mpc_flat_get_pair_index(mpc, seq_index_x, seq_index_z);
            let pair_index_zy = mpc_flat_get_pair_index(mpc, seq_index_z, seq_index_y);
            let xz = mpc.sparse_posts1[pair_index_xz as usize]
                .as_ref()
                .unwrap_or_else(|| panic!("missing sparse post {pair_index_xz}"))
                .clone();
            let zy = mpc.sparse_posts1[pair_index_zy as usize]
                .as_ref()
                .unwrap_or_else(|| panic!("missing sparse post {pair_index_zy}"))
                .clone();
            relax_flat_xz_zy(&xz, &zy, weight_z, &mut post);
        } else if seq_index_z > seq_index_x && seq_index_z > seq_index_y {
            let pair_index_xz = mpc_flat_get_pair_index(mpc, seq_index_x, seq_index_z);
            let pair_index_yz = mpc_flat_get_pair_index(mpc, seq_index_y, seq_index_z);
            let xz = mpc.sparse_posts1[pair_index_xz as usize]
                .as_ref()
                .unwrap_or_else(|| panic!("missing sparse post {pair_index_xz}"))
                .clone();
            let yz = mpc.sparse_posts1[pair_index_yz as usize]
                .as_ref()
                .unwrap_or_else(|| panic!("missing sparse post {pair_index_yz}"))
                .clone();
            relax_flat_xz_yz(&xz, &yz, weight_z, &mut post);
        } else {
            panic!("invalid ConsPair sequence ordering");
        }
    }

    let updated_sparse_post_xy = mpc_flat_get_updated_sparse_post(mpc, pair_index);
    my_sparse_mx_update_from_post(updated_sparse_post_xy, &sparse_post_xy, &post, seq_count);
    updated_sparse_post_xy.x = sparse_post_xy.x;
    updated_sparse_post_xy.y = sparse_post_xy.y;
}

#[track_caller]
pub fn cmd_core_blocks(
    msa_file_name: &str,
    output_file_name: &str,
    min_block_length: uint,
    min_block_seqs: uint,
) -> String {
    let aln = msa_from_fasta_file_l95(msa_file_name);
    let seq_count = aln.seqs.len() as uint;
    let col_count = multi_sequence_get_col_count(&aln);

    let mut ungapped_mx = vec![vec![false; col_count as usize]; seq_count as usize];
    for seq_idx in 0..seq_count {
        for col_idx in 0..col_count {
            ungapped_mx[seq_idx as usize][col_idx as usize] = !msa_is_gap(&aln, seq_idx, col_idx);
        }
    }

    let blocks = greedy_rects(&ungapped_mx, min_block_length as i32, min_block_seqs as i32);
    let mut out = String::new();
    out.push_str(&format!("core_blocks\t{}\n", blocks.len()));
    for (block_idx, r) in blocks.iter().enumerate() {
        out.push_str(&format!(
            "block\t{}\t{}\t{}\n",
            block_idx, r.width, r.height
        ));
        for seq_idx in r.top..r.top + r.height {
            let label = msa_get_seq_label(&aln, seq_idx as uint);
            let col_to_pos = msa_get_col_to_pos(&aln, seq_idx as uint);
            for col_idx in r.left..r.left + r.width {
                out.push(msa_get_char(&aln, seq_idx as uint, col_idx as uint));
            }
            out.push_str(&format!("\t{}\t{}\n", col_to_pos[r.left as usize], label));
        }
    }

    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, &out).expect("failed to write core_blocks output");
    }
    out
}

