pub fn msa_from_fasta_file_l95(file_name: &str) -> MultiSequence {
    let mut tf = text_file_text_file_l5(file_name, false);
    let msa = msa_from_fasta_file_l5(&mut tf);
    text_file_destructor_text_file(&mut tf);
    msa
}

#[track_caller]
pub fn msa_to_fasta_file_l103(msa: &MultiSequence, file_name: &str) {
    if file_name.is_empty() {
        return;
    }
    std::fs::write(file_name, msa_to_fasta_file_l124(msa)).expect("failed to write MSA FASTA");
}

#[track_caller]
pub fn msa_to_fasta_file_l112(msa: &MultiSequence) -> String {
    const ROW_LEN: usize = 80;
    let col_count = multi_sequence_get_col_count(msa) as usize;
    if col_count == 0 {
        return String::new();
    }
    let block_count = col_count.div_ceil(ROW_LEN);
    let mut out = String::new();
    for seq in &msa.seqs {
        out.push('>');
        out.push_str(&seq.label);
        out.push('\n');
        for block_index in 0..block_count {
            let from = block_index * ROW_LEN;
            let to = std::cmp::min(from + ROW_LEN, col_count);
            for pos in from..to {
                out.push(seq.char_vec[pos]);
            }
            out.push('\n');
        }
    }
    out
}

#[track_caller]
pub fn msa_to_fasta_file_l124(msa: &MultiSequence) -> String {
    const FASTA_BLOCK: usize = 60;
    let col_count = multi_sequence_get_col_count(msa) as usize;
    assert!(col_count > 0);
    let lines_per_seq = (col_count - 1) / FASTA_BLOCK + 1;
    let mut out = String::new();
    for seq in &msa.seqs {
        out.push('>');
        out.push_str(&seq.label);
        out.push('\n');
        let mut n = 0usize;
        for line in 0..lines_per_seq {
            let mut letters = col_count - line * FASTA_BLOCK;
            if letters > FASTA_BLOCK {
                letters = FASTA_BLOCK;
            }
            for _ in 0..letters {
                out.push(seq.char_vec[n]);
                n += 1;
            }
            out.push('\n');
        }
    }
    out
}

#[track_caller]
pub fn get_fasta_seq(file: &mut TextFile, delete_gaps: bool) -> Option<(String, String)> {
    loop {
        let c = text_file_get_char(file)?;
        if c != b'>' {
            panic!("Invalid file format, expected '>' to start FASTA label");
        }

        let mut label = Vec::new();
        loop {
            let Some(c) = text_file_get_char(file) else {
                panic!("End-of-file or input error in FASTA label");
            };
            if c == b'\n' || c == b'\r' {
                break;
            }
            label.push(c);
        }

        let mut seq = Vec::new();
        let mut previous_char = b'\n';
        loop {
            let Some(mut c) = text_file_get_char(file) else {
                break;
            };
            if c == b'>' {
                if previous_char == b'\n' || previous_char == b'\r' {
                    file.pushed_back = Some(c);
                    break;
                }
                panic!("Unexpected '>' in FASTA sequence data");
            } else if (c as char).is_ascii_whitespace() {
            } else if c == b'-' || c == b'.' {
                if !delete_gaps {
                    seq.push(c);
                }
            } else if (c as char).is_ascii_alphabetic() {
                if *FASTA_UPPER.lock().unwrap() {
                    c = c.to_ascii_uppercase();
                }
                seq.push(c);
            } else if *FASTA_ALLOW_DIGITS.lock().unwrap() && (c as char).is_ascii_digit() {
                seq.push(c);
            } else if (c as char).is_ascii_graphic() || c == b' ' {
                previous_char = c;
                continue;
            } else {
                previous_char = c;
                continue;
            }
            previous_char = c;
        }

        if seq.is_empty() {
            continue;
        }
        return Some((
            String::from_utf8_lossy(&label).into_owned(),
            String::from_utf8_lossy(&seq).into_owned(),
        ));
    }
}

#[track_caller]
pub fn calc_fwd_flat_l12(x: &[byte], lx: uint, y: &[byte], ly: uint, flat: &mut [f32]) {
    assert!(!MEGA_STATE.lock().unwrap().loaded);
    if f64::from(lx) * f64::from(ly) * 5.0 + 100.0 > f64::from(i32::MAX) {
        panic!("HMM overflow, sequence lengths {lx}, {ly} (max ~21k)");
    }
    assert!(lx > 0 && ly > 0);
    assert!(x.len() >= lx as usize);
    assert!(y.len() >= ly as usize);
    assert!(flat.len() >= get_fb_size(lx, ly) as usize);

    let start_score = *PAIR_HMM_START_SCORE.lock().unwrap();
    let trans_score = *PAIR_HMM_TRANS_SCORE.lock().unwrap();
    let ins_score = *PAIR_HMM_INS_SCORE.lock().unwrap();
    let match_score = PAIR_HMM_MATCH_SCORE.lock().unwrap();

    let t_sm = start_score[HMMSTATE_M as usize];
    let t_si = start_score[HMMSTATE_IX as usize];
    let t_sj = start_score[HMMSTATE_JX as usize];
    let t_mm = trans_score[HMMSTATE_M as usize][HMMSTATE_M as usize];
    let t_mi = trans_score[HMMSTATE_M as usize][HMMSTATE_IX as usize];
    let t_mj = trans_score[HMMSTATE_M as usize][HMMSTATE_JX as usize];
    let t_ii = trans_score[HMMSTATE_IX as usize][HMMSTATE_IX as usize];
    let t_im = trans_score[HMMSTATE_IX as usize][HMMSTATE_M as usize];
    let t_jj = trans_score[HMMSTATE_JX as usize][HMMSTATE_JX as usize];
    let t_jm = trans_score[HMMSTATE_JX as usize][HMMSTATE_M as usize];

    let x0 = x[0] as usize;
    let y0 = y[0] as usize;
    let ins_x0 = ins_score[x0];
    let ins_y0 = ins_score[y0];
    let emit_x0_y0 = match_score[x0][y0];

    let ly1 = (ly + 1) as usize;
    let base_0_0 = 0usize;
    let base_1_1 = HMMSTATE_COUNT as usize * (ly1 + 1);
    let base_1_0 = HMMSTATE_COUNT as usize * ly1;
    let base_0_1 = HMMSTATE_COUNT as usize;
    let base_inc_i = HMMSTATE_COUNT as usize * ly1;
    let base_inc_j = HMMSTATE_COUNT as usize;

    flat[base_0_0 + HMMSTATE_M as usize] = LOG_ZERO;
    flat[base_0_0 + HMMSTATE_IX as usize] = LOG_ZERO;
    flat[base_0_0 + HMMSTATE_JX as usize] = LOG_ZERO;
    flat[base_0_0 + HMMSTATE_IY as usize] = LOG_ZERO;
    flat[base_0_0 + HMMSTATE_JY as usize] = LOG_ZERO;

    flat[base_1_1 + HMMSTATE_M as usize] = t_sm + emit_x0_y0;
    flat[base_1_0 + HMMSTATE_IX as usize] = t_si + ins_x0;
    flat[base_1_0 + HMMSTATE_JX as usize] = t_sj + ins_x0;
    flat[base_0_1 + HMMSTATE_IY as usize] = t_si + ins_y0;
    flat[base_0_1 + HMMSTATE_JY as usize] = t_sj + ins_y0;

    let mut base = base_1_0;
    for _i in 1..=lx {
        flat[base + HMMSTATE_M as usize] = LOG_ZERO;
        flat[base + HMMSTATE_IY as usize] = LOG_ZERO;
        flat[base + HMMSTATE_JY as usize] = LOG_ZERO;
        base += base_inc_i;
    }

    base = base_0_1;
    for _j in 1..=ly {
        flat[base + HMMSTATE_M as usize] = LOG_ZERO;
        flat[base + HMMSTATE_IX as usize] = LOG_ZERO;
        flat[base + HMMSTATE_JX as usize] = LOG_ZERO;
        base += base_inc_j;
    }

    base = base_1_0;
    let mut next_base = base + base_inc_i;
    for i in 1..lx as usize {
        let emit_x = ins_score[x[i] as usize];
        flat[next_base + HMMSTATE_IX as usize] = flat[base + HMMSTATE_IX as usize] + t_ii + emit_x;
        flat[next_base + HMMSTATE_JX as usize] = flat[base + HMMSTATE_JX as usize] + t_jj + emit_x;
        base = next_base;
        next_base += base_inc_i;
    }

    base = base_0_1;
    next_base = base + base_inc_j;
    for j in 1..ly as usize {
        let emit_y = ins_score[y[j] as usize];
        flat[next_base + HMMSTATE_IY as usize] = flat[base + HMMSTATE_IY as usize] + t_ii + emit_y;
        flat[next_base + HMMSTATE_JY as usize] = flat[base + HMMSTATE_JY as usize] + t_jj + emit_y;
        base = next_base;
        next_base += base_inc_j;
    }

    let mut base_i_j = base_1_1;
    let mut base_i1_j = base_0_1;
    let mut base_i_j1 = base_1_0;
    let mut base_i1_j1 = base_0_0;

    for i in 1..=lx as usize {
        let x_char = x[i - 1] as usize;
        let emit_x = ins_score[x_char];
        for j in 1..=ly as usize {
            let y_char = y[j - 1] as usize;
            let emit_y = ins_score[y_char];
            let emit_pair = match_score[x_char][y_char];
            if i == 1 && j == 1 {
                flat[base_1_1 + HMMSTATE_M as usize] = t_sm + emit_x0_y0;
            } else {
                let sum_prev = log_add_hack(
                    log_add_hack(
                        flat[base_i1_j1 + HMMSTATE_M as usize] + t_mm,
                        flat[base_i1_j1 + HMMSTATE_IX as usize] + t_im,
                    ),
                    log_add_hack(
                        flat[base_i1_j1 + HMMSTATE_JX as usize] + t_jm,
                        log_add_hack(
                            flat[base_i1_j1 + HMMSTATE_IY as usize] + t_im,
                            flat[base_i1_j1 + HMMSTATE_JY as usize] + t_jm,
                        ),
                    ),
                );
                flat[base_i_j + HMMSTATE_M as usize] = sum_prev + emit_pair;
            }

            let prev_m_i1_j = flat[base_i1_j + HMMSTATE_M as usize];
            let prev_m_i_j1 = flat[base_i_j1 + HMMSTATE_M as usize];
            flat[base_i_j + HMMSTATE_IX as usize] = log_add_hack(
                flat[base_i1_j + HMMSTATE_IX as usize] + t_ii,
                prev_m_i1_j + t_mi,
            ) + emit_x;
            flat[base_i_j + HMMSTATE_JX as usize] = log_add_hack(
                flat[base_i1_j + HMMSTATE_JX as usize] + t_jj,
                prev_m_i1_j + t_mj,
            ) + emit_x;
            flat[base_i_j + HMMSTATE_IY as usize] = log_add_hack(
                flat[base_i_j1 + HMMSTATE_IY as usize] + t_ii,
                prev_m_i_j1 + t_mi,
            ) + emit_y;
            flat[base_i_j + HMMSTATE_JY as usize] = log_add_hack(
                flat[base_i_j1 + HMMSTATE_JY as usize] + t_jj,
                prev_m_i_j1 + t_mj,
            ) + emit_y;

            base_i_j += base_inc_j;
            base_i1_j += base_inc_j;
            base_i_j1 += base_inc_j;
            base_i1_j1 += base_inc_j;
        }

        base_i_j += base_inc_j;
        base_i1_j += base_inc_j;
        base_i_j1 += base_inc_j;
        base_i1_j1 += base_inc_j;
    }
}

#[track_caller]
pub fn mega_calc_fwd_flat_mega(profile_x: &[Vec<byte>], profile_y: &[Vec<byte>], flat: &mut [f32]) {
    let lx = profile_x.len() as uint;
    let ly = profile_y.len() as uint;
    if f64::from(lx) * f64::from(ly) * 5.0 + 100.0 > f64::from(i32::MAX) {
        panic!("HMM overflow, sequence lengths {lx}, {ly} (max ~21k)");
    }
    assert!(lx > 0 && ly > 0);
    assert!(flat.len() >= get_fb_size(lx, ly) as usize);

    let start_score = *PAIR_HMM_START_SCORE.lock().unwrap();
    let trans_score = *PAIR_HMM_TRANS_SCORE.lock().unwrap();
    let t_sm = start_score[HMMSTATE_M as usize];
    let t_si = start_score[HMMSTATE_IX as usize];
    let t_sj = start_score[HMMSTATE_JX as usize];
    let t_mm = trans_score[HMMSTATE_M as usize][HMMSTATE_M as usize];
    let t_mi = trans_score[HMMSTATE_M as usize][HMMSTATE_IX as usize];
    let t_mj = trans_score[HMMSTATE_M as usize][HMMSTATE_JX as usize];
    let t_ii = trans_score[HMMSTATE_IX as usize][HMMSTATE_IX as usize];
    let t_im = trans_score[HMMSTATE_IX as usize][HMMSTATE_M as usize];
    let t_jj = trans_score[HMMSTATE_JX as usize][HMMSTATE_JX as usize];
    let t_jm = trans_score[HMMSTATE_JX as usize][HMMSTATE_M as usize];

    let ins_x0 = mega_get_ins_score(profile_x, 0);
    let ins_y0 = mega_get_ins_score(profile_y, 0);
    let emit_x0_y0 = mega_get_match_score(profile_x, 0, profile_y, 0);

    let ly1 = (ly + 1) as usize;
    let base_0_0 = 0usize;
    let base_1_1 = HMMSTATE_COUNT as usize * (ly1 + 1);
    let base_1_0 = HMMSTATE_COUNT as usize * ly1;
    let base_0_1 = HMMSTATE_COUNT as usize;
    let base_inc_i = HMMSTATE_COUNT as usize * ly1;
    let base_inc_j = HMMSTATE_COUNT as usize;

    flat[base_0_0 + HMMSTATE_M as usize] = LOG_ZERO;
    flat[base_0_0 + HMMSTATE_IX as usize] = LOG_ZERO;
    flat[base_0_0 + HMMSTATE_JX as usize] = LOG_ZERO;
    flat[base_0_0 + HMMSTATE_IY as usize] = LOG_ZERO;
    flat[base_0_0 + HMMSTATE_JY as usize] = LOG_ZERO;

    flat[base_1_1 + HMMSTATE_M as usize] = t_sm + emit_x0_y0;
    flat[base_1_0 + HMMSTATE_IX as usize] = t_si + ins_x0;
    flat[base_1_0 + HMMSTATE_JX as usize] = t_sj + ins_x0;
    flat[base_0_1 + HMMSTATE_IY as usize] = t_si + ins_y0;
    flat[base_0_1 + HMMSTATE_JY as usize] = t_sj + ins_y0;

    let mut base = base_1_0;
    for _i in 1..=lx {
        flat[base + HMMSTATE_M as usize] = LOG_ZERO;
        flat[base + HMMSTATE_IY as usize] = LOG_ZERO;
        flat[base + HMMSTATE_JY as usize] = LOG_ZERO;
        base += base_inc_i;
    }

    base = base_0_1;
    for _j in 1..=ly {
        flat[base + HMMSTATE_M as usize] = LOG_ZERO;
        flat[base + HMMSTATE_IX as usize] = LOG_ZERO;
        flat[base + HMMSTATE_JX as usize] = LOG_ZERO;
        base += base_inc_j;
    }

    base = base_1_0;
    let mut next_base = base + base_inc_i;
    for i in 1..lx {
        let emit_x = mega_get_ins_score(profile_x, i);
        flat[next_base + HMMSTATE_IX as usize] = flat[base + HMMSTATE_IX as usize] + t_ii + emit_x;
        flat[next_base + HMMSTATE_JX as usize] = flat[base + HMMSTATE_JX as usize] + t_jj + emit_x;
        base = next_base;
        next_base += base_inc_i;
    }

    base = base_0_1;
    next_base = base + base_inc_j;
    for j in 1..ly {
        let emit_y = mega_get_ins_score(profile_y, j);
        flat[next_base + HMMSTATE_IY as usize] = flat[base + HMMSTATE_IY as usize] + t_ii + emit_y;
        flat[next_base + HMMSTATE_JY as usize] = flat[base + HMMSTATE_JY as usize] + t_jj + emit_y;
        base = next_base;
        next_base += base_inc_j;
    }

    let mut base_i_j = base_1_1;
    let mut base_i1_j = base_0_1;
    let mut base_i_j1 = base_1_0;
    let mut base_i1_j1 = base_0_0;

    for i in 1..=lx {
        let emit_x = mega_get_ins_score(profile_x, i - 1);
        for j in 1..=ly {
            let emit_y = mega_get_ins_score(profile_y, j - 1);
            let emit_pair = mega_get_match_score(profile_x, i - 1, profile_y, j - 1);
            if i == 1 && j == 1 {
                flat[base_1_1 + HMMSTATE_M as usize] = t_sm + emit_x0_y0;
            } else {
                let sum_prev = log_add_hack(
                    log_add_hack(
                        flat[base_i1_j1 + HMMSTATE_M as usize] + t_mm,
                        flat[base_i1_j1 + HMMSTATE_IX as usize] + t_im,
                    ),
                    log_add_hack(
                        flat[base_i1_j1 + HMMSTATE_JX as usize] + t_jm,
                        log_add_hack(
                            flat[base_i1_j1 + HMMSTATE_IY as usize] + t_im,
                            flat[base_i1_j1 + HMMSTATE_JY as usize] + t_jm,
                        ),
                    ),
                );
                flat[base_i_j + HMMSTATE_M as usize] = sum_prev + emit_pair;
            }

            let prev_m_i1_j = flat[base_i1_j + HMMSTATE_M as usize];
            let prev_m_i_j1 = flat[base_i_j1 + HMMSTATE_M as usize];
            flat[base_i_j + HMMSTATE_IX as usize] = log_add_hack(
                flat[base_i1_j + HMMSTATE_IX as usize] + t_ii,
                prev_m_i1_j + t_mi,
            ) + emit_x;
            flat[base_i_j + HMMSTATE_JX as usize] = log_add_hack(
                flat[base_i1_j + HMMSTATE_JX as usize] + t_jj,
                prev_m_i1_j + t_mj,
            ) + emit_x;
            flat[base_i_j + HMMSTATE_IY as usize] = log_add_hack(
                flat[base_i_j1 + HMMSTATE_IY as usize] + t_ii,
                prev_m_i_j1 + t_mi,
            ) + emit_y;
            flat[base_i_j + HMMSTATE_JY as usize] = log_add_hack(
                flat[base_i_j1 + HMMSTATE_JY as usize] + t_jj,
                prev_m_i_j1 + t_mj,
            ) + emit_y;

            base_i_j += base_inc_j;
            base_i1_j += base_inc_j;
            base_i_j1 += base_inc_j;
            base_i1_j1 += base_inc_j;
        }

        base_i_j += base_inc_j;
        base_i1_j += base_inc_j;
        base_i_j1 += base_inc_j;
        base_i1_j1 += base_inc_j;
    }
}

#[track_caller]
pub fn get_cons_char(msa: &MultiSequence, col_index: uint) -> char {
    let state = ALPHA_STATE.lock().unwrap();
    assert!(state.alpha_size == 4 || state.alpha_size == 20);
    let alpha_size = state.alpha_size as usize;
    let mut counts = vec![0_u32; alpha_size + 1];
    let col_count = multi_sequence_get_col_count(msa);
    assert!(col_index < col_count);
    let seq_count = msa.seqs.len();
    for seq_index in 0..seq_count {
        let c = msa.seqs[seq_index].char_vec[col_index as usize];
        if c == '-' || c == '.' {
            counts[alpha_size] += 1;
            continue;
        }
        let letter = state.char_to_letter[c as usize];
        if letter < state.alpha_size {
            counts[letter as usize] += 1;
        }
    }

    let mut max_count = 0;
    let mut max_letter = 0;
    for letter in 0..=alpha_size {
        let count = counts[letter];
        if count > max_count {
            max_count = count;
            max_letter = letter;
        }
    }
    if max_letter == alpha_size {
        return '-';
    }
    state.letter_to_char[max_letter] as char
}

#[track_caller]
pub fn get_consensus_sequence(msa: &MultiSequence) -> String {
    let mut seq = String::new();
    let seq_count = msa.seqs.len();
    let col_count = multi_sequence_get_col_count(msa);
    let _freqs = vec![0_u32; ALPHA_STATE.lock().unwrap().alpha_size as usize];
    for col_index in 0..col_count {
        let c = get_cons_char(msa, col_index);
        if c != '-' {
            seq.push(c);
        }
    }
    let _ = seq_count;
    seq
}

#[track_caller]
pub fn cmd_consseq(msa_file_name: &str, output_file_name: &str, label: Option<&str>) {
    let label = label.unwrap_or("CONSENSUS");
    let mut msa = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut msa, msa_file_name, false);
    let cons_seq = get_consensus_sequence(&msa);
    let out = seq_to_fasta_l2561(&cons_seq, label);
    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, out).expect("failed to write consensus FASTA");
    }
}

#[track_caller]
pub fn get_all_pairs_l3(count: uint) -> (Vec<uint>, Vec<uint>) {
    let mut indexes1 = Vec::new();
    let mut indexes2 = Vec::new();
    for i in 0..count {
        for j in i + 1..count {
            indexes1.push(i);
            indexes2.push(j);
        }
    }
    (indexes1, indexes2)
}

#[track_caller]
pub fn get_all_pairs_l18(count1: uint, count2: uint) -> (Vec<uint>, Vec<uint>) {
    let mut indexes1 = Vec::new();
    let mut indexes2 = Vec::new();
    for i in 0..count1 {
        for j in 0..count2 {
            indexes1.push(i);
            indexes2.push(j);
        }
    }
    (indexes1, indexes2)
}

#[track_caller]
pub fn get_pairs(count1: uint, count2: uint, target_pair_count: uint) -> (Vec<uint>, Vec<uint>) {
    let all_pair_count = count1 * count2;
    if target_pair_count == uint::MAX || all_pair_count < target_pair_count * 3 / 2 {
        return get_all_pairs_l18(count1, count2);
    }

    let mut pair_set = std::collections::BTreeSet::new();
    let max_counter = target_pair_count * 10;
    let mut counter = 0;
    while counter < max_counter && (pair_set.len() as uint) < target_pair_count {
        counter += 1;
        let i = randu32() % count1;
        let j = randu32() % count2;
        if i == j {
            continue;
        }
        pair_set.insert((i, j));
    }

    let pair_count = pair_set.len() as uint;
    assert!(pair_count > target_pair_count / 2);
    pair_set.into_iter().unzip()
}

#[track_caller]
pub fn p_prog_get_post_pairs_aligned_flat(
    progress_str: &str,
    msa1: &MultiSequence,
    msa2: &MultiSequence,
    seq_indexes1: &[uint],
    seq_indexes2: &[uint],
    sparse_posts: &mut Vec<MySparseMx>,
) -> f32 {
    let _progress_str = if progress_str.len() > 20 {
        &progress_str[..20]
    } else {
        progress_str
    };

    let seq_count1 = msa1.seqs.len() as uint;
    let seq_count2 = msa2.seqs.len() as uint;
    let pair_count = seq_indexes1.len() as uint;
    assert_eq!(seq_indexes2.len() as uint, pair_count);
    assert!(sparse_posts.is_empty());

    sparse_posts.resize(pair_count as usize, MySparseMx::default());

    let mut sum_ea = 0.0_f32;
    for pair_index in 0..pair_count {
        let _min = seq_count1.min(seq_count2);
        let _max = seq_count1.max(seq_count2);

        let seq_index1 = seq_indexes1[pair_index as usize];
        let seq_index2 = seq_indexes2[pair_index as usize];
        assert!(seq_index1 < seq_count1);
        assert!(seq_index2 < seq_count2);
        let label1 = &msa1.seqs[seq_index1 as usize].label;
        let label2 = &msa2.seqs[seq_index2 as usize].label;
        let l1 = get_seq_length_by_global_label(label1);
        let l2 = get_seq_length_by_global_label(label2);

        let post = calc_post(label1, label2);
        let mut dp_rows = alloc_dp_rows(l1, l2);
        let mut tb = alloc_tb(l1, l2);

        let (score, _path) = calc_aln_flat(&post, l1, l2, &mut dp_rows, &mut tb);

        my_sparse_mx_from_post(&mut sparse_posts[pair_index as usize], &post, l1, l2);

        let ea = score / l1.min(l2) as f32;
        sum_ea += ea;
    }
    sum_ea / pair_count as f32
}

#[track_caller]
pub fn get_post_pairs_aligned_flat_mega(
    progress_str: &str,
    msa1: &MultiSequence,
    msa2: &MultiSequence,
    seq_indexes1: &[uint],
    seq_indexes2: &[uint],
    sparse_posts: &mut Vec<MySparseMx>,
) -> f32 {
    let _progress_str = if progress_str.len() > 20 {
        &progress_str[..20]
    } else {
        progress_str
    };

    let seq_count1 = msa1.seqs.len() as uint;
    let seq_count2 = msa2.seqs.len() as uint;
    let pair_count = seq_indexes1.len() as uint;
    assert_eq!(seq_indexes2.len() as uint, pair_count);
    assert!(sparse_posts.is_empty());

    sparse_posts.resize(pair_count as usize, MySparseMx::default());

    let mut sum_ea = 0.0_f32;
    for pair_index in 0..pair_count {
        let _min = seq_count1.min(seq_count2);
        let _max = seq_count1.max(seq_count2);

        let seq_index1 = seq_indexes1[pair_index as usize];
        let seq_index2 = seq_indexes2[pair_index as usize];
        assert!(seq_index1 < seq_count1);
        assert!(seq_index2 < seq_count2);

        let gapped_seq1 = &msa1.seqs[seq_index1 as usize];
        let gapped_seq2 = &msa2.seqs[seq_index2 as usize];
        let seq1 = sequence_copy_delete_gaps(&sequence_get_seq_as_string(gapped_seq1));
        let seq2 = sequence_copy_delete_gaps(&sequence_get_seq_as_string(gapped_seq2));
        let byte_seq1 = seq1.into_bytes();
        let byte_seq2 = seq2.into_bytes();
        let l1 = byte_seq1.len() as uint;
        let l2 = byte_seq2.len() as uint;

        let mut fwd = alloc_fb(l1, l2);
        let mut bwd = alloc_fb(l1, l2);
        let mut post = alloc_post(l1, l2);

        calc_fwd_flat_l12(&byte_seq1, l1, &byte_seq2, l2, &mut fwd);
        calc_bwd_flat_l10(&byte_seq1, l1, &byte_seq2, l2, &mut bwd);
        calc_post_flat(&fwd, &bwd, l1, l2, &mut post);

        let mut dp_rows = alloc_dp_rows(l1, l2);
        let mut tb = alloc_tb(l1, l2);
        let (score, _path) = calc_aln_flat(&post, l1, l2, &mut dp_rows, &mut tb);

        my_sparse_mx_from_post(&mut sparse_posts[pair_index as usize], &post, l1, l2);

        let ea = score / l1.min(l2) as f32;
        sum_ea += ea;
    }
    sum_ea / pair_count as f32
}

