pub fn in_bounds(r: i32, c: i32, r_count: i32, c_count: i32) -> bool {
    r >= 0 && r < r_count && c >= 0 && c < c_count
}

pub fn greedy_rects(mat: &[Vec<bool>], min_width: i32, min_height: i32) -> Vec<Rect> {
    let mut rects = Vec::new();
    if mat.is_empty() {
        return rects;
    }

    let row_count = mat.len();
    let col_count = mat[0].len();
    if col_count == 0 {
        return rects;
    }

    for row in mat {
        if row.len() != col_count {
            return rects;
        }
    }

    let mut consumed = vec![vec![false; col_count]; row_count];
    for r in 0..row_count {
        for c in 0..col_count {
            if consumed[r][c] || !mat[r][c] {
                continue;
            }

            let mut width = 0usize;
            while c + width < col_count && mat[r][c + width] && !consumed[r][c + width] {
                width += 1;
            }

            let mut height = 1usize;
            'height_loop: while r + height < row_count {
                for cc in c..c + width {
                    if !mat[r + height][cc] || consumed[r + height][cc] {
                        break 'height_loop;
                    }
                }
                height += 1;
            }

            for rr in r..r + height {
                for cc in c..c + width {
                    consumed[rr][cc] = true;
                }
            }

            if width as i32 >= min_width && height as i32 >= min_height {
                rects.push(Rect {
                    top: r as i32,
                    left: c as i32,
                    width: width as i32,
                    height: height as i32,
                });
            }
        }
    }

    rects
}

#[track_caller]
pub fn get_dp_mem_l18() -> XDPMem {
    let mut mems = GTB_NODE_DP_MEMS.lock().unwrap();
    if mems.is_empty() {
        let n = get_requested_thread_count();
        assert!(n > 0);
        for _i in 0..n {
            mems.push(XDPMem::default());
        }
    }
    let thread_index = get_thread_index();
    assert!(thread_index < mems.len() as uint);
    mems[thread_index as usize].clone()
}

#[track_caller]
pub fn gtb_node_get_label(node: &GTBNode, seq_index: uint) -> &str {
    let builder = node
        .builder
        .as_ref()
        .expect("GTBNode::GetLabel null builder");
    let seqs = builder.seqs.as_ref().expect("GTBNode::GetLabel null seqs");
    seqs.seqs[seq_index as usize].label.as_str()
}

#[track_caller]
pub fn gtb_node_get_byte_seq(node: &GTBNode, seq_index: uint) -> Vec<byte> {
    let builder = node
        .builder
        .as_ref()
        .expect("GTBNode::GetByteSeq null builder");
    let seqs = builder
        .seqs
        .as_ref()
        .expect("GTBNode::GetByteSeq null seqs");
    seqs.seqs[seq_index as usize]
        .char_vec
        .iter()
        .map(|&c| c as byte)
        .collect()
}

#[track_caller]
pub fn gtb_node_get_prot_dist<FViterbi, FDist>(
    node: &GTBNode,
    seq_indexi: uint,
    seq_indexj: uint,
    mut viterbi_fast_mem: FViterbi,
    mut get_prot_dist: FDist,
) -> f64
where
    FViterbi: FnMut(&[byte], uint, &[byte], uint) -> PathInfo,
    FDist: FnMut(&str, &str, uint) -> f64,
{
    let seqi = gtb_node_get_byte_seq(node, seq_indexi);
    let li = seqi.len() as uint;
    let _labeli = gtb_node_get_label(node, seq_indexi);

    let seqj = gtb_node_get_byte_seq(node, seq_indexj);
    let lj = seqj.len() as uint;
    let _labelj = gtb_node_get_label(node, seq_indexj);

    let pi = viterbi_fast_mem(&seqi, li, &seqj, lj);
    let (row_x, row_y) = make_aln_rows_l45(&seqi, li, &seqj, lj, &pi);

    let col_count = pi.path.len() as uint;
    assert_eq!(row_x.len() as uint, col_count);
    assert_eq!(row_y.len() as uint, col_count);
    get_prot_dist(&row_x, &row_y, col_count)
}

#[track_caller]
pub fn gtb_node_do_all<FDist, FRunUPGMA>(
    node: &mut GTBNode,
    mut get_prot_dist: FDist,
    mut run_upgma: FRunUPGMA,
) where
    FDist: FnMut(&GTBNode, uint, uint) -> f64,
    FRunUPGMA: FnMut(&mut UPGMA5, &mut Tree),
{
    let seq_count = node.seq_indexes.len() as uint;
    assert!(seq_count > 0);
    if seq_count < 3 {
        return;
    }
    node.upgma.dist_mx.resize(seq_count as usize, Vec::new());
    node.upgma.labels.clear();
    for i in 0..seq_count {
        let seq_index = node.seq_indexes[i as usize];
        let label = gtb_node_get_label(node, seq_index).to_string();
        node.upgma.labels.push(label);

        node.upgma.dist_mx[i as usize].resize(seq_count as usize, f32::MAX);
        node.upgma.dist_mx[i as usize][i as usize] = 0.0;
    }

    let pair_count = (seq_count * (seq_count - 1)) / 2;
    let mut i = 1usize;
    let mut j = 0usize;
    for _pair_index in 0..pair_count {
        let seq_indexi = node.seq_indexes[i];
        let seq_indexj = node.seq_indexes[j];
        let d = get_prot_dist(node, seq_indexi, seq_indexj) as f32;
        node.upgma.dist_mx[i][j] = d;
        node.upgma.dist_mx[j][i] = d;

        j += 1;
        assert!(j <= i);
        if j == i {
            i += 1;
            j = 0;
        }
    }
    run_upgma(&mut node.upgma, &mut node.tree);
}

#[track_caller]
pub fn gtb_node_run<FDist, FRunUPGMA, FChildRun>(
    node: &mut GTBNode,
    mut get_prot_dist: FDist,
    mut run_upgma: FRunUPGMA,
    mut child_run: FChildRun,
) where
    FDist: FnMut(&GTBNode, uint, uint) -> f64,
    FRunUPGMA: FnMut(&mut UPGMA5, &mut Tree),
    FChildRun: FnMut(&mut GTBNode),
{
    assert!(node.builder.is_some());
    assert!(!node.seq_indexes.is_empty());
    let seq_count = node.seq_indexes.len() as uint;
    let builder = node.builder.as_ref().expect("GTBNode::Run null builder");
    if seq_count < builder.max_all {
        gtb_node_do_all(node, get_prot_dist, run_upgma);
        return;
    }
    let n = std::cmp::min(builder.target_seed_count, seq_count);
    let mut seed_set = std::collections::BTreeSet::new();
    for i in 0..n + 4 {
        let _r = randu32() % seq_count;
        let seq_index = node.seq_indexes[i as usize];
        seed_set.insert(seq_index);
        if seed_set.len() as uint == n {
            break;
        }
    }
    let seed_count = seed_set.len() as uint;
    for seq_index in &seed_set {
        node.seed_seq_indexes.push(*seq_index);
    }
    assert_eq!(node.seed_seq_indexes.len() as uint, seed_count);

    node.upgma.dist_mx.resize(seed_count as usize, Vec::new());
    node.upgma.labels.clear();
    for i in 0..seed_count {
        node.upgma.dist_mx[i as usize].resize(seed_count as usize, f32::MAX);
        node.upgma.dist_mx[i as usize][i as usize] = 0.0;
    }

    let pair_count = (seed_count * (seed_count - 1)) / 2;
    let mut i = 1usize;
    let mut j = 0usize;
    for _pair_index in 0..pair_count {
        let seq_indexi = node.seed_seq_indexes[i];
        let seq_indexj = node.seed_seq_indexes[j];
        let d = get_prot_dist(node, seq_indexi, seq_indexj) as f32;
        node.upgma.dist_mx[i][j] = d;
        node.upgma.dist_mx[j][i] = d;

        j += 1;
        assert!(j <= i);
        if j == i {
            i += 1;
            j = 0;
        }
    }

    for i in 0..seed_count {
        let seq_index = node.seed_seq_indexes[i as usize];
        let seq_label = gtb_node_get_label(node, seq_index);
        let label = format!("Seed{i}.{seq_label}");
        node.upgma.labels.push(label);
    }

    run_upgma(&mut node.upgma, &mut node.tree);

    node.children.clear();
    node.children
        .resize(seed_count as usize, GTBNode::default());
    for i in 0..seed_count {
        let seed_seq_index = node.seed_seq_indexes[i as usize];
        node.children[i as usize].builder = node.builder.clone();
        node.children[i as usize].seq_indexes.push(seed_seq_index);
    }

    for i in 0..seq_count {
        let seq_index = node.seq_indexes[i as usize];
        if seed_set.contains(&seq_index) {
            continue;
        }
        let mut min_d = f64::MAX;
        let mut best_seed_index = uint::MAX;
        for seed_index in 0..seed_count {
            let seed_seq_index = node.seed_seq_indexes[seed_index as usize];
            let d = get_prot_dist(node, seq_index, seed_seq_index);
            if d < min_d {
                min_d = d;
                best_seed_index = seed_index;
            }
        }
        assert!((best_seed_index as usize) < node.children.len());
        node.children[best_seed_index as usize]
            .seq_indexes
            .push(seq_index);
    }

    for child_index in 0..seed_count {
        child_run(&mut node.children[child_index as usize]);
    }
}

#[track_caller]
pub fn validate_join_order(indexes1: &[uint], indexes2: &[uint]) {
    let join_count = indexes1.len() as uint;
    assert!(indexes2.len() as uint == join_count);

    let leaf_count = join_count + 1;
    let node_count = 2 * leaf_count - 1;

    let mut pending = std::collections::BTreeSet::new();
    for leaf_index in 0..leaf_count {
        pending.insert(leaf_index);
    }

    let mut used = vec![false; node_count as usize];
    for join_index in 0..join_count {
        let index1 = indexes1[join_index as usize];
        let index2 = indexes2[join_index as usize];
        assert!(index1 != index2);
        assert!(index1 < node_count);
        assert!(index2 < node_count);

        assert!(!used[index1 as usize]);
        assert!(!used[index2 as usize]);
        assert!(pending.contains(&index1));
        assert!(pending.contains(&index2));

        let join_node_index = leaf_count + join_index;
        used[index1 as usize] = true;
        used[index2 as usize] = true;

        pending.remove(&index1);
        pending.remove(&index2);
        pending.insert(join_node_index);
    }
    assert!(pending.len() == 1);
    let mut used_count = 0_u32;
    let mut not_used_count = 0_u32;
    for node_index in 0..node_count {
        if used[node_index as usize] {
            used_count += 1;
        } else {
            not_used_count += 1;
        }
    }
    assert!(used_count == node_count - 1);
    assert!(not_used_count == 1);
}

#[track_caller]
pub fn get_label(label_to_index: &std::collections::HashMap<String, uint>, index: uint) -> String {
    for (label, label_index) in label_to_index {
        if *label_index == index {
            return label.clone();
        }
    }
    panic!("GetLabel({index}) failed");
}

#[track_caller]
pub fn log_guide_tree_join_order(
    guide_tree: &Tree,
    label_to_index: &std::collections::HashMap<String, uint>,
    indexes1: &[uint],
    indexes2: &[uint],
) -> String {
    assert!(guide_tree.rooted);
    let node_count = guide_tree.node_count;
    let leaf_count = (node_count + 1) / 2;
    let join_count = leaf_count - 1;
    assert!(indexes1.len() as uint == join_count);
    assert!(indexes2.len() as uint == join_count);

    let mut s = String::new();
    s.push_str("  Join  Index1  Index2\n");
    for join_index in 0..join_count {
        let index1 = indexes1[join_index as usize];
        let index2 = indexes2[join_index as usize];
        s.push_str(&format!("{join_index:6}"));
        s.push_str(&format!("  {index1:6}"));
        s.push_str(&format!("  {index2:6}"));

        s.push_str("  ");
        if index1 < leaf_count {
            s.push_str(&format!(" '{}'", get_label(label_to_index, index1)));
        } else {
            s.push_str(&format!(" Join{}", index1 - leaf_count));
        }
        s.push_str(" +");
        if index2 < leaf_count {
            s.push_str(&format!(" '{}'", get_label(label_to_index, index2)));
        } else {
            s.push_str(&format!(" Join{}", index2 - leaf_count));
        }

        s.push('\n');
    }
    s
}

#[track_caller]
pub fn get_guide_tree_join_order(
    guide_tree: &Tree,
    label_to_index: &std::collections::HashMap<String, uint>,
) -> (Vec<uint>, Vec<uint>) {
    assert!(guide_tree.rooted);

    let mut indexes1 = Vec::new();
    let mut indexes2 = Vec::new();

    let node_count = guide_tree.node_count;
    let leaf_count = (node_count + 1) / 2;
    let mut index_used = vec![false; leaf_count as usize];

    let join_count = leaf_count - 1;
    let mut join_index = leaf_count;
    let mut stack = Vec::new();
    let mut node = tree_first_depth_first_node(guide_tree);
    while node != uint::MAX {
        let neighbor_count = (guide_tree.neighbor1[node as usize] != NULL_NEIGHBOR) as uint
            + (guide_tree.neighbor2[node as usize] != NULL_NEIGHBOR) as uint
            + (guide_tree.neighbor3[node as usize] != NULL_NEIGHBOR) as uint;
        if guide_tree.node_count == 1 || neighbor_count == 1 {
            let label = tree_get_leaf_name(guide_tree, node)
                .unwrap_or_else(|| panic!("Guide tree leaf {node} has no label"));
            let index = *label_to_index
                .get(label)
                .unwrap_or_else(|| panic!("Label not found >{label}"));
            assert!(index < leaf_count);
            assert!(!index_used[index as usize]);
            stack.push(index);
            index_used[index as usize] = true;
        } else {
            assert!(stack.len() >= 2);
            let left = stack.pop().unwrap();
            let right = stack.pop().unwrap();

            indexes1.push(right);
            indexes2.push(left);

            stack.push(join_index);
            join_index += 1;
        }
        node = tree_next_depth_first_node(guide_tree, node);
    }
    assert!(indexes1.len() as uint == join_count);
    assert!(indexes2.len() as uint == join_count);
    (indexes1, indexes2)
}

#[track_caller]
pub fn make_guide_tree_from_join_order(
    indexes1: &[uint],
    indexes2: &[uint],
    label_to_index: &std::collections::HashMap<String, uint>,
    guide_tree: &mut Tree,
) {
    let join_count = indexes1.len() as uint;
    assert!(indexes2.len() as uint == join_count);
    assert!(join_count > 0);
    let leaf_count = join_count + 1;
    let node_count = leaf_count + join_count;

    let mut leaf_labels = Vec::new();
    for leaf_index in 0..leaf_count {
        leaf_labels.push(get_label(label_to_index, leaf_index));
    }

    let mut lefts = Vec::new();
    let mut rights = Vec::new();
    for join_index in 0..join_count {
        let index1 = indexes1[join_index as usize];
        let index2 = indexes2[join_index as usize];
        lefts.push(index1);
        rights.push(index2);
    }

    let leaf_ids = vec![1; leaf_count as usize];
    let lengths = vec![1.0_f32; node_count as usize];

    tree_create(
        guide_tree,
        leaf_count,
        join_count - 1,
        &lefts,
        &rights,
        &lengths,
        &lengths,
        &leaf_ids,
        &leaf_labels,
    );
}

#[track_caller]
pub fn cmd_guide_tree_join_order(tree_file_name: &str, output_file_name: Option<&str>) -> String {
    let mut guide_tree = Tree::default();
    tree_from_file_l143(&mut guide_tree, tree_file_name);

    let mut label_to_index = std::collections::HashMap::new();
    let node_count = guide_tree.node_count;
    let leaf_count = (node_count + 1) / 2;
    let join_count = leaf_count - 1;

    let mut leaf_index = 0_u32;
    for node in 0..node_count {
        let neighbor_count = (guide_tree.neighbor1[node as usize] != NULL_NEIGHBOR) as uint
            + (guide_tree.neighbor2[node as usize] != NULL_NEIGHBOR) as uint
            + (guide_tree.neighbor3[node as usize] != NULL_NEIGHBOR) as uint;
        if guide_tree.node_count == 1 || neighbor_count == 1 {
            let label = tree_get_leaf_name(&guide_tree, node)
                .unwrap_or_else(|| panic!("Guide tree leaf {node} has no label"))
                .to_string();
            assert!(!label_to_index.contains_key(&label));
            label_to_index.insert(label, leaf_index);
            leaf_index += 1;
        }
    }

    let (indexes1, indexes2) = get_guide_tree_join_order(&guide_tree, &label_to_index);
    let log = log_guide_tree_join_order(&guide_tree, &label_to_index, &indexes1, &indexes2);
    validate_join_order(&indexes1, &indexes2);

    let mut output = String::new();
    if output_file_name.is_some() {
        assert!(guide_tree.rooted);
        assert!(indexes1.len() as uint == join_count);
        assert!(indexes2.len() as uint == join_count);

        for join_index in 0..join_count {
            let index1 = indexes1[join_index as usize];
            let index2 = indexes2[join_index as usize];
            output.push_str(&format!("{join_index}"));
            output.push_str(&format!("\t{index1}"));
            output.push_str(&format!("\t{index2}"));

            if index1 < leaf_count {
                output.push_str(&format!("\tleaf\t{}", get_label(&label_to_index, index1)));
            } else {
                output.push_str(&format!("\tjoin\t{}", index1 - leaf_count));
            }

            if index2 < leaf_count {
                output.push_str(&format!("\tleaf\t{}", get_label(&label_to_index, index2)));
            } else {
                output.push_str(&format!("\tjoin\t{}", index2 - leaf_count));
            }

            output.push('\n');
        }
    }

    if let Some(file_name) = output_file_name {
        std::fs::write(file_name, output.as_bytes()).unwrap();
    }

    log
}

#[track_caller]
pub fn help() -> String {
    let raw = include_str!("../muscle/src/help.h");
    let mut text = print_banner();
    for line in raw.lines() {
        let mut chars = line.trim().chars();
        if chars.next() != Some('"') {
            continue;
        }
        let mut escape = false;
        for c in chars {
            if escape {
                match c {
                    'n' => text.push('\n'),
                    'r' => text.push('\r'),
                    't' => text.push('\t'),
                    '"' => text.push('"'),
                    '\\' => text.push('\\'),
                    _ => text.push(c),
                }
                escape = false;
            } else if c == '\\' {
                escape = true;
            } else if c == '"' {
                break;
            } else {
                text.push(c);
            }
        }
    }
    text
}

#[track_caller]
pub fn pair_hmm_write_params_report_l4(file_name: &str) {
    if file_name.is_empty() {
        return;
    }
    std::fs::write(file_name, pair_hmm_write_params_report_l13()).unwrap();
}

#[track_caller]
pub fn pair_hmm_write_params_report_l13() -> String {
    let fmt5 = |x: f32| -> String {
        if x == 0.0 {
            return "0".to_string();
        }
        if !x.is_finite() {
            return x.to_string();
        }
        let x64 = f64::from(x);
        let exp = x64.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 5 {
            let raw = format!("{x64:.4e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (4 - exp).max(0) as usize;
            format!("{x64:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };
    let start_score = *PAIR_HMM_START_SCORE.lock().unwrap();
    let trans_score = *PAIR_HMM_TRANS_SCORE.lock().unwrap();
    let ins_score = *PAIR_HMM_INS_SCORE.lock().unwrap();
    let match_score = PAIR_HMM_MATCH_SCORE.lock().unwrap();

    let mut init_probs = Vec::new();
    let mut init_scores = Vec::new();
    for score in start_score.iter().take(HMMSTATE_COUNT as usize) {
        init_probs.push(score.exp());
        init_scores.push(*score);
    }

    let init_prob_m = init_probs[HMMSTATE_M as usize];
    let init_prob_ix = init_probs[HMMSTATE_IX as usize];
    let init_prob_iy = init_probs[HMMSTATE_IY as usize];
    let init_prob_jx = init_probs[HMMSTATE_JX as usize];
    let init_prob_jy = init_probs[HMMSTATE_JY as usize];
    let init_sum = init_prob_m + init_prob_ix + init_prob_iy + init_prob_jx + init_prob_jy;
    assert!(myfeq(init_prob_ix as f64, init_prob_iy as f64));
    assert!(myfeq(init_prob_jx as f64, init_prob_jy as f64));
    assert!(myfeq(init_sum as f64, 1.0));

    let mut out = String::new();
    out.push('\n');
    out.push_str("// Probs\n");
    out.push_str(&format!(
        "const float InitProb_IM = {};\n",
        fmt5(init_prob_m)
    ));
    out.push_str(&format!(
        "const float InitProb_IS = {};\n",
        fmt5(init_prob_ix)
    ));
    out.push_str(&format!(
        "const float InitProb_IL = {};\n",
        fmt5(init_prob_jx)
    ));

    let mut trans_probs = vec![vec![0.0_f32; HMMSTATE_COUNT as usize]; HMMSTATE_COUNT as usize];
    let mut trans_scores = vec![vec![0.0_f32; HMMSTATE_COUNT as usize]; HMMSTATE_COUNT as usize];
    for i in 0..HMMSTATE_COUNT as usize {
        let mut sum = 0.0_f32;
        for j in 0..HMMSTATE_COUNT as usize {
            let score = trans_score[i][j];
            let prob = score.exp();
            sum += prob;
            trans_probs[i][j] = prob;
            trans_scores[i][j] = score;
        }
        assert!(myfeq(sum as f64, 1.0));
    }

    assert_eq!(trans_probs[HMMSTATE_IX as usize][HMMSTATE_IY as usize], 0.0);
    assert_eq!(trans_probs[HMMSTATE_IX as usize][HMMSTATE_JY as usize], 0.0);
    assert_eq!(trans_probs[HMMSTATE_JX as usize][HMMSTATE_IY as usize], 0.0);
    assert_eq!(trans_probs[HMMSTATE_JX as usize][HMMSTATE_JY as usize], 0.0);
    assert_eq!(trans_probs[HMMSTATE_IY as usize][HMMSTATE_IX as usize], 0.0);
    assert_eq!(trans_probs[HMMSTATE_IY as usize][HMMSTATE_JX as usize], 0.0);
    assert_eq!(trans_probs[HMMSTATE_JY as usize][HMMSTATE_IX as usize], 0.0);
    assert_eq!(trans_probs[HMMSTATE_JY as usize][HMMSTATE_JX as usize], 0.0);
    assert!(myfeq(
        trans_probs[HMMSTATE_M as usize][HMMSTATE_IX as usize] as f64,
        trans_probs[HMMSTATE_M as usize][HMMSTATE_IY as usize] as f64
    ));
    assert!(myfeq(
        trans_probs[HMMSTATE_M as usize][HMMSTATE_JX as usize] as f64,
        trans_probs[HMMSTATE_M as usize][HMMSTATE_JY as usize] as f64
    ));
    assert!(myfeq(
        trans_probs[HMMSTATE_IX as usize][HMMSTATE_M as usize] as f64,
        trans_probs[HMMSTATE_IY as usize][HMMSTATE_M as usize] as f64
    ));
    assert!(myfeq(
        trans_probs[HMMSTATE_JX as usize][HMMSTATE_M as usize] as f64,
        trans_probs[HMMSTATE_JY as usize][HMMSTATE_M as usize] as f64
    ));

    let trans_prob_m_m = trans_probs[HMMSTATE_M as usize][HMMSTATE_M as usize];
    let trans_score_m_m = trans_scores[HMMSTATE_M as usize][HMMSTATE_M as usize];
    let trans_prob_m_is = trans_probs[HMMSTATE_M as usize][HMMSTATE_IX as usize];
    let trans_score_m_is = trans_scores[HMMSTATE_M as usize][HMMSTATE_IX as usize];
    let trans_prob_m_il = trans_probs[HMMSTATE_M as usize][HMMSTATE_JX as usize];
    let trans_score_m_il = trans_scores[HMMSTATE_M as usize][HMMSTATE_JX as usize];
    let trans_prob_is_is = trans_probs[HMMSTATE_IX as usize][HMMSTATE_IX as usize];
    let trans_score_is_is = trans_scores[HMMSTATE_IX as usize][HMMSTATE_IX as usize];
    let trans_prob_il_il = trans_probs[HMMSTATE_JX as usize][HMMSTATE_JX as usize];
    let trans_score_il_il = trans_scores[HMMSTATE_JX as usize][HMMSTATE_JX as usize];
    let trans_prob_is_m = trans_probs[HMMSTATE_IX as usize][HMMSTATE_M as usize];
    let trans_score_is_m = trans_scores[HMMSTATE_IX as usize][HMMSTATE_M as usize];
    let trans_prob_il_m = trans_probs[HMMSTATE_JX as usize][HMMSTATE_M as usize];
    let trans_score_il_m = trans_scores[HMMSTATE_JX as usize][HMMSTATE_M as usize];

    assert!(myfeq(
        (init_prob_m + 2.0 * init_prob_ix + 2.0 * init_prob_jx) as f64,
        1.0
    ));
    assert!(myfeq((trans_prob_is_is + trans_prob_is_m) as f64, 1.0));
    assert!(myfeq((trans_prob_il_il + trans_prob_il_m) as f64, 1.0));
    assert!(myfeq(
        (trans_prob_m_m + 2.0 * trans_prob_m_is + 2.0 * trans_prob_m_il) as f64,
        1.0
    ));

    out.push('\n');
    out.push_str(&format!(
        "const float TransProb_M_M   = {};\n",
        fmt5(trans_prob_m_m)
    ));
    out.push_str(&format!(
        "const float TransProb_M_IS  = {};\n",
        fmt5(trans_prob_m_is)
    ));
    out.push_str(&format!(
        "const float TransProb_M_IL  = {};\n",
        fmt5(trans_prob_m_il)
    ));
    out.push_str(&format!(
        "const float TransProb_IS_IS = {};\n",
        fmt5(trans_prob_is_is)
    ));
    out.push_str(&format!(
        "const float TransProb_IL_IL = {};\n",
        fmt5(trans_prob_il_il)
    ));
    out.push_str(&format!(
        "const float TransProb_IS_M  = {};\n",
        fmt5(trans_prob_is_m)
    ));
    out.push_str(&format!(
        "const float TransProb_IL_M  = {};\n",
        fmt5(trans_prob_il_m)
    ));

    let a = b"ACDEFGHIKLMNPQRSTVWY";
    assert_eq!(a.len(), 20);
    let mut ins_probs = vec![0.0_f32; 20];
    let mut ins_scores = vec![0.0_f32; 20];
    let mut sum = 0.0_f32;
    for i in 0..20 {
        let letter = a[i] as usize;
        let score = ins_score[letter];
        let prob = score.exp();
        ins_probs[i] = prob;
        ins_scores[i] = score;
        sum += prob;
    }
    assert!(myfeq(sum as f64, 1.0));

    let mut emit_probs = vec![vec![0.0_f32; 20]; 20];
    let mut emit_scores = vec![vec![0.0_f32; 20]; 20];
    sum = 0.0;
    for i in 0..20 {
        let letter_a = a[i] as usize;
        for j in 0..20 {
            let letter_b = a[j] as usize;
            let score = match_score[letter_a][letter_b];
            let prob = score.exp();
            emit_probs[i][j] = prob;
            emit_scores[i][j] = score;
            sum += prob;
        }
    }
    assert!(myfeq(sum as f64, 1.0));

    out.push('\n');
    out.push_str("const float InsProbs[20] =\n");
    out.push_str("\t{\n");
    for i in 0..20 {
        out.push_str(&format!("\t{},\t// {}\n", fmt5(ins_probs[i]), a[i] as char));
    }
    out.push_str("\t};\n");

    out.push('\n');
    out.push_str("const float EmitProbs[20][20] =\n");
    out.push_str("\t{\n");
    out.push_str("//\t      ");
    for c in a {
        out.push_str(&format!("        {}", *c as char));
    }
    out.push('\n');
    for i in 0..20 {
        out.push_str(&format!("/* {} */ {{ ", a[i] as char));
        for j in 0..20 {
            out.push_str(&format!(" {}", fmt5(emit_probs[i][j])));
        }
        out.push_str(&format!(" }} // {}\n", a[i] as char));
    }
    out.push_str("\t};\n");

    out.push('\n');
    out.push_str("// Scores\n");
    out.push_str(&format!(
        "const float InitScore_IM = {};\n",
        fmt5(init_scores[HMMSTATE_M as usize])
    ));
    out.push_str(&format!(
        "const float InitScore_IS = {};\n",
        fmt5(init_scores[HMMSTATE_IX as usize])
    ));
    out.push_str(&format!(
        "const float InitScore_IL = {};\n",
        fmt5(init_scores[HMMSTATE_JX as usize])
    ));

    out.push('\n');
    out.push_str(&format!(
        "const float TransScore_M_M   = {};\n",
        fmt5(trans_score_m_m)
    ));
    out.push_str(&format!(
        "const float TransScore_M_IS  = {};\n",
        fmt5(trans_score_m_is)
    ));
    out.push_str(&format!(
        "const float TransScore_M_IL  = {};\n",
        fmt5(trans_score_m_il)
    ));
    out.push_str(&format!(
        "const float TransScore_IS_IS = {};\n",
        fmt5(trans_score_is_is)
    ));
    out.push_str(&format!(
        "const float TransScore_IL_IL = {};\n",
        fmt5(trans_score_il_il)
    ));
    out.push_str(&format!(
        "const float TransScore_IS_M  = {};\n",
        fmt5(trans_score_is_m)
    ));
    out.push_str(&format!(
        "const float TransScore_IL_M  = {};\n",
        fmt5(trans_score_il_m)
    ));

    out.push('\n');
    out.push_str("const float InsScores[20] =\n");
    out.push_str("\t{\n");
    for i in 0..20 {
        out.push_str(&format!(
            "\t{},\t// {}\n",
            fmt5(ins_scores[i]),
            a[i] as char
        ));
    }
    out.push_str("\t};\n");

    out.push('\n');
    out.push_str("const float EmitScores[20][20] =\n");
    out.push_str("\t{\n");
    out.push_str("//\t      ");
    for c in a {
        out.push_str(&format!("        {}", *c as char));
    }
    out.push('\n');
    for i in 0..20 {
        out.push_str(&format!("/* {} */ {{ ", a[i] as char));
        for j in 0..20 {
            out.push_str(&format!(" {}", fmt5(emit_scores[i][j])));
        }
        out.push_str(&format!(" }} // {}\n", a[i] as char));
    }
    out.push_str("\t};\n");
    out
}

#[track_caller]
pub fn cmd_hmmdump<FUpdate>(
    out_dir: &str,
    nucleo: bool,
    mut cmd_line_update: FUpdate,
) -> Vec<String>
where
    FUpdate: FnMut(&mut HMMParams),
{
    let mut out_dir = out_dir.to_string();
    dirize(&mut out_dir);

    set_alpha_l209(ALPHA::ALPHA_Amino);
    init_probcons();

    let params_report = format!("{out_dir}params_report.txt");
    pair_hmm_write_params_report_l4(&params_report);

    let mut hp = hmm_params_from_defaults(nucleo);
    let hmm = format!("{out_dir}hmm.tsv");
    hmm_params_to_file(&hp, &hmm);

    cmd_line_update(&mut hp);
    hmm_params_to_pair_hmm(&hp);
    let params_report2 = format!("{out_dir}params_report2.txt");
    pair_hmm_write_params_report_l4(&params_report2);

    let hmm2 = format!("{out_dir}hmm2.tsv");
    hmm_params_to_file(&hp, &hmm2);
    hp = hmm_params_from_file(&hmm2);
    let hmm3 = format!("{out_dir}hmm3.tsv");
    hmm_params_to_file(&hp, &hmm3);

    let sa = hmm_params_to_single_affine_probs(&hp);
    let sa_hmm = format!("{out_dir}sa.hmm");
    hmm_params_to_file(&sa, &sa_hmm);

    vec![params_report, hmm, params_report2, hmm2, hmm3, sa_hmm]
}

pub fn hmmtrans_to_str(t: HMMTRANS) -> &'static str {
    match t {
        HMMTRANS::HMMTRANS_START_M => "START_M",
        HMMTRANS::HMMTRANS_START_IS => "START_IS",
        HMMTRANS::HMMTRANS_START_IL => "START_IL",
        HMMTRANS::HMMTRANS_M_M => "M_M",
        HMMTRANS::HMMTRANS_M_IS => "M_IS",
        HMMTRANS::HMMTRANS_M_IL => "M_IL",
        HMMTRANS::HMMTRANS_IS_IS => "IS_IS",
        HMMTRANS::HMMTRANS_IS_M => "IS_M",
        HMMTRANS::HMMTRANS_IL_IL => "IL_IL",
        HMMTRANS::HMMTRANS_IL_M => "IL_M",
    }
}

#[track_caller]
pub fn hmm_params_get_probs(params: &HMMParams) -> HMMParams {
    let probs = if params.logs {
        hmm_params_scores_to_probs(params)
    } else {
        params.clone()
    };
    hmm_params_assert_probs_valid(&probs);
    probs
}

#[track_caller]
pub fn hmm_params_from_params(params: &HMMParams, as_probs: bool) -> HMMParams {
    if as_probs {
        hmm_params_get_probs(params)
    } else {
        hmm_params_get_scores(params)
    }
}

#[track_caller]
pub fn hmm_params_get_scores(params: &HMMParams) -> HMMParams {
    if params.logs {
        params.clone()
    } else {
        hmm_params_assert_probs_valid(params);
        hmm_params_probs_to_scores(params)
    }
}

#[track_caller]
pub fn hmm_params_to_single_affine_probs(params: &HMMParams) -> HMMParams {
    let mut params = hmm_params_get_probs(params);
    let t = &mut params.trans;

    let si =
        (t[HMMTRANS::HMMTRANS_START_IS as usize] + t[HMMTRANS::HMMTRANS_START_IL as usize]) / 2.0;
    let mi = (t[HMMTRANS::HMMTRANS_M_IS as usize] + t[HMMTRANS::HMMTRANS_M_IL as usize]) / 2.0;
    let im = (t[HMMTRANS::HMMTRANS_IS_M as usize] + t[HMMTRANS::HMMTRANS_IL_M as usize]) / 2.0;
    let ii = (t[HMMTRANS::HMMTRANS_IS_IS as usize] + t[HMMTRANS::HMMTRANS_IL_IL as usize]) / 2.0;

    t[HMMTRANS::HMMTRANS_START_IS as usize] = si;
    t[HMMTRANS::HMMTRANS_START_IL as usize] = si;
    t[HMMTRANS::HMMTRANS_M_IS as usize] = mi;
    t[HMMTRANS::HMMTRANS_M_IL as usize] = mi;
    t[HMMTRANS::HMMTRANS_IS_M as usize] = im;
    t[HMMTRANS::HMMTRANS_IL_M as usize] = im;
    t[HMMTRANS::HMMTRANS_IS_IS as usize] = ii;
    t[HMMTRANS::HMMTRANS_IL_IL as usize] = ii;

    hmm_params_assert_probs_valid(&params);
    params
}

#[track_caller]
pub fn hmm_params_scores_to_probs(scores: &HMMParams) -> HMMParams {
    let alpha_size = scores.alpha.len();
    assert!(alpha_size == 4 || alpha_size == 20);

    let mut probs = HMMParams {
        logs: false,
        var: DEFAULT_PERTURB_VAR,
        alpha: scores.alpha.clone(),
        trans: vec![0.0; HMMTRANS_N],
        emits: vec![vec![0.0; alpha_size]; alpha_size],
        ..HMMParams::default()
    };

    for i in 0..HMMTRANS_N {
        probs.trans[i] = scores.trans[i].exp();
    }
    for i in 0..alpha_size {
        for j in 0..alpha_size {
            probs.emits[i][j] = scores.emits[i][j].exp();
        }
    }

    hmm_params_assert_probs_valid(&probs);
    probs
}

#[track_caller]
pub fn hmm_params_probs_to_scores(probs: &HMMParams) -> HMMParams {
    hmm_params_assert_probs_valid(probs);
    let alpha_size = probs.alpha.len();

    let mut scores = HMMParams {
        logs: true,
        var: DEFAULT_PERTURB_VAR,
        alpha: probs.alpha.clone(),
        trans: vec![0.0; HMMTRANS_N],
        emits: vec![vec![f32::MAX; alpha_size]; alpha_size],
        ..HMMParams::default()
    };

    for i in 0..HMMTRANS_N {
        scores.trans[i] = probs.trans[i].ln();
    }
    for i in 0..alpha_size {
        for j in 0..alpha_size {
            scores.emits[i][j] = probs.emits[i][j].ln();
        }
    }
    scores
}

#[track_caller]
pub fn hmm_params_assert_probs_valid(params: &HMMParams) {
    assert!(!params.logs);
    assert_eq!(params.trans.len(), HMMTRANS_N);
    let alpha_size = params.alpha.len();
    assert!(alpha_size == 4 || alpha_size == 20);
    assert_eq!(params.emits.len(), alpha_size);
    for i in 0..alpha_size {
        assert_eq!(params.emits[i].len(), alpha_size);
    }

    let sum_start = params.trans[HMMTRANS::HMMTRANS_START_M as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_START_IS as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_START_IL as usize];
    assert!(myfeq(sum_start as f64, 1.0));

    let sum_is = params.trans[HMMTRANS::HMMTRANS_IS_M as usize]
        + params.trans[HMMTRANS::HMMTRANS_IS_IS as usize];
    assert!(myfeq(sum_is as f64, 1.0));

    let sum_il = params.trans[HMMTRANS::HMMTRANS_IL_M as usize]
        + params.trans[HMMTRANS::HMMTRANS_IL_IL as usize];
    assert!(myfeq(sum_il as f64, 1.0));

    let sum_m = params.trans[HMMTRANS::HMMTRANS_M_M as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_M_IS as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_M_IL as usize];
    assert!(myfeq(sum_m as f64, 1.0));

    let mut sum_emit = 0.0;
    for i in 0..alpha_size {
        for j in 0..alpha_size {
            sum_emit += params.emits[i][j];
        }
    }
    assert!(myfeq(sum_emit as f64, 1.0));

    for i in 0..alpha_size {
        for j in 0..i {
            assert!(myfeq(params.emits[i][j] as f64, params.emits[j][i] as f64));
        }
    }
}

#[track_caller]
pub fn hmm_params_to_file(params: &HMMParams, file_name: &str) -> Option<String> {
    if file_name.is_empty() {
        return None;
    }

    hmm_params_assert_probs_valid(params);
    let alpha_size = params.alpha.len();
    let mut out = String::new();
    if params.alpha == AMINO_ALPHA {
        out.push_str("HMM\taa\n");
    } else if params.alpha == NT_ALPHA {
        out.push_str("HMM\tnt\n");
    } else {
        panic!("HMMParams::ToFile alpha='{}'", params.alpha);
    }

    let format_g5 = |d: f32| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let d64 = f64::from(d);
        let exp = d64.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 5 {
            let raw = format!("{d64:.4e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (4 - exp).max(0) as usize;
            format!("{d64:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };

    for t in [
        HMMTRANS::HMMTRANS_START_M,
        HMMTRANS::HMMTRANS_START_IS,
        HMMTRANS::HMMTRANS_START_IL,
        HMMTRANS::HMMTRANS_M_M,
        HMMTRANS::HMMTRANS_M_IS,
        HMMTRANS::HMMTRANS_M_IL,
        HMMTRANS::HMMTRANS_IS_IS,
        HMMTRANS::HMMTRANS_IS_M,
        HMMTRANS::HMMTRANS_IL_IL,
        HMMTRANS::HMMTRANS_IL_M,
    ] {
        let p = format_g5(params.trans[t as usize]);
        out.push_str(&format!("T.{}\t{}\n", hmmtrans_to_str(t), p));
    }

    let alpha = params.alpha.as_bytes();
    for i in 0..alpha_size {
        let a = alpha[i] as char;
        for j in 0..=i {
            let b = alpha[j] as char;
            let p = format_g5(params.emits[i][j]);
            out.push_str(&format!("E.{a}{b}\t{p}\n"));
        }
    }

    std::fs::write(file_name, out.as_bytes()).expect("failed to write HMM params file");
    Some(out)
}

#[track_caller]
pub fn hmm_params_get_next_prob(params: &mut HMMParams, name: &str) -> f32 {
    let line = hmm_params_get_next_line(params)
        .unwrap_or_else(|| panic!("GetNextProb({name}) end-of-data"));
    let fields: Vec<&str> = line.split('\t').collect();
    if fields.len() != 2 {
        panic!("GetNextProb({name}) expected 2 fields got '{line}'");
    }
    if fields[0] != name {
        panic!("ReadGetNextProbTrans({name}) got '{line}'");
    }
    fields[1].parse::<f32>().unwrap_or_else(|_| {
        panic!(
            "Invalid floating point value in HMM parameter line '{}'",
            line
        )
    })
}

#[track_caller]
pub fn hmm_params_get_next_line(params: &mut HMMParams) -> Option<String> {
    if (params.line_nr as usize) >= params.lines.len() {
        return None;
    }
    let line = params.lines[params.line_nr as usize].clone();
    params.line_nr += 1;
    Some(line)
}

#[track_caller]
pub fn hmm_params_from_file(file_name: &str) -> HMMParams {
    let text = std::fs::read_to_string(file_name)
        .unwrap_or_else(|e| panic!("Cannot open {file_name}, errno={:?} {e}", e.raw_os_error()));
    let lines = text.lines().map(|s| s.to_string()).collect::<Vec<_>>();
    hmm_params_from_strings(&lines)
}

#[track_caller]
pub fn hmm_params_from_strings(lines: &[String]) -> HMMParams {
    let mut params = HMMParams {
        lines: lines.to_vec(),
        line_nr: 0,
        var: DEFAULT_PERTURB_VAR,
        ..HMMParams::default()
    };

    let alpha_line = hmm_params_get_next_line(&mut params).expect("Invalid HMM file");
    let fields: Vec<&str> = alpha_line.split('\t').collect();
    if fields.len() != 2 || fields[0] != "HMM" {
        panic!("Invalid HMM file");
    }
    params.alpha = match fields[1] {
        "aa" => AMINO_ALPHA.to_string(),
        "nt" => NT_ALPHA.to_string(),
        other => panic!("Invalid HMM alphabet '{other}'"),
    };

    params.trans.clear();
    params.trans.resize(HMMTRANS_N, f32::MAX);
    for t in [
        HMMTRANS::HMMTRANS_START_M,
        HMMTRANS::HMMTRANS_START_IS,
        HMMTRANS::HMMTRANS_START_IL,
        HMMTRANS::HMMTRANS_M_M,
        HMMTRANS::HMMTRANS_M_IS,
        HMMTRANS::HMMTRANS_M_IL,
        HMMTRANS::HMMTRANS_IS_IS,
        HMMTRANS::HMMTRANS_IS_M,
        HMMTRANS::HMMTRANS_IL_IL,
        HMMTRANS::HMMTRANS_IL_M,
    ] {
        let name = format!("T.{}", hmmtrans_to_str(t));
        params.trans[t as usize] = hmm_params_get_next_prob(&mut params, &name);
    }

    let alpha_size = params.alpha.len();
    params.emits.clear();
    params.emits.resize(alpha_size, vec![f32::MAX; alpha_size]);

    let alpha_bytes = params.alpha.as_bytes().to_vec();
    for i in 0..alpha_size {
        let a = alpha_bytes[i] as char;
        for j in 0..=i {
            let b = alpha_bytes[j] as char;
            let name = format!("E.{a}{b}");
            let p = hmm_params_get_next_prob(&mut params, &name);
            params.emits[i][j] = p;
            params.emits[j][i] = p;
        }
    }

    hmm_params_normalize(&mut params);
    hmm_params_assert_probs_valid(&params);
    params
}

#[track_caller]
pub fn hmm_params_from_defaults(nucleo: bool) -> HMMParams {
    let lines = hmm_params_get_default_hmm_params(nucleo);
    hmm_params_from_strings(&lines)
}

#[track_caller]
pub fn hmm_params_cmd_line_update(
    params: &mut HMMParams,
    s_is: Option<f32>,
    s_il: Option<f32>,
    m_is: Option<f32>,
    m_il: Option<f32>,
    is_is: Option<f32>,
    il_il: Option<f32>,
) {
    if s_is.is_none()
        && s_il.is_none()
        && m_is.is_none()
        && m_il.is_none()
        && is_is.is_none()
        && il_il.is_none()
    {
        return;
    }
    assert!(!params.logs);
    if let Some(value) = s_is {
        params.trans[HMMTRANS::HMMTRANS_START_IS as usize] = value;
    }
    if let Some(value) = s_il {
        params.trans[HMMTRANS::HMMTRANS_START_IL as usize] = value;
    }
    if let Some(value) = m_is {
        params.trans[HMMTRANS::HMMTRANS_M_IS as usize] = value;
    }
    if let Some(value) = m_il {
        params.trans[HMMTRANS::HMMTRANS_M_IL as usize] = value;
    }
    if let Some(value) = is_is {
        params.trans[HMMTRANS::HMMTRANS_IS_IS as usize] = value;
    }
    if let Some(value) = il_il {
        params.trans[HMMTRANS::HMMTRANS_IL_IL as usize] = value;
    }
    hmm_params_normalize(params);
}

#[track_caller]
pub fn hmm_params_to_pair_hmm(params: &HMMParams) {
    let scores = hmm_params_get_scores(params);
    let probs = hmm_params_get_probs(params);
    let alpha_size = params.alpha.len();

    let mut insert_scores = Vec::new();
    let mut sum_inserts = 0.0;
    for i in 0..alpha_size {
        let mut marginal_prob = 0.0;
        for j in 0..alpha_size {
            marginal_prob += probs.emits[i][j];
        }
        insert_scores.push(marginal_prob.ln());
        sum_inserts += marginal_prob;
    }
    assert!(myfeq(sum_inserts as f64, 1.0));

    {
        let mut start_score = PAIR_HMM_START_SCORE.lock().unwrap();
        start_score[HMMSTATE_M as usize] = scores.trans[HMMTRANS::HMMTRANS_START_M as usize];
        start_score[HMMSTATE_IX as usize] = scores.trans[HMMTRANS::HMMTRANS_START_IS as usize];
        start_score[HMMSTATE_IY as usize] = scores.trans[HMMTRANS::HMMTRANS_START_IS as usize];
        start_score[HMMSTATE_JX as usize] = scores.trans[HMMTRANS::HMMTRANS_START_IL as usize];
        start_score[HMMSTATE_JY as usize] = scores.trans[HMMTRANS::HMMTRANS_START_IL as usize];
    }

    {
        let mut trans_score = PAIR_HMM_TRANS_SCORE.lock().unwrap();
        for i in 0..HMMSTATE_COUNT as usize {
            for j in 0..HMMSTATE_COUNT as usize {
                trans_score[i][j] = LOG_ZERO;
            }
        }
        trans_score[HMMSTATE_M as usize][HMMSTATE_M as usize] =
            scores.trans[HMMTRANS::HMMTRANS_M_M as usize];
        trans_score[HMMSTATE_M as usize][HMMSTATE_IX as usize] =
            scores.trans[HMMTRANS::HMMTRANS_M_IS as usize];
        trans_score[HMMSTATE_M as usize][HMMSTATE_IY as usize] =
            scores.trans[HMMTRANS::HMMTRANS_M_IS as usize];
        trans_score[HMMSTATE_M as usize][HMMSTATE_JX as usize] =
            scores.trans[HMMTRANS::HMMTRANS_M_IL as usize];
        trans_score[HMMSTATE_M as usize][HMMSTATE_JY as usize] =
            scores.trans[HMMTRANS::HMMTRANS_M_IL as usize];
        trans_score[HMMSTATE_IX as usize][HMMSTATE_IX as usize] =
            scores.trans[HMMTRANS::HMMTRANS_IS_IS as usize];
        trans_score[HMMSTATE_IY as usize][HMMSTATE_IY as usize] =
            scores.trans[HMMTRANS::HMMTRANS_IS_IS as usize];
        trans_score[HMMSTATE_JX as usize][HMMSTATE_JX as usize] =
            scores.trans[HMMTRANS::HMMTRANS_IL_IL as usize];
        trans_score[HMMSTATE_JY as usize][HMMSTATE_JY as usize] =
            scores.trans[HMMTRANS::HMMTRANS_IL_IL as usize];
        trans_score[HMMSTATE_IX as usize][HMMSTATE_M as usize] =
            scores.trans[HMMTRANS::HMMTRANS_IS_M as usize];
        trans_score[HMMSTATE_IY as usize][HMMSTATE_M as usize] =
            scores.trans[HMMTRANS::HMMTRANS_IS_M as usize];
        trans_score[HMMSTATE_JX as usize][HMMSTATE_M as usize] =
            scores.trans[HMMTRANS::HMMTRANS_IL_M as usize];
        trans_score[HMMSTATE_JY as usize][HMMSTATE_M as usize] =
            scores.trans[HMMTRANS::HMMTRANS_IL_M as usize];
    }

    let wildcard_insert_prob = 1.0 / alpha_size as f32;
    {
        let mut ins_score = PAIR_HMM_INS_SCORE.lock().unwrap();
        for i in 0..256 {
            ins_score[i] = wildcard_insert_prob.ln();
        }
        for i in 0..alpha_size {
            let a = params.alpha.as_bytes()[i];
            let p = insert_scores[i];
            ins_score[a.to_ascii_lowercase() as usize] = p;
            ins_score[a.to_ascii_uppercase() as usize] = p;
        }
    }

    {
        let mut match_score = PAIR_HMM_MATCH_SCORE.lock().unwrap();
        let wild_score = (wildcard_insert_prob * wildcard_insert_prob).ln();
        for i in 0..256 {
            for j in 0..256 {
                match_score[i][j] = wild_score;
            }
        }
        for i in 0..alpha_size {
            let a = params.alpha.as_bytes()[i];
            let ia = a.to_ascii_lowercase();
            let i_a = a.to_ascii_uppercase();
            for j in 0..alpha_size {
                let b = params.alpha.as_bytes()[j];
                let ib = b.to_ascii_lowercase();
                let i_b = b.to_ascii_uppercase();
                let p = scores.emits[i][j];
                match_score[ia as usize][ib as usize] = p;
                match_score[ia as usize][i_b as usize] = p;
                match_score[i_a as usize][ib as usize] = p;
                match_score[i_a as usize][i_b as usize] = p;
            }
        }
    }

    if alpha_size == 4 {
        pair_hmm_fix_ut();
    }
}

#[track_caller]
pub fn pair_hmm_fix_ut() {
    {
        let mut ins_score = PAIR_HMM_INS_SCORE.lock().unwrap();
        ins_score[b'U' as usize] = ins_score[b'T' as usize];
        ins_score[b'u' as usize] = ins_score[b't' as usize];
    }

    let mut match_score = PAIR_HMM_MATCH_SCORE.lock().unwrap();
    for i in 0..256 {
        let p = match_score[b'T' as usize][i];
        match_score[b'U' as usize][i] = p;
        match_score[b'u' as usize][i] = p;
        match_score[i][b'U' as usize] = p;
        match_score[i][b'u' as usize] = p;
    }
}

#[track_caller]
pub fn hmm_params_normalize_emit(params: &mut HMMParams) {
    assert!(!params.logs);
    let alpha_size = params.alpha.len();
    assert!(alpha_size == 4 || alpha_size == 20);

    let mut sum = 0.0;
    for i in 0..alpha_size {
        for j in 0..=i {
            let p = params.emits[i][j];
            params.emits[i][j] = p;
            params.emits[j][i] = p;
            sum += p;
            if i != j {
                sum += p;
            }
        }
    }

    for i in 0..alpha_size {
        for j in 0..alpha_size {
            params.emits[i][j] /= sum;
        }
    }
}

#[track_caller]
pub fn hmm_params_normalize_start(params: &mut HMMParams) {
    let sum = params.trans[HMMTRANS::HMMTRANS_START_M as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_START_IS as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_START_IL as usize];
    params.trans[HMMTRANS::HMMTRANS_START_M as usize] /= sum;
    params.trans[HMMTRANS::HMMTRANS_START_IS as usize] /= sum;
    params.trans[HMMTRANS::HMMTRANS_START_IL as usize] /= sum;
}

#[track_caller]
pub fn hmm_params_normalize_short_gap(params: &mut HMMParams) {
    let sum_m = params.trans[HMMTRANS::HMMTRANS_M_M as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_M_IS as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_M_IL as usize];
    params.trans[HMMTRANS::HMMTRANS_M_M as usize] /= sum_m;
    params.trans[HMMTRANS::HMMTRANS_M_IS as usize] /= sum_m;
    params.trans[HMMTRANS::HMMTRANS_M_IL as usize] /= sum_m;

    let sum_is = params.trans[HMMTRANS::HMMTRANS_IS_IS as usize]
        + params.trans[HMMTRANS::HMMTRANS_IS_M as usize];
    params.trans[HMMTRANS::HMMTRANS_IS_IS as usize] /= sum_is;
    params.trans[HMMTRANS::HMMTRANS_IS_M as usize] /= sum_is;
}

#[track_caller]
pub fn hmm_params_normalize_long_gap(params: &mut HMMParams) {
    let sum_m = params.trans[HMMTRANS::HMMTRANS_M_M as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_M_IS as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_M_IL as usize];
    params.trans[HMMTRANS::HMMTRANS_M_M as usize] /= sum_m;
    params.trans[HMMTRANS::HMMTRANS_M_IS as usize] /= sum_m;
    params.trans[HMMTRANS::HMMTRANS_M_IL as usize] /= sum_m;

    let sum_il = params.trans[HMMTRANS::HMMTRANS_IL_IL as usize]
        + params.trans[HMMTRANS::HMMTRANS_IL_M as usize];
    params.trans[HMMTRANS::HMMTRANS_IL_IL as usize] /= sum_il;
    params.trans[HMMTRANS::HMMTRANS_IL_M as usize] /= sum_il;
}

#[track_caller]
pub fn hmm_params_normalize_match(params: &mut HMMParams) {
    let sum_m = params.trans[HMMTRANS::HMMTRANS_M_M as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_M_IS as usize]
        + 2.0 * params.trans[HMMTRANS::HMMTRANS_M_IL as usize];
    params.trans[HMMTRANS::HMMTRANS_M_M as usize] /= sum_m;
    params.trans[HMMTRANS::HMMTRANS_M_IS as usize] /= sum_m;
    params.trans[HMMTRANS::HMMTRANS_M_IL as usize] /= sum_m;
}

#[track_caller]
pub fn hmm_params_normalize(params: &mut HMMParams) {
    hmm_params_normalize_start(params);
    hmm_params_normalize_short_gap(params);
    hmm_params_normalize_long_gap(params);
    hmm_params_normalize_emit(params);
    hmm_params_assert_probs_valid(params);
}

#[track_caller]
pub fn hscore(xs: &[f64], ys: &[f64], x: f64) -> f64 {
    let n = xs.len();
    assert_eq!(ys.len(), n);
    assert!(n > 0);
    if x < xs[0] {
        return ys[0];
    }
    for i in 1..n {
        if x >= xs[i - 1] && x < xs[i] {
            let f = (x - xs[i - 1]) / (xs[i] - xs[i - 1]);
            return f * ys[i] + (1.0 - f) * ys[i - 1];
        }
    }
    ys[n - 1]
}

#[track_caller]
pub fn test_l21() -> String {
    let xs = [0.1_f64, 0.5, 0.9];
    let ys = [1.0_f64, 2.0, 3.0];
    let n = xs.len();
    assert_eq!(ys.len(), n);
    let x = 0.0_f64;
    let y = hscore(&xs, &ys, x);
    format!("x={x:.3} y={y:.3}\n")
        .replace(".000", "")
        .replace(".00", "")
}

