#[track_caller]
pub fn path_to_col_vecs(path_xy: &str) -> (Vec<uint>, Vec<uint>, Vec<uint>, Vec<uint>) {
    let mut pos_to_col_x = Vec::new();
    let mut pos_to_col_y = Vec::new();
    let mut col_to_pos_x = Vec::new();
    let mut col_to_pos_y = Vec::new();

    let col_count = path_xy.len();
    for (col, c) in path_xy.chars().enumerate() {
        let col = col as uint;
        if c == 'B' {
            let pos_x = pos_to_col_x.len() as uint;
            let pos_y = pos_to_col_y.len() as uint;
            col_to_pos_x.push(pos_x);
            col_to_pos_y.push(pos_y);
            pos_to_col_x.push(col);
            pos_to_col_y.push(col);
        } else if c == 'X' {
            let pos_x = pos_to_col_x.len() as uint;
            col_to_pos_x.push(pos_x);
            col_to_pos_y.push(uint::MAX);
            pos_to_col_x.push(col);
        } else if c == 'Y' {
            let pos_y = pos_to_col_y.len() as uint;
            col_to_pos_y.push(pos_y);
            col_to_pos_x.push(uint::MAX);
            pos_to_col_y.push(col);
        } else {
            panic!("invalid path char");
        }
    }

    assert_eq!(col_to_pos_x.len(), col_count);
    assert_eq!(col_to_pos_y.len(), col_count);
    for col in 0..col_count {
        let pos_x = col_to_pos_x[col];
        let pos_y = col_to_pos_y[col];
        if pos_x != uint::MAX {
            assert!((pos_x as usize) < pos_to_col_x.len());
            assert_eq!(pos_to_col_x[pos_x as usize], col as uint);
        }
        if pos_y != uint::MAX {
            assert!((pos_y as usize) < pos_to_col_y.len());
            assert_eq!(pos_to_col_y[pos_y as usize], col as uint);
        }
    }

    (pos_to_col_x, pos_to_col_y, col_to_pos_x, col_to_pos_y)
}

#[track_caller]
pub fn write_annot_row(
    a: &[byte],
    b: &[byte],
    path: &str,
    mut i: uint,
    mut j: uint,
    col_lo: uint,
    col_hi: uint,
) -> String {
    let mut out = format!("{:5.5} ", "");
    let path_bytes = path.as_bytes();
    for k in col_lo..=col_hi {
        let c = path_bytes[k as usize] as char;
        if c == 'M' {
            let aa = a[i as usize];
            let bb = b[j as usize];
            i += 1;
            j += 1;
            if aa.to_ascii_uppercase() == bb.to_ascii_uppercase() {
                out.push('|');
            } else {
                out.push(' ');
            }
        } else {
            if c == 'D' {
                i += 1;
            } else if c == 'I' {
                j += 1;
            } else {
                panic!("invalid path char");
            }
            out.push(' ');
        }
    }
    out.push('\n');
    out
}

#[track_caller]
pub fn write_b_row(
    b: &[byte],
    path: &str,
    mut j: uint,
    col_lo: uint,
    col_hi: uint,
    label_b: &str,
) -> (String, uint) {
    let mut out = format!("{:5} ", j + 1);
    let path_bytes = path.as_bytes();
    for k in col_lo..=col_hi {
        let c = path_bytes[k as usize] as char;
        if c == 'M' || c == 'I' {
            out.push(b[j as usize] as char);
            j += 1;
        } else {
            out.push('-');
        }
    }
    out.push_str(&format!(" {j}  {label_b}\n"));
    (out, j)
}

#[track_caller]
pub fn write_a_row(
    a: &[byte],
    path: &str,
    mut i: uint,
    col_lo: uint,
    col_hi: uint,
    label_a: &str,
) -> (String, uint) {
    let mut out = format!("{:5} ", i + 1);
    let path_bytes = path.as_bytes();
    for k in col_lo..=col_hi {
        let c = path_bytes[k as usize] as char;
        if c == 'M' || c == 'D' {
            out.push(a[i as usize] as char);
            i += 1;
        } else {
            out.push('-');
        }
    }
    out.push_str(&format!(" {i}  {label_a}\n"));
    (out, i)
}

#[track_caller]
pub fn write_aln_pretty(a: &[byte], b: &[byte], path: &str) -> String {
    const BLOCK_SIZE: uint = 80;
    let col_lo = 0;
    let col_hi = path.len() as uint - 1;
    assert!(col_hi >= col_lo);

    let mut out = String::new();
    let mut i = 0;
    let mut j = 0;
    let mut col_from = col_lo;
    loop {
        if col_from > col_hi {
            break;
        }
        let mut col_to = col_from + BLOCK_SIZE - 1;
        if col_to > col_hi {
            col_to = col_hi;
        }

        let i0 = i;
        let j0 = j;
        let (a_row, new_i) = write_a_row(a, path, i, col_from, col_to, "");
        i = new_i;
        out.push_str(&a_row);
        out.push_str(&write_annot_row(a, b, path, i0, j0, col_from, col_to));
        let (b_row, new_j) = write_b_row(b, path, j, col_from, col_to, "");
        j = new_j;
        out.push_str(&b_row);
        out.push('\n');

        col_from = col_to + 1;
    }
    out
}

#[track_caller]
pub fn get_mega_profile_aa_seq(profile: &[Vec<byte>]) -> String {
    let mega = MEGA_STATE.lock().unwrap();
    let mut pi = uint::MAX;
    for i in 0..mega.feature_names.len() {
        if mega.feature_names[i] == "AA" {
            pi = i as uint;
            break;
        }
    }
    assert_ne!(pi, uint::MAX);
    let state = ALPHA_STATE.lock().unwrap();
    let mut seq = String::new();
    for row in profile {
        seq.push(state.letter_to_char[row[pi as usize] as usize] as char);
    }
    seq
}

#[track_caller]
pub fn write_local_aln_masm(
    label_a: &str,
    ma: &MASM,
    label_b: &str,
    pb: &[Vec<byte>],
    loi: uint,
    loj: uint,
    path: &str,
) -> String {
    const BLOCK_SIZE: uint = 80;
    let str_a = masm_get_consensus_seq(ma);
    let str_b = get_mega_profile_aa_seq(pb);
    let a = str_a.as_bytes();
    let b = str_b.as_bytes();
    let col_lo = 0;
    let col_hi = path.len() as uint - 1;
    assert!(col_hi >= col_lo);

    let mut out = String::new();
    let mut pos_a = loi;
    let mut pos_b = loj;
    let mut col_from = col_lo;
    loop {
        if col_from > col_hi {
            break;
        }
        let mut col_to = col_from + BLOCK_SIZE - 1;
        if col_to > col_hi {
            col_to = col_hi;
        }

        out.push('\n');
        let i0 = pos_a;
        let j0 = pos_b;
        let (a_row, new_pos_a) = write_a_row(a, path, pos_a, col_from, col_to, label_a);
        pos_a = new_pos_a;
        out.push_str(&a_row);
        out.push_str(&write_annot_row(a, b, path, i0, j0, col_from, col_to));
        let (b_row, new_pos_b) = write_b_row(b, path, pos_b, col_from, col_to, label_b);
        pos_b = new_pos_b;
        out.push_str(&b_row);

        col_from += BLOCK_SIZE;
    }
    out
}

#[track_caller]
pub fn log_dist_mx(msg: &str, mx: &[Vec<f32>]) -> String {
    let mut out = String::new();
    let format_g3 = |d: f32| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let d64 = f64::from(d);
        let exp = d64.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 3 {
            let raw = format!("{d64:.2e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (2 - exp).max(0) as usize;
            format!("{d64:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };
    out.push('\n');
    out.push_str(&format!("LogDistMx({msg})\n"));
    let row_count = mx.len();
    assert!(row_count > 0);
    for row in 0..row_count {
        out.push_str(&format!("[{row:5}]  "));
        let col_count = mx[row].len();
        for col in 0..col_count {
            let x = mx[row][col];
            if x == f32::MAX {
                out.push_str(&format!("  {:>7.7}", "*"));
            } else if x == LOG_ZERO {
                out.push_str(&format!("  {:>7.7}", "."));
            } else {
                out.push_str(&format!("  {:>7}", format_g3(x)));
            }
        }
        out.push('\n');
    }
    out
}

