#[track_caller]
pub fn m3_aln_params_print(ap: &M3AlnParams) -> String {
    let state = ALPHA_STATE.lock().unwrap();
    let mut out = String::new();
    let format_g = |d: f32, precision: usize| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let d64 = f64::from(d);
        let exp = d64.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= precision as i32 {
            let raw = format!("{d64:.p$e}", p = precision - 1);
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (precision as i32 - 1 - exp).max(0) as usize;
            format!("{d64:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };
    out.push('\n');
    out.push_str(&format!(
        "m_GapOpen={} m_Center={}",
        format_g(ap.gap_open, 6),
        format_g(ap.center, 6)
    ));
    out.push_str(&format!(" linkage={}", ap.linkage));
    out.push_str(&format!(" treeiters={}", ap.tree_iters));
    out.push_str(&format!(" kmerdist={}\n", ap.kmer_dist));
    out.push_str(&format!(" perturb({})", ap.perturb_seed));
    if ap.perturb_seed != 0 {
        out.push_str(&format!(
            " substmx={}, gapparams={}, distmx={}",
            format_g(ap.perturb_subst_mx_delta, 3),
            format_g(ap.perturb_gap_params_delta, 3),
            format_g(ap.perturb_dist_mx_delta, 3)
        ));
    }
    out.push('\n');
    for i in 0..3 {
        out.push_str(&format!("  SubstMx[{}]: ", state.letter_to_char[i]));
        for j in 0..8 {
            out.push_str(&format!(
                " {}={:8.4}",
                state.letter_to_char[j], ap.subst_mx_letter[i][j]
            ));
        }
        out.push('\n');
    }
    out.push('\n');
    for i in 0..3 {
        out.push_str(&format!("SubstMx-C[{}]: ", state.letter_to_char[i]));
        for j in 0..8 {
            out.push_str(&format!(
                " {}={:8.4}",
                state.letter_to_char[j],
                ap.subst_mx_letter[i][j] - ap.center
            ));
        }
        out.push('\n');
    }
    out
}

#[track_caller]
pub fn m3_aln_params_add_center(ap: &mut M3AlnParams, x: f32) {
    if x == 0.0 {
        return;
    }
    assert!(!ap.center_added);
    for i in 0..20 {
        for j in 0..20 {
            ap.subst_mx_letter[i][j] += x;
        }
    }
    ap.center_added = true;
}

#[track_caller]
pub fn m3_aln_params_set_blosum(
    ap: &mut M3AlnParams,
    pct_id: uint,
    n: uint,
    gap_open: f32,
    center: f32,
    perturb_seed: uint,
    perturb_subst_mx_delta: f32,
    perturb_gap_params_delta: f32,
    perturb_dist_mx_delta: f32,
) {
    set_alpha_lc(false);
    ap.perturb_seed = perturb_seed;
    ap.perturb_subst_mx_delta = perturb_subst_mx_delta;
    ap.perturb_gap_params_delta = perturb_gap_params_delta;
    ap.perturb_dist_mx_delta = perturb_dist_mx_delta;
    ap.center_added = false;
    ap.perturb_gap_params_done = false;
    ap.perturb_subst_mx_done = false;
    ap.subst_mx_letter = get_subst_mx_letter_blosum(pct_id);
    let (default_gap_open, default_center) = get_gap_params_blosum(pct_id, n);
    ap.gap_open = if gap_open != f32::MAX {
        gap_open
    } else {
        default_gap_open
    };
    ap.center = if center != f32::MAX {
        center
    } else {
        default_center
    };
    m3_aln_params_add_center(ap, ap.center);
    m3_aln_params_perturb_my_params(ap);
    ap.ready = true;
}

#[track_caller]
pub fn m3_aln_params_update_mx(
    ap: &mut M3AlnParams,
    subst_mx_letter: &[[f32; 20]; 20],
    gap_open: f32,
    center: f32,
) {
    set_alpha_lc(false);
    for i in 0..20 {
        for j in 0..20 {
            ap.subst_mx_letter[i][j] = subst_mx_letter[i][j];
        }
    }
    ap.perturb_subst_mx_done = false;
    ap.perturb_gap_params_done = false;
    ap.center_added = false;
    ap.gap_open = gap_open;
    ap.center = center;
    m3_aln_params_add_center(ap, ap.center);
    ap.ready = true;
}

#[track_caller]
pub fn m3_aln_params_set_from_cmd_line(
    ap: &mut M3AlnParams,
    is_nucleo: bool,
    do_log: bool,
    subst_mx_file_name: Option<&str>,
    gap_open: Option<f32>,
    center: Option<f32>,
    blosum_pct: Option<uint>,
    blosum_param_set: Option<uint>,
    perturb_seed: Option<uint>,
    linkage: Option<&str>,
    kmer_dist: Option<&str>,
    tree_iters: Option<uint>,
) -> Option<String> {
    assert!(!is_nucleo);
    set_alpha_lc(is_nucleo);

    if let Some(file_name) = subst_mx_file_name {
        assert!(gap_open.is_some());
        assert!(center.is_some());
        ap.subst_mx_letter = read_subst_mx_letter_from_file(file_name);
        ap.gap_open = gap_open.unwrap();
        ap.center = center.unwrap();
        ap.perturb_subst_mx_done = false;
        ap.perturb_gap_params_done = false;
        ap.center_added = false;
    } else {
        ap.perturb_subst_mx_done = false;
        ap.perturb_gap_params_done = false;
        ap.center_added = false;

        let blosum_pct = blosum_pct.unwrap_or(62);
        let blosum_param_set = blosum_param_set.unwrap_or(0);
        ap.subst_mx_letter = get_subst_mx_letter_blosum(blosum_pct);
        let (default_gap_open, default_center) =
            get_gap_params_blosum(blosum_pct, blosum_param_set);
        ap.gap_open = gap_open.unwrap_or(default_gap_open);
        ap.center = center.unwrap_or(default_center);
    }

    m3_aln_params_add_center(ap, ap.center);

    if let Some(seed) = perturb_seed {
        ap.perturb_seed = seed;
        if ap.perturb_seed != 0 {
            ap.perturb_subst_mx_delta = 0.1;
            ap.perturb_gap_params_delta = 0.1;
            ap.perturb_dist_mx_delta = 0.1;
        }
        m3_aln_params_perturb_my_params(ap);
    }

    ap.linkage = "biased".to_string();
    if let Some(linkage) = linkage {
        ap.linkage = linkage.to_string();
    }

    ap.kmer_dist = "66".to_string();
    if let Some(kmer_dist) = kmer_dist {
        ap.kmer_dist = kmer_dist.to_string();
    }

    ap.tree_iters = 1;
    if let Some(tree_iters) = tree_iters {
        ap.tree_iters = tree_iters;
    }

    ap.ready = true;

    if do_log {
        Some(m3_aln_params_print(ap))
    } else {
        None
    }
}

#[track_caller]
pub fn m3_aln_params_perturb_subst_mx(ap: &mut M3AlnParams) {
    if ap.perturb_seed == 0 || ap.perturb_subst_mx_delta == 0.0 {
        return;
    }
    assert!(!ap.perturb_subst_mx_done);
    for i in 0..20 {
        for j in 0..20 {
            let mut score = ap.subst_mx_letter[i][j];
            m3_aln_params_perturb1_l17(ap, &mut score, ap.perturb_subst_mx_delta);
            ap.subst_mx_letter[i][j] = score;
        }
    }
    ap.perturb_subst_mx_done = true;
}

#[track_caller]
pub fn m3_aln_params_perturb_gap_params(ap: &mut M3AlnParams) {
    if ap.perturb_gap_params_delta == 0.0 {
        return;
    }
    assert!(!ap.perturb_gap_params_done);
    let mut gap_open = ap.gap_open;
    m3_aln_params_perturb1_l17(ap, &mut gap_open, ap.perturb_gap_params_delta);
    ap.gap_open = gap_open;
    let mut center = ap.center;
    m3_aln_params_perturb1_l17(ap, &mut center, ap.perturb_gap_params_delta);
    ap.center = center;
    ap.perturb_gap_params_done = true;
}

#[track_caller]
pub fn m3_aln_params_perturb_my_params(ap: &mut M3AlnParams) {
    if ap.perturb_seed == 0 {
        return;
    }
    m3_aln_params_init_perturb(ap, ap.perturb_seed);
    m3_aln_params_perturb_gap_params(ap);
    m3_aln_params_perturb_subst_mx(ap);
}

#[track_caller]
pub fn m3_aln_params_init_perturb(ap: &mut M3AlnParams, seed: uint) {
    let mut s = seed % 2_147_483_647;
    if s == 0 {
        s = 1;
    }
    ap.min_std_rand = s;
}

#[track_caller]
pub fn m3_aln_params_get_rand(ap: &mut M3AlnParams) -> uint {
    let product = (ap.min_std_rand as u64) * 48271_u64;
    ap.min_std_rand = (product % 2_147_483_647_u64) as uint;
    ap.min_std_rand
}

#[track_caller]
pub fn m3_aln_params_perturb_dist_mx(ap: &mut M3AlnParams, dist_mx: &mut [Vec<f32>]) {
    if ap.perturb_seed == 0 || ap.perturb_dist_mx_delta == 0.0 {
        return;
    }
    let n = dist_mx.len();
    for i in 0..n {
        assert_eq!(dist_mx[i].len(), n);
        for j in 0..i {
            let mut d = dist_mx[i][j];
            m3_aln_params_perturb1_l6(ap, &mut d, ap.perturb_dist_mx_delta);
            dist_mx[i][j] = d;
            dist_mx[j][i] = d;
        }
    }
}

pub fn normalize_weights(seq_weights: &mut [f32]) {
    let n = seq_weights.len();
    assert!(n > 0);
    let mut sum = 0.0;
    for &weight in seq_weights.iter() {
        sum += weight;
    }
    for weight in seq_weights {
        *weight /= sum;
    }
}

pub fn split_indexes3(n: uint) -> Vec<Vec<uint>> {
    let mut index_vec = vec![Vec::new(), Vec::new(), Vec::new()];

    let mut ix0 = randu32() % (n - 1);
    let mut ix1 = randu32() % (n - 1);
    if ix1 == ix0 {
        ix1 = (ix1 + 1) % (n - 1);
    }
    if ix0 > ix1 {
        std::mem::swap(&mut ix0, &mut ix1);
    }

    for i in 0..=ix0 {
        index_vec[0].push(i);
    }
    for i in ix0 + 1..=ix1 {
        index_vec[1].push(i);
    }
    for i in ix1 + 1..n {
        index_vec[2].push(i);
    }

    index_vec
}

#[track_caller]
pub fn m3_refine<FNwSmall3>(
    input_msa: &MultiSequence,
    ap: &M3AlnParams,
    seq_weights: &[f32],
    refined_msa: &mut MultiSequence,
    mut nw_small3: FNwSmall3,
) -> String
where
    FNwSmall3: FnMut(&mut CacheMem3, &Profile3, &Profile3) -> String,
{
    let subst_mx_letter = &ap.subst_mx_letter;
    let gap_open = ap.gap_open;

    let seq_count = input_msa.seqs.len() as uint;
    let mut current_best_msa = MultiSequence::default();
    multi_sequence_copy(&mut current_best_msa, input_msa);

    let mut prof3 = Profile3::default();
    profile3_from_msa(
        &mut prof3,
        &current_best_msa,
        subst_mx_letter,
        gap_open,
        seq_weights,
    );
    let _current_best_self_score = profile3_get_self_score(&prof3);

    let mut cm = CacheMem3::default();
    let mut out = String::new();
    for _iter in 0..32 {
        let index_vec = split_indexes3(seq_count);

        let sub_msa0 = multi_sequence_project_l3(&current_best_msa, &index_vec[0]);
        let sub_msa1 = multi_sequence_project_l3(&current_best_msa, &index_vec[1]);
        let sub_msa2 = multi_sequence_project_l3(&current_best_msa, &index_vec[2]);

        let mut seq_weights0 = Vec::new();
        let mut seq_weights1 = Vec::new();
        let mut seq_weights2 = Vec::new();

        for &seq_index in &index_vec[0] {
            seq_weights0.push(seq_weights[seq_index as usize]);
        }
        for &seq_index in &index_vec[1] {
            seq_weights1.push(seq_weights[seq_index as usize]);
        }
        for &seq_index in &index_vec[2] {
            seq_weights2.push(seq_weights[seq_index as usize]);
        }

        normalize_weights(&mut seq_weights0);
        normalize_weights(&mut seq_weights1);
        normalize_weights(&mut seq_weights2);

        let mut prof0 = Profile3::default();
        let mut prof1 = Profile3::default();
        let mut prof2 = Profile3::default();
        profile3_from_msa(
            &mut prof0,
            &sub_msa0,
            subst_mx_letter,
            gap_open,
            &seq_weights0,
        );
        profile3_from_msa(
            &mut prof1,
            &sub_msa1,
            subst_mx_letter,
            gap_open,
            &seq_weights1,
        );
        profile3_from_msa(
            &mut prof2,
            &sub_msa2,
            subst_mx_letter,
            gap_open,
            &seq_weights2,
        );

        let path01 = nw_small3(&mut cm, &prof0, &prof1);
        let _path02 = nw_small3(&mut cm, &prof0, &prof2);
        let _path12 = nw_small3(&mut cm, &prof1, &prof2);

        out.push('\n');
        out.push_str(&format!("Path01={path01}\n"));
        out.push_str(&format!("Path02={path01}\n"));
        out.push_str(&format!("Path12={path01}\n"));
    }

    let _ = refined_msa;
    out
}

#[track_caller]
pub fn cmd_m3refine<FRunUpgma, FSetParams, FRefine>(
    input_file_name: &str,
    mut run_upgma: FRunUpgma,
    mut set_params: FSetParams,
    mut refine: FRefine,
) -> (
    MultiSequence,
    Vec<String>,
    Vec<f32>,
    Tree,
    M3AlnParams,
    MultiSequence,
    String,
)
where
    FRunUpgma: FnMut(&mut UPGMA5, &mut Tree),
    FSetParams: FnMut(&mut M3AlnParams),
    FRefine: FnMut(&MultiSequence, &M3AlnParams, &[f32], &mut MultiSequence) -> String,
{
    let mut msa = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut msa, input_file_name, false);
    assert!(multi_sequence_is_aligned(&msa));
    let seq_count = msa.seqs.len() as uint;

    let mut labels = Vec::new();
    let mut seq_weights = Vec::new();
    let w = 1.0 / seq_count as f32;
    for i in 0..seq_count {
        labels.push(msa.seqs[i as usize].label.clone());
        seq_weights.push(w);
    }

    let dist_mx = get_kimura_dist_mx(&msa);
    let mut u5 = UPGMA5::default();
    let mut t = Tree::default();
    upgma5_init(&mut u5, &labels, &dist_mx);
    run_upgma(&mut u5, &mut t);

    let mut cw = ClustalWeights::default();
    seq_weights = clustal_weights_run(&mut cw, &msa, &t);

    let mut ap = M3AlnParams::default();
    set_params(&mut ap);

    let mut refined_msa = MultiSequence::default();
    let log = refine(&msa, &ap, &seq_weights, &mut refined_msa);
    (msa, labels, seq_weights, t, ap, refined_msa, log)
}

#[track_caller]
pub fn cmd_m3select(
    input_file_name: &str,
    output_file_name: &str,
    replicates: Option<uint>,
) -> String {
    let mut input_seqs = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut input_seqs, input_file_name, true);
    set_global_input_ms(&input_seqs);

    let mut master_ap = M3AlnParams {
        linkage: "min".to_string(),
        tree_iters: 1,
        kmer_dist: "66".to_string(),
        ..M3AlnParams::default()
    };
    m3_aln_params_set_blosum(&mut master_ap, 62, 0, f32::MAX, f32::MAX, 0, 0.0, 0.0, 0.0);
    master_ap.linkage = "min".to_string();
    master_ap.tree_iters = 1;
    master_ap.kmer_dist = "66".to_string();
    let master_subst_mx_letter = master_ap.subst_mx_letter;
    let master_gap_open = master_ap.gap_open;

    let delta = 0.1_f32;
    let replicates = replicates.unwrap_or(64);
    assert!(replicates > 0);

    let mut best_msa: Option<MultiSequence> = None;
    let mut best_self_score = 0.0_f32;
    for ii in 0..replicates {
        let perturb_seed = ii;
        let param_group = 0;
        let pct_id = 62;

        let perturb_subst_mx_delta = 0.0_f32;
        let perturb_gap_params_delta = 0.0_f32;
        let perturb_dist_mx_delta = delta;

        let mut ap = M3AlnParams {
            linkage: "min".to_string(),
            tree_iters: 1,
            kmer_dist: "66".to_string(),
            ..M3AlnParams::default()
        };
        m3_aln_params_set_blosum(
            &mut ap,
            pct_id,
            param_group,
            f32::MAX,
            f32::MAX,
            perturb_seed,
            perturb_subst_mx_delta,
            perturb_gap_params_delta,
            perturb_dist_mx_delta,
        );
        ap.linkage = "min".to_string();
        ap.tree_iters = 1;
        ap.kmer_dist = "66".to_string();

        let mut m3 = Muscle3::default();
        let final_msa = muscle3_run(
            &mut m3,
            &ap,
            &input_seqs,
            |u, linkage, tree| upgma5_run_l75(u, linkage, tree),
            |pp, input, weights, tree| {
                p_prog3_run(
                    pp,
                    input,
                    weights,
                    tree,
                    |cm, prof_a, prof_b| nw_small3(cm, prof_a, prof_b).1,
                    |prof_a, weight_a, prof_b, weight_b, subst_mx_letter, gap_open, path| {
                        align_two_profs_given_path(
                            prof_a,
                            weight_a,
                            prof_b,
                            weight_b,
                            subst_mx_letter,
                            gap_open,
                            path,
                        )
                    },
                );
                pp.msa.clone()
            },
        );
        let mut prof = Profile3::default();
        profile3_from_msa(
            &mut prof,
            &final_msa,
            &master_subst_mx_letter,
            master_gap_open,
            &m3.input_seq_weights,
        );
        let self_score = profile3_get_self_score(&prof);
        if self_score > best_self_score {
            best_msa = Some(final_msa);
            best_self_score = self_score;
        }
    }
    let best_msa = best_msa.expect("BestMSA != 0");
    let out = msa_to_fasta_file_l112(&best_msa);
    if !output_file_name.is_empty() {
        msa_to_fasta_file_l103(&best_msa, output_file_name);
    }
    out
}

