#[track_caller]
pub fn mega_from_msa_aa_only(aln: &MultiSequence, gap_open: f32, gap_ext: f32) {
    let mut mega = MEGA_STATE.lock().unwrap();
    mega.file_name = "FromMSA_AAOnly()".to_string();
    mega.lines.clear();

    mega.feature_names.clear();
    mega.feature_names.push("AA".to_string());

    mega.weights.clear();
    mega.weights.push(1.0);

    mega.alpha_sizes.clear();
    mega.alpha_sizes.push(20);
    mega.feature_count = 1;

    mega.label_to_idx.clear();
    mega.seq_to_idx.clear();
    mega.labels.clear();
    mega.seqs.clear();
    mega.profiles.clear();
    let seq_count = aln.seqs.len();
    mega.profiles.resize(seq_count, Vec::new());

    for seq_idx in 0..seq_count {
        let label = aln.seqs[seq_idx].label.clone();
        mega.labels.push(label.clone());
        let mut ungapped_seq = String::new();
        for &c in &aln.seqs[seq_idx].char_vec {
            if c != '-' && c != '.' {
                ungapped_seq.push(c);
            }
        }
        mega.seqs.push(ungapped_seq.clone());
        mega.label_to_idx.insert(label, seq_idx as uint);
        mega.seq_to_idx
            .insert(ungapped_seq.clone(), seq_idx as uint);

        let profile = &mut mega.profiles[seq_idx];
        for c in ungapped_seq.bytes() {
            let mut letter = match (c as char).to_ascii_uppercase() {
                'A' => 0,
                'C' => 1,
                'D' => 2,
                'E' => 3,
                'F' => 4,
                'G' => 5,
                'H' => 6,
                'I' => 7,
                'K' => 8,
                'L' => 9,
                'M' => 10,
                'N' => 11,
                'P' => 12,
                'Q' => 13,
                'R' => 14,
                'S' => 15,
                'T' => 16,
                'V' => 17,
                'W' => 18,
                'Y' => 19,
                _ => uint::MAX,
            };
            if letter >= 20 {
                letter = 0;
            }
            let mut col = Vec::new();
            col.push(letter as byte);
            profile.push(col);
        }
    }

    mega.log_probs_vec.clear();
    mega.log_prob_mx_vec.clear();
    mega.log_odds_mx_vec.clear();
    mega.log_odds_mx_vec.resize(1, Vec::new());
    mega.log_odds_mx_vec[0] = get_blosum62_log_odds_letter_mx();
    mega.gap_open = gap_open;
    mega.gap_ext = gap_ext;
    mega.loaded = true;
}

pub fn get_feature_char(is_aa: bool, letter: uint) -> byte {
    if is_aa {
        let state = ALPHA_STATE.lock().unwrap();
        return state.char_to_letter[letter as usize] as byte;
    }
    if letter < 26 {
        b'A' + letter as byte
    } else if letter < 26 * 2 {
        b'a' + letter as byte
    } else {
        panic!("invalid feature letter");
    }
}

#[track_caller]
pub fn cmd_mega_msas(fasta_file_name: &str, output_prefix: &str) -> Vec<(String, Vec<byte>)> {
    let aln = msa_from_fasta_file_preserve_case(fasta_file_name);
    let seq_count = aln.seqs.len() as uint;
    let col_count = multi_sequence_get_col_count(&aln);
    let feature_count = MEGA_STATE.lock().unwrap().feature_count;
    if feature_count == 0 {
        panic!("No features in {}", fasta_file_name);
    }

    let mut outputs = Vec::new();
    for feature_idx in 0..feature_count {
        let feature_name = mega_get_feature_name(feature_idx);
        let is_aa = feature_name == "AA";
        let output_file_name = format!("{output_prefix}{feature_name}");

        let mut out = Vec::new();
        for seq_idx in 0..seq_count {
            let row = sequence_get_seq_as_string(&aln.seqs[seq_idx as usize]);
            let label = msa_get_seq_label(&aln, seq_idx);
            let profile = mega_get_profile_by_label(&label);
            let mut pos = 0_usize;
            let mut feature_row = Vec::new();
            for c in row.chars().take(col_count as usize) {
                if c == '-' || c == '.' {
                    feature_row.push(c as byte);
                } else {
                    assert_eq!(profile[pos].len(), feature_count as usize);
                    let feature_letter = profile[pos][feature_idx as usize] as uint;
                    feature_row.push(get_feature_char(is_aa, feature_letter));
                    pos += 1;
                }
            }

            out.push(b'>');
            out.extend_from_slice(label.as_bytes());
            out.push(b'\n');
            let rowlen = 80;
            let block_count = feature_row.len().div_ceil(rowlen);
            for block_index in 0..block_count {
                let from = block_index * rowlen;
                let mut to = from + rowlen;
                if to >= feature_row.len() {
                    to = feature_row.len();
                }
                out.extend_from_slice(&feature_row[from..to]);
                out.push(b'\n');
            }
        }

        std::fs::write(&output_file_name, &out).expect("failed to write mega feature MSA");
        outputs.push((output_file_name, out));
    }
    outputs
}

