#[track_caller]
pub fn secs_to_hhmmss(secs: uint) -> String {
    let hh = secs / 3600;
    let mm = (secs - hh * 3600) / 60;
    let ss = secs % 60;
    if hh == 0 {
        format!("{mm:02}:{ss:02}")
    } else {
        format!("{hh:02}:{mm:02}:{ss:02}")
    }
}

#[track_caller]
pub fn secs_to_str(secs: f64) -> String {
    let format_g2 = |d: f64| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let exp = d.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 2 {
            let raw = format!("{d:.1e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (1 - exp).max(0) as usize;
            format!("{d:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };
    if secs >= 60.0 {
        return secs_to_hhmmss(secs as uint);
    }
    if secs < 1e-6 {
        format!("{}s", format_g2(secs))
    } else if secs < 1e-3 {
        format!("{:.2}ms", secs * 1e3)
    } else if secs < 1.0 {
        format!("{secs:.3}s")
    } else if secs < 10.0 {
        format!("{secs:.2}s")
    } else {
        format!("{secs:.1}s")
    }
}

#[track_caller]
pub fn mem_bytes_to_str(bytes: f64) -> String {
    if bytes < 1e4 {
        format!("{bytes:.1}b")
    } else if bytes < 1e6 {
        format!("{:.1}kb", bytes / 1e3)
    } else if bytes < 10e6 {
        format!("{:.1}Mb", bytes / 1e6)
    } else if bytes < 1e9 {
        format!("{:.0}Mb", bytes / 1e6)
    } else if bytes < 100e9 {
        format!("{:.1}Gb", bytes / 1e9)
    } else {
        format!("{:.0}Gb", bytes / 1e9)
    }
}

