#[track_caller]
pub fn strings_to_file(file_name: &str, v: &[String]) {
    if file_name.is_empty() {
        return;
    }
    let mut data = String::new();
    for s in v {
        data.push_str(s);
        data.push('\n');
    }
    std::fs::write(file_name, data.as_bytes()).unwrap();
}

#[track_caller]
pub fn divide_tree_fraction(input_tree: &Tree, fract: f64, tree1: &mut Tree, tree2: &mut Tree) {
    assert!(fract > 0.0 && fract < 1.0);

    let input_leaf_count = (input_tree.node_count + 1) / 2;
    assert!(input_leaf_count >= 3);

    assert!(input_tree.rooted);
    let node_count = input_tree.node_count;
    let mut best_node = uint::MAX;
    let mut best_leaf_count = uint::MAX;
    let mut best_diff = uint::MAX;
    let mut target_leaf_count = (f64::from(input_leaf_count) * fract + 0.5) as uint;
    if target_leaf_count == 0 {
        target_leaf_count = 1;
    }

    for node in 0..node_count {
        let subtree_leaf_count = tree_get_subtree_leaf_count(input_tree, node);
        let diff = if subtree_leaf_count > target_leaf_count {
            subtree_leaf_count - target_leaf_count
        } else {
            target_leaf_count - subtree_leaf_count
        };
        if best_node == uint::MAX || diff < best_diff {
            best_node = node;
            best_diff = diff;
            best_leaf_count = subtree_leaf_count;
        }
    }

    assert!(best_leaf_count != uint::MAX);
    divide_tree(input_tree, best_node, tree1, tree2);
}

#[track_caller]
pub fn permute_tree(
    input_tree: &Tree,
    tree_abc: &mut Tree,
    tree_acb: &mut Tree,
    tree_bca: &mut Tree,
    labels_a: &mut Vec<String>,
    labels_b: &mut Vec<String>,
    labels_c: &mut Vec<String>,
) {
    labels_a.clear();
    labels_b.clear();
    labels_c.clear();

    let input_leaf_count = (input_tree.node_count + 1) / 2;
    if input_leaf_count < 6 {
        tree_copy(tree_abc, input_tree);
        tree_copy(tree_acb, input_tree);
        tree_copy(tree_bca, input_tree);
        return;
    }

    let new_edge_length = 0.1_f32;

    let mut tree_a = Tree::default();
    let mut tree_bc = Tree::default();
    let mut tree_b = Tree::default();
    let mut tree_c = Tree::default();
    divide_tree_fraction(input_tree, 0.33, &mut tree_a, &mut tree_bc);
    divide_tree_fraction(&tree_bc, 0.5, &mut tree_b, &mut tree_c);

    *labels_a = tree_get_leaf_labels(&tree_a);
    *labels_b = tree_get_leaf_labels(&tree_b);
    *labels_c = tree_get_leaf_labels(&tree_c);

    let mut join_ab = Tree::default();
    join_trees(&tree_a, &tree_b, &mut join_ab, new_edge_length);
    join_trees(&join_ab, &tree_c, tree_abc, new_edge_length);

    let mut join_ac = Tree::default();
    join_trees(&tree_a, &tree_c, &mut join_ac, new_edge_length);
    join_trees(&join_ac, &tree_b, tree_acb, new_edge_length);

    let mut join_bc = Tree::default();
    join_trees(&tree_b, &tree_c, &mut join_bc, new_edge_length);
    join_trees(&join_bc, &tree_a, tree_bca, new_edge_length);

    tree_ladderize(tree_abc, true);
    tree_ladderize(tree_acb, true);
    tree_ladderize(tree_bca, true);
}

#[track_caller]
pub fn perm_tree(input_tree: &mut Tree, tp: TREEPERM) {
    if tp == TREEPERM::TP_None {
        return;
    }
    let leaf_count = (input_tree.node_count + 1) / 2;
    if leaf_count < 10 {
        return;
    }

    let mut tree_abc = Tree::default();
    let mut tree_acb = Tree::default();
    let mut tree_bca = Tree::default();
    let mut labels_a = Vec::new();
    let mut labels_b = Vec::new();
    let mut labels_c = Vec::new();
    permute_tree(
        input_tree,
        &mut tree_abc,
        &mut tree_acb,
        &mut tree_bca,
        &mut labels_a,
        &mut labels_b,
        &mut labels_c,
    );
    match tp {
        TREEPERM::TP_ABC => tree_copy(input_tree, &tree_abc),
        TREEPERM::TP_ACB => tree_copy(input_tree, &tree_acb),
        TREEPERM::TP_BCA => tree_copy(input_tree, &tree_bca),
        _ => panic!("PermTree, invalid tree permutation {:?}", tp),
    }
}

#[track_caller]
pub fn cmd_permute_tree(
    input_file_name: &str,
    prefix: Option<&str>,
) -> (Tree, Tree, Tree, Vec<String>, Vec<String>, Vec<String>) {
    let mut input_tree = Tree::default();
    tree_from_file_l143(&mut input_tree, input_file_name);

    let mut tree_abc = Tree::default();
    let mut tree_acb = Tree::default();
    let mut tree_bca = Tree::default();
    let mut labels_a = Vec::new();
    let mut labels_b = Vec::new();
    let mut labels_c = Vec::new();
    permute_tree(
        &input_tree,
        &mut tree_abc,
        &mut tree_acb,
        &mut tree_bca,
        &mut labels_a,
        &mut labels_b,
        &mut labels_c,
    );

    if let Some(prefix) = prefix {
        tree_to_file_l13(&tree_abc, &format!("{prefix}ABC.newick"));
        tree_to_file_l13(&tree_acb, &format!("{prefix}ACB.newick"));
        tree_to_file_l13(&tree_bca, &format!("{prefix}BCA.newick"));
        strings_to_file(&format!("{prefix}labelsA.txt"), &labels_a);
        strings_to_file(&format!("{prefix}labelsB.txt"), &labels_b);
        strings_to_file(&format!("{prefix}labelsC.txt"), &labels_c);
    }

    (tree_abc, tree_acb, tree_bca, labels_a, labels_b, labels_c)
}

#[track_caller]
pub fn perturb(p: &mut f32, var: f32) {
    assert!((0.0..1.0).contains(&var));
    let pct = randu32() % 100;
    let fract = pct as f32 / 100.0;
    assert!((0.0..=1.0).contains(&fract));
    let lo = 1.0 - var;
    let hi = 1.0 + var;
    let d = lo + (hi - lo) * fract;
    *p *= d;
}

#[track_caller]
pub fn hmm_params_perturb_probs(params: &mut HMMParams, seed: uint) {
    if seed == 0 {
        return;
    }

    reset_rand(seed);
    assert!(params.var > 0.0 && params.var < 1.0);

    for i in 0..params.trans.len() {
        let pct = randu32() % 100;
        let fract = pct as f32 / 100.0;
        assert!((0.0..=1.0).contains(&fract));
        let lo = 1.0 - params.var;
        let hi = 1.0 + params.var;
        let d = lo + (hi - lo) * fract;
        params.trans[i] *= d;
    }

    let alpha_size = params.alpha.len();
    for i in 0..alpha_size {
        for j in 0..=i {
            let pct = randu32() % 100;
            let fract = pct as f32 / 100.0;
            assert!((0.0..=1.0).contains(&fract));
            let lo = 1.0 - params.var;
            let hi = 1.0 + params.var;
            let d = lo + (hi - lo) * fract;
            let p = params.emits[i][j] * d;
            params.emits[i][j] = p;
            params.emits[j][i] = p;
        }
    }

    hmm_params_normalize(params);
}

#[track_caller]
pub fn hmm_params_compare(hp1: &HMMParams, hp2: &HMMParams) -> (f32, f32) {
    let nt = hp1.trans.len();
    let alpha_size = hp1.alpha.len();
    assert_eq!(hp2.trans.len(), nt);
    assert_eq!(hp1.emits.len(), alpha_size);
    assert_eq!(hp2.emits.len(), alpha_size);

    let mut sum_t = 0.0;
    for i in 0..nt {
        let p1 = hp1.trans[i];
        let p2 = hp2.trans[i];
        sum_t += (p1 - p2).abs();
    }
    let mean_trans_delta = sum_t / nt as f32;

    let mut sum_e = 0.0;
    for i in 0..alpha_size {
        for j in 0..alpha_size {
            let p1 = hp1.emits[i][j];
            let p2 = hp2.emits[i][j];
            sum_e += (p1 - p2).abs();
        }
    }
    let mean_emit_delta = sum_e / (alpha_size * alpha_size) as f32;
    (mean_trans_delta, mean_emit_delta)
}

#[track_caller]
pub fn run1(iter: uint, nucleo: bool) -> String {
    let hp_def = hmm_params_from_defaults(nucleo);

    let mut hp = hmm_params_from_defaults(nucleo);
    hmm_params_perturb_probs(&mut hp, iter);

    let (mean_trans_delta, mean_emit_delta) = hmm_params_compare(&hp_def, &hp);

    progress_log(&format!(
        "Iter {iter}, trans {mean_trans_delta:8.6}, emit {mean_emit_delta:8.6}\n"
    ))
}

#[track_caller]
pub fn cmd_perturbhmm(iters: uint, nucleo: bool) -> String {
    let mut out = String::new();
    for iter in 0..iters {
        out.push_str(&run1(iter, nucleo));
    }
    out
}

#[track_caller]
pub fn read_strings_from_file(file_name: &str) -> Vec<String> {
    let bytes = std::fs::read(file_name).unwrap();
    let mut strings = Vec::new();
    let mut line = String::new();
    for b in bytes {
        if b == b'\r' {
            continue;
        }
        if b == b'\n' {
            strings.push(line);
            line = String::new();
        } else {
            line.push(b as char);
        }
    }
    if !line.is_empty() {
        strings.push(line);
    }
    strings
}

pub fn invert_path(path: &str) -> String {
    let mut inverted_path = String::new();
    for c in path.bytes() {
        if c == b'B' {
            inverted_path.push('B');
        } else if c == b'X' {
            inverted_path.push('Y');
        } else if c == b'Y' {
            inverted_path.push('X');
        } else {
            panic!("Invalid path char '{}'", c as char);
        }
    }
    inverted_path
}

pub fn validate_path(path: &str, lx: uint, ly: uint) {
    let mut nx = 0;
    let mut ny = 0;
    for c in path.bytes() {
        match c.to_ascii_uppercase() {
            b'X' => nx += 1,
            b'Y' => ny += 1,
            b'B' => {
                nx += 1;
                ny += 1;
            }
            _ => panic!("invalid path char"),
        }
    }
    assert_eq!(nx, lx);
    assert_eq!(ny, ly);
}

#[track_caller]
pub fn align_ms_as_by_path(
    msa1: &MultiSequence,
    msa2: &MultiSequence,
    path: &str,
    msa12: &mut MultiSequence,
) {
    let lx = multi_sequence_get_col_count(msa1);
    let ly = multi_sequence_get_col_count(msa2);
    validate_path(path, lx, ly);
    let seq_count1 = msa1.seqs.len();
    let seq_count2 = msa2.seqs.len();

    for seq_index in 0..seq_count1 {
        let seq1 = &msa1.seqs[seq_index];
        let aligned_seq1 = sequence_add_gaps_path(seq1, path, 'X');
        msa12.seqs.push(aligned_seq1);
        msa12.owners.push(true);
    }

    for seq_index in 0..seq_count2 {
        let seq2 = &msa2.seqs[seq_index];
        let aligned_seq2 = sequence_add_gaps_path(seq2, path, 'Y');
        msa12.seqs.push(aligned_seq2);
        msa12.owners.push(true);
    }
}

#[track_caller]
pub fn p_prog_delete_indexes_from_pending(pp: &mut PProg, index1: uint, index2: uint) {
    let mut found1 = false;
    let mut found2 = false;
    let mut new_pending = Vec::new();
    for i in 0..pp.pending.len() {
        let index = pp.pending[i];
        if index == index1 {
            assert!(!found1);
            found1 = true;
            continue;
        }
        if index == index2 {
            assert!(!found2);
            found2 = true;
            continue;
        }
        new_pending.push(index);
    }
    assert!(found1);
    assert!(found2);
    assert_eq!(new_pending.len() + 2, pp.pending.len());
    pp.pending = new_pending;
}

#[track_caller]
pub fn p_prog_find_best_pair(pp: &PProg) -> (uint, uint) {
    let n = pp.pending.len();
    assert!(n >= 2);
    let mut best_index1 = pp.pending[0];
    let mut best_index2 = pp.pending[1];
    assert!(best_index1 < pp.node_count);
    assert!(best_index2 < pp.node_count);
    let mut best_score = pp.score_mx[best_index1 as usize][best_index2 as usize];
    for i in 0..n {
        let indexi = pp.pending[i];
        for j in i + 1..n {
            let indexj = pp.pending[j];
            assert!((indexi as usize) < pp.score_mx.len());
            assert!((indexj as usize) < pp.score_mx[indexi as usize].len());
            let score = pp.score_mx[indexi as usize][indexj as usize];
            if score > best_score {
                best_score = score;
                best_index1 = indexi;
                best_index2 = indexj;
            }
        }
    }
    (best_index1, best_index2)
}

#[track_caller]
pub fn p_prog_get_msa_label(pp: &PProg, index: uint) -> &str {
    assert!((index as usize) < pp.msa_labels.len());
    let label = &pp.msa_labels[index as usize];
    assert!(!label.is_empty());
    label
}

#[track_caller]
pub fn p_prog_set_msa(pp: &mut PProg, index: uint, msa: &MultiSequence) {
    assert!((index as usize) < pp.msas.len());
    pp.msas[index as usize] = Some(msa.clone());
}

#[track_caller]
pub fn p_prog_set_msa_label(pp: &mut PProg, index: uint, label: &str) {
    assert!((index as usize) < pp.msa_labels.len());
    assert!(pp.msa_labels[index as usize].is_empty());
    pp.msa_labels[index as usize] = label.to_string();
    assert!(!pp.msa_label_to_index.contains_key(label));
    pp.msa_label_to_index.insert(label.to_string(), index);
}

#[track_caller]
pub fn p_prog_get_msa(pp: &PProg, index: uint) -> &MultiSequence {
    assert!((index as usize) < pp.msas.len());
    pp.msas[index as usize]
        .as_ref()
        .expect("PProg::GetMSA null MSA")
}

#[track_caller]
pub fn p_prog_get_final_msa(pp: &PProg) -> &MultiSequence {
    assert!(pp.input_msa_count > 0);
    let final_index = 2 * (pp.input_msa_count - 1);
    assert_eq!(final_index + 1, pp.msas.len() as uint);
    pp.msas[final_index as usize]
        .as_ref()
        .expect("PProg::GetFinalMSA null final MSA")
}

#[track_caller]
pub fn p_prog_set_ms_as(pp: &mut PProg, msas: &[MultiSequence], msa_labels: &[String]) {
    pp.msa_label_to_index.clear();
    pp.input_msa_count = msas.len() as uint;
    assert_eq!(msa_labels.len() as uint, pp.input_msa_count);
    pp.msas = msas.iter().cloned().map(Some).collect();
    pp.msa_labels = msa_labels.to_vec();

    let total_msa_count = 2 * pp.input_msa_count - 1;
    pp.msas.resize(total_msa_count as usize, None);
    pp.msa_labels
        .resize(total_msa_count as usize, String::new());

    for msa_index in 0..pp.input_msa_count {
        let msa_label = &msa_labels[msa_index as usize];
        assert!(!pp.msa_label_to_index.contains_key(msa_label));
        pp.msa_label_to_index.insert(msa_label.clone(), msa_index);
    }
}

#[track_caller]
pub fn p_prog_load_ms_as(pp: &mut PProg, file_names: &[String]) -> bool {
    pp.msa_label_to_index.clear();
    pp.msas.clear();
    pp.msa_labels.clear();

    pp.input_msa_count = file_names.len() as uint;
    assert!(pp.input_msa_count > 1);

    let total_msa_count = 2 * pp.input_msa_count - 1;
    pp.msas.resize(total_msa_count as usize, None);
    pp.msa_labels
        .resize(total_msa_count as usize, String::new());

    pp.join_count = pp.input_msa_count - 1;
    pp.node_count = pp.input_msa_count + pp.join_count;

    let mut is_nucleo = false;
    let mut global_input = MultiSequence::default();
    for msa_index in 0..pp.input_msa_count {
        let file_name = &file_names[msa_index as usize];
        let mut msa = MultiSequence::default();
        multi_sequence_load_mfa_l8(&mut msa, file_name, false);
        let is_nuc = multi_sequence_guess_is_nucleo(&msa);
        if msa_index == 0 {
            is_nucleo = is_nuc;
        } else {
            assert_eq!(is_nucleo, is_nuc);
        }

        let msa_label = get_base_name(file_name);
        p_prog_set_msa_label(pp, msa_index, &msa_label);
        for seq in &msa.seqs {
            let ungapped = sequence_copy_delete_gaps(&sequence_get_seq_as_string(seq));
            let mut global_seq = Sequence::default();
            sequence_from_string(&mut global_seq, &seq.label, &ungapped);
            global_input.seqs.push(global_seq);
            global_input.owners.push(false);
        }
        p_prog_set_msa(pp, msa_index, &msa);
    }
    set_global_input_ms(&global_input);
    is_nucleo
}

#[track_caller]
pub fn p_prog_run<FAlignMSAsFlat>(pp: &mut PProg, mut align_msas_flat: FAlignMSAsFlat)
where
    FAlignMSAsFlat: FnMut(&str, &MultiSequence, &MultiSequence, uint, &mut String) -> f32,
{
    pp.join_msa_indexes1.clear();
    pp.join_msa_indexes2.clear();
    pp.score_mx.clear();
    pp.path_mx.clear();

    pp.pending.clear();
    for i in 0..pp.input_msa_count {
        pp.pending.push(i);
    }

    pp.join_count = pp.input_msa_count - 1;
    pp.node_count = pp.input_msa_count + pp.join_count;
    p_prog_align_all_input_pairs(pp, |label, msa1, msa2, target_pair_count, path| {
        align_msas_flat(label, msa1, msa2, target_pair_count, path)
    });

    pp.join_index = 0;
    while pp.join_index < pp.join_count {
        let (index1, index2) = p_prog_find_best_pair(pp);
        assert_ne!(index1, index2);
        p_prog_join_by_precomputed_path(pp, index1, index2);
        p_prog_align_new_to_pending(pp, |label, msa1, msa2, target_pair_count, path| {
            align_msas_flat(label, msa1, msa2, target_pair_count, path)
        });
        pp.join_index += 1;
    }
}

#[track_caller]
pub fn p_prog_align_all_input_pairs<FAlignMSAsFlat>(
    pp: &mut PProg,
    mut align_msas_flat: FAlignMSAsFlat,
) where
    FAlignMSAsFlat: FnMut(&str, &MultiSequence, &MultiSequence, uint, &mut String) -> f32,
{
    let _pair_count = (pp.input_msa_count * (pp.input_msa_count - 1)) / 2;
    pp.score_mx = vec![vec![0.0; pp.node_count as usize]; pp.node_count as usize];
    pp.path_mx = vec![vec![String::new(); pp.node_count as usize]; pp.node_count as usize];

    for msa_index1 in 0..pp.input_msa_count {
        let msa_label1 = p_prog_get_msa_label(pp, msa_index1).to_string();
        let msa1 = p_prog_get_msa(pp, msa_index1).clone();
        for msa_index2 in msa_index1 + 1..pp.input_msa_count {
            let msa_label2 = p_prog_get_msa_label(pp, msa_index2).to_string();
            let msa2 = p_prog_get_msa(pp, msa_index2).clone();
            let mut path = String::new();
            let score = align_msas_flat(
                &format!("{msa_label1}+{msa_label2}"),
                &msa1,
                &msa2,
                pp.target_pair_count,
                &mut path,
            );

            let col_count1 = multi_sequence_get_col_count(&msa1);
            let col_count2 = multi_sequence_get_col_count(&msa2);
            validate_path(&path, col_count1, col_count2);
            let inverted_path = invert_path(&path);
            validate_path(&inverted_path, col_count2, col_count1);

            pp.score_mx[msa_index1 as usize][msa_index2 as usize] = score;
            pp.score_mx[msa_index2 as usize][msa_index1 as usize] = score;
            pp.path_mx[msa_index1 as usize][msa_index2 as usize] = path;
            pp.path_mx[msa_index2 as usize][msa_index1 as usize] = inverted_path;
        }
    }
}

#[track_caller]
pub fn p_prog_log_pending(pp: &PProg, s: &str) -> String {
    let mut out = String::new();
    out.push_str(&format!(
        "\nLogPending({s}) m_JoinIndex={}\n",
        pp.join_index
    ));
    for i in 0..pp.pending.len() {
        let index = pp.pending[i];
        let msa = p_prog_get_msa(pp, index);
        let seq_count = msa.seqs.len() as uint;
        let col_count = multi_sequence_get_col_count(msa);
        out.push_str(&format!(
            "  [{index:4}]  seqs={seq_count},cols={col_count} {}\n",
            p_prog_get_msa_label(pp, index)
        ));
    }
    out
}

#[track_caller]
pub fn p_prog_join_by_precomputed_path(pp: &mut PProg, index1: uint, index2: uint) {
    assert_eq!(pp.join_msa_indexes1.len() as uint, pp.join_index);
    assert_eq!(pp.join_msa_indexes2.len() as uint, pp.join_index);
    pp.join_msa_indexes1.push(index1);
    pp.join_msa_indexes2.push(index2);

    let new_msa_index = pp.input_msa_count + pp.join_index;
    let new_msa_label = format!("Join{}", pp.join_index + 1);

    let msa1 = p_prog_get_msa(pp, index1).clone();
    let msa2 = p_prog_get_msa(pp, index2).clone();
    let path = pp.path_mx[index1 as usize][index2 as usize].clone();
    let mut msa12 = MultiSequence::default();
    align_ms_as_by_path(&msa1, &msa2, &path, &mut msa12);

    p_prog_set_msa(pp, new_msa_index, &msa12);
    p_prog_set_msa_label(pp, new_msa_index, &new_msa_label);

    let _joined_seq_count = msa12.seqs.len() as uint;
    let _joined_col_count = multi_sequence_get_col_count(&msa12);

    pp.pending.push(new_msa_index);
    let pending_count_before_join = pp.pending.len();
    p_prog_delete_indexes_from_pending(pp, index1, index2);
    let pending_count_after_join = pp.pending.len();
    assert_eq!(pending_count_after_join + 2, pending_count_before_join);
}

#[track_caller]
pub fn p_prog_align_new_to_pending<FAlignMSAsFlat>(
    pp: &mut PProg,
    mut align_msas_flat: FAlignMSAsFlat,
) where
    FAlignMSAsFlat: FnMut(&str, &MultiSequence, &MultiSequence, uint, &mut String) -> f32,
{
    let pending_count = pp.pending.len();
    assert!(pending_count > 0);
    let new_index = pp.pending[pending_count - 1];

    let new_msa_label = pp.msa_labels[new_index as usize].clone();
    let new_msa = p_prog_get_msa(pp, new_index).clone();
    for i in 0..pending_count - 1 {
        let index = pp.pending[i];
        let msa = p_prog_get_msa(pp, index).clone();
        let msa_labeli = pp.msa_labels[i].clone();
        let mut path = String::new();
        let score = align_msas_flat(
            &format!("{new_msa_label}+{msa_labeli}"),
            &new_msa,
            &msa,
            pp.target_pair_count,
            &mut path,
        );

        let inverted_path = invert_path(&path);
        pp.score_mx[new_index as usize][index as usize] = score;
        pp.score_mx[index as usize][new_index as usize] = score;
        pp.path_mx[new_index as usize][index as usize] = path;
        pp.path_mx[index as usize][new_index as usize] = inverted_path;
    }
}

#[track_caller]
pub fn p_prog_write_guide_tree(pp: &PProg, file_name: &str) -> Option<Tree> {
    if file_name.is_empty() {
        return None;
    }
    let mut guide_tree = Tree::default();
    let label_to_index = pp
        .msa_label_to_index
        .iter()
        .map(|(k, v)| (k.clone(), *v))
        .collect::<std::collections::HashMap<_, _>>();
    make_guide_tree_from_join_order(
        &pp.join_msa_indexes1,
        &pp.join_msa_indexes2,
        &label_to_index,
        &mut guide_tree,
    );
    tree_to_file_l13(&guide_tree, file_name);
    Some(guide_tree)
}

#[track_caller]
pub fn cmd_pprog<FAlignMSAsFlat>(
    list_file_name: &str,
    output_file_name: &str,
    guide_tree_output_file_name: Option<&str>,
    target_pair_count: Option<uint>,
    mut align_msas_flat: FAlignMSAsFlat,
) -> (PProg, Option<Tree>)
where
    FAlignMSAsFlat: FnMut(&str, &MultiSequence, &MultiSequence, uint, &mut String) -> f32,
{
    let text = std::fs::read_to_string(list_file_name).expect("failed to read PProg file list");
    let msa_file_names = text
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .map(ToString::to_string)
        .collect::<Vec<_>>();
    assert!(msa_file_names.len() > 1);

    let mut pp = PProg {
        target_pair_count: 2000,
        ..PProg::default()
    };
    if let Some(pair_count) = target_pair_count {
        pp.target_pair_count = pair_count;
    }

    let _is_nucleo = p_prog_load_ms_as(&mut pp, &msa_file_names);
    set_alpha_l209(if _is_nucleo {
        ALPHA::ALPHA_Nucleo
    } else {
        ALPHA::ALPHA_Amino
    });
    init_probcons();
    p_prog_run(&mut pp, |label, msa1, msa2, pair_count, path| {
        align_msas_flat(label, msa1, msa2, pair_count, path)
    });

    assert_eq!(pp.pending.len(), 1);
    let _index = pp.pending[0];
    let final_msa = p_prog_get_final_msa(&pp).clone();
    msa_to_fasta_file_l103(&final_msa, output_file_name);
    let guide_tree =
        guide_tree_output_file_name.and_then(|file_name| p_prog_write_guide_tree(&pp, file_name));
    (pp, guide_tree)
}

#[track_caller]
pub fn p_prog_align_and_join<FAlignMSAsFlat>(
    pp: &mut PProg,
    index1: uint,
    index2: uint,
    mut align_msas_flat: FAlignMSAsFlat,
) where
    FAlignMSAsFlat: FnMut(&str, &MultiSequence, &MultiSequence, uint, &mut String) -> f32,
{
    pp.join_msa_indexes1.push(index1);
    pp.join_msa_indexes2.push(index2);

    let msa1 = p_prog_get_msa(pp, index1).clone();
    let msa2 = p_prog_get_msa(pp, index2).clone();
    let _msa_label1 = pp.msa_labels[index1 as usize].clone();
    let _msa_label2 = pp.msa_labels[index2 as usize].clone();
    let progress_str = format!("Join {} / {}", pp.join_index + 1, pp.join_count);

    let mut path = String::new();
    align_msas_flat(&progress_str, &msa1, &msa2, pp.target_pair_count, &mut path);

    let _msa_label12 = format!("Join_{}", pp.join_index + 1);
    let mut msa12 = MultiSequence::default();
    align_ms_as_by_path(&msa1, &msa2, &path, &mut msa12);

    if index1 >= pp.input_msa_count {
        pp.msas[index1 as usize] = None;
    }
    if index2 >= pp.input_msa_count {
        pp.msas[index2 as usize] = None;
    }

    let new_msa_index = pp.input_msa_count + pp.join_index;
    p_prog_set_msa(pp, new_msa_index, &msa12);
}

#[track_caller]
pub fn p_prog_run2<FAlignAndJoin>(
    pp: &mut PProg,
    indexes1: &[uint],
    indexes2: &[uint],
    mut align_and_join: FAlignAndJoin,
) where
    FAlignAndJoin: FnMut(&mut PProg, uint, uint),
{
    assert!(pp.input_msa_count > 0);
    pp.join_count = pp.input_msa_count - 1;
    pp.node_count = pp.input_msa_count + pp.join_count;

    assert_eq!(indexes1.len() as uint, pp.join_count);
    assert_eq!(indexes2.len() as uint, pp.join_count);
    validate_join_order(indexes1, indexes2);

    pp.join_index = 0;
    while pp.join_index < pp.join_count {
        let index1 = indexes1[pp.join_index as usize];
        let index2 = indexes2[pp.join_index as usize];
        align_and_join(pp, index1, index2);
        pp.join_index += 1;
    }
}

#[track_caller]
pub fn cmd_pprog2<FAlignMSAsFlat>(
    list_file_name: &str,
    joins_file_name: &str,
    output_file_name: &str,
    target_pair_count: Option<uint>,
    mut align_msas_flat: FAlignMSAsFlat,
) -> PProg
where
    FAlignMSAsFlat: FnMut(&str, &MultiSequence, &MultiSequence, uint, &mut String) -> f32,
{
    let text = std::fs::read_to_string(list_file_name).expect("failed to read PProg2 file list");
    let msa_file_names = text
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .map(ToString::to_string)
        .collect::<Vec<_>>();
    assert!(msa_file_names.len() > 1);

    let mut pp = PProg {
        target_pair_count: 2000,
        ..PProg::default()
    };
    if let Some(pair_count) = target_pair_count {
        pp.target_pair_count = pair_count;
    }

    let _is_nucleo = p_prog_load_ms_as(&mut pp, &msa_file_names);
    set_alpha_l209(if _is_nucleo {
        ALPHA::ALPHA_Nucleo
    } else {
        ALPHA::ALPHA_Amino
    });
    init_probcons();

    let joins_text = std::fs::read_to_string(joins_file_name).expect("failed to read joins file");
    let mut indexes1 = Vec::new();
    let mut indexes2 = Vec::new();
    for line in joins_text
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
    {
        let fields = split(line, '\t');
        assert_eq!(fields.len(), 2);
        indexes1.push(str_to_uint_l1278(&fields[0], false));
        indexes2.push(str_to_uint_l1278(&fields[1], false));
    }

    p_prog_run2(&mut pp, &indexes1, &indexes2, |pp, index1, index2| {
        p_prog_align_and_join(pp, index1, index2, |label, msa1, msa2, pair_count, path| {
            align_msas_flat(label, msa1, msa2, pair_count, path)
        });
    });

    let final_msa = p_prog_get_final_msa(&pp).clone();
    msa_to_fasta_file_l103(&final_msa, output_file_name);
    pp
}

#[track_caller]
pub fn p_prog3_run<FNwSmall3, FAlignTwoProfsGivenPath>(
    pp: &mut PProg3,
    input_seqs: &MultiSequence,
    input_seq_weights: &[f32],
    guide_tree: &Tree,
    mut nw_small3: FNwSmall3,
    mut align_two_profs_given_path: FAlignTwoProfsGivenPath,
) where
    FNwSmall3: FnMut(&mut CacheMem3, &Profile3, &Profile3) -> String,
    FAlignTwoProfsGivenPath:
        FnMut(&Profile3, f32, &Profile3, f32, &[[f32; 20]; 20], f32, &str) -> Profile3,
{
    let ap = pp.ap.as_ref().expect("PProg3::Run no alignment params");
    let subst_mx_letter = ap.subst_mx_letter;
    let gap_open = ap.gap_open;
    pp.input_seqs = Some(input_seqs.clone());
    pp.input_seq_weights = input_seq_weights.to_vec();
    pp.guide_tree = Some(guide_tree.clone());
    assert!(guide_tree.rooted);
    let seq_count = input_seqs.seqs.len() as uint;
    let leaf_count = (guide_tree.node_count + 1) / 2;
    assert_eq!(leaf_count, seq_count);
    assert_eq!(input_seq_weights.len() as uint, seq_count);

    let node_count = guide_tree.node_count;
    pp.node_to_profile = vec![None; node_count as usize];
    pp.node_to_sum_input_weights = vec![f32::MAX; node_count as usize];
    pp.node_to_path = vec![String::new(); node_count as usize];

    let mut weights1 = vec![f32::MAX; 1];
    let mut node = tree_first_depth_first_node(guide_tree);
    loop {
        pp.node_to_profile[node as usize] = None;
        let i = node as usize;
        let is_leaf = guide_tree.node_count == 1
            || (guide_tree.neighbor2[i] == NULL_NEIGHBOR
                && guide_tree.neighbor3[i] == NULL_NEIGHBOR);
        if is_leaf {
            let seq_index = tree_get_leaf_id(guide_tree, node);
            let seq = input_seqs.seqs[seq_index as usize].clone();
            let mut msa1 = MultiSequence::default();
            msa1.seqs.push(seq);
            msa1.owners.push(false);
            let weight = input_seq_weights[seq_index as usize];
            pp.node_to_sum_input_weights[node as usize] = weight;

            weights1[0] = 1.0;
            let mut prof = Profile3::default();
            profile3_from_msa(&mut prof, &msa1, &subst_mx_letter, gap_open, &weights1);
            pp.node_to_profile[node as usize] = Some(prof);
        } else {
            let left = guide_tree.neighbor2[i];
            let right = guide_tree.neighbor3[i];
            assert!(left < node_count && right < node_count);

            let sum_input_weights_left = pp.node_to_sum_input_weights[left as usize];
            let sum_input_weights_right = pp.node_to_sum_input_weights[right as usize];
            assert!(sum_input_weights_left != f32::MAX);
            assert!(sum_input_weights_right != f32::MAX);
            pp.node_to_sum_input_weights[node as usize] =
                sum_input_weights_left + sum_input_weights_right;

            let prof_left = pp.node_to_profile[left as usize]
                .take()
                .expect("PProg3::Run missing left profile");
            let prof_right = pp.node_to_profile[right as usize]
                .take()
                .expect("PProg3::Run missing right profile");

            let path = nw_small3(&mut pp.cm, &prof_left, &prof_right);
            pp.node_to_path[node as usize] = path.clone();

            if node != guide_tree.root_node_index {
                let prof = align_two_profs_given_path(
                    &prof_left,
                    sum_input_weights_left,
                    &prof_right,
                    sum_input_weights_right,
                    &subst_mx_letter,
                    gap_open,
                    &path,
                );
                pp.node_to_profile[node as usize] = Some(prof);
            }
        }

        node = tree_next_depth_first_node(guide_tree, node);
        if node == uint::MAX {
            break;
        }
    }
    p_prog3_build_msa(pp);
}

#[track_caller]
pub fn p_prog3_build_msa(pp: &mut PProg3) {
    let guide_tree = pp
        .guide_tree
        .as_ref()
        .expect("PProg3::BuildMSA no guide tree");
    let node_count = guide_tree.node_count;
    let leaf_count = ((guide_tree.node_count + 1) / 2) as usize;
    multi_sequence_clear(&mut pp.msa);

    for node in 0..node_count {
        let i = node as usize;
        let is_leaf = guide_tree.node_count == 1
            || (guide_tree.neighbor2[i] == NULL_NEIGHBOR
                && guide_tree.neighbor3[i] == NULL_NEIGHBOR);
        if !is_leaf {
            continue;
        }
        let seq = p_prog3_get_aligned_seq(pp, node);
        pp.msa.seqs.push(seq);
        pp.msa.owners.push(true);
    }
    assert_eq!(pp.msa.seqs.len(), leaf_count);
}

#[track_caller]
pub fn p_prog3_get_aligned_seq(pp: &PProg3, leaf_node: uint) -> Sequence {
    let guide_tree = pp
        .guide_tree
        .as_ref()
        .expect("PProg3::GetAlignedSeq no guide tree");
    let leaf_i = leaf_node as usize;
    assert!(
        guide_tree.node_count == 1
            || (guide_tree.neighbor2[leaf_i] == NULL_NEIGHBOR
                && guide_tree.neighbor3[leaf_i] == NULL_NEIGHBOR)
    );
    let input_seq_index = tree_get_leaf_id(guide_tree, leaf_node);
    let input_seqs = pp
        .input_seqs
        .as_ref()
        .expect("PProg3::GetAlignedSeq no input seqs");
    let mut seq = input_seqs.seqs[input_seq_index as usize].clone();

    let path_to_root = tree_get_path_to_root(guide_tree, leaf_node);
    let n = path_to_root.len();
    for i in 0..n.saturating_sub(1) {
        let path_node = path_to_root[i];
        let parent = guide_tree.neighbor1[path_node as usize];
        let parent_left = guide_tree.neighbor2[parent as usize];
        let parent_right = guide_tree.neighbor3[parent as usize];
        let dor_i = if parent_right == path_node {
            'I'
        } else if parent_left == path_node {
            'D'
        } else {
            panic!("PProg3::GetAlignedSeq invalid parent/child relation");
        };
        assert!((parent as usize) < pp.node_to_path.len());
        let alignment_path = &pp.node_to_path[parent as usize];
        seq = sequence_add_gaps_path(&seq, alignment_path, dor_i);
    }
    seq
}

