#[track_caller]
pub fn q_scorer_cmp_ref_ms_as(
    qs: &mut QScorer,
    name: &str,
    test: &MultiSequence,
    ref_msa: &MultiSequence,
    by_sequence: bool,
) {
    q_scorer_clear(qs);

    qs.name = name.to_string();
    qs.test = Some(test.clone());
    qs.ref_msa = Some(ref_msa.clone());

    let test_col_count = multi_sequence_get_col_count(test);

    if by_sequence {
        q_scorer_init_ref_labels_bysequence(qs);
        q_scorer_init_ref_to_test_bysequence(qs);
    } else {
        q_scorer_init_ref_labels(qs);
        q_scorer_init_ref_to_test(qs);
    }
    q_scorer_init_col_pos_vecs(qs);
    q_scorer_set_test_col_is_aligned(qs);
    q_scorer_set_ref_col_is_aligned(qs);

    let n = qs.ref_seq_indexes.len();
    assert_eq!(qs.test_seq_indexes.len(), n);
    if n == 0 {
        panic!("No matched sequences/labels {name}");
    }

    let mut ref_col_to_count = std::collections::BTreeMap::<uint, uint>::new();
    qs.ref_msas_compared_col_count = 0;
    let mut sum_col_q = 0.0;
    for test_col in 0..test_col_count {
        if !qs.test_col_is_aligned[test_col as usize] {
            continue;
        }
        let mut m = 0;
        let mut best_n = 0;
        let mut best_ref_col = uint::MAX;
        for i in 0..n {
            let test_pos = qs.test_col_to_pos_vec[i][test_col as usize];
            if test_pos == uint::MAX {
                continue;
            }
            m += 1;
            let ref_col = qs.pos_to_ref_col_vec[i][test_pos as usize];
            if !qs.ref_col_is_aligned[ref_col as usize] {
                continue;
            }
            let n_col = if let Some(old_n) = ref_col_to_count.get(&ref_col).copied() {
                let new_n = old_n + 1;
                ref_col_to_count.insert(ref_col, new_n);
                new_n
            } else {
                ref_col_to_count.insert(ref_col, 1);
                1
            };
            if n_col > best_n {
                best_ref_col = ref_col;
                best_n = n_col;
            }
        }
        if best_ref_col == uint::MAX || m < 2 {
            continue;
        }
        assert!(m > 0);
        qs.ref_msas_compared_col_count += 1;
        let col_q = (best_n as f64) / (m as f64);
        qs.ref_msas_col_qs.push(col_q);
        qs.ref_msas_test_cols.push(test_col);
        qs.ref_msas_ref_cols.push(best_ref_col);
        sum_col_q += col_q;
    }
    qs.ref_msas_q = -1.0;
    if qs.ref_msas_compared_col_count > 0 {
        qs.ref_msas_q = sum_col_q / (qs.ref_msas_compared_col_count as f64);
    }
}

pub fn q_scorer2_strip_gaps(row: &str) -> String {
    let mut seq = String::new();
    for c in row.bytes() {
        if c != b'-' && c != b'.' {
            seq.push(char::from(c));
        }
    }
    seq
}

#[track_caller]
pub fn q_scorer2_get_pos_to_col(row: &str) -> Vec<uint> {
    let mut pos_to_col = Vec::new();
    for (col, c) in row.bytes().enumerate() {
        if c != b'-' && c != b'.' {
            pos_to_col.push(col as uint);
        }
    }
    pos_to_col
}

#[track_caller]
pub fn q_scorer2_get_q(t1: &str, t2: &str, r1: &str, r2: &str) -> f64 {
    let nt = t1.len();
    assert_eq!(t2.len(), nt);
    let nr = r1.len();
    assert_eq!(r2.len(), nr);

    assert_eq!(q_scorer2_strip_gaps(t1), q_scorer2_strip_gaps(r1));
    assert_eq!(q_scorer2_strip_gaps(t2), q_scorer2_strip_gaps(r2));

    let pos_to_col_t1 = q_scorer2_get_pos_to_col(t1);
    let pos_to_col_t2 = q_scorer2_get_pos_to_col(t2);

    let t1_bytes = t1.as_bytes();
    let t2_bytes = t2.as_bytes();
    let r1_bytes = r1.as_bytes();
    let r2_bytes = r2.as_bytes();
    let mut ref_pos1 = 0usize;
    let mut ref_pos2 = 0usize;
    let mut ref_aligned_count = 0_u32;
    let mut correct_count = 0_u32;
    for ref_col in 0..nr {
        let rc1 = r1_bytes[ref_col];
        let rc2 = r2_bytes[ref_col];
        let gap1 = rc1 == b'-' || rc1 == b'.';
        let gap2 = rc2 == b'-' || rc2 == b'.';
        if !gap1 && !gap2 {
            assert!(ref_pos1 < pos_to_col_t1.len());
            assert!(ref_pos2 < pos_to_col_t2.len());
            let test_col1 = pos_to_col_t1[ref_pos1] as usize;
            let test_col2 = pos_to_col_t2[ref_pos2] as usize;
            let tc1 = t1_bytes[test_col1];
            let tc2 = t2_bytes[test_col2];
            assert_eq!(rc1.to_ascii_uppercase(), tc1.to_ascii_uppercase());
            assert_eq!(rc2.to_ascii_uppercase(), tc2.to_ascii_uppercase());
            ref_aligned_count += 1;
            if test_col1 == test_col2 {
                correct_count += 1;
            }
        }
        if !gap1 {
            ref_pos1 += 1;
        }
        if !gap2 {
            ref_pos2 += 1;
        }
    }
    correct_count as f64 / ref_aligned_count as f64
}

#[track_caller]
pub fn q_scorer2_run_l91(test: &MultiSequence, ref_ms: &MultiSequence) -> f64 {
    q_scorer2_run_l100(test, ref_ms)
}

#[track_caller]
pub fn q_scorer2_run_l100(test: &MultiSequence, ref_ms: &MultiSequence) -> f64 {
    let mut test_label_to_seq_index = std::collections::BTreeMap::new();
    for (seq_index, seq) in test.seqs.iter().enumerate() {
        test_label_to_seq_index.insert(seq.label.clone(), seq_index as uint);
    }

    let ref_seq_count = ref_ms.seqs.len() as uint;
    assert_eq!(ref_seq_count % 2, 0);
    let ref_pair_count = ref_seq_count / 2;
    let mut sum_q = 0.0_f64;
    for ref_pair_index in 0..ref_pair_count {
        let ref_seq_index1 = ref_pair_index * 2;
        let ref_seq_index2 = ref_seq_index1 + 1;
        let ref_seq1 = &ref_ms.seqs[ref_seq_index1 as usize];
        let ref_seq2 = &ref_ms.seqs[ref_seq_index2 as usize];
        let label1 = &ref_seq1.label;
        let label2 = &ref_seq2.label;
        let col_count = ref_seq1.char_vec.len();
        assert_eq!(ref_seq2.char_vec.len(), col_count);

        let test_seq_index1 = *test_label_to_seq_index
            .get(label1)
            .unwrap_or_else(|| panic!("test label not found: {label1}"));
        let test_seq_index2 = *test_label_to_seq_index
            .get(label2)
            .unwrap_or_else(|| panic!("test label not found: {label2}"));

        let test_row1 = sequence_get_seq_as_string(&test.seqs[test_seq_index1 as usize]);
        let test_row2 = sequence_get_seq_as_string(&test.seqs[test_seq_index2 as usize]);
        let ref_row1 = sequence_get_seq_as_string(ref_seq1);
        let ref_row2 = sequence_get_seq_as_string(ref_seq2);
        let q = q_scorer2_get_q(&test_row1, &test_row2, &ref_row1, &ref_row2);
        sum_q += q;
    }
    sum_q / ref_pair_count as f64
}

#[track_caller]
pub fn get_quarts(v: &[uint]) -> Quarts {
    let n = v.len();
    let mut q = Quarts::default();
    if n == 0 {
        return q;
    }
    let mut vs = v.to_vec();
    vs.sort_unstable();
    for x in &vs {
        q.total += *x;
    }
    q.min = vs[0];
    q.lo_q = vs[n / 4];
    q.med = vs[n / 2];
    q.hi_q = vs[(3 * n) / 4];
    q.max = vs[n - 1];
    q.avg = f64::from(q.total) / n as f64;
    q
}

#[track_caller]
pub fn get_quarts_float(v: &[f32]) -> QuartsFloat {
    let n = v.len();
    let mut q = QuartsFloat::default();
    if n == 0 {
        return q;
    }
    let mut vs = v.to_vec();
    vs.sort_by(|a, b| a.partial_cmp(b).unwrap());
    for x in &vs {
        q.total += *x;
    }
    let mean = q.total / n as f32;
    let mut sumd = 0.0;
    for x in &vs {
        let d = (*x - mean) * (*x - mean);
        sumd += d;
    }
    q.min = vs[0];
    q.lo_q = vs[n / 4];
    q.med = vs[n / 2];
    q.hi_q = vs[(3 * n) / 4];
    q.max = vs[n - 1];
    q.avg = mean;
    q.std_dev = (sumd / n as f32).sqrt();
    q
}

#[track_caller]
pub fn make_random_chain_tree(labels: &[String], t: &mut Tree) {
    let seq_count = labels.len();
    let mut seq_indexes: Vec<uint> = (0..seq_count as uint).collect();
    shuffle(&mut seq_indexes);

    let mut parents = vec![uint::MAX; 2 * seq_count - 1];
    let mut lengths = Vec::new();
    let mut node_labels = Vec::new();
    for seq_index in &seq_indexes {
        node_labels.push(labels[*seq_index as usize].clone());
        lengths.push(1.0);
    }

    for i in 0..seq_count.saturating_sub(1) {
        if i == 0 {
            let left = seq_indexes[0];
            let right = seq_indexes[1];
            parents[left as usize] = seq_count as uint;
            parents[right as usize] = seq_count as uint;
        } else {
            let left = seq_count as uint + i as uint - 1;
            let right = seq_indexes[i + 1];
            parents[left as usize] = seq_count as uint + i as uint;
            parents[right as usize] = seq_count as uint + i as uint;
        }
        node_labels.push(String::new());
        lengths.push(1.0);
    }

    tree_from_vectors(t, &node_labels, &parents, &lengths);
}

#[track_caller]
pub fn mpc_flat_calc_guide_tree_random_chain(mpc: &mut MPCFlat) {
    make_random_chain_tree(&mpc.labels, &mut mpc.guide_tree);
}

#[track_caller]
pub fn cmd_labels2randomchaintree(labels_file_name: &str, newick_file_name: &str) -> Tree {
    let labels = read_strings_from_file(labels_file_name);
    let mut t = Tree::default();
    make_random_chain_tree(&labels, &mut t);
    tree_to_file_l13(&t, newick_file_name);
    t
}

#[track_caller]
pub fn get_random_dist_mx(seq_count: uint) -> Vec<Vec<f32>> {
    let mut dist_mx = vec![vec![0.0_f32; seq_count as usize]; seq_count as usize];
    for i in 0..seq_count as usize {
        dist_mx[i][i] = 0.0;
        for j in 0..i {
            let d = (randu32() % 100) as f32 / 100.0 + 0.001;
            dist_mx[i][j] = d;
            dist_mx[j][i] = d;
        }
    }
    dist_mx
}

#[track_caller]
pub fn mpc_flat_refine_iter<FRand, FAlignAlns>(
    mpc: &mut MPCFlat,
    mut rand_value: FRand,
    mut align_alns: FAlignAlns,
) where
    FRand: FnMut() -> uint,
    FAlignAlns: FnMut(&mut MPCFlat, &MultiSequence, &MultiSequence) -> MultiSequence,
{
    let mut seq_indexes1 = std::collections::BTreeSet::new();
    let mut seq_indexes2 = std::collections::BTreeSet::new();

    let seq_count = mpc_flat_get_seq_count(mpc);
    let msa = mpc.msa.as_ref().expect("MPCFlat::RefineIter, no MSA");
    assert_eq!(msa.seqs.len() as uint, seq_count);

    for seq_index in 0..seq_count {
        if rand_value() % 2 == 0 {
            seq_indexes1.insert(seq_index as i32);
        } else {
            seq_indexes2.insert(seq_index as i32);
        }
    }

    if seq_indexes1.is_empty() || seq_indexes2.is_empty() {
        return;
    }

    let msa1 = multi_sequence_project_l16(msa, &seq_indexes1);
    let msa2 = multi_sequence_project_l16(msa, &seq_indexes2);
    let msa12 = align_alns(mpc, &msa1, &msa2);
    mpc.msa = Some(msa12);
}

#[track_caller]
pub fn cmd_relabel(
    input_file_name: &str,
    labels2_file_name: &str,
    output_file_name: &str,
) -> String {
    let mut m = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut m, input_file_name, false);

    let labels_text = std::fs::read_to_string(labels2_file_name).expect("failed to read labels2");
    let mut old_label_to_new_label = std::collections::BTreeMap::<String, String>::new();
    let mut _label_count = 0_u32;
    for line in labels_text.lines() {
        let fields = split(line, '\t');
        if fields.len() != 2 {
            panic!("Expected 2 fields in line '{}'", line);
        }
        let old_label = fields[0].clone();
        let new_label = fields[1].clone();
        if old_label_to_new_label.contains_key(&old_label) {
            panic!("Dupe label >{}", old_label);
        }
        old_label_to_new_label.insert(old_label, new_label);
        _label_count += 1;
    }

    let mut _not_found = 0_u32;
    let mut _found = 0_u32;
    let mut out = String::new();
    for seq in &m.seqs {
        if let Some(new_label) = old_label_to_new_label.get(&seq.label) {
            out.push_str(&seq_to_fasta_l2561(
                &sequence_get_seq_as_string(seq),
                new_label,
            ));
            _found += 1;
        } else {
            out.push_str(&seq_to_fasta_l2561(
                &sequence_get_seq_as_string(seq),
                &seq.label,
            ));
            _not_found += 1;
        }
    }

    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, &out).expect("failed to write relabel output");
    }
    out
}

#[track_caller]
pub fn relax_flat_xz_zy(xz: &MySparseMx, zy: &MySparseMx, weight_z: f32, post: &mut [f32]) {
    let lx = xz.lx;
    let lz = xz.ly;
    let ly = zy.ly;
    assert_eq!(zy.lx, lz);
    assert!(post.len() >= (lx * ly) as usize);

    for pos_x in 0..lx {
        let offset_xz = my_sparse_mx_get_offset(xz, pos_x);
        let size_xz = my_sparse_mx_get_size(xz, pos_x);
        for k in 0..size_xz {
            let (p_xz, pos_z) = xz.value_vec[(offset_xz + k) as usize];

            let offset_zy = my_sparse_mx_get_offset(zy, pos_z);
            let size_zy = my_sparse_mx_get_size(zy, pos_z);
            for m in 0..size_zy {
                let (p_zy, pos_y) = zy.value_vec[(offset_zy + m) as usize];
                post[(pos_x * ly + pos_y) as usize] += weight_z * p_xz * p_zy;
            }
        }
    }
}

#[track_caller]
pub fn relax_flat_zx_zy(zx: &MySparseMx, zy: &MySparseMx, weight_z: f32, post: &mut [f32]) {
    let lz = zx.lx;
    let lx = zx.ly;
    let ly = zy.ly;
    assert_eq!(zy.lx, lz);
    assert!(post.len() >= (lx * ly) as usize);

    for pos_z in 0..lz {
        let offset_zx = my_sparse_mx_get_offset(zx, pos_z);
        let size_zx = my_sparse_mx_get_size(zx, pos_z);
        for k in 0..size_zx {
            let (p_zx, pos_x) = zx.value_vec[(offset_zx + k) as usize];

            let offset_zy = my_sparse_mx_get_offset(zy, pos_z);
            let size_zy = my_sparse_mx_get_size(zy, pos_z);
            for m in 0..size_zy {
                let (p_zy, pos_y) = zy.value_vec[(offset_zy + m) as usize];
                post[(pos_x * ly + pos_y) as usize] += weight_z * p_zx * p_zy;
            }
        }
    }
}

#[track_caller]
pub fn relax_flat_xz_yz(xz: &MySparseMx, yz: &MySparseMx, weight_z: f32, post: &mut [f32]) {
    let lx = xz.lx;
    let lz = xz.ly;
    let ly = yz.lx;
    assert_eq!(yz.ly, lz);
    assert!(post.len() >= (lx * ly) as usize);

    let (pos_z_to_lo_pos_y, pos_z_to_hi_pos_y) = my_sparse_mx_get_col_to_row_lo_hi(yz);

    for pos_x in 0..lx {
        let offset_xz = my_sparse_mx_get_offset(xz, pos_x);
        let size_xz = my_sparse_mx_get_size(xz, pos_x);
        for k in 0..size_xz {
            let (p_xz, pos_z) = xz.value_vec[(offset_xz + k) as usize];

            let lo_pos_y = pos_z_to_lo_pos_y[pos_z as usize];
            let hi_pos_y = pos_z_to_hi_pos_y[pos_z as usize];
            if lo_pos_y == uint::MAX {
                continue;
            }
            for pos_y in lo_pos_y..=hi_pos_y {
                let p_yz = my_sparse_mx_get_prob(yz, pos_y, pos_z);
                post[(pos_x * ly + pos_y) as usize] += weight_z * p_xz * p_yz;
            }
        }
    }
}

