pub fn sequence_add_gaps_path(seq: &Sequence, path: &str, id: char) -> Sequence {
    let mut ret = Sequence {
        label: seq.label.clone(),
        char_vec: Vec::new(),
    };
    let mut data_iter = seq.char_vec.iter();
    for c in path.chars() {
        if c == 'M' || c == 'B' || c == id {
            ret.char_vec.push(*data_iter.next().unwrap());
        } else {
            ret.char_vec.push('-');
        }
    }
    ret
}

