#[track_caller]
pub fn sweeper_spatter_iter<F>(s: &mut Sweeper, mut get_score: F) -> (bool, String)
where
    F: FnMut(&Sweeper, &[f32]) -> (f64, f64),
{
    let new_seed_indexes = sweeper_get_distinct_top_indexes(
        s,
        s.spatter_tries_per_iter,
        s.max_distinct_score_drop,
        s.min_distinct_param_dist,
    );
    assert!(!new_seed_indexes.is_empty());
    s.spatter_seed_indexes = new_seed_indexes;

    let best_score_start = s.best_score;
    let k_count = s.spatter_seed_indexes.len();
    assert!(k_count > 0);
    let mut k = 0usize;
    let mut fev = String::new();
    s.spatter_try = 0;
    while s.spatter_try < s.spatter_tries_per_iter {
        assert!(k < k_count);
        let index = s.spatter_seed_indexes[k];
        let values = s.param_values_vec[index as usize].clone();
        k %= k_count;

        let spattered_values = sweeper_get_spattered_values(s, &values, &s.spatter_deltas);
        let (q, tc) = get_score(s, &spattered_values);
        fev.push_str(&sweeper_run1(s, &spattered_values, q, tc));
        s.spatter_try += 1;
    }

    let best_score_end = s.best_score;
    let improved = best_score_end - best_score_start > 0.001;
    (improved, fev)
}

pub fn sweeper_get_params(s: &Sweeper, index: uint) -> &[f32] {
    assert!((index as usize) < s.param_values_vec.len());
    &s.param_values_vec[index as usize]
}

pub fn sweeper_get_param_dist(s: &Sweeper, index1: uint, index2: uint) -> f32 {
    let params1 = sweeper_get_params(s, index1);
    let params2 = sweeper_get_params(s, index2);
    let mut sum2 = 0.0;
    for param_index in 0..s.param_count as usize {
        let param1 = params1[param_index];
        let param2 = params2[param_index];
        let d = param1 - param2;
        sum2 += d * d;
    }
    sum2.sqrt()
}

pub fn sweeper_get_score_l552(s: &Sweeper, index: uint) -> f32 {
    assert!((index as usize) < s.scores.len());
    s.scores[index as usize]
}

pub fn sweeper_get_q(s: &Sweeper, index: uint) -> f32 {
    assert!((index as usize) < s.qs.len());
    s.qs[index as usize]
}

pub fn sweeper_get_tc(s: &Sweeper, index: uint) -> f32 {
    assert!((index as usize) < s.tcs.len());
    s.tcs[index as usize]
}

pub fn sweeper_get_score_diff(s: &Sweeper, index1: uint, index2: uint) -> f32 {
    let score1 = sweeper_get_score_l552(s, index1);
    let score2 = sweeper_get_score_l552(s, index2);
    score1 - score2
}

pub fn sweeper_get_score_dist(s: &Sweeper, index1: uint, index2: uint) -> f32 {
    let diff = sweeper_get_score_diff(s, index1, index2);
    diff.abs()
}

#[track_caller]
pub fn sweeper_get_cloud(
    s: &Sweeper,
    index: uint,
    max_size: uint,
    max_score_dist: f32,
    max_param_dist: f32,
) -> Vec<uint> {
    let mut indexes = Vec::new();
    let n = s.param_values_vec.len();
    let mut tmp_indexes = Vec::new();
    let mut score_diffs = Vec::new();
    for index2 in 0..n as uint {
        if index2 == index {
            continue;
        }
        let score_diff = sweeper_get_score_diff(s, index, index2);
        if score_diff.abs() > max_score_dist {
            continue;
        }
        let param_dist = sweeper_get_param_dist(s, index, index2);
        if param_dist > max_param_dist {
            continue;
        }
        tmp_indexes.push(index2);
        score_diffs.push(score_diff);
    }
    let m = tmp_indexes.len();
    if m == 0 {
        return indexes;
    }
    let mut order: Vec<uint> = (0..m as uint).collect();
    order.sort_by(|a, b| {
        score_diffs[*a as usize]
            .partial_cmp(&score_diffs[*b as usize])
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    for i in 0..std::cmp::min(m, max_size as usize) {
        indexes.push(tmp_indexes[order[i] as usize]);
    }
    indexes
}

#[track_caller]
pub fn on_path_l18<F>(
    pos_a: uint,
    pos_b: uint,
    path: &str,
    fwd_m: &mut [Vec<f32>],
    best_pos_a: &mut uint,
    best_pos_b: &mut uint,
    best_score: &mut f32,
    best_path: &mut String,
    get_local_score: &F,
) where
    F: Fn(uint, uint, &str) -> f32,
{
    let score = get_local_score(pos_a, pos_b, path);
    if score > *best_score {
        *best_score = score;
        *best_pos_a = pos_a;
        *best_pos_b = pos_b;
        *best_path = path.to_string();
    }
    let na = get_na(path);
    let nb = get_nb(path);
    let ix_a = pos_a + na;
    let ix_b = pos_b + nb;
    assert!((ix_a as usize) < fwd_m.len());
    let row_a = &mut fwd_m[ix_a as usize];
    assert!((ix_b as usize) < row_a.len());
    if row_a[ix_b as usize] == f32::MAX || score > row_a[ix_b as usize] {
        row_a[ix_b as usize] = score;
    }
}

#[track_caller]
pub fn sw_enum_dp_fwd_m<F>(
    la: uint,
    lb: uint,
    fwd_m: &mut Vec<Vec<f32>>,
    get_local_score: F,
) -> (f32, uint, uint, String)
where
    F: Fn(uint, uint, &str) -> f32,
{
    let mut best_score = 0.0;
    let mut best_pos_a = uint::MAX;
    let mut best_pos_b = uint::MAX;
    let mut best_path = String::new();
    *fwd_m = vec![vec![f32::MAX; lb as usize + 1]; la as usize + 1];
    for i in 0..=la {
        fwd_m[i as usize][0] = 0.0;
    }
    for j in 0..=lb {
        fwd_m[0][j as usize] = 0.0;
    }
    for (pos_a, pos_b, path) in enum_paths_local_l63(la, lb) {
        on_path_l18(
            pos_a,
            pos_b,
            &path,
            fwd_m,
            &mut best_pos_a,
            &mut best_pos_b,
            &mut best_score,
            &mut best_path,
            &get_local_score,
        );
    }
    (best_score, best_pos_a, best_pos_b, best_path)
}

#[track_caller]
pub fn sw_enum_dp<F>(la: uint, lb: uint, get_local_score: F) -> (f32, uint, uint, String)
where
    F: Fn(uint, uint, &str) -> f32,
{
    let mut fwd_m = Vec::new();
    sw_enum_dp_fwd_m(la, lb, &mut fwd_m, get_local_score)
}

#[track_caller]
pub fn log_m(msg: &str, m: &[Vec<f32>]) -> String {
    let la = m.len();
    assert!(la > 0);
    let lb = m[0].len();
    let mut out = String::new();
    out.push_str(&format!("LogM({msg})\n"));
    out.push_str("      ");
    for j in 0..lb {
        out.push_str(&format!(" {j:10}"));
    }
    out.push('\n');
    for i in 0..la {
        out.push_str(&format!("{i:3} | "));
        for j in 0..lb {
            let x = m[i][j];
            if x == f32::MAX {
                out.push_str(&format!(" {:>10}", "*"));
            } else {
                out.push_str(&format!(" {:>10}", float_to_str_l1385(f64::from(x))));
            }
        }
        out.push('\n');
    }
    out
}

#[track_caller]
pub fn cmp_fwd_m(m1: &[Vec<f32>], m2: &[Vec<f32>]) {
    let la = m1.len();
    assert!(la > 0);
    assert_eq!(m2.len(), la);
    let lb = m1[0].len();
    assert_eq!(m2[0].len(), lb);
    for i in 0..la {
        for j in 0..lb {
            let a = m1[i][j];
            let b = m2[i][j];
            if (a - b).abs() > 1e-6 && !(a.is_nan() && b.is_nan()) {
                let _m1_log = log_m("M1", m1);
                let _m2_log = log_m("M2", m2);
                panic!("CmpFwdM");
            }
        }
    }
}

#[track_caller]
pub fn make_masm_seq(seq: &str, gap_open: f32, gap_ext: f32) -> MASM {
    let mut aln = MultiSequence::default();
    multi_sequence_from_strings(&mut aln, &["LABEL".to_string()], &[seq.to_string()]);
    let mut m = MASM::default();
    mega_from_msa_aa_only(&aln, gap_open, gap_ext);
    masm_from_msa(&mut m, &aln, "MSA", -gap_open, -gap_ext);
    m
}

#[track_caller]
pub fn make_masm_rows(rows: &[String], gap_open: f32, gap_ext: f32) -> MASM {
    let seq_count = rows.len();
    let mut col_count = uint::MAX;
    for i in 0..seq_count {
        let row = &rows[i];
        if i == 0 {
            col_count = row.len() as uint;
        } else {
            assert_eq!(row.len() as uint, col_count);
        }
    }
    let labels = vec!["Row".to_string(); seq_count];
    let mut aln = MultiSequence::default();
    multi_sequence_from_strings(&mut aln, &labels, rows);
    let mut m = MASM::default();
    mega_from_msa_aa_only(&aln, gap_open, gap_ext);
    masm_from_msa(&mut m, &aln, "Rows", -gap_open, -gap_ext);
    m
}

#[track_caller]
pub fn make_mega_profile(seq: &str) -> Vec<Vec<byte>> {
    let mut prof = Vec::new();
    for c in seq.bytes() {
        let mut letter = match (c as char).to_ascii_uppercase() {
            'A' => 0,
            'C' => 1,
            'D' => 2,
            'E' => 3,
            'F' => 4,
            'G' => 5,
            'H' => 6,
            'I' => 7,
            'K' => 8,
            'L' => 9,
            'M' => 10,
            'N' => 11,
            'P' => 12,
            'Q' => 13,
            'R' => 14,
            'S' => 15,
            'T' => 16,
            'V' => 17,
            'W' => 18,
            'Y' => 19,
            _ => uint::MAX,
        };
        if letter >= 20 {
            letter = 0;
        }
        let mut col = Vec::new();
        col.push(letter as byte);
        prof.push(col);
    }
    prof
}

#[track_caller]
pub fn s_wer_get_na(path: &str) -> uint {
    let mut n = 0;
    for c in path.chars() {
        if c == 'M' || c == 'D' {
            n += 1;
        }
    }
    n
}

#[track_caller]
pub fn s_wer_get_nb(path: &str) -> uint {
    let mut n = 0;
    for c in path.chars() {
        if c == 'M' || c == 'I' {
            n += 1;
        }
    }
    n
}

#[track_caller]
pub fn s_wer_run<FSW>(
    s: &mut SWer,
    a: &str,
    b: &str,
    lo_a: &mut uint,
    lo_b: &mut uint,
    path: &mut String,
    mut sw: FSW,
) -> f32
where
    FSW: FnMut(&mut SWer, &mut uint, &mut uint, &mut String) -> f32,
{
    s.rows_a.clear();
    s.a = a.to_string();
    s.b = b.to_string();
    s.rows_a = split(a, '|');
    s.la = s.rows_a[0].len() as uint;
    s.lb = s.b.len() as uint;
    let score = sw(s, lo_a, lo_b, path);
    if score <= 0.0 {
        return 0.0;
    }
    let na = s_wer_get_na(path);
    let nb = s_wer_get_nb(path);
    let hi_a = *lo_a + na - 1;
    let hi_b = *lo_b + nb - 1;
    assert!(hi_a < s.la);
    assert!(hi_b < s.lb);
    score
}

#[track_caller]
pub fn on_path_l158<F>(
    state: &mut TestSwMmBruteState,
    pos_a: uint,
    pos_b: uint,
    path: &str,
    mut get_local_score: F,
) where
    F: FnMut(uint, uint, &str) -> f32,
{
    let score = get_local_score(pos_a, pos_b, path);
    if score > state.best_score {
        state.best_score = score;
        state.best_path = path.to_string();
        state.best_pos_a = pos_a;
        state.best_pos_b = pos_b;
    }
}

