#[track_caller]
pub fn cmd_swmasm<FLoadMega>(
    masm_file_name: &str,
    mega_file_name: &str,
    output_file_name: &str,
    mut load_mega: FLoadMega,
) -> String
where
    FLoadMega: FnMut(&str),
{
    load_mega(mega_file_name);

    let mut m = MASM::default();
    masm_from_file(&mut m, masm_file_name);
    let label_m = m.label.clone();

    let query_profile_count = MEGA_STATE.lock().unwrap().profiles.len() as uint;
    let mut mem = XDPMem::default();
    let mut out = String::new();
    let mut tab = String::new();
    let format_g3 = |d: f32| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let d64 = f64::from(d);
        let exp = d64.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 3 {
            let raw = format!("{d64:.2e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (2 - exp).max(0) as usize;
            format!("{d64:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };
    for i in 0..query_profile_count {
        let q = mega_get_profile(i);
        let label_q = mega_get_label(i);
        let (score, loi, loj, _leni, _lenj, path) = sw_fast_masm(&mut mem, &m, &q);
        if !path.is_empty() {
            out.push_str(&write_local_aln_masm(
                &label_m, &m, &label_q, &q, loi, loj, &path,
            ));
        }
        let score_s = format_g3(score);
        out.push_str(&format!("Score = {score_s}\n\n"));
        tab.push_str(&format!("{}\t{}\t{}\n", label_m, label_q, score_s));
    }
    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, &tab).expect("failed to write SWMASM output");
    }
    out
}

#[track_caller]
pub fn sw_fast_masm_mega_prof(
    mem: &mut XDPMem,
    ma: &MASM,
    pb: &[Vec<byte>],
    open: f32,
    ext: f32,
) -> (f32, uint, uint, uint, uint, String) {
    const TRACEBITS_DM: byte = 0x01;
    const TRACEBITS_IM: byte = 0x02;
    const TRACEBITS_MD: byte = 0x04;
    const TRACEBITS_MI: byte = 0x08;
    const TRACEBITS_SM: byte = 0x10;
    const TRACEBITS_UNINIT: byte = !0x1f;

    let la = ma.col_count;
    let lb = pb.len() as uint;
    assert!(open <= 0.0);
    assert!(ext <= 0.0);
    assert!(ma.cols.len() >= la as usize);

    mem.max_la = la + 32;
    mem.max_lb = lb + 32;
    mem.buffer1 = vec![0.0; mem.max_lb as usize + 1];
    mem.buffer2 = vec![0.0; mem.max_lb as usize + 1];
    mem.tb_bit = vec![vec![TRACEBITS_UNINIT; mem.max_lb as usize]; mem.max_la as usize];
    mem.tb_bit_row_count = la;
    mem.tb_bit_col_count = lb;
    mem.tb_bit_allocated_row_count = mem.max_la;
    mem.tb_bit_allocated_col_count = mem.max_lb;

    let mut len_i = 0;
    let mut len_j = 0;
    for j in 0..=lb as usize {
        mem.buffer1[j] = MINUS_INFINITY;
        mem.buffer2[j] = MINUS_INFINITY;
    }

    let mut best_score = 0.0;
    let mut best_i = uint::MAX;
    let mut best_j = uint::MAX;
    let mut m0 = 0.0;
    for i in 0..la {
        let col_a = &ma.cols[i as usize];
        let mut i0 = MINUS_INFINITY;
        for j in 0..lb {
            let col_b = &pb[j as usize];
            let mut trace_bits: byte = 0;
            let saved_m0 = m0;

            let mut xm = m0;
            if mem.buffer2[j as usize] > xm {
                xm = mem.buffer2[j as usize];
                trace_bits = TRACEBITS_DM;
            }
            if i0 > xm {
                xm = i0;
                trace_bits = TRACEBITS_IM;
            }
            if 0.0 >= xm {
                xm = 0.0;
                trace_bits = TRACEBITS_SM;
            }

            m0 = mem.buffer1[j as usize];
            xm += masm_col_get_match_score_mega_profile_pos(col_a, col_b);
            if xm > best_score {
                best_score = xm;
                best_i = i;
                best_j = j;
            }
            mem.buffer1[j as usize] = xm;

            let md = saved_m0 + open;
            mem.buffer2[j as usize] += ext;
            if md >= mem.buffer2[j as usize] {
                mem.buffer2[j as usize] = md;
                trace_bits |= TRACEBITS_MD;
            }

            let mi = saved_m0 + open;
            i0 += ext;
            if mi >= i0 {
                i0 = mi;
                trace_bits |= TRACEBITS_MI;
            }

            mem.tb_bit[i as usize][j as usize] = trace_bits;
        }
        m0 = MINUS_INFINITY;
    }

    if best_score <= 0.0 {
        return (0.0, uint::MAX, uint::MAX, len_i, len_j, String::new());
    }

    let (trace_len_i, trace_len_j, path) = trace_back_bit_sw(mem, la, lb, best_i + 1, best_j + 1);
    len_i = trace_len_i;
    len_j = trace_len_j;
    assert!(best_i + 1 >= len_i);
    assert!(best_j + 1 >= len_j);
    let lo_i = best_i + 1 - len_i;
    let lo_j = best_j + 1 - len_j;
    (best_score, lo_i, lo_j, len_i, len_j, path)
}

#[track_caller]
pub fn sw_fast_masm_seq(
    mem: &mut XDPMem,
    a: &MASM,
    b: &Sequence,
    open: f32,
    ext: f32,
) -> (f32, uint, uint, uint, uint, String) {
    let smx = masm_make_s_mx_sequence(a, b);
    sw_fast_s_mx(mem, &smx, -open, -ext)
}

#[track_caller]
pub fn cmd_swmasm_seq<FLoadMega>(
    aln_file_name: &str,
    mega_file_name: &str,
    fasta_file_name: &str,
    output_file_name: &str,
    mut load_mega: FLoadMega,
) -> String
where
    FLoadMega: FnMut(&str),
{
    load_mega(mega_file_name);

    let mut aln = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut aln, aln_file_name, false);

    let gap_open = 4.0_f32;
    let gap_ext = 0.5_f32;

    let mut m = MASM::default();
    masm_from_msa(&mut m, &aln, "FomMSA", gap_open, gap_ext);
    masm_to_file_l150(&m, output_file_name);

    let mut query = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut query, fasta_file_name, true);

    let mut mem = XDPMem::default();
    let mut out = String::new();
    let format_g3 = |d: f32| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let d64 = f64::from(d);
        let exp = d64.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 3 {
            let raw = format!("{d64:.2e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (2 - exp).max(0) as usize;
            format!("{d64:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };
    for q in &query.seqs {
        let (score, loi, loj, _leni, _lenj, path) =
            sw_fast_masm_seq(&mut mem, &m, q, gap_open, gap_ext);
        let label = q.label.chars().take(16).collect::<String>();
        out.push_str(&format!(
            "{:>10}  {:>16}  {:7}  {:7}  {}\n\n",
            format_g3(score),
            label,
            loi,
            loj,
            path
        ));
    }
    out
}

#[track_caller]
pub fn swps<FMatch, FMM, FMD, FMI, FDM, FDD, FIM, FII>(
    mem: &mut XDPMem,
    la: uint,
    lb: uint,
    lo_i: &mut uint,
    lo_j: &mut uint,
    path: &mut String,
    get_match_score: FMatch,
    get_score_mm: FMM,
    get_score_md: FMD,
    get_score_mi: FMI,
    get_score_dm: FDM,
    get_score_dd: FDD,
    get_score_im: FIM,
    get_score_ii: FII,
) -> f32
where
    FMatch: Fn(uint, uint) -> f32,
    FMM: Fn(uint, uint) -> f32,
    FMD: Fn(uint, uint) -> f32,
    FMI: Fn(uint, uint) -> f32,
    FDM: Fn(uint, uint) -> f32,
    FDD: Fn(uint, uint) -> f32,
    FIM: Fn(uint, uint) -> f32,
    FII: Fn(uint, uint) -> f32,
{
    const TRACEBITS_DM: byte = 0x01;
    const TRACEBITS_IM: byte = 0x02;
    const TRACEBITS_MD: byte = 0x04;
    const TRACEBITS_MI: byte = 0x08;
    const TRACEBITS_SM: byte = 0x10;
    const TRACEBITS_UNINIT: byte = !0x1f;

    mem.max_la = la + 32;
    mem.max_lb = lb + 32;
    mem.buffer1 = vec![0.0; mem.max_lb as usize + 1];
    mem.buffer2 = vec![0.0; mem.max_lb as usize + 1];
    mem.tb_bit = vec![vec![TRACEBITS_UNINIT; mem.max_lb as usize]; mem.max_la as usize];
    mem.tb_bit_row_count = la;
    mem.tb_bit_col_count = lb;
    mem.tb_bit_allocated_row_count = mem.max_la;
    mem.tb_bit_allocated_col_count = mem.max_lb;

    for j in 0..=lb as usize {
        mem.buffer1[j] = MINUS_INFINITY;
        mem.buffer2[j] = MINUS_INFINITY;
    }

    let mut best_score = 0.0;
    let mut best_i = uint::MAX;
    let mut best_j = uint::MAX;
    for i in 0..la {
        let mut iscore = MINUS_INFINITY;
        let mut prev_saved_m = MINUS_INFINITY;
        for j in 0..lb {
            let mut trace_bits: byte = 0;
            let saved_m = mem.buffer1[j as usize + 1];

            let mm = prev_saved_m + get_score_mm(i, j);
            let dm = mem.buffer2[j as usize] + get_score_dm(i, j);
            let im = iscore + get_score_im(i, j);
            let mut t = mm;
            if dm > t {
                t = dm;
                trace_bits = TRACEBITS_DM;
            }
            if im > t {
                t = im;
                trace_bits = TRACEBITS_IM;
            }
            if t < 0.0 {
                t = 0.0;
                trace_bits = TRACEBITS_SM;
            }

            let m = t + get_match_score(i, j);
            if m > best_score {
                best_score = m;
                best_i = i;
                best_j = j;
            }
            mem.buffer1[j as usize + 1] = m;

            let md = prev_saved_m + get_score_md(i, j);
            let dd = mem.buffer2[j as usize] + get_score_dd(i, j);
            if md >= dd {
                mem.buffer2[j as usize] = md;
                trace_bits |= TRACEBITS_MD;
            } else {
                mem.buffer2[j as usize] = dd;
            }

            let mi = prev_saved_m + get_score_mi(i, j);
            let ii = iscore + get_score_ii(i, j);
            iscore = ii;
            if mi > iscore {
                iscore = mi;
                trace_bits |= TRACEBITS_MI;
            }

            prev_saved_m = saved_m;
            mem.tb_bit[i as usize][j as usize] = trace_bits;
        }
    }

    if best_score <= 0.0 {
        return 0.0;
    }

    let (len_i, len_j, aln_path) = trace_back_bit_sw(mem, la, lb, best_i + 1, best_j + 1);
    assert!(best_i + 1 >= len_i);
    assert!(best_j + 1 >= len_j);
    *lo_i = best_i + 1 - len_i;
    *lo_j = best_j + 1 - len_j;
    *path = aln_path;
    best_score
}

#[track_caller]
pub fn sw_simple_fwd_mdi<FMatch, FMM, FMD, FMI, FDM, FDD, FIM, FII>(
    la: uint,
    lb: uint,
    lo_a: &mut uint,
    lo_b: &mut uint,
    path: &mut String,
    fwd_m: &mut Vec<Vec<f32>>,
    fwd_d: &mut Vec<Vec<f32>>,
    fwd_i: &mut Vec<Vec<f32>>,
    tbm: &mut Vec<Vec<char>>,
    tbd: &mut Vec<Vec<char>>,
    tbi: &mut Vec<Vec<char>>,
    get_match_score: FMatch,
    get_score_mm: FMM,
    get_score_md: FMD,
    get_score_mi: FMI,
    get_score_dm: FDM,
    get_score_dd: FDD,
    get_score_im: FIM,
    get_score_ii: FII,
) -> f32
where
    FMatch: Fn(uint, uint) -> f32,
    FMM: Fn(uint, uint) -> f32,
    FMD: Fn(uint, uint) -> f32,
    FMI: Fn(uint, uint) -> f32,
    FDM: Fn(uint, uint) -> f32,
    FDD: Fn(uint, uint) -> f32,
    FIM: Fn(uint, uint) -> f32,
    FII: Fn(uint, uint) -> f32,
{
    *fwd_m = vec![vec![f32::MAX; lb as usize + 1]; la as usize + 1];
    *fwd_d = vec![vec![f32::MAX; lb as usize + 1]; la as usize + 1];
    *fwd_i = vec![vec![f32::MAX; lb as usize + 1]; la as usize + 1];
    *tbm = vec![vec!['?'; lb as usize + 1]; la as usize + 1];
    *tbd = vec![vec!['?'; lb as usize + 1]; la as usize + 1];
    *tbi = vec![vec!['?'; lb as usize + 1]; la as usize + 1];

    for i in 0..=la as usize {
        fwd_m[i][0] = MINUS_INFINITY;
        fwd_d[i][0] = MINUS_INFINITY;
        fwd_i[i][0] = MINUS_INFINITY;
        tbm[i][0] = 'S';
        tbd[i][0] = '?';
        tbi[i][0] = '?';
    }

    for j in 0..=lb as usize {
        fwd_m[0][j] = MINUS_INFINITY;
        fwd_d[0][j] = MINUS_INFINITY;
        fwd_i[0][j] = MINUS_INFINITY;
        tbm[0][j] = 'S';
        tbd[0][j] = '?';
        tbi[0][j] = '?';
    }

    let mut best_score = 0.0;
    let mut best_i = uint::MAX;
    let mut best_j = uint::MAX;
    for i in 0..la {
        for j in 0..lb {
            let m = get_match_score(i, j);
            let sm = m;
            let mm = fwd_m[i as usize][j as usize] + get_score_mm(i, j) + m;
            let dm = fwd_d[i as usize][j as usize] + get_score_dm(i, j) + m;
            let im = fwd_i[i as usize][j as usize] + get_score_im(i, j) + m;

            let mut s = mm;
            let mut t = 'M';
            if dm > s {
                s = dm;
                t = 'D';
            }
            if im > s {
                s = im;
                t = 'I';
            }
            if sm >= s {
                s = sm;
                t = 'S';
            }

            fwd_m[i as usize + 1][j as usize + 1] = s;
            tbm[i as usize + 1][j as usize + 1] = t;
            if s > best_score {
                best_score = s;
                best_i = i + 1;
                best_j = j + 1;
            }

            let md = fwd_m[i as usize][j as usize + 1] + get_score_md(i, j + 1);
            let dd = fwd_d[i as usize][j as usize + 1] + get_score_dd(i, j + 1);
            if md >= dd {
                fwd_d[i as usize + 1][j as usize + 1] = md;
                tbd[i as usize + 1][j as usize + 1] = 'M';
            } else {
                fwd_d[i as usize + 1][j as usize + 1] = dd;
                tbd[i as usize + 1][j as usize + 1] = 'D';
            }

            let mi = fwd_m[i as usize + 1][j as usize] + get_score_mi(i + 1, j);
            let ii = fwd_i[i as usize + 1][j as usize] + get_score_ii(i + 1, j);
            if mi >= ii {
                fwd_i[i as usize + 1][j as usize + 1] = mi;
                tbi[i as usize + 1][j as usize + 1] = 'M';
            } else {
                fwd_i[i as usize + 1][j as usize + 1] = ii;
                tbi[i as usize + 1][j as usize + 1] = 'I';
            }
        }
    }

    if best_i == uint::MAX {
        return 0.0;
    }

    let mut i = best_i;
    let mut j = best_j;
    path.clear();
    let mut state = 'M';
    loop {
        path.push(state);
        match state {
            'M' => {
                state = tbm[i as usize][j as usize];
                i -= 1;
                j -= 1;
            }
            'D' => {
                state = tbd[i as usize][j as usize];
                i -= 1;
            }
            'I' => {
                state = tbi[i as usize][j as usize];
                j -= 1;
            }
            _ => panic!("invalid traceback state"),
        }

        if i == 0 || j == 0 || state == 'S' {
            break;
        }
    }

    *path = path.chars().rev().collect();
    *lo_a = i;
    *lo_b = j;

    assert!(best_i >= *lo_a);
    assert!(best_j >= *lo_b);
    best_score
}

