#[track_caller]
pub fn hack(x: f32) -> f32 {
    assert!(x >= 0.0);
    assert!(x <= LOG_UNDERFLOW_THRESHOLD);
    if x <= 1.0 {
        return ((-0.009350833524763_f32 * x + 0.130659527668286_f32) * x + 0.498799810682272_f32)
            * x
            + 0.693203116424741_f32;
    }
    ((-0.000458661602210_f32 * x + 0.009695946122598_f32) * x + 0.930734667215156_f32) * x
        + 0.168037164329057_f32
}

#[track_caller]
pub fn log_add_hack(x: f32, y: f32) -> f32 {
    if x < y {
        return if x == LOG_ZERO || y - x >= LOG_UNDERFLOW_THRESHOLD {
            y
        } else {
            hack(y - x) + x
        };
    }
    if y == LOG_ZERO || x - y >= LOG_UNDERFLOW_THRESHOLD {
        x
    } else {
        hack(x - y) + y
    }
}

#[track_caller]
pub fn log1pexp(x: f32) -> f32 {
    if x < -88.029691931_f32 {
        0.0
    } else {
        x.exp().ln_1p()
    }
}

#[track_caller]
pub fn sum_log_prob(x: f32, y: f32) -> f32 {
    if x > y {
        x + log1pexp(y - x)
    } else {
        y + log1pexp(x - y)
    }
}

#[track_caller]
pub fn cmd_testlog() -> String {
    const N: uint = 0;
    const M: uint = 0;
    let mut v = Vec::<f32>::new();
    for _ in 0..N {
        let x = -((randu32() % 20) as f32) + ((randu32() % 100) as f32) / 10000.0;
        v.push(x);
    }
    let mut mv = Vec::<f32>::new();
    for _ in 0..M {
        let x = -((randu32() % 20) as f32) + ((randu32() % 100) as f32) / 10000.0;
        mv.push(x);
    }
    let mut diffs = 0_u32;
    for x in &v {
        for y in &v {
            let sum1 = sum_log_prob(*x, *y);
            let sum2 = sum_log_prob(*x, *y);
            if !myfeq(sum1 as f64, sum2 as f64) {
                diffs += 1;
            }
        }
    }
    let mut total = 0.0_f32;
    for x in &v {
        for y in &v {
            total += sum_log_prob(*x, *y);
            total += sum_log_prob(*x, *y);
            total += log_add_hack(*x, *y);
            total += *x + *y;
        }
    }
    for x in &mv {
        total += *x;
    }
    assert_eq!(diffs, 0);
    assert_eq!(total, 0.0);
    String::new()
}

#[track_caller]
pub fn test2_l4(p1d: f64, p2d: f64) -> String {
    let p1 = p1d as f32;
    let p2 = p2d as f32;

    let prod = p1 * p2;
    let sum = p1 + p2;

    let log_p1 = p1.ln();
    let log_p2 = p2.ln();
    let log_prod = prod.ln();
    let log_sum = sum.ln();

    let sum_p12 = log_p1 + log_p2;
    assert!(myfeq(log_prod as f64, sum_p12 as f64));

    let add = sum_log_prob(log_p1, log_p2);
    assert!(myfeq(add as f64, log_sum as f64));

    let mut pe = log_p1;
    pe = sum_log_prob(pe, log_p2);
    assert!(myfeq(pe as f64, log_sum as f64));

    let format_g3 = |d: f32| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let d64 = f64::from(d);
        let exp = d64.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 3 {
            let raw = format!("{d64:.2e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (2 - exp).max(0) as usize;
            format!("{d64:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };
    format!("P1={} P2={} ok\n", format_g3(p1), format_g3(p2))
}

