#[track_caller]
pub fn calc_total_prob_flat(flat_fwd: &[f32], flat_bwd: &[f32], lx: uint, ly: uint) -> f32 {
    let state_count = HMMSTATE_COUNT as usize;
    let base = state_count * (lx as usize * (ly as usize + 1) + ly as usize);
    assert!(flat_fwd.len() >= base + state_count);
    assert!(flat_bwd.len() >= base + state_count);

    let mut sum = LOG_ZERO;
    for state in 0..state_count {
        sum = log_add_hack(sum, flat_fwd[base + state] + flat_bwd[base + state]);
    }
    sum
}

#[track_caller]
pub fn trace_back_bit_mem(mem: &XDPMem, la: uint, lb: uint, state: byte, pi: &mut PathInfo) {
    const TRACEBITS_DM: byte = 0x01;
    const TRACEBITS_IM: byte = 0x02;
    const TRACEBITS_MD: byte = 0x04;
    const TRACEBITS_MI: byte = 0x08;

    path_info_alloc2(pi, la, lb);
    path_info_set_empty(pi);

    let mut i = la;
    let mut j = lb;
    let mut state = state;
    loop {
        if i == 0 && j == 0 {
            break;
        }

        path_info_append_char(pi, state);

        match state {
            b'M' => {
                assert!(i > 0 && j > 0);
                let t = mem.tb_bit[(i - 1) as usize][(j - 1) as usize];
                if t & TRACEBITS_DM != 0 {
                    state = b'D';
                } else if t & TRACEBITS_IM != 0 {
                    state = b'I';
                } else {
                    state = b'M';
                }
                i -= 1;
                j -= 1;
            }
            b'D' => {
                assert!(i > 0);
                let t = mem.tb_bit[(i - 1) as usize][j as usize];
                if t & TRACEBITS_MD != 0 {
                    state = b'M';
                } else {
                    state = b'D';
                }
                i -= 1;
            }
            b'I' => {
                assert!(j > 0);
                let t = mem.tb_bit[i as usize][(j - 1) as usize];
                if t & TRACEBITS_MI != 0 {
                    state = b'M';
                } else {
                    state = b'I';
                }
                j -= 1;
            }
            _ => panic!("TraceBackBit, invalid state {}", state as char),
        }
    }
    path_info_reverse(pi);
}

#[track_caller]
pub fn trace_back_flat(tb: &[i8], lx: uint, ly: uint) -> String {
    assert!(tb.len() >= ((lx + 1) * (ly + 1)) as usize);
    let mut path = Vec::new();
    let mut i = lx as i32;
    let mut j = ly as i32;
    loop {
        if i == 0 && j == 0 {
            break;
        }
        if i < 0 || j < 0 {
            return String::from_utf8(path).unwrap();
        }
        let tb_char = tb[(i as uint * (ly + 1) + j as uint) as usize];
        path.push(tb_char as u8);
        match tb_char {
            x if x == b'B' as i8 => {
                i -= 1;
                j -= 1;
            }
            x if x == b'X' as i8 => i -= 1,
            x if x == b'Y' as i8 => j -= 1,
            _ => panic!("TraceBackFlat invalid byte {}", tb_char),
        }
    }
    path.reverse();
    String::from_utf8(path).unwrap()
}

#[track_caller]
pub fn trans_aln_log_me(ta: &TransAln) -> String {
    let mut out = String::new();
    out.push('\n');
    out.push_str("Pair-wise alignments:\n");
    let fresh_count = trans_aln_get_fresh_count(ta);
    for fresh_index in 0..fresh_count {
        let fresh_seq = trans_aln_get_fresh_seq(ta, fresh_index);
        let msa_index = trans_aln_get_msa_index(ta, fresh_index);
        let ungapped_msa_seq = trans_aln_get_ungapped_msa_seq(ta, msa_index);
        let pw_path = trans_aln_get_pw_path(ta, fresh_index);
        let mut fresh_pos = 0usize;
        let mut msa_pos = 0usize;
        let mut fresh_row = String::new();
        let mut msa_row = String::new();
        for c in pw_path.bytes() {
            match c {
                b'B' => {
                    fresh_row.push(fresh_seq.char_vec[fresh_pos]);
                    msa_row.push(ungapped_msa_seq.char_vec[msa_pos]);
                    fresh_pos += 1;
                    msa_pos += 1;
                }
                b'X' => {
                    fresh_row.push(fresh_seq.char_vec[fresh_pos]);
                    msa_row.push('-');
                    fresh_pos += 1;
                }
                b'Y' => {
                    fresh_row.push('-');
                    msa_row.push(ungapped_msa_seq.char_vec[msa_pos]);
                    msa_pos += 1;
                }
                _ => panic!("Invalid PWPath char {}", c as char),
            }
        }
        out.push_str(&format!(
            "{pw_path}\n{}  >{}\n{}  >{}\n",
            fresh_row, fresh_seq.label, msa_row, ungapped_msa_seq.label
        ));
    }

    out.push('\n');
    out.push_str("MSAPaths:\n");
    let msa_count = trans_aln_get_msa_count(ta);
    for msa_index in 0..msa_count {
        let msa_path = trans_aln_get_msa_path(ta, msa_index);
        let msa_label = trans_aln_get_msa_label(ta, msa_index);
        out.push_str(msa_path);
        out.push_str(&format!("  >{msa_label}\n"));
    }

    out.push('\n');
    out.push_str("MaxInserts:\n");
    let mut m = 0;
    for col in 0..ta.msa_col_to_max_inserts.len() {
        let n = ta.msa_col_to_max_inserts[col];
        if n > 0 {
            out.push_str(&format!(" [{col}]={n}"));
            m += 1;
        }
    }
    out.push_str(&format!(" ({m})\n"));
    out.push_str(&format!(
        "ExtendedColCount = {}\n\n",
        ta.extended_msa_col_count
    ));

    out.push('\n');
    out.push_str("TPaths1:\n");
    for i in 0..ta.t_paths1.len() {
        let path1 = &ta.t_paths1[i];
        let fresh_label = trans_aln_get_fresh_label(ta, i as uint);
        out.push_str(path1);
        out.push_str(&format!("  >{fresh_label}\n"));
    }

    for i in 0..ta.t_paths1.len() {
        out.push_str(&trans_aln_log_t_path1_aln(ta, i as uint));
    }

    out.push('\n');
    out.push_str("TPaths2:\n");
    for i in 0..ta.t_paths2.len() {
        let path2 = &ta.t_paths2[i];
        let fresh_label = trans_aln_get_fresh_label(ta, i as uint);
        out.push_str(path2);
        out.push_str(&format!("  >{fresh_label}\n"));
    }
    out.push('\n');
    out.push_str("MPath\n");
    out.push_str(&format!("{}\n", ta.m_path));

    for i in 0..ta.t_paths2.len() {
        out.push_str(&trans_aln_log_t_path2_aln(ta, i as uint, true));
    }

    out.push('\n');
    for i in 0..msa_count {
        out.push_str(&trans_aln_log_m_path_aln(ta, i, false));
    }
    for i in 0..ta.t_paths2.len() {
        out.push_str(&trans_aln_log_t_path2_aln(ta, i as uint, false));
    }
    out
}

