#[track_caller]
pub fn trans_aln_make_t_path1(ta: &TransAln, fresh_index: uint) -> String {
    let msa_col_count = ta.msa_col_count;
    let msa_index = trans_aln_get_msa_index(ta, fresh_index);
    let pw_path = trans_aln_get_pw_path(ta, fresh_index).as_bytes();
    let msa_path = trans_aln_get_msa_path(ta, msa_index).as_bytes();
    let fresh_l = trans_aln_get_fresh_seq_length(ta, fresh_index);
    let ul = trans_aln_get_ungapped_msa_seq_length(ta, msa_index);

    let mut path1 = String::new();
    let mut nf = 0;
    let mut ng = 0;
    let mut ni = 0;
    let mut n_gap_msa = 0;
    let mut msa_col = 0usize;
    for c in pw_path {
        if *c == b'B' || *c == b'Y' {
            while msa_path[msa_col] == b'G' {
                msa_col += 1;
                path1.push('g');
                n_gap_msa += 1;
            }
        }

        match *c {
            b'B' => {
                path1.push('F');
                nf += 1;
                msa_col += 1;
            }
            b'X' => {
                path1.push('I');
                ni += 1;
            }
            b'Y' => {
                path1.push('G');
                ng += 1;
                msa_col += 1;
            }
            _ => panic!("invalid PW path char {}", *c as char),
        }
    }

    while msa_col < msa_col_count as usize {
        assert_eq!(msa_path[msa_col], b'G');
        msa_col += 1;
        path1.push('g');
        n_gap_msa += 1;
    }

    assert_eq!(nf + ng + n_gap_msa, msa_col_count);
    assert_eq!(nf + ni, fresh_l);
    assert_eq!(nf + ng, ul);
    path1
}

#[track_caller]
pub fn trans_aln_make_msa_path(ta: &TransAln, msa_index: uint) -> String {
    let msa_seq = trans_aln_get_msa_seq(ta, msa_index);
    assert_eq!(msa_seq.char_vec.len() as uint, ta.msa_col_count);
    let mut msa_path = String::new();
    for col in 0..ta.msa_col_count {
        let c = msa_seq.char_vec[col as usize];
        if c == '-' {
            msa_path.push('G');
        } else {
            msa_path.push('M');
        }
    }
    msa_path
}

#[track_caller]
pub fn trans_aln_make_m_path(ta: &TransAln) -> String {
    assert_eq!(
        ta.msa_col_to_max_inserts.len(),
        ta.msa_col_count as usize + 1
    );
    let mut m_path = String::new();
    for col in 0..=ta.msa_col_count {
        let ins = ta.msa_col_to_max_inserts[col as usize];
        for _ in 0..ins {
            m_path.push('i');
        }
        if col < ta.msa_col_count {
            m_path.push('M');
        }
    }
    m_path
}

#[track_caller]
pub fn trans_aln_init(
    ta: &mut TransAln,
    msa: &MultiSequence,
    fresh_seqs: &MultiSequence,
    fresh_index_to_msa_index: &[uint],
    pw_paths: &[String],
) {
    ta.msa_paths.clear();
    ta.t_paths1.clear();
    ta.t_paths2.clear();
    ta.ungapped_msa_seqs.clear();

    ta.msa = Some(msa.clone());
    ta.fresh_seqs = Some(fresh_seqs.clone());
    ta.fresh_index_to_msa_index = fresh_index_to_msa_index.to_vec();
    ta.pw_paths = pw_paths.to_vec();
    ta.msa_col_count = multi_sequence_get_col_count(msa);

    let msa_seq_count = msa.seqs.len() as uint;
    for msa_index in 0..msa_seq_count {
        let msa_path = trans_aln_make_msa_path(ta, msa_index);
        ta.msa_paths.push(msa_path);

        let seq = &msa.seqs[msa_index as usize];
        let ungapped = sequence_copy_delete_gaps(&sequence_get_seq_as_string(seq));
        let mut ungapped_seq = Sequence::default();
        sequence_from_string(&mut ungapped_seq, &seq.label, &ungapped);
        ta.ungapped_msa_seqs.push(ungapped_seq);
    }

    let fresh_seq_count = fresh_seqs.seqs.len() as uint;
    for fresh_index in 0..fresh_seq_count {
        let path1 = trans_aln_make_t_path1(ta, fresh_index);
        ta.t_paths1.push(path1);
    }

    trans_aln_set_max_inserts(ta);

    for fresh_index in 0..fresh_seq_count {
        let path2 = trans_aln_make_t_path2(ta, fresh_index);
        ta.t_paths2.push(path2);
    }
    ta.m_path = trans_aln_make_m_path(ta);
}

#[track_caller]
pub fn trans_aln_set_max_inserts(ta: &mut TransAln) {
    let fresh_count = trans_aln_get_fresh_count(ta);
    assert_eq!(ta.t_paths1.len(), fresh_count as usize);
    ta.msa_col_to_max_inserts.clear();
    ta.msa_col_to_max_inserts
        .resize(ta.msa_col_count as usize + 1, 0);
    for fresh_index in 0..fresh_count {
        let msa_col_to_inserts = trans_aln_make_msa_col_to_inserts(ta, fresh_index);
        assert_eq!(msa_col_to_inserts.len(), ta.msa_col_count as usize + 1);
        for msa_col in 0..=ta.msa_col_count {
            let ins = msa_col_to_inserts[msa_col as usize];
            ta.msa_col_to_max_inserts[msa_col as usize] =
                std::cmp::max(ins, ta.msa_col_to_max_inserts[msa_col as usize]);
        }
    }

    ta.extended_msa_col_count = 0;
    for msa_col in 0..=ta.msa_col_count {
        let ins = ta.msa_col_to_max_inserts[msa_col as usize];
        ta.extended_msa_col_count += ins;
        if msa_col < ta.msa_col_count {
            ta.extended_msa_col_count += 1;
        }
    }
}

#[track_caller]
pub fn trans_aln_make_msa_col_to_inserts(ta: &TransAln, fresh_index: uint) -> Vec<uint> {
    let t_path1 = trans_aln_get_t_path1(ta, fresh_index).as_bytes();
    let mut msa_col = 0usize;
    let mut msa_col_to_inserts = vec![0; ta.msa_col_count as usize + 1];

    for c in t_path1 {
        match *c {
            b'F' | b'G' | b'g' => {
                msa_col += 1;
            }
            b'I' => {
                assert!(msa_col <= ta.msa_col_count as usize);
                msa_col_to_inserts[msa_col] += 1;
            }
            _ => panic!("invalid TPath1 char {}", *c as char),
        }
    }

    assert_eq!(msa_col, ta.msa_col_count as usize);
    msa_col_to_inserts
}

#[track_caller]
pub fn trans_aln_make_t_path2(ta: &TransAln, fresh_index: uint) -> String {
    assert_eq!(
        ta.msa_col_to_max_inserts.len(),
        ta.msa_col_count as usize + 1
    );
    let t_path1 = trans_aln_get_t_path1(ta, fresh_index).as_bytes();
    let msa_col_to_inserts = trans_aln_make_msa_col_to_inserts(ta, fresh_index);

    let mut path2 = String::new();
    let mut msa_col = 0usize;
    for c in t_path1 {
        path2.push(*c as char);
        if *c != b'I' {
            assert!(msa_col < ta.msa_col_count as usize);
            let insert_count = msa_col_to_inserts[msa_col];
            let max_insert_count = ta.msa_col_to_max_inserts[msa_col];
            assert!(insert_count <= max_insert_count);
            for _ in insert_count..max_insert_count {
                path2.push('i');
            }
        }

        match *c {
            b'F' | b'G' | b'g' => {
                msa_col += 1;
            }
            b'I' => {}
            _ => panic!("invalid TPath1 char {}", *c as char),
        }
    }
    assert_eq!(msa_col, ta.msa_col_count as usize);
    let insert_count = msa_col_to_inserts[ta.msa_col_count as usize];
    let max_insert_count = ta.msa_col_to_max_inserts[ta.msa_col_count as usize];
    assert!(insert_count <= max_insert_count);
    for _ in insert_count..max_insert_count {
        path2.push('i');
    }

    if path2.len() != ta.extended_msa_col_count as usize {
        panic!(
            "|Path2|={}, m_ExtendedMSAColCount={}",
            path2.len(),
            ta.extended_msa_col_count
        );
    }
    path2
}

#[track_caller]
pub fn trans_aln_log_t_path1_aln(ta: &TransAln, fresh_index: uint) -> String {
    let t_path1 = trans_aln_get_t_path1(ta, fresh_index);
    let msa_index = trans_aln_get_msa_index(ta, fresh_index);
    let f = trans_aln_get_fresh_seq(ta, fresh_index);
    let u = trans_aln_get_ungapped_msa_seq(ta, msa_index);
    let fl = f.char_vec.len();
    let ul = u.char_vec.len();
    let f_label = trans_aln_get_fresh_label(ta, fresh_index);
    let u_label = trans_aln_get_msa_label(ta, msa_index);
    let mut f_pos = 0usize;
    let mut u_pos = 0usize;
    let mut f_row = String::new();
    let mut u_row = String::new();
    for c in t_path1.bytes() {
        match c {
            b'F' => {
                f_row.push(f.char_vec[f_pos]);
                u_row.push(u.char_vec[u_pos]);
                f_pos += 1;
                u_pos += 1;
            }
            b'G' => {
                f_row.push('-');
                u_row.push(u.char_vec[u_pos]);
                u_pos += 1;
            }
            b'I' => {
                f_row.push(f.char_vec[f_pos]);
                u_row.push('.');
                f_pos += 1;
            }
            b'g' => {
                f_row.push('.');
                u_row.push('.');
            }
            _ => {}
        }
    }
    assert_eq!(f_pos, fl);
    assert_eq!(u_pos, ul);
    format!("\n{t_path1}\n{f_row}  >{f_label}\n{u_row}  >{u_label}\n")
}

#[track_caller]
pub fn trans_aln_log_t_path2_aln(ta: &TransAln, fresh_index: uint, with_path: bool) -> String {
    let t_path2 = trans_aln_get_t_path2(ta, fresh_index);
    let msa_index = trans_aln_get_msa_index(ta, fresh_index);
    let f = trans_aln_get_fresh_seq(ta, fresh_index);
    let u = trans_aln_get_ungapped_msa_seq(ta, msa_index);
    let fl = f.char_vec.len();
    let ul = u.char_vec.len();
    let f_label = trans_aln_get_fresh_label(ta, fresh_index);
    let u_label = trans_aln_get_msa_label(ta, msa_index);
    let mut f_pos = 0usize;
    let mut u_pos = 0usize;
    let mut f_row = String::new();
    let mut u_row = String::new();
    for c in t_path2.bytes() {
        match c {
            b'F' => {
                f_row.push(f.char_vec[f_pos]);
                u_row.push(u.char_vec[u_pos]);
                f_pos += 1;
                u_pos += 1;
            }
            b'G' => {
                f_row.push('-');
                u_row.push(u.char_vec[u_pos]);
                u_pos += 1;
            }
            b'I' => {
                f_row.push(f.char_vec[f_pos]);
                u_row.push('.');
                f_pos += 1;
            }
            b'g' | b'i' => {
                f_row.push('.');
                u_row.push('.');
            }
            _ => {}
        }
    }
    assert_eq!(f_pos, fl);
    assert_eq!(u_pos, ul);
    let mut out = String::new();
    if with_path {
        out.push_str(&format!("\n{t_path2}\n"));
    }
    out.push_str(&format!("{f_row}  [F] >{f_label}\n"));
    out.push_str(&format!("{u_row}  [U] >{u_label}\n"));
    out
}

#[track_caller]
pub fn trans_aln_log_m_path_aln(ta: &TransAln, msa_index: uint, with_path: bool) -> String {
    let m = trans_aln_get_msa_seq(ta, msa_index);
    let m_label = trans_aln_get_msa_label(ta, msa_index);
    let mut msa_col = 0usize;
    let mut m_row = String::new();
    for c in ta.m_path.bytes() {
        match c {
            b'M' => {
                m_row.push(m.char_vec[msa_col]);
                msa_col += 1;
            }
            b'i' => {
                m_row.push('.');
            }
            _ => {}
        }
    }
    assert_eq!(msa_col, ta.msa_col_count as usize);
    let mut out = String::new();
    if with_path {
        out.push_str(&format!("\n{}\n", ta.m_path));
    }
    out.push_str(&format!("{m_row}  [M] >{m_label}\n"));
    out
}

#[track_caller]
pub fn trans_aln_extend_fresh_seq(ta: &TransAln, fresh_index: uint) -> Sequence {
    let f = trans_aln_get_fresh_seq(ta, fresh_index);
    let t_path2 = trans_aln_get_t_path2(ta, fresh_index);
    let col_count = ta.m_path.len();
    let mut fx = Sequence {
        label: f.label.clone(),
        char_vec: Vec::new(),
    };
    let mut f_pos = 0usize;
    for c in t_path2.bytes().take(col_count) {
        match c {
            b'F' | b'I' => {
                fx.char_vec.push(f.char_vec[f_pos]);
                f_pos += 1;
            }
            b'G' | b'g' | b'i' => {
                fx.char_vec.push('-');
            }
            _ => panic!("Invalid char '{}' in TPath2", c as char),
        }
    }
    assert_eq!(fx.char_vec.len(), ta.extended_msa_col_count as usize);
    fx
}

#[track_caller]
pub fn trans_aln_extend_msa_seq(ta: &TransAln, msa_index: uint) -> Sequence {
    let m = trans_aln_get_msa_seq(ta, msa_index);
    let mut mx = Sequence {
        label: m.label.clone(),
        char_vec: Vec::new(),
    };
    let mut msa_col = 0usize;
    for c in ta.m_path.bytes() {
        match c {
            b'M' => {
                mx.char_vec.push(m.char_vec[msa_col]);
                msa_col += 1;
            }
            b'i' => {
                mx.char_vec.push('-');
            }
            _ => panic!("Invalid char '{}' in MPath", c as char),
        }
    }
    assert_eq!(mx.char_vec.len(), ta.extended_msa_col_count as usize);
    mx
}

#[track_caller]
pub fn trans_aln_make_extended_msa(ta: &mut TransAln) {
    let msa_count = trans_aln_get_msa_count(ta);
    let fresh_count = trans_aln_get_fresh_count(ta);
    let mut extended_msa = MultiSequence::default();

    for i in 0..msa_count {
        let s = trans_aln_extend_msa_seq(ta, i);
        extended_msa.seqs.push(s);
        extended_msa.owners.push(true);
    }

    for i in 0..fresh_count {
        let s = trans_aln_extend_fresh_seq(ta, i);
        extended_msa.seqs.push(s);
        extended_msa.owners.push(true);
    }
    ta.extended_msa = Some(extended_msa);
}

#[track_caller]
pub fn cmd_transaln<FAlignPairFlat>(
    input_file_name: &str,
    ref_file_name: &str,
    output_file_name: &str,
    mut align_pair_flat: FAlignPairFlat,
) -> (TransAln, MultiSequence)
where
    FAlignPairFlat: FnMut(&str, &str, &mut String),
{
    let mut input_seqs = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut input_seqs, input_file_name, false);
    let input_seq_count = input_seqs.seqs.len() as uint;

    let mut ref_msa = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut ref_msa, ref_file_name, false);
    let ref_seq_count = ref_msa.seqs.len() as uint;

    let mut global_input = MultiSequence::default();
    for seq in &input_seqs.seqs {
        let ungapped = sequence_copy_delete_gaps(&sequence_get_seq_as_string(seq));
        let mut global_seq = Sequence::default();
        sequence_from_string(&mut global_seq, &seq.label, &ungapped);
        global_input.seqs.push(global_seq);
        global_input.owners.push(false);
    }
    for seq in &ref_msa.seqs {
        let ungapped = sequence_copy_delete_gaps(&sequence_get_seq_as_string(seq));
        let mut global_seq = Sequence::default();
        sequence_from_string(&mut global_seq, &seq.label, &ungapped);
        global_input.seqs.push(global_seq);
        global_input.owners.push(false);
    }
    set_global_input_ms(&global_input);

    let mut pw_paths = Vec::new();
    let mut fresh_index_to_msa_index = Vec::new();
    for input_seq_index in 0..input_seq_count {
        let ref_seq_index = input_seq_index % ref_seq_count;
        fresh_index_to_msa_index.push(ref_seq_index);

        let input_label = input_seqs.seqs[input_seq_index as usize].label.clone();
        let ref_label = ref_msa.seqs[ref_seq_index as usize].label.clone();
        let mut pw_path = String::new();
        align_pair_flat(&input_label, &ref_label, &mut pw_path);
        pw_paths.push(pw_path);
    }

    let mut ta = TransAln::default();
    trans_aln_init(
        &mut ta,
        &ref_msa,
        &input_seqs,
        &fresh_index_to_msa_index,
        &pw_paths,
    );
    trans_aln_make_extended_msa(&mut ta);
    let extended_msa = ta
        .extended_msa
        .as_ref()
        .expect("TransAln extended MSA not built")
        .clone();
    msa_to_fasta_file_l103(&extended_msa, output_file_name);
    (ta, extended_msa)
}

pub fn strip_gaps(row: &str) -> String {
    let mut ungapped_seq = String::new();
    for r in row.bytes() {
        if r != b'-' && r != b'.' {
            ungapped_seq.push(char::from(r));
        }
    }
    ungapped_seq
}

#[track_caller]
pub fn cmd_transalnref<FViterbi>(
    ref_aln_file_name: &str,
    add_fasta_file_name: &str,
    ref_label: &str,
    output_file_name: &str,
    mut viterbi_fast_mem: FViterbi,
) -> (TransAln, MultiSequence, String)
where
    FViterbi: FnMut(&[byte], uint, &[byte], uint) -> PathInfo,
{
    assert!(!output_file_name.is_empty());
    let mut ref_aln = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut ref_aln, ref_aln_file_name, false);
    let ref_seq_index = multi_sequence_get_seq_index(&ref_aln, ref_label, true);
    assert_ne!(ref_seq_index, uint::MAX);

    let row_r = &ref_aln.seqs[ref_seq_index as usize];
    let row_r_str = sequence_get_seq_as_string(row_r);
    let r_str = strip_gaps(&row_r_str);
    let lr = r_str.len() as uint;

    let mut seqs_to_add = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut seqs_to_add, add_fasta_file_name, false);
    if seqs_to_add.seqs.len() != 1 {
        die("-input2 must have exactly one sequence");
    }
    let add_label = seqs_to_add.seqs[0].label.clone();
    let row_a_str = sequence_get_seq_as_string(&seqs_to_add.seqs[0]);
    let a_str = strip_gaps(&row_a_str);
    let la = a_str.len() as uint;

    let pi = viterbi_fast_mem(r_str.as_bytes(), lr, a_str.as_bytes(), la);
    let path_str = pi.path;
    let pair_col_count = path_str.len() as uint;
    let mut pos_r = 0usize;
    let mut pos_a = 0usize;
    let mut ids = 0_u32;
    for c in path_str.bytes() {
        match c {
            b'M' => {
                let r = r_str.as_bytes()[pos_r] as char;
                let a = a_str.as_bytes()[pos_a] as char;
                if r.eq_ignore_ascii_case(&a) {
                    ids += 1;
                }
                pos_r += 1;
                pos_a += 1;
            }
            b'D' => pos_r += 1,
            b'I' => pos_a += 1,
            _ => panic!("Invalid TransAlnRef path char '{}'", c as char),
        }
    }
    assert_eq!(pos_r, lr as usize);
    assert_eq!(pos_a, la as usize);
    let pct_id = if pair_col_count == 0 {
        0.0
    } else {
        100.0 * f64::from(ids) / f64::from(pair_col_count)
    };
    let log = format!("ref {ref_label}, add {add_label} ({pct_id:.1}% id)\nDone.\n");

    let mut path_str_xyb = String::new();
    for c in path_str.bytes() {
        match c {
            b'M' => path_str_xyb.push('B'),
            b'D' => path_str_xyb.push('Y'),
            b'I' => path_str_xyb.push('X'),
            _ => panic!("Invalid TransAlnRef path char '{}'", c as char),
        }
    }

    let fresh_index_to_msa_index = vec![ref_seq_index];
    let pw_paths = vec![path_str_xyb];
    let mut ta = TransAln::default();
    trans_aln_init(
        &mut ta,
        &ref_aln,
        &seqs_to_add,
        &fresh_index_to_msa_index,
        &pw_paths,
    );
    trans_aln_make_extended_msa(&mut ta);
    let extended_msa = ta
        .extended_msa
        .as_ref()
        .expect("TransAlnRef extended MSA not built")
        .clone();
    msa_to_fasta_file_l103(&extended_msa, output_file_name);
    (ta, extended_msa, log)
}

#[track_caller]
pub fn q_scorer3_trans_q_pair(qs3: &mut QScorer3, indexi: uint, indexj: uint) {
    let labeli = &qs3.qs1.labels[indexi as usize];
    let labelj = &qs3.qs1.labels[indexj as usize];

    let ref_seq_indexi = qs3.qs1.ref_seq_indexes[indexi as usize];
    let ref_seq_indexj = qs3.qs1.ref_seq_indexes[indexj as usize];
    assert_eq!(qs3.ref_msa.seqs[ref_seq_indexi as usize].label, *labeli);
    assert_eq!(qs3.ref_msa.seqs[ref_seq_indexj as usize].label, *labelj);

    let indexi2 = qs3.indexes2[indexi as usize];
    let indexj2 = qs3.indexes2[indexj as usize];
    assert_eq!(qs3.qs2.labels[indexi2 as usize], *labeli);
    assert_eq!(qs3.qs2.labels[indexj2 as usize], *labelj);
    assert_eq!(qs3.qs2.ref_seq_indexes[indexi2 as usize], ref_seq_indexi);
    assert_eq!(qs3.qs2.ref_seq_indexes[indexj2 as usize], ref_seq_indexj);

    let test_col_to_posi1 = &qs3.qs1.test_col_to_pos_vec[indexi as usize];
    let test_col_to_posi2 = &qs3.qs2.test_col_to_pos_vec[indexi2 as usize];

    let test_col_to_posj1 = &qs3.qs1.test_col_to_pos_vec[indexj as usize];
    let test_col_to_posj2 = &qs3.qs2.test_col_to_pos_vec[indexj2 as usize];

    let ref_col_to_posi1 = &qs3.qs1.ref_col_to_pos_vec[indexi as usize];
    let ref_col_to_posi2 = &qs3.qs2.ref_col_to_pos_vec[indexi2 as usize];

    let ref_col_to_posj1 = &qs3.qs1.ref_col_to_pos_vec[indexj as usize];
    let ref_col_to_posj2 = &qs3.qs2.ref_col_to_pos_vec[indexj2 as usize];

    let pos_to_test_coli1 = &qs3.qs1.pos_to_test_col_vec[indexi as usize];
    let pos_to_test_coli2 = &qs3.qs2.pos_to_test_col_vec[indexi2 as usize];

    let pos_to_test_colj1 = &qs3.qs1.pos_to_test_col_vec[indexj as usize];
    let pos_to_test_colj2 = &qs3.qs2.pos_to_test_col_vec[indexj2 as usize];

    let ref_col_count = ref_col_to_posi1.len();
    assert_eq!(ref_col_to_posi2.len(), ref_col_count);
    assert_eq!(ref_col_to_posj1.len(), ref_col_count);
    assert_eq!(ref_col_to_posj2.len(), ref_col_count);

    let li = pos_to_test_coli1.len();
    let lj = pos_to_test_colj1.len();

    assert_eq!(pos_to_test_coli2.len(), li);
    assert_eq!(pos_to_test_colj2.len(), lj);

    let ref_cols = &qs3.ref_cols;
    let ref_aligned_col_count = qs3.qs1.ref_aligned_col_count;
    assert_eq!(qs3.qs2.ref_aligned_col_count, ref_aligned_col_count);

    let mut correct_col_count1 = 0;
    let mut correct_col_count2 = 0;
    let mut posis = Vec::new();
    let mut posjs = Vec::new();
    for k in 0..ref_aligned_col_count {
        let ref_col = ref_cols[k as usize];

        let posi = ref_col_to_posi1[ref_col as usize];
        let posi2 = ref_col_to_posi2[ref_col as usize];
        if posi == uint::MAX || posi2 == uint::MAX {
            continue;
        }
        assert_eq!(posi2, posi);

        let test_coli1 = pos_to_test_coli1[posi as usize];
        let test_coli2 = pos_to_test_coli2[posi as usize];

        let posj = ref_col_to_posj1[ref_col as usize];
        let posj2 = qs3.qs2.ref_col_to_pos_vec[indexj2 as usize][ref_col as usize];
        if posj == uint::MAX || posj2 == uint::MAX {
            continue;
        }
        assert_eq!(posj2, posj);
        posis.push(posi);
        posjs.push(posj);

        let test_colj1 = pos_to_test_colj1[posj as usize];
        let test_colj2 = pos_to_test_colj2[posj as usize];

        if test_coli1 == test_colj1 {
            correct_col_count1 += 1;
        }
        if test_coli2 == test_colj2 {
            correct_col_count2 += 1;
        }
    }

    let test_aligned_pos_count = posis.len();
    assert_eq!(posjs.len(), test_aligned_pos_count);

    let mut same_col_count = 0;
    for k in 0..test_aligned_pos_count {
        let posi = posis[k];

        let test_col1 = pos_to_test_coli1[posi as usize];
        let posj1 = test_col_to_posj1[test_col1 as usize];

        let test_col2 = pos_to_test_coli2[posi as usize];
        let posj2 = test_col_to_posj2[test_col2 as usize];

        if posj1 == posj2 {
            same_col_count += 1;
        }
    }

    for k in 0..test_aligned_pos_count {
        let posj = posjs[k];

        let test_col1 = pos_to_test_colj1[posj as usize];
        let posi1 = test_col_to_posi1[test_col1 as usize];

        let test_col2 = pos_to_test_colj2[posj as usize];
        let posi2 = test_col_to_posi2[test_col2 as usize];

        if posi1 == posi2 {
            same_col_count += 1;
        }
    }

    let q1 = correct_col_count1 as f32 / ref_aligned_col_count as f32;
    let q2 = correct_col_count2 as f32 / ref_aligned_col_count as f32;
    let pwc = same_col_count as f32 / (2 * test_aligned_pos_count) as f32;

    qs3.pairs.push((indexi, indexj));
    qs3.pair_index_to_q1.push(q1);
    qs3.pair_index_to_q2.push(q2);
    qs3.pair_index_to_pwc.push(pwc);
}

#[track_caller]
pub fn q_scorer3_trans_q(qs3: &mut QScorer3) {
    let n = qs3.qs1.labels.len() as uint;

    assert!(!qs3.ref_cols.is_empty());

    qs3.pairs.clear();
    qs3.pair_index_to_q1.clear();
    qs3.pair_index_to_q2.clear();
    qs3.pair_index_to_pwc.clear();
    for indexi in 0..n {
        for indexj in indexi + 1..n {
            q_scorer3_trans_q_pair(qs3, indexi, indexj);
        }
    }
}

pub fn tree_init_cache(t: &mut Tree, cache_count: uint) {
    t.cache_count = cache_count;
    let n = cache_count as usize;
    t.neighbor1 = vec![NULL_NEIGHBOR; n];
    t.neighbor2 = vec![NULL_NEIGHBOR; n];
    t.neighbor3 = vec![NULL_NEIGHBOR; n];
    t.ids = vec![uint::MAX; n];
    t.edge_length1 = vec![f64::MAX; n];
    t.edge_length2 = vec![f64::MAX; n];
    t.edge_length3 = vec![f64::MAX; n];
    t.height = vec![f64::MAX; n];
    t.has_edge_length1 = vec![false; n];
    t.has_edge_length2 = vec![false; n];
    t.has_edge_length3 = vec![false; n];
    t.has_height = vec![false; n];
    t.names = vec![None; n];
}

pub fn tree_assert_are_neighbors(t: &Tree, node_index1: uint, node_index2: uint) {
    if node_index1 >= t.node_count || node_index2 >= t.node_count {
        panic!(
            "AssertAreNeighbors({node_index1},{node_index2}), are {} nodes",
            t.node_count
        );
    }

    let i1 = node_index1 as usize;
    let i2 = node_index2 as usize;
    if t.neighbor1[i1] != node_index2
        && t.neighbor2[i1] != node_index2
        && t.neighbor3[i1] != node_index2
    {
        panic!("AssertAreNeighbors({node_index1},{node_index2}) failed");
    }
    if t.neighbor1[i2] != node_index1
        && t.neighbor2[i2] != node_index1
        && t.neighbor3[i2] != node_index1
    {
        panic!("AssertAreNeighbors({node_index1},{node_index2}) failed");
    }

    let has12 = tree_has_edge_length(t, node_index1, node_index2);
    let has21 = tree_has_edge_length(t, node_index2, node_index1);
    if has12 != has21 {
        panic!("Tree::AssertAreNeighbors, HasEdgeLength not symmetric");
    }
    if has12 {
        let d12 = tree_get_edge_length(t, node_index1, node_index2);
        let d21 = tree_get_edge_length(t, node_index2, node_index1);
        if d12 != d21 {
            let format_g3 = |d: f64| -> String {
                if d == 0.0 {
                    return "0".to_string();
                }
                if !d.is_finite() {
                    return d.to_string();
                }
                let exp = d.abs().log10().floor() as i32;
                let mut s = if exp < -4 || exp >= 3 {
                    let raw = format!("{d:.2e}");
                    let (mantissa, exponent) = raw.split_once('e').unwrap();
                    let mut mantissa = mantissa
                        .trim_end_matches('0')
                        .trim_end_matches('.')
                        .to_string();
                    if mantissa == "-0" {
                        mantissa = "0".to_string();
                    }
                    let exp_value = exponent.parse::<i32>().unwrap();
                    let sign = if exp_value >= 0 { '+' } else { '-' };
                    format!("{mantissa}e{sign}{:02}", exp_value.abs())
                } else {
                    let decimals = (2 - exp).max(0) as usize;
                    format!("{d:.decimals$}")
                };
                if !s.contains('e') && !s.contains('E') {
                    s = s.trim_end_matches('0').trim_end_matches('.').to_string();
                }
                if s == "-0" {
                    s = "0".to_string();
                }
                s
            };
            panic!(
                "Tree::AssertAreNeighbors, Edge length disagrees {node_index1}-{node_index2}={}, {node_index2}-{node_index1}={}",
                format_g3(d12),
                format_g3(d21)
            );
        }
    }
}

pub fn tree_validate_node(t: &Tree, node_index: uint) {
    if node_index >= t.node_count {
        panic!("ValidateNode({node_index}), {} nodes", t.node_count);
    }

    let i = node_index as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    if neighbor_count == 2 {
        if !t.rooted {
            panic!("Tree::ValidateNode: Node {node_index} has two neighbors, tree is not rooted");
        }
        if node_index != t.root_node_index {
            panic!(
                "Tree::ValidateNode: Node {node_index} has two neighbors, but not root node={}",
                t.root_node_index
            );
        }
    }

    let n1 = t.neighbor1[i];
    let n2 = t.neighbor2[i];
    let n3 = t.neighbor3[i];
    if n2 == NULL_NEIGHBOR && n3 != NULL_NEIGHBOR {
        panic!("Tree::ValidateNode, n2=null, n3!=null");
    }
    if n3 == NULL_NEIGHBOR && n2 != NULL_NEIGHBOR {
        panic!("Tree::ValidateNode, n3=null, n2!=null");
    }

    if n1 != NULL_NEIGHBOR {
        tree_assert_are_neighbors(t, node_index, n1);
    }
    if n2 != NULL_NEIGHBOR {
        tree_assert_are_neighbors(t, node_index, n2);
    }
    if n3 != NULL_NEIGHBOR {
        tree_assert_are_neighbors(t, node_index, n3);
    }

    if n1 != NULL_NEIGHBOR && (n1 == n2 || n1 == n3) {
        panic!("Tree::ValidateNode, duplicate neighbors in node {node_index}");
    }
    if n2 != NULL_NEIGHBOR && (n2 == n1 || n2 == n3) {
        panic!("Tree::ValidateNode, duplicate neighbors in node {node_index}");
    }
    if n3 != NULL_NEIGHBOR && (n3 == n1 || n3 == n2) {
        panic!("Tree::ValidateNode, duplicate neighbors in node {node_index}");
    }

    if t.rooted {
        let parent = t.neighbor1[i];
        if parent == NULL_NEIGHBOR {
            if node_index != t.root_node_index {
                panic!("Tree::ValiateNode({node_index}), no parent");
            }
        } else if t.neighbor2[parent as usize] != node_index
            && t.neighbor3[parent as usize] != node_index
        {
            panic!("Tree::ValidateNode({node_index}), parent / child mismatch");
        }
    }
}

pub fn tree_validate(t: &Tree) {
    for node_index in 0..t.node_count {
        tree_validate_node(t, node_index);
    }
}

pub fn tree_get_sibling(t: &Tree, node: uint) -> uint {
    if node == uint::MAX {
        return uint::MAX;
    }
    assert!(t.rooted && node < t.node_count);
    let parent = t.neighbor1[node as usize];
    if parent == uint::MAX {
        return uint::MAX;
    }
    assert!(t.rooted && parent < t.node_count);
    let parent_left = t.neighbor2[parent as usize];
    let parent_right = t.neighbor3[parent as usize];
    assert!(parent_left != uint::MAX);
    assert!(parent_right != uint::MAX);
    if parent_left == node {
        return parent_right;
    }
    if parent_right == node {
        return parent_left;
    }
    panic!("Tree::GetSibling: node is not a child of its parent");
}

pub fn tree_is_edge(t: &Tree, node_index1: uint, node_index2: uint) -> bool {
    assert!(node_index1 < t.node_count && node_index2 < t.node_count);
    let i = node_index1 as usize;
    t.neighbor1[i] == node_index2 || t.neighbor2[i] == node_index2 || t.neighbor3[i] == node_index2
}

pub fn tree_get_edge_length(t: &Tree, node_index1: uint, node_index2: uint) -> f64 {
    assert!(node_index1 < t.node_count && node_index2 < t.node_count);
    if !tree_has_edge_length(t, node_index1, node_index2) {
        panic!("Missing edge length in tree {node_index1}-{node_index2}");
    }

    let i = node_index1 as usize;
    if t.neighbor1[i] == node_index2 {
        t.edge_length1[i]
    } else if t.neighbor2[i] == node_index2 {
        t.edge_length2[i]
    } else {
        assert!(t.neighbor3[i] == node_index2);
        t.edge_length3[i]
    }
}

pub fn tree_expand_cache(t: &mut Tree) {
    let new_cache_count = t.cache_count + 100;
    let new_len = new_cache_count as usize;
    t.neighbor1.resize(new_len, NULL_NEIGHBOR);
    t.neighbor2.resize(new_len, NULL_NEIGHBOR);
    t.neighbor3.resize(new_len, NULL_NEIGHBOR);
    t.ids.resize(new_len, uint::MAX);
    t.edge_length1.resize(new_len, f64::MAX);
    t.edge_length2.resize(new_len, f64::MAX);
    t.edge_length3.resize(new_len, f64::MAX);
    t.height.resize(new_len, f64::MAX);
    t.has_edge_length1.resize(new_len, false);
    t.has_edge_length2.resize(new_len, false);
    t.has_edge_length3.resize(new_len, false);
    t.has_height.resize(new_len, false);
    t.names.resize(new_len, None);
    t.cache_count = new_cache_count;
}

pub fn tree_create_rooted(t: &mut Tree) {
    *t = Tree::default();
    tree_expand_cache(t);
    t.node_count = 1;
    t.neighbor1[0] = NULL_NEIGHBOR;
    t.neighbor2[0] = NULL_NEIGHBOR;
    t.neighbor3[0] = NULL_NEIGHBOR;
    t.has_edge_length1[0] = false;
    t.has_edge_length2[0] = false;
    t.has_edge_length3[0] = false;
    t.has_height[0] = false;
    t.root_node_index = 0;
    t.rooted = true;
}

pub fn tree_create_unrooted(t: &mut Tree, edge_length: f64) {
    *t = Tree::default();
    tree_expand_cache(t);
    t.node_count = 2;
    t.neighbor1[0] = 1;
    t.neighbor2[0] = NULL_NEIGHBOR;
    t.neighbor3[0] = NULL_NEIGHBOR;
    t.neighbor1[1] = 0;
    t.neighbor2[1] = NULL_NEIGHBOR;
    t.neighbor3[1] = NULL_NEIGHBOR;
    t.edge_length1[0] = edge_length;
    t.edge_length1[1] = edge_length;
    t.has_edge_length1[0] = true;
    t.has_edge_length1[1] = true;
    t.rooted = false;
}

pub fn tree_set_leaf_name(t: &mut Tree, node_index: uint, name: &str) {
    assert!(node_index < t.node_count);
    let i = node_index as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    assert!(t.node_count == 1 || neighbor_count == 1);
    t.names[i] = Some(name.to_string());
}

pub fn tree_set_leaf_id(t: &mut Tree, node_index: uint, id: uint) {
    assert!(node_index < t.node_count);
    let i = node_index as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    assert!(t.node_count == 1 || neighbor_count == 1);
    t.ids[i] = id;
}

pub fn tree_get_leaf_name(t: &Tree, node_index: uint) -> Option<&str> {
    assert!(node_index < t.node_count);
    let i = node_index as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    assert!(t.node_count == 1 || neighbor_count == 1);
    t.names[i].as_deref()
}

pub fn tree_get_leaf_id(t: &Tree, node_index: uint) -> uint {
    assert!(node_index < t.node_count);
    let i = node_index as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    assert!(t.node_count == 1 || neighbor_count == 1);
    t.ids[i]
}

#[track_caller]
pub fn tree_append_branch(t: &mut Tree, existing_leaf_index: uint) -> uint {
    if t.node_count == 0 {
        panic!("Tree::AppendBranch: tree has not been created");
    }
    assert!(existing_leaf_index < t.node_count);
    let existing = existing_leaf_index as usize;
    let neighbor_count = (t.neighbor1[existing] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[existing] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[existing] != NULL_NEIGHBOR) as uint;
    if !(t.node_count == 1 || neighbor_count == 1) {
        panic!("AppendBranch({existing_leaf_index}): not leaf");
    }

    if t.node_count >= t.cache_count - 2 {
        tree_expand_cache(t);
    }

    let new_leaf1 = t.node_count;
    let new_leaf2 = t.node_count + 1;
    t.node_count += 2;

    assert!(t.neighbor2[existing] == NULL_NEIGHBOR);
    assert!(t.neighbor3[existing] == NULL_NEIGHBOR);

    t.neighbor2[existing] = new_leaf1;
    t.neighbor3[existing] = new_leaf2;

    let l1 = new_leaf1 as usize;
    let l2 = new_leaf2 as usize;
    t.neighbor1[l1] = existing_leaf_index;
    t.neighbor1[l2] = existing_leaf_index;
    t.neighbor2[l1] = NULL_NEIGHBOR;
    t.neighbor2[l2] = NULL_NEIGHBOR;
    t.neighbor3[l1] = NULL_NEIGHBOR;
    t.neighbor3[l2] = NULL_NEIGHBOR;

    t.edge_length2[existing] = 0.0;
    t.edge_length3[existing] = 0.0;
    t.edge_length1[l1] = 0.0;
    t.edge_length2[l1] = 0.0;
    t.edge_length3[l1] = 0.0;
    t.edge_length1[l2] = 0.0;
    t.edge_length2[l2] = 0.0;
    t.edge_length3[l2] = 0.0;

    t.has_edge_length1[l1] = false;
    t.has_edge_length2[l1] = false;
    t.has_edge_length3[l1] = false;
    t.has_edge_length1[l2] = false;
    t.has_edge_length2[l2] = false;
    t.has_edge_length3[l2] = false;
    t.has_height[l1] = false;
    t.has_height[l2] = false;
    t.ids[l1] = uint::MAX;
    t.ids[l2] = uint::MAX;
    new_leaf1
}

#[track_caller]
pub fn tree_log_me(t: &Tree) -> String {
    let is_leaf = |node_index: usize| -> bool {
        let neighbor_count = (t.neighbor1[node_index] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[node_index] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[node_index] != NULL_NEIGHBOR) as uint;
        t.node_count == 1 || neighbor_count == 1
    };
    let mut out = String::new();
    out.push_str(&format!("Tree::LogMe {} nodes, ", t.node_count));
    if t.rooted {
        out.push_str("rooted.\n");
        out.push('\n');
        out.push_str("Index  Parnt  LengthP  Left   LengthL  Right  LengthR     Id  Name\n");
        out.push_str("-----  -----  -------  ----   -------  -----  -------  -----  ----\n");
    } else {
        out.push_str("unrooted.\n");
        out.push('\n');
        out.push_str("Index  Nbr_1  Length1  Nbr_2  Length2  Nbr_3  Length3     Id  Name\n");
        out.push_str("-----  -----  -------  -----  -------  -----  -------  -----  ----\n");
    }

    for node_index in 0..t.node_count as usize {
        out.push_str(&format!("{node_index:5}  "));
        let ns = [
            t.neighbor1[node_index],
            t.neighbor2[node_index],
            t.neighbor3[node_index],
        ];
        let lengths = [
            t.edge_length1[node_index],
            t.edge_length2[node_index],
            t.edge_length3[node_index],
        ];
        let has_lengths = [
            t.has_edge_length1[node_index],
            t.has_edge_length2[node_index],
            t.has_edge_length3[node_index],
        ];
        for n in 0..3 {
            if ns[n] != NULL_NEIGHBOR {
                out.push_str(&format!("{:5}  ", ns[n]));
                if has_lengths[n] {
                    out.push_str(&format!("{:7.4}  ", lengths[n]));
                } else {
                    out.push_str("      *  ");
                }
            } else {
                out.push_str("                ");
            }
        }

        if is_leaf(node_index) {
            let id = t.ids[node_index];
            if id == uint::MAX {
                out.push_str("    *");
            } else {
                out.push_str(&format!("{id:5}"));
            }
        } else {
            out.push_str("     ");
        }

        if t.rooted && node_index as uint == t.root_node_index {
            out.push_str("  [ROOT] ");
        }
        if let Some(name) = &t.names[node_index] {
            out.push_str("  ");
            out.push_str(name);
        }
        out.push('\n');
    }
    out
}

pub fn tree_set_edge_length(t: &mut Tree, node_index1: uint, node_index2: uint, length: f64) {
    assert!(node_index1 < t.node_count && node_index2 < t.node_count);
    assert!(tree_is_edge(t, node_index1, node_index2));

    let i1 = node_index1 as usize;
    if t.neighbor1[i1] == node_index2 {
        t.edge_length1[i1] = length;
        t.has_edge_length1[i1] = true;
    } else if t.neighbor2[i1] == node_index2 {
        t.edge_length2[i1] = length;
        t.has_edge_length2[i1] = true;
    } else {
        assert!(t.neighbor3[i1] == node_index2);
        t.edge_length3[i1] = length;
        t.has_edge_length3[i1] = true;
    }

    let i2 = node_index2 as usize;
    if t.neighbor1[i2] == node_index1 {
        t.edge_length1[i2] = length;
        t.has_edge_length1[i2] = true;
    } else if t.neighbor2[i2] == node_index1 {
        t.edge_length2[i2] = length;
        t.has_edge_length2[i2] = true;
    } else {
        assert!(t.neighbor3[i2] == node_index1);
        t.edge_length3[i2] = length;
        t.has_edge_length3[i2] = true;
    }
}

#[track_caller]
pub fn tree_unroot_from_file(t: &mut Tree) -> uint {
    if !t.rooted {
        panic!("Tree::Unroot, not rooted");
    }
    assert!(t.root_node_index == 0);
    assert!(t.neighbor1[0] == NULL_NEIGHBOR);
    if t.node_count >= t.cache_count {
        tree_expand_cache(t);
    }

    let third_node = t.node_count;
    t.node_count += 1;
    let third = third_node as usize;

    t.neighbor1[0] = third_node;
    t.neighbor1[third] = 0;
    t.neighbor2[third] = NULL_NEIGHBOR;
    t.neighbor3[third] = NULL_NEIGHBOR;
    t.edge_length1[0] = 0.0;
    t.edge_length1[third] = 0.0;
    t.has_edge_length1[third] = true;
    t.rooted = false;
    third_node
}

pub fn tree_get_first_neighbor(t: &Tree, node_index: uint, neighbor_index: uint) -> uint {
    assert!(node_index < t.node_count);
    assert!(neighbor_index < t.node_count);
    assert!(tree_is_edge(t, node_index, neighbor_index));

    for n in 0..3 {
        let neighbor = tree_get_neighbor(t, node_index, n);
        if neighbor != NULL_NEIGHBOR && neighbor_index != neighbor {
            return neighbor;
        }
    }
    NULL_NEIGHBOR
}

pub fn tree_get_second_neighbor(t: &Tree, node_index: uint, neighbor_index: uint) -> uint {
    assert!(node_index < t.node_count);
    assert!(neighbor_index < t.node_count);
    assert!(tree_is_edge(t, node_index, neighbor_index));

    let mut found_one = false;
    for n in 0..3 {
        let neighbor = tree_get_neighbor(t, node_index, n);
        if neighbor != NULL_NEIGHBOR && neighbor_index != neighbor {
            if found_one {
                return neighbor;
            }
            found_one = true;
        }
    }
    NULL_NEIGHBOR
}

pub fn tree_get_leaf_count_unrooted(t: &Tree, node_index1: uint, node_index2: uint) -> (uint, f64) {
    assert!(!t.rooted);

    let i2 = node_index2 as usize;
    let neighbor_count = (t.neighbor1[i2] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i2] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i2] != NULL_NEIGHBOR) as uint;
    if t.node_count == 1 || neighbor_count == 1 {
        return (1, tree_get_edge_length(t, node_index1, node_index2));
    }

    let left = tree_get_first_neighbor(t, node_index2, node_index1);
    let right = tree_get_second_neighbor(t, node_index2, node_index1);
    let (left_count, left_distance) = tree_get_leaf_count_unrooted(t, node_index2, left);
    let (right_count, right_distance) = tree_get_leaf_count_unrooted(t, node_index2, right);
    (left_count + right_count, left_distance + right_distance)
}

pub fn tree_has_edge_length(t: &Tree, node_index1: uint, node_index2: uint) -> bool {
    assert!(node_index1 < t.node_count);
    assert!(node_index2 < t.node_count);
    assert!(tree_is_edge(t, node_index1, node_index2));

    let i = node_index1 as usize;
    if t.neighbor1[i] == node_index2 {
        t.has_edge_length1[i]
    } else if t.neighbor2[i] == node_index2 {
        t.has_edge_length2[i]
    } else {
        assert!(t.neighbor3[i] == node_index2);
        t.has_edge_length3[i]
    }
}

pub fn tree_orient_parent(t: &mut Tree, node_index: uint, parent_node_index: uint) {
    if node_index == NULL_NEIGHBOR {
        return;
    }

    let i = node_index as usize;
    if t.neighbor1[i] == parent_node_index {
    } else if t.neighbor2[i] == parent_node_index {
        let edge_length2 = t.edge_length2[i];
        t.neighbor2[i] = t.neighbor1[i];
        t.edge_length2[i] = t.edge_length1[i];
        t.neighbor1[i] = parent_node_index;
        t.edge_length1[i] = edge_length2;
    } else {
        assert!(t.neighbor3[i] == parent_node_index);
        let edge_length3 = t.edge_length3[i];
        t.neighbor3[i] = t.neighbor1[i];
        t.edge_length3[i] = t.edge_length1[i];
        t.neighbor1[i] = parent_node_index;
        t.edge_length1[i] = edge_length3;
    }

    let child1 = t.neighbor2[i];
    let child2 = t.neighbor3[i];
    tree_orient_parent(t, child1, node_index);
    tree_orient_parent(t, child2, node_index);
}

pub fn tree_first_depth_first_node(t: &Tree) -> uint {
    assert!(t.rooted);
    let mut node_index = t.root_node_index;
    loop {
        let i = node_index as usize;
        let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if t.node_count == 1 || neighbor_count == 1 {
            return node_index;
        }
        assert!(t.rooted && node_index < t.node_count);
        node_index = t.neighbor2[i];
    }
}

pub fn tree_first_depth_first_node_r(t: &Tree) -> uint {
    assert!(t.rooted);
    let mut node_index = t.root_node_index;
    loop {
        let i = node_index as usize;
        let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if t.node_count == 1 || neighbor_count == 1 {
            return node_index;
        }
        assert!(t.rooted && node_index < t.node_count);
        node_index = t.neighbor3[i];
    }
}

pub fn tree_next_depth_first_node(t: &Tree, node_index: uint) -> uint {
    assert!(t.rooted);
    assert!(node_index < t.node_count);

    if t.rooted && t.root_node_index == node_index {
        return NULL_NEIGHBOR;
    }

    let parent = t.neighbor1[node_index as usize];
    assert!(t.rooted && parent < t.node_count);
    if t.neighbor3[parent as usize] == node_index {
        return parent;
    }

    let mut node_index = t.neighbor3[parent as usize];
    loop {
        let i = node_index as usize;
        let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if t.node_count == 1 || neighbor_count == 1 {
            return node_index;
        }
        node_index = t.neighbor2[i];
    }
}

pub fn tree_next_depth_first_node_r(t: &Tree, node_index: uint) -> uint {
    assert!(t.rooted);
    assert!(node_index < t.node_count);

    if t.rooted && t.root_node_index == node_index {
        return NULL_NEIGHBOR;
    }

    let parent = t.neighbor1[node_index as usize];
    assert!(t.rooted && parent < t.node_count);
    if t.neighbor2[parent as usize] == node_index {
        return parent;
    }

    let mut node_index = t.neighbor2[parent as usize];
    loop {
        let i = node_index as usize;
        let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if t.node_count == 1 || neighbor_count == 1 {
            return node_index;
        }
        node_index = t.neighbor3[i];
    }
}

pub fn get_max_string(v: &[String]) -> String {
    assert!(!v.is_empty());
    let mut max_str = v[0].clone();
    for s in &v[1..] {
        if s > &max_str {
            max_str = s.clone();
        }
    }
    max_str
}

pub fn compare_labels(labels1: &[String], labels2: &[String]) -> bool {
    let max1 = get_max_string(labels1);
    let max2 = get_max_string(labels2);
    max1 > max2
}

pub fn tree_ladderize(t: &mut Tree, more_right: bool) -> uint {
    let node_count = t.node_count;
    let mut rotated_count = 0;
    for node in 0..node_count {
        let i = node as usize;
        let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if t.node_count == 1 || neighbor_count == 1 {
            continue;
        }

        let left = t.neighbor2[i];
        let right = t.neighbor3[i];
        let n_left = tree_get_subtree_leaf_count(t, left);
        let n_right = tree_get_subtree_leaf_count(t, right);

        let mut do_rotate = if more_right {
            n_right < n_left
        } else {
            n_left < n_right
        };
        if n_left == n_right {
            let left_labels = tree_get_subtree_leaf_labels(t, left);
            let right_labels = tree_get_subtree_leaf_labels(t, right);
            do_rotate = compare_labels(&left_labels, &right_labels);
        }
        if do_rotate {
            rotated_count += 1;
            let left = t.neighbor2[i];
            let right = t.neighbor3[i];
            t.neighbor2[i] = right;
            t.neighbor3[i] = left;
        }
    }
    rotated_count
}

pub fn tree_unroot_by_deleting_root(t: &mut Tree) {
    assert!(t.rooted);
    assert!(t.node_count >= 3);

    let root = t.root_node_index;
    let r = root as usize;
    let left = t.neighbor2[r];
    let right = t.neighbor3[r];

    t.neighbor1[left as usize] = right;
    t.neighbor1[right as usize] = left;

    let has_edge_length =
        tree_has_edge_length(t, root, left) && tree_has_edge_length(t, root, right);
    if has_edge_length {
        let edge_length =
            tree_get_edge_length(t, root, left) + tree_get_edge_length(t, root, right);
        t.edge_length1[left as usize] = edge_length;
        t.edge_length1[right as usize] = edge_length;
    }

    t.neighbor1.remove(r);
    t.neighbor2.remove(r);
    t.neighbor3.remove(r);
    t.edge_length1.remove(r);
    t.edge_length2.remove(r);
    t.edge_length3.remove(r);
    t.has_edge_length1.remove(r);
    t.has_edge_length2.remove(r);
    t.has_edge_length3.remove(r);
    t.names.remove(r);

    t.node_count -= 1;
    t.rooted = false;

    for node_index in 0..t.node_count as usize {
        if t.neighbor1[node_index] != NULL_NEIGHBOR && t.neighbor1[node_index] > root {
            t.neighbor1[node_index] -= 1;
        }
        if t.neighbor2[node_index] != NULL_NEIGHBOR && t.neighbor2[node_index] > root {
            t.neighbor2[node_index] -= 1;
        }
        if t.neighbor3[node_index] != NULL_NEIGHBOR && t.neighbor3[node_index] > root {
            t.neighbor3[node_index] -= 1;
        }
    }
}

pub fn tree_get_leaf_parent(t: &Tree, node_index: uint) -> uint {
    assert!(node_index < t.node_count);
    let i = node_index as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    assert!(t.node_count == 1 || neighbor_count == 1);

    if t.rooted {
        return t.neighbor1[i];
    }
    if t.neighbor1[i] != NULL_NEIGHBOR {
        return t.neighbor1[i];
    }
    if t.neighbor2[i] != NULL_NEIGHBOR {
        return t.neighbor2[i];
    }
    t.neighbor3[i]
}

pub fn tree_get_lca(t: &Tree, node1: uint, node2: uint) -> uint {
    let path1 = tree_get_path_to_root(t, node1);
    let path2 = tree_get_path_to_root(t, node2);
    for anc_node1 in &path1 {
        for anc_node2 in &path2 {
            if anc_node2 == anc_node1 {
                return *anc_node1;
            }
        }
    }
    panic!("Tree::GetLCA: no common ancestor");
}

pub fn tree_get_path_to_root(t: &Tree, mut node: uint) -> Vec<uint> {
    if !t.rooted {
        panic!("GetPathToRoot(), not rooted");
    }
    let node_count = t.node_count;
    let mut path = Vec::new();
    loop {
        assert!(node < node_count);
        path.push(node);
        assert!(path.len() <= node_count as usize);
        if t.rooted && t.root_node_index == node {
            return path;
        }
        node = t.neighbor1[node as usize];
    }
}

pub fn tree_get_distance(t: &Tree, node: uint, anc_node: uint) -> f64 {
    if node == t.root_node_index && anc_node == uint::MAX {
        return 0.0;
    }

    let path = tree_get_path_to_root(t, node);
    let mut distance = 0.0;
    assert!(path[0] == node);
    for path_node in path {
        if path_node == anc_node {
            return distance;
        }
        if t.has_edge_length1[path_node as usize] {
            distance += t.edge_length1[path_node as usize];
        }
    }
    panic!("GetDistance, not ancestor");
}

pub fn tree_get_subtree_leaf_labels(t: &Tree, node: uint) -> Vec<String> {
    let leaves = tree_get_subtree_leaf_nodes(t, node);
    let mut labels = Vec::new();
    for leaf_node in leaves {
        labels.push(t.names[leaf_node as usize].clone().unwrap_or_default());
    }
    labels
}

pub fn tree_get_subtree_leaf_nodes(t: &Tree, node: uint) -> Vec<uint> {
    let mut leaf_nodes = Vec::new();
    tree_append_leaves(t, node, &mut leaf_nodes);
    leaf_nodes
}

pub fn tree_get_subtree_leaf_count(t: &Tree, node: uint) -> uint {
    if node == uint::MAX {
        return 0;
    }
    let leaves = tree_get_subtree_leaf_nodes(t, node);
    leaves.len() as uint
}

pub fn tree_get_leaf_labels(t: &Tree) -> Vec<String> {
    let mut labels = Vec::new();
    for node in 0..t.node_count {
        let i = node as usize;
        let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if t.node_count == 1 || neighbor_count == 1 {
            labels.push(t.names[i].clone().unwrap_or_default());
        }
    }
    labels
}

pub fn tree_append_leaves(t: &Tree, node: uint, leaves: &mut Vec<uint>) {
    let node_count = t.node_count;
    let leaf_count = if t.rooted {
        assert!(t.node_count % 2 == 1);
        (t.node_count + 1) / 2
    } else {
        assert!(t.node_count % 2 == 0);
        (t.node_count + 2) / 2
    };
    assert!(node < node_count);
    assert!((leaves.len() as uint) < leaf_count);

    let i = node as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    if t.node_count == 1 || neighbor_count == 1 {
        leaves.push(node);
    } else {
        let edge2 = t.neighbor2[i];
        let edge3 = t.neighbor3[i];
        tree_append_leaves(t, edge2, leaves);
        tree_append_leaves(t, edge3, leaves);
    }
}

pub fn tree_get_node_height(t: &mut Tree, node_index: uint) -> f64 {
    if !t.rooted {
        panic!("Tree::GetNodeHeight: undefined unless rooted tree");
    }

    let i = node_index as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    if t.node_count == 1 || neighbor_count == 1 {
        return 0.0;
    }

    if t.has_height[i] {
        return t.height[i];
    }

    let left = t.neighbor2[i];
    let right = t.neighbor3[i];
    let mut left_length = tree_get_edge_length(t, node_index, left);
    let mut right_length = tree_get_edge_length(t, node_index, right);
    if left_length < 0.0 {
        left_length = 0.0;
    }
    if right_length < 0.0 {
        right_length = 0.0;
    }

    let left_height = left_length + tree_get_node_height(t, left);
    let right_height = right_length + tree_get_node_height(t, right);
    let height = (left_height + right_height) / 2.0;
    t.has_height[i] = true;
    t.height[i] = height;
    height
}

pub fn tree_get_neighbor_subscript(t: &Tree, node_index: uint, neighbor_index: uint) -> uint {
    assert!(node_index < t.node_count);
    assert!(neighbor_index < t.node_count);
    let i = node_index as usize;
    if neighbor_index == t.neighbor1[i] {
        return 0;
    }
    if neighbor_index == t.neighbor2[i] {
        return 1;
    }
    if neighbor_index == t.neighbor3[i] {
        return 2;
    }
    NULL_NEIGHBOR
}

pub fn tree_get_neighbor(t: &Tree, node_index: uint, neighbor_subscript: uint) -> uint {
    let i = node_index as usize;
    match neighbor_subscript {
        0 => t.neighbor1[i],
        1 => t.neighbor2[i],
        2 => t.neighbor3[i],
        _ => panic!("Tree::GetNeighbor, sub={neighbor_subscript}"),
    }
}

pub fn tree_leaf_index_to_node_index(t: &Tree, leaf_index: uint) -> uint {
    let mut leaf_count = 0;
    for node_index in 0..t.node_count {
        let i = node_index as usize;
        let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if t.node_count == 1 || neighbor_count == 1 {
            if leaf_count == leaf_index {
                return node_index;
            }
            leaf_count += 1;
        }
    }
    panic!("LeafIndexToNodeIndex: out of range");
}

pub fn tree_get_node_index_l1199(t: &Tree, label: &str) -> uint {
    tree_get_node_index_l1204(t, label)
}

pub fn tree_get_node_index_l1204(t: &Tree, name: &str) -> uint {
    for node_index in 0..t.node_count {
        if let Some(leaf_name) = &t.names[node_index as usize] {
            if leaf_name == name {
                return node_index;
            }
        }
    }
    panic!("Tree::GetLeafNodeIndex, name not found");
}

pub fn tree_copy(dst: &mut Tree, src: &Tree) {
    let node_count = src.node_count as usize;
    tree_init_cache(dst, src.node_count);
    dst.node_count = src.node_count;
    dst.neighbor1[..node_count].copy_from_slice(&src.neighbor1[..node_count]);
    dst.neighbor2[..node_count].copy_from_slice(&src.neighbor2[..node_count]);
    dst.neighbor3[..node_count].copy_from_slice(&src.neighbor3[..node_count]);
    dst.ids[..node_count].copy_from_slice(&src.ids[..node_count]);
    dst.edge_length1[..node_count].copy_from_slice(&src.edge_length1[..node_count]);
    dst.edge_length2[..node_count].copy_from_slice(&src.edge_length2[..node_count]);
    dst.edge_length3[..node_count].copy_from_slice(&src.edge_length3[..node_count]);
    dst.height[..node_count].copy_from_slice(&src.height[..node_count]);
    dst.has_edge_length1[..node_count].copy_from_slice(&src.has_edge_length1[..node_count]);
    dst.has_edge_length2[..node_count].copy_from_slice(&src.has_edge_length2[..node_count]);
    dst.has_edge_length3[..node_count].copy_from_slice(&src.has_edge_length3[..node_count]);
    dst.has_height[..node_count].copy_from_slice(&src.has_height[..node_count]);
    dst.root_node_index = src.root_node_index;
    dst.rooted = src.rooted;
    dst.names.clear();
    dst.names.resize(node_count, None);
    for i in 0..node_count {
        dst.names[i] = src.names[i].clone();
    }
}

pub fn tree_to_vectors(t: &Tree) -> (Vec<String>, Vec<uint>, Vec<f32>) {
    assert!(t.rooted);

    let mut labels = Vec::new();
    let mut parents = Vec::new();
    let mut lengths = Vec::new();
    for node in 0..t.node_count {
        let label = t.names[node as usize].clone().unwrap_or_default();
        let parent = t.neighbor1[node as usize];
        let mut length = 0.0;
        if parent != uint::MAX {
            length = tree_get_edge_length(t, node, parent) as f32;
        }
        labels.push(label);
        parents.push(parent);
        lengths.push(length);
    }
    (labels, parents, lengths)
}

pub fn tree_from_vectors(t: &mut Tree, labels: &[String], parents: &[uint], lengths: &[f32]) {
    let node_count = labels.len();
    assert!(parents.len() == node_count);
    assert!(lengths.len() == node_count);

    let mut lefts = vec![uint::MAX; node_count];
    let mut rights = vec![uint::MAX; node_count];
    let mut root = uint::MAX;
    for node in 0..node_count {
        let parent = parents[node];
        if parent == uint::MAX {
            assert!(root == uint::MAX);
            root = node as uint;
            continue;
        }
        assert!((parent as usize) < node_count);
        let p = parent as usize;
        if lefts[p] == uint::MAX {
            lefts[p] = node as uint;
        } else if rights[p] == uint::MAX {
            rights[p] = node as uint;
        } else {
            panic!("Tree::FromVectors(), invalid vector topology");
        }
    }
    assert!(root != uint::MAX);

    let mut leaf_nodes = Vec::new();
    let mut int_nodes = Vec::new();
    let mut node_to_leaf_index = vec![uint::MAX; node_count];
    let mut node_to_int_index = vec![uint::MAX; node_count];
    for node in 0..node_count {
        if lefts[node] == uint::MAX {
            assert!(rights[node] == uint::MAX);
            let leaf_index = leaf_nodes.len() as uint;
            node_to_leaf_index[node] = leaf_index;
            leaf_nodes.push(node as uint);
        } else {
            assert!(rights[node] != uint::MAX);
            let int_index = int_nodes.len() as uint;
            node_to_int_index[node] = int_index;
            int_nodes.push(node as uint);
        }
    }

    let leaf_count = leaf_nodes.len();
    let int_count = int_nodes.len();
    assert!(leaf_count == (node_count + 1) / 2);
    assert!(int_count == leaf_count - 1);

    t.node_count = node_count as uint;
    t.cache_count = node_count as uint;
    t.neighbor1 = vec![NULL_NEIGHBOR; node_count];
    t.neighbor2 = vec![NULL_NEIGHBOR; node_count];
    t.neighbor3 = vec![NULL_NEIGHBOR; node_count];
    t.edge_length1 = vec![0.0; node_count];
    t.edge_length2 = vec![0.0; node_count];
    t.edge_length3 = vec![0.0; node_count];
    t.height = vec![0.0; node_count];
    t.has_edge_length1 = vec![false; node_count];
    t.has_edge_length2 = vec![false; node_count];
    t.has_edge_length3 = vec![false; node_count];
    t.has_height = vec![false; node_count];
    t.ids = vec![uint::MAX; node_count];
    t.names = vec![None; node_count];
    t.rooted = false;
    t.root_node_index = uint::MAX;

    for (i, node) in leaf_nodes.iter().enumerate() {
        let node = *node as usize;
        let label = &labels[node];
        assert!(!label.is_empty());
        t.ids[i] = i as uint;
        t.names[i] = Some(label.clone());
    }

    for (i, node) in int_nodes.iter().enumerate() {
        let node = *node as usize;
        let new_node = leaf_count + i;
        let left = lefts[node] as usize;
        let right = rights[node] as usize;

        let left_int_index = node_to_int_index[left];
        let right_int_index = node_to_int_index[right];
        let left_leaf_index = node_to_leaf_index[left];
        let right_leaf_index = node_to_leaf_index[right];

        let new_left_node = if left_int_index == uint::MAX {
            assert!((left_leaf_index as usize) < leaf_count);
            left_leaf_index
        } else {
            assert!((left_int_index as usize) < int_count);
            leaf_count as uint + left_int_index
        };
        let new_right_node = if right_int_index == uint::MAX {
            assert!((right_leaf_index as usize) < leaf_count);
            right_leaf_index
        } else {
            assert!((right_int_index as usize) < int_count);
            leaf_count as uint + right_int_index
        };

        t.neighbor2[new_node] = new_left_node;
        t.neighbor3[new_node] = new_right_node;
        t.neighbor1[new_left_node as usize] = new_node as uint;
        t.neighbor1[new_right_node as usize] = new_node as uint;
        t.has_edge_length1[new_left_node as usize] = false;
        t.has_edge_length1[new_right_node as usize] = false;

        let left_length = lengths[left];
        let right_length = lengths[right];
        t.has_edge_length2[new_node] = false;
        t.has_edge_length3[new_node] = false;
        if (left_length as f64) != MISSING_LENGTH {
            t.has_edge_length2[new_node] = true;
            t.edge_length2[new_node] = left_length as f64;
            t.has_edge_length1[new_left_node as usize] = true;
            t.edge_length1[new_left_node as usize] = left_length as f64;
        }
        if (right_length as f64) != MISSING_LENGTH {
            t.has_edge_length3[new_node] = true;
            t.edge_length3[new_node] = right_length as f64;
            t.has_edge_length1[new_right_node as usize] = true;
            t.edge_length1[new_right_node as usize] = right_length as f64;
        }
    }

    let new_root_int_index = node_to_int_index[root as usize];
    assert!(new_root_int_index != uint::MAX);
    t.rooted = true;
    t.root_node_index = leaf_count as uint + new_root_int_index;
}

pub fn tree_create(
    t: &mut Tree,
    leaf_count: uint,
    root: uint,
    left: &[uint],
    right: &[uint],
    left_length: &[f32],
    right_length: &[f32],
    leaf_ids: &[uint],
    leaf_names: &[String],
) {
    *t = Tree::default();
    t.node_count = 2 * leaf_count - 1;
    tree_init_cache(t, t.node_count);

    for node_index in 0..leaf_count as usize {
        t.ids[node_index] = leaf_ids[node_index];
        t.names[node_index] = Some(leaf_names[node_index].clone());
    }

    for node_index in leaf_count..t.node_count {
        let i = node_index as usize;
        let v = (node_index - leaf_count) as usize;
        let left_node = left[v];
        let right_node = right[v];
        let left_len = left_length[v] as f64;
        let right_len = right_length[v] as f64;

        t.neighbor2[i] = left_node;
        t.neighbor3[i] = right_node;
        t.has_edge_length2[i] = true;
        t.has_edge_length3[i] = true;
        t.edge_length2[i] = left_len;
        t.edge_length3[i] = right_len;

        t.neighbor1[left_node as usize] = node_index;
        t.neighbor1[right_node as usize] = node_index;
        t.edge_length1[left_node as usize] = left_len;
        t.edge_length1[right_node as usize] = right_len;
        t.has_edge_length1[left_node as usize] = true;
        t.has_edge_length1[right_node as usize] = true;
    }

    t.rooted = true;
    t.root_node_index = root + leaf_count;
}

pub fn tree_get_subtree_sizes(t: &Tree) -> Vec<uint> {
    assert!(t.rooted);
    let node_count = t.node_count;
    let mut sizes = vec![uint::MAX; node_count as usize];
    let mut node = tree_first_depth_first_node(t);
    loop {
        assert!(node < node_count);
        let i = node as usize;
        let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if t.node_count == 1 || neighbor_count == 1 {
            sizes[i] = 1;
        } else {
            let left = t.neighbor2[i];
            let right = t.neighbor3[i];
            assert!(left < node_count);
            assert!(right < node_count);
            let size_left = sizes[left as usize];
            let size_right = sizes[right as usize];
            assert!(size_left != uint::MAX && size_left > 0);
            assert!(size_right != uint::MAX && size_right > 0);
            assert!(sizes[i] == uint::MAX);
            sizes[i] = size_left + size_right;
        }
        node = tree_next_depth_first_node(t, node);
        if node == uint::MAX {
            break;
        }
    }
    sizes
}

pub fn phy_enum_edges(tree: &Tree, es: &mut PhyEnumEdgeState) -> bool {
    let node1;
    if !es.init {
        if tree.node_count <= 1 {
            es.node_index1 = NULL_NEIGHBOR;
            es.node_index2 = NULL_NEIGHBOR;
            return false;
        }
        node1 = tree_first_depth_first_node(tree);
        es.init = true;
    } else {
        let mut next = tree_next_depth_first_node(tree, es.node_index1);
        if next == NULL_NEIGHBOR {
            return false;
        }
        if tree.rooted && tree.root_node_index == next {
            next = tree_next_depth_first_node(tree, next);
            if next == NULL_NEIGHBOR {
                return false;
            }
        }
        node1 = next;
    }
    let node2 = tree.neighbor1[node1 as usize];
    es.node_index1 = node1;
    es.node_index2 = node2;
    true
}

pub fn phy_enum_edges_r(tree: &Tree, es: &mut PhyEnumEdgeState) -> bool {
    let node1;
    if !es.init {
        if tree.node_count <= 1 {
            es.node_index1 = NULL_NEIGHBOR;
            es.node_index2 = NULL_NEIGHBOR;
            return false;
        }
        node1 = tree_first_depth_first_node_r(tree);
        es.init = true;
    } else {
        let mut next = tree_next_depth_first_node_r(tree, es.node_index1);
        if next == NULL_NEIGHBOR {
            return false;
        }
        if tree.rooted && tree.root_node_index == next {
            next = tree_next_depth_first_node(tree, next);
            if next == NULL_NEIGHBOR {
                return false;
            }
        }
        node1 = next;
    }
    let node2 = tree.neighbor1[node1 as usize];
    es.node_index1 = node1;
    es.node_index2 = node2;
    true
}

pub fn get_leaves_subtree(
    tree: &Tree,
    node_index1: uint,
    node_index2: uint,
    leaves: &mut Vec<uint>,
) {
    let i = node_index1 as usize;
    let neighbor_count = (tree.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (tree.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (tree.neighbor3[i] != NULL_NEIGHBOR) as uint;
    if tree.node_count == 1 || neighbor_count == 1 {
        leaves.push(node_index1);
        return;
    }

    let left = tree_get_first_neighbor(tree, node_index1, node_index2);
    let right = tree_get_second_neighbor(tree, node_index1, node_index2);
    if left != NULL_NEIGHBOR {
        get_leaves_subtree(tree, left, node_index1, leaves);
    }
    if right != NULL_NEIGHBOR {
        get_leaves_subtree(tree, right, node_index1, leaves);
    }
}

pub fn phy_get_leaves(tree: &Tree, node_index1: uint, node_index2: uint) -> Vec<uint> {
    let mut leaves = Vec::new();
    get_leaves_subtree(tree, node_index1, node_index2, &mut leaves);
    leaves
}

pub fn phy_enum_bi_parts(tree: &Tree, es: &mut PhyEnumEdgeState) -> Option<(Vec<uint>, Vec<uint>)> {
    let mut ok = phy_enum_edges(tree, es);
    if !ok {
        return None;
    }

    if tree.rooted
        && tree.root_node_index == es.node_index2
        && tree.neighbor3[es.node_index2 as usize] == es.node_index1
    {
        ok = phy_enum_edges(tree, es);
        if !ok {
            return None;
        }
    }

    let leaves1 = phy_get_leaves(tree, es.node_index1, es.node_index2);
    let leaves2 = phy_get_leaves(tree, es.node_index2, es.node_index1);
    let leaf_count = if tree.rooted {
        assert!(tree.node_count % 2 == 1);
        (tree.node_count + 1) / 2
    } else {
        assert!(tree.node_count % 2 == 0);
        (tree.node_count + 2) / 2
    };
    if leaves1.len() as uint + leaves2.len() as uint != leaf_count {
        panic!(
            "PhyEnumBiParts {} + {} != {}",
            leaves1.len(),
            leaves2.len(),
            leaf_count
        );
    }
    Some((leaves1, leaves2))
}

#[track_caller]
pub fn test_bi_part(tree: &Tree) -> String {
    let mut out = tree_log_me(tree);
    let mut es = PhyEnumEdgeState {
        init: false,
        node_index1: NULL_NEIGHBOR,
        node_index2: NULL_NEIGHBOR,
    };
    loop {
        let bipart = phy_enum_bi_parts(tree, &mut es);
        let ok = bipart.is_some();
        out.push_str(&format!(
            "PEBP={} ES.Init={} ES.ni1={} ES.ni2={}\n",
            ok as uint, es.init as uint, es.node_index1, es.node_index2
        ));
        let Some((leaves1, leaves2)) = bipart else {
            break;
        };
        out.push('\n');
        out.push_str("Part1: ");
        for leaf in &leaves1 {
            let name = tree_get_leaf_name(tree, *leaf).unwrap_or("");
            out.push_str(&format!(" {}({})", leaf, name));
        }
        out.push('\n');
        out.push_str("Part2: ");
        for leaf in &leaves2 {
            let name = tree_get_leaf_name(tree, *leaf).unwrap_or("");
            out.push_str(&format!(" {}({})", leaf, name));
        }
        out.push('\n');
    }
    out
}

pub fn get_leaves_subtree_excluding(
    tree: &Tree,
    node_index: uint,
    exclude: uint,
    leaves: &mut Vec<uint>,
) {
    if node_index == exclude {
        return;
    }

    let i = node_index as usize;
    let neighbor_count = (tree.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (tree.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (tree.neighbor3[i] != NULL_NEIGHBOR) as uint;
    if tree.node_count == 1 || neighbor_count == 1 {
        leaves.push(node_index);
        return;
    }

    let left = tree.neighbor2[i];
    let right = tree.neighbor3[i];
    if left != NULL_NEIGHBOR {
        get_leaves_subtree_excluding(tree, left, exclude, leaves);
    }
    if right != NULL_NEIGHBOR {
        get_leaves_subtree_excluding(tree, right, exclude, leaves);
    }
}

pub fn get_leaves_excluding(tree: &Tree, node_index: uint, exclude: uint) -> Vec<uint> {
    let mut leaves = Vec::new();
    get_leaves_subtree_excluding(tree, node_index, exclude, &mut leaves);
    leaves
}

pub fn get_internal_nodes_in_height_order(tree: &mut Tree) -> Vec<uint> {
    let node_count = tree.node_count;
    if node_count < 3 {
        panic!("GetInternalNodesInHeightOrder: {node_count} nodes, none are internal");
    }
    let internal_node_count = (node_count - 1) / 2;
    let mut node_indexes = Vec::new();
    let mut heights = Vec::new();
    for node_index in 0..node_count {
        let i = node_index as usize;
        let neighbor_count = (tree.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (tree.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (tree.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if tree.node_count == 1 || neighbor_count == 1 {
            continue;
        }
        node_indexes.push(node_index);
        heights.push(tree_get_node_height(tree, node_index));
    }
    if node_indexes.len() as uint != internal_node_count {
        panic!("Internal error: GetInternalNodesInHeightOrder");
    }

    let mut done = false;
    while !done {
        done = true;
        for i in 0..(internal_node_count as usize - 1) {
            if heights[i] > heights[i + 1] {
                heights.swap(i, i + 1);
                node_indexes.swap(i, i + 1);
                done = false;
            }
        }
    }
    node_indexes
}

pub fn apply_min_edge_length(tree: &mut Tree, min_edge_length: f64) {
    let node_count = tree.node_count;
    for node_index in 0..node_count {
        let i = node_index as usize;
        let neighbor_count = (tree.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (tree.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (tree.neighbor3[i] != NULL_NEIGHBOR) as uint;
        for n in 0..neighbor_count {
            let neighbor_node_index = tree_get_neighbor(tree, node_index, n);
            if !tree_has_edge_length(tree, node_index, neighbor_node_index) {
                continue;
            }
            if tree_get_edge_length(tree, node_index, neighbor_node_index) < min_edge_length {
                tree_set_edge_length(tree, node_index, neighbor_node_index, min_edge_length);
            }
        }
    }
}

#[track_caller]
pub fn cluster_by_height(tree: &mut Tree, d_max_height: f64) -> Vec<uint> {
    if !tree.rooted {
        panic!("ClusterByHeight: requires rooted tree");
    }

    let mut subtrees = Vec::new();
    for node_index in 0..tree.node_count {
        if node_index == tree.root_node_index {
            continue;
        }
        let parent = tree.neighbor1[node_index as usize];
        let height = tree_get_node_height(tree, node_index);
        let parent_height = tree_get_node_height(tree, parent);
        if parent_height > d_max_height && height <= d_max_height {
            subtrees.push(node_index);
        }
    }
    subtrees
}

#[track_caller]
pub fn cluster_by_subfam_count_iteration(tree: &mut Tree, subfams: &mut [uint], count: uint) {
    let mut highest_height = -1e20;
    let mut parent_subscript = i32::MIN;

    for n in 0..count as usize {
        let node_index = subfams[n];
        let i = node_index as usize;
        let neighbor_count = (tree.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (tree.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (tree.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if tree.node_count == 1 || neighbor_count == 1 {
            continue;
        }

        let left = tree.neighbor2[i];
        let height_left = tree_get_node_height(tree, left);
        if height_left > highest_height {
            highest_height = height_left;
            parent_subscript = n as i32;
        }

        let right = tree.neighbor3[i];
        let height_right = tree_get_node_height(tree, right);
        if height_right > highest_height {
            highest_height = height_right;
            parent_subscript = n as i32;
        }
    }

    if parent_subscript == i32::MIN {
        panic!("CBSFCIter: failed to find highest child");
    }

    let node_index = subfams[parent_subscript as usize];
    let left = tree.neighbor2[node_index as usize];
    let right = tree.neighbor3[node_index as usize];
    subfams[parent_subscript as usize] = left;
    subfams[count as usize] = right;
}

#[track_caller]
pub fn cluster_by_subfam_count(tree: &mut Tree, subfam_count: uint) -> Vec<uint> {
    let node_count = tree.node_count;
    let leaf_count = (node_count + 1) / 2;

    if node_count == 0 {
        return Vec::new();
    }

    if subfam_count >= leaf_count {
        return (0..leaf_count).collect();
    }

    let mut subfams = vec![NULL_NEIGHBOR; subfam_count as usize];
    subfams[0] = tree.root_node_index;
    for i in 1..subfam_count {
        cluster_by_subfam_count_iteration(tree, &mut subfams, i);
    }
    subfams
}

#[track_caller]
pub fn get_leaves_recurse(tree: &Tree, node_index: uint, leaves: &mut Vec<uint>) {
    let i = node_index as usize;
    let neighbor_count = (tree.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (tree.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (tree.neighbor3[i] != NULL_NEIGHBOR) as uint;
    if tree.node_count == 1 || neighbor_count == 1 {
        leaves.push(node_index);
        return;
    }

    let left = tree.neighbor2[i];
    let right = tree.neighbor3[i];
    get_leaves_recurse(tree, left, leaves);
    get_leaves_recurse(tree, right, leaves);
}

#[track_caller]
pub fn get_leaves(tree: &Tree, node_index: uint) -> Vec<uint> {
    let mut leaves = Vec::new();
    get_leaves_recurse(tree, node_index, &mut leaves);
    leaves
}

#[track_caller]
pub fn tree_prune_tree(
    pruned: &mut Tree,
    tree: &Tree,
    subfams: &[uint],
    label_prefix: &str,
) -> Vec<String> {
    if !tree.rooted {
        panic!("Tree::PruneTree: requires rooted tree");
    }
    let subfam_count = subfams.len();
    let mut labels = Vec::new();

    *pruned = Tree::default();
    pruned.node_count = 2 * subfam_count as uint - 1;
    tree_init_cache(pruned, pruned.node_count);

    let unpruned_node_count = tree.node_count as usize;
    let pruned_node_count = pruned.node_count as usize;
    let mut unpruned_to_pruned_index = vec![NULL_NEIGHBOR; unpruned_node_count];
    let mut pruned_to_unpruned_index = vec![NULL_NEIGHBOR; pruned_node_count];

    let mut internal_node_index = subfam_count as uint;
    for (subfam_index, subfam) in subfams.iter().enumerate() {
        let mut unpruned_node_index = *subfam;
        unpruned_to_pruned_index[unpruned_node_index as usize] = subfam_index as uint;
        pruned_to_unpruned_index[subfam_index] = unpruned_node_index;
        loop {
            unpruned_node_index = tree.neighbor1[unpruned_node_index as usize];
            if unpruned_node_index == tree.root_node_index {
                break;
            }
            if unpruned_to_pruned_index[unpruned_node_index as usize] != NULL_NEIGHBOR {
                break;
            }

            unpruned_to_pruned_index[unpruned_node_index as usize] = internal_node_index;
            pruned_to_unpruned_index[internal_node_index as usize] = unpruned_node_index;
            internal_node_index += 1;
        }
    }

    let unpruned_root_index = tree.root_node_index;
    unpruned_to_pruned_index[unpruned_root_index as usize] = internal_node_index;
    pruned_to_unpruned_index[internal_node_index as usize] = unpruned_root_index;

    if internal_node_index != pruned.node_count - 1 {
        panic!("Tree::PruneTree, Internal error");
    }

    for subfam_index in 0..subfam_count {
        let label = format!("{label_prefix}{subfam_index}");
        pruned.names[subfam_index] = Some(label.clone());
        labels.push(label);
    }

    for pruned_node_index in subfam_count..pruned_node_count {
        let unpruned_node_index = pruned_to_unpruned_index[pruned_node_index];
        let unpruned_left = tree.neighbor2[unpruned_node_index as usize];
        let unpruned_right = tree.neighbor3[unpruned_node_index as usize];
        let pruned_left = unpruned_to_pruned_index[unpruned_left as usize];
        let pruned_right = unpruned_to_pruned_index[unpruned_right as usize];

        let left_length = tree_get_edge_length(tree, unpruned_node_index, unpruned_left);
        let right_length = tree_get_edge_length(tree, unpruned_node_index, unpruned_right);

        pruned.neighbor2[pruned_node_index] = pruned_left;
        pruned.neighbor3[pruned_node_index] = pruned_right;

        pruned.edge_length1[pruned_left as usize] = left_length;
        pruned.edge_length1[pruned_right as usize] = right_length;

        pruned.neighbor1[pruned_left as usize] = pruned_node_index as uint;
        pruned.neighbor1[pruned_right as usize] = pruned_node_index as uint;

        pruned.has_edge_length1[pruned_left as usize] = true;
        pruned.has_edge_length1[pruned_right as usize] = true;

        pruned.edge_length2[pruned_node_index] = left_length;
        pruned.edge_length3[pruned_node_index] = right_length;

        pruned.has_edge_length2[pruned_node_index] = true;
        pruned.has_edge_length3[pruned_node_index] = true;
    }

    pruned.root_node_index = unpruned_to_pruned_index[unpruned_root_index as usize];
    pruned.rooted = true;
    tree_validate(pruned);
    labels
}

#[track_caller]
pub fn leaf_indexes_to_ids(tree: &Tree, leaves: &[uint]) -> Vec<uint> {
    let mut ids = Vec::new();
    for leaf in leaves {
        ids.push(tree_get_leaf_id(tree, *leaf));
    }
    ids
}

#[track_caller]
pub fn tree_ntt_str(ntt: NEWICKTOKENTYPE) -> &'static str {
    match ntt {
        NEWICKTOKENTYPE::NTT_Unknown => "Unknown",
        NEWICKTOKENTYPE::NTT_Lparen => "Lparen",
        NEWICKTOKENTYPE::NTT_Rparen => "Rparen",
        NEWICKTOKENTYPE::NTT_Colon => "Colon",
        NEWICKTOKENTYPE::NTT_Comma => "Comma",
        NEWICKTOKENTYPE::NTT_Semicolon => "Semicolon",
        NEWICKTOKENTYPE::NTT_String => "String",
        NEWICKTOKENTYPE::NTT_SingleQuotedString => "SingleQuotedString",
        NEWICKTOKENTYPE::NTT_DoubleQuotedString => "DoubleQuotedString",
        NEWICKTOKENTYPE::NTT_Comment => "Comment",
    }
}

#[track_caller]
pub fn tree_get_token(file: &mut TextFile, bytes: uint) -> (NEWICKTOKENTYPE, String) {
    text_file_skip_white(file);

    let mut c = text_file_get_char_x(file);
    match c {
        b'(' => return (NEWICKTOKENTYPE::NTT_Lparen, "(".to_string()),
        b')' => return (NEWICKTOKENTYPE::NTT_Rparen, ")".to_string()),
        b':' => return (NEWICKTOKENTYPE::NTT_Colon, ":".to_string()),
        b';' => return (NEWICKTOKENTYPE::NTT_Semicolon, ";".to_string()),
        b',' => return (NEWICKTOKENTYPE::NTT_Comma, ",".to_string()),
        _ => {}
    }

    let tt = match c {
        b'\'' => {
            c = text_file_get_char_x(file);
            NEWICKTOKENTYPE::NTT_SingleQuotedString
        }
        b'"' => {
            c = text_file_get_char_x(file);
            NEWICKTOKENTYPE::NTT_DoubleQuotedString
        }
        b'[' => NEWICKTOKENTYPE::NTT_Comment,
        _ => NEWICKTOKENTYPE::NTT_String,
    };

    let mut token = Vec::new();
    loop {
        if tt != NEWICKTOKENTYPE::NTT_Comment {
            if token.len() < bytes as usize - 2 {
                token.push(c);
            } else {
                panic!(
                    "Tree::GetToken: input buffer too small, token so far='{}'",
                    String::from_utf8_lossy(&token)
                );
            }
        }

        let Some(next) = text_file_get_char(file) else {
            return (tt, String::from_utf8_lossy(&token).into_owned());
        };
        c = next;

        match tt {
            NEWICKTOKENTYPE::NTT_String => {
                if b"():;,".contains(&c) {
                    file.pushed_back = Some(c);
                    return (
                        NEWICKTOKENTYPE::NTT_String,
                        String::from_utf8_lossy(&token).into_owned(),
                    );
                }
                if (c as char).is_ascii_whitespace() {
                    return (
                        NEWICKTOKENTYPE::NTT_String,
                        String::from_utf8_lossy(&token).into_owned(),
                    );
                }
            }
            NEWICKTOKENTYPE::NTT_SingleQuotedString => {
                if c == b'\'' {
                    return (
                        NEWICKTOKENTYPE::NTT_String,
                        String::from_utf8_lossy(&token).into_owned(),
                    );
                }
            }
            NEWICKTOKENTYPE::NTT_DoubleQuotedString => {
                if c == b'"' {
                    return (
                        NEWICKTOKENTYPE::NTT_String,
                        String::from_utf8_lossy(&token).into_owned(),
                    );
                }
            }
            NEWICKTOKENTYPE::NTT_Comment => {
                if c == b']' {
                    return tree_get_token(file, bytes);
                }
            }
            _ => panic!("Tree::GetToken, invalid TT={:?}", tt),
        }
    }
}

#[track_caller]
pub fn tree_from_file_l143(tree: &mut Tree, file_name: &str) {
    let mut file = text_file_text_file_l5(file_name, false);
    tree_from_file_l150(tree, &mut file);
    text_file_destructor_text_file(&mut file);
}

#[track_caller]
pub fn tree_from_file_l150(tree: &mut Tree, file: &mut TextFile) {
    tree_create_rooted(tree);

    let root_edge_length = tree_get_group_from_file(tree, file, 0);
    let (ntt, token) = tree_get_token(file, 16);

    if ntt == NEWICKTOKENTYPE::NTT_Semicolon {
        tree_validate(tree);
        return;
    }

    if ntt != NEWICKTOKENTYPE::NTT_Comma {
        panic!("Tree::FromFile, expected ';' or ',', got '{token}'");
    }

    let third_node = tree_unroot_from_file(tree);
    let third_edge_length = tree_get_group_from_file(tree, file, third_node);
    if let Some(edge_length) = third_edge_length {
        tree_set_edge_length(tree, 0, third_node, edge_length);
    }
    let _ = root_edge_length;
    tree_validate(tree);
}

#[track_caller]
pub fn tree_get_group_from_file(
    tree: &mut Tree,
    file: &mut TextFile,
    node_index: uint,
) -> Option<f64> {
    let (mut ntt, mut token) = tree_get_token(file, 1024);

    if ntt == NEWICKTOKENTYPE::NTT_String {
        tree_set_leaf_name(tree, node_index, &token);
    } else if ntt == NEWICKTOKENTYPE::NTT_Lparen {
        let left = tree_append_branch(tree, node_index);
        let right = left + 1;

        if let Some(edge_length) = tree_get_group_from_file(tree, file, left) {
            tree_set_edge_length(tree, node_index, left, edge_length);
        }

        (ntt, token) = tree_get_token(file, 1024);
        if ntt != NEWICKTOKENTYPE::NTT_Comma {
            panic!("Tree::GetGroupFromFile, expected ',', got '{token}'");
        }

        if let Some(edge_length) = tree_get_group_from_file(tree, file, right) {
            tree_set_edge_length(tree, node_index, right, edge_length);
        }

        (ntt, token) = tree_get_token(file, 1024);
        if ntt == NEWICKTOKENTYPE::NTT_Rparen {
        } else if ntt == NEWICKTOKENTYPE::NTT_Comma {
            file.pushed_back = Some(b',');
            return None;
        } else {
            panic!("Tree::GetGroupFromFile, expected ')' or ',', got '{token}'");
        }
    } else {
        panic!("Tree::GetGroupFromFile, expected '(' or leaf name, got '{token}'");
    }

    if text_file_skip_white_x(file) {
        return None;
    }
    let c = text_file_get_char_x(file);
    if c == b':' {
        let (edge_ntt, edge_token) = tree_get_token(file, 1024);
        if edge_ntt != NEWICKTOKENTYPE::NTT_String {
            panic!("Tree::GetGroupFromFile, expected edge length, got '{edge_token}'");
        }
        return Some(edge_token.parse::<f64>().unwrap_or(0.0));
    }
    file.pushed_back = Some(c);
    None
}

#[track_caller]
pub fn str_to_treeperm(s: &str) -> TREEPERM {
    match s {
        "none" => TREEPERM::TP_None,
        "abc" => TREEPERM::TP_ABC,
        "acb" => TREEPERM::TP_ACB,
        "bca" => TREEPERM::TP_BCA,
        "all" => TREEPERM::TP_All,
        _ => panic!("Invalid perm '{s}'"),
    }
}

#[track_caller]
pub fn treeperm_to_str(tp: TREEPERM) -> &'static str {
    match tp {
        TREEPERM::TP_None => "none",
        TREEPERM::TP_ABC => "abc",
        TREEPERM::TP_ACB => "acb",
        TREEPERM::TP_BCA => "bca",
        TREEPERM::TP_All => "all",
    }
}

#[track_caller]
pub fn tree_splitter_run(ts: &mut TreeSplitter, t: &Tree, split_count: uint) {
    ts.t = Some(t.clone());
    let tree = ts.t.as_ref().unwrap();
    let node_count = tree.node_count;
    let root = tree.root_node_index;
    ts.target_size = node_count / split_count;
    ts.split_count = split_count;
    if ts.target_size == 0 {
        ts.target_size = 1;
    }
    ts.subtree_nodes.clear();
    ts.subtree_nodes.push(root);
    let mut terminated_early = false;
    for split_index in 1..ts.split_count {
        ts.split_index = split_index;
        assert!(ts.subtree_nodes.len() as uint == ts.split_index);
        let biggest_node = tree_splitter_get_biggest_node(ts);
        let i = biggest_node as usize;
        let neighbor_count = (tree.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (tree.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (tree.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if tree.node_count == 1 || neighbor_count == 1 {
            terminated_early = true;
            break;
        }
        let left = tree.neighbor2[biggest_node as usize];
        let right = tree.neighbor3[biggest_node as usize];
        assert!(left != uint::MAX);
        assert!(right != uint::MAX);

        let mut new_subtree_nodes = Vec::new();
        for &node in &ts.subtree_nodes {
            if node == biggest_node {
                new_subtree_nodes.push(left);
                new_subtree_nodes.push(right);
            } else {
                new_subtree_nodes.push(node);
            }
        }
        ts.subtree_nodes = new_subtree_nodes;
        let _ = tree_splitter_log_state(ts);
    }
    if !terminated_early {
        assert!(ts.subtree_nodes.len() as uint == ts.split_count);
    }
}

#[track_caller]
pub fn tree_splitter_get_size_order(ts: &TreeSplitter) -> Vec<uint> {
    let tree = ts.t.as_ref().expect("TreeSplitter::GetSizeOrder, no tree");
    let mut order: Vec<uint> = (0..ts.subtree_nodes.len() as uint).collect();
    order.sort_by(|a, b| {
        let size_a = tree_get_subtree_leaf_count(tree, ts.subtree_nodes[*a as usize]);
        let size_b = tree_get_subtree_leaf_count(tree, ts.subtree_nodes[*b as usize]);
        size_b.cmp(&size_a).then_with(|| a.cmp(b))
    });
    order
}

#[track_caller]
pub fn tree_splitter_log_state(ts: &TreeSplitter) -> String {
    let tree = ts.t.as_ref().expect("TreeSplitter::LogState, no tree");
    let mut out = String::new();
    out.push('\n');
    out.push_str(&format!(
        "_______________ Split {} ______________\n",
        ts.split_index
    ));
    out.push_str(" Node   Size  LSize  RSize\n");
    let order = tree_splitter_get_size_order(ts);
    let mut sum_size = 0_u32;
    for i in 0..ts.subtree_nodes.len() {
        let k = order[i] as usize;
        let node = ts.subtree_nodes[k];
        let size = tree_get_subtree_leaf_count(tree, node);
        sum_size += size;
        out.push_str(&format!("{node:5}"));
        out.push_str(&format!("  {size:5}"));
        let ni = node as usize;
        let neighbor_count = (tree.neighbor1[ni] != NULL_NEIGHBOR) as uint
            + (tree.neighbor2[ni] != NULL_NEIGHBOR) as uint
            + (tree.neighbor3[ni] != NULL_NEIGHBOR) as uint;
        if !(tree.node_count == 1 || neighbor_count == 1) {
            let left = tree.neighbor2[ni];
            let right = tree.neighbor2[ni];
            let l_size = tree_get_subtree_leaf_count(tree, left);
            let r_size = tree_get_subtree_leaf_count(tree, right);
            out.push_str(&format!("  {l_size:5}  {r_size:5}"));
        }
        out.push('\n');
    }
    out.push_str(&format!("Total {sum_size}\n"));
    out
}

#[track_caller]
pub fn tree_splitter_get_biggest_node(ts: &TreeSplitter) -> uint {
    let tree =
        ts.t.as_ref()
            .expect("TreeSplitter::GetBiggestNode, no tree");
    let mut max_size = 0_u32;
    let mut max_node = uint::MAX;
    for &node in &ts.subtree_nodes {
        let size = tree_get_subtree_leaf_count(tree, node);
        if size > max_size {
            max_node = node;
            max_size = size;
        }
    }
    assert!(max_node != uint::MAX);
    max_node
}

#[track_caller]
pub fn tree_splitter_get_labels_vec(ts: &TreeSplitter) -> Vec<Vec<String>> {
    let tree = ts.t.as_ref().expect("TreeSplitter::GetLabelsVec, no tree");
    let split_count = ts.subtree_nodes.len();
    let order = tree_splitter_get_size_order(ts);
    assert!(order.len() == split_count);
    let mut labels_vec = Vec::with_capacity(split_count);
    for i in 0..split_count {
        let k = order[i] as usize;
        let node = ts.subtree_nodes[k];
        labels_vec.push(tree_get_subtree_leaf_labels(tree, node));
    }
    labels_vec
}

#[track_caller]
pub fn tree_splitter_write_labels(ts: &TreeSplitter, file_name_prefix: &str) -> Vec<String> {
    if file_name_prefix.is_empty() {
        return Vec::new();
    }
    let labels_vec = tree_splitter_get_labels_vec(ts);
    let mut file_names = Vec::new();
    for (i, labels) in labels_vec.iter().enumerate() {
        let labels_file_name = format!("{file_name_prefix}{}", i + 1);
        let mut text = String::new();
        for label in labels {
            text.push_str(label);
            text.push('\n');
        }
        std::fs::write(&labels_file_name, text).expect("failed to write split labels");
        file_names.push(labels_file_name);
    }
    file_names
}

#[track_caller]
pub fn tree_splitter_get_subtree(ts: &TreeSplitter) -> (Tree, Vec<String>) {
    let tree = ts.t.as_ref().expect("TreeSplitter::GetSubtree, no tree");
    let size = ts.subtree_nodes.len();
    let mut split_labels = Vec::new();
    for i in 0..size {
        split_labels.push(format!("split{i}"));
    }
    let subtree = make_subset_nodes(tree, &ts.subtree_nodes, &split_labels);
    (subtree, split_labels)
}

#[track_caller]
pub fn cmd_split_tree(
    tree_file_name: &str,
    n: uint,
    prefix: &str,
    output_file_name: Option<&str>,
) -> Option<Vec<String>> {
    assert!(n > 1);
    let mut t = Tree::default();
    tree_from_file_l143(&mut t, tree_file_name);
    assert!(t.rooted);

    let mut splitter = TreeSplitter::default();
    tree_splitter_run(&mut splitter, &t, n);
    let files = tree_splitter_write_labels(&splitter, prefix);

    if let Some(output_file_name) = output_file_name {
        let (subtree, _sub_labels) = tree_splitter_get_subtree(&splitter);
        tree_to_file_l13(&subtree, output_file_name);
    }
    Some(files)
}

#[track_caller]
pub fn ints_from_file(file_name: &str) -> (Vec<uint>, Vec<String>) {
    let text = std::fs::read_to_string(file_name)
        .unwrap_or_else(|e| panic!("OpenStdioFile({file_name}) failed: {e}"));
    let mut ints = Vec::new();
    let mut labels = Vec::new();
    for line in text.lines() {
        let fields = split(line, '\t');
        assert!(fields.len() == 2);
        let i = str_to_uint_l1278(&fields[0], false);
        let label = fields[1].clone();
        ints.push(i);
        labels.push(label);
    }
    (ints, labels)
}

#[track_caller]
pub fn make_subset_nodes(
    input_tree: &Tree,
    subset_nodes: &[uint],
    subset_labels: &[String],
) -> Tree {
    if !input_tree.rooted {
        panic!("Tree must be rooted");
    }

    let subset_node_count = subset_nodes.len();
    if subset_node_count < 2 {
        panic!("Need at least two nodes");
    }
    assert!(subset_labels.len() == subset_node_count);

    let node_count = input_tree.node_count;

    let mut old_node_to_new_label = std::collections::BTreeMap::<uint, String>::new();
    let mut subset_set = std::collections::BTreeSet::<uint>::new();
    for i in 0..subset_node_count {
        let subset_node = subset_nodes[i];
        subset_set.insert(subset_node);
        old_node_to_new_label.insert(subset_node, subset_labels[i].clone());
    }

    let mut parent_set = std::collections::BTreeSet::<uint>::new();
    for &subset_node in subset_nodes.iter().take(subset_node_count) {
        let path = tree_get_path_to_root(input_tree, subset_node);
        let n = path.len();
        assert!(path[0] == subset_node);
        for &node in path.iter().take(n).skip(1) {
            assert!(node < node_count);
            if subset_set.contains(&node) {
                parent_set.insert(node);
            }
        }
    }

    let parent_count = parent_set.len();
    let mut new_tips = std::collections::BTreeSet::<uint>::new();
    for &node in &subset_set {
        if !parent_set.contains(&node) {
            new_tips.insert(node);
        }
    }
    let new_tip_count = new_tips.len();
    if new_tip_count == 1 {
        panic!("One tip in subset tree");
    }

    assert!(new_tip_count + parent_count == subset_node_count);

    let mut node_to_path_count = vec![0_u32; node_count as usize];
    for &tip in &new_tips {
        let path = tree_get_path_to_root(input_tree, tip);
        let n = path.len();
        assert!(path[0] == tip);
        for &node2 in path.iter().take(n) {
            node_to_path_count[node2 as usize] += 1;
        }
    }

    let mut old_node_to_new_parent = vec![uint::MAX; node_count as usize];
    let mut pending = std::collections::BTreeSet::<uint>::new();
    let mut done = std::collections::BTreeSet::<uint>::new();
    for &tip in &new_tips {
        pending.insert(tip);
    }

    loop {
        if pending.is_empty() {
            break;
        }
        let node = *pending.iter().next().unwrap();
        assert!(!done.contains(&node));
        done.insert(node);
        pending.remove(&node);
        if input_tree.rooted && input_tree.root_node_index == node {
            continue;
        }

        let path = tree_get_path_to_root(input_tree, node);
        assert!(path[0] == node);
        let n = path.len();
        let mut new_parent = uint::MAX;
        for &node2 in path.iter().take(n).skip(1) {
            let left = input_tree.neighbor2[node2 as usize];
            let right = input_tree.neighbor3[node2 as usize];
            assert!(left != uint::MAX);
            assert!(right != uint::MAX);
            let left_path_count = node_to_path_count[left as usize];
            let right_path_count = node_to_path_count[right as usize];
            if left_path_count > 0 && right_path_count > 0 {
                new_parent = node2;
                break;
            }
        }
        assert!(old_node_to_new_parent[node as usize] == uint::MAX);
        old_node_to_new_parent[node as usize] = new_parent;
        if new_parent != uint::MAX && !done.contains(&new_parent) {
            pending.insert(new_parent);
        }
    }

    let mut old_node_to_new_node = vec![uint::MAX; node_count as usize];
    let mut new_node_to_old_node = Vec::new();
    for &old_node in &done {
        assert!((old_node as usize) < old_node_to_new_node.len());
        let new_node = new_node_to_old_node.len() as uint;

        old_node_to_new_node[old_node as usize] = new_node;
        new_node_to_old_node.push(old_node);
    }

    let mut new_parents = Vec::new();
    let mut new_lengths = Vec::new();
    let mut new_labels = Vec::new();
    for &old_node in &done {
        assert!((old_node as usize) < old_node_to_new_node.len());
        assert!((old_node as usize) < old_node_to_new_parent.len());
        let parent = old_node_to_new_parent[old_node as usize];
        let mut new_parent = uint::MAX;
        if parent != uint::MAX {
            new_parent = old_node_to_new_node[parent as usize];
        }

        let label = if let Some(label) = old_node_to_new_label.get(&old_node) {
            label.clone()
        } else {
            input_tree.names[old_node as usize]
                .clone()
                .unwrap_or_default()
        };

        let distance = if parent == uint::MAX {
            0.0
        } else {
            tree_get_distance(input_tree, old_node, parent) as f32
        };

        new_parents.push(new_parent);
        new_labels.push(label);
        new_lengths.push(distance);
    }

    let mut subset_tree = Tree::default();
    tree_from_vectors(&mut subset_tree, &new_labels, &new_parents, &new_lengths);
    subset_tree
}

#[track_caller]
pub fn cmd_tree_subset_nodes(
    input_file_name: &str,
    nodes_file_name: &str,
    output_file_name: &str,
    right: bool,
) {
    let (nodes, new_labels) = ints_from_file(nodes_file_name);

    let mut t = Tree::default();
    tree_from_file_l143(&mut t, input_file_name);

    let subtree = make_subset_nodes(&t, &nodes, &new_labels);
    tree_ladderize(&mut t, right);
    tree_to_file_l13(&subtree, output_file_name);
}

#[track_caller]
pub fn tree_get_any_non_leaf_node(t: &Tree) -> uint {
    for node_index in 0..t.node_count {
        let i = node_index as usize;
        let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
            + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
        if !(t.node_count == 1 || neighbor_count == 1) {
            return node_index;
        }
    }
    NULL_NEIGHBOR
}

#[track_caller]
pub fn tree_to_file_l13(t: &Tree, file_name: &str) {
    if file_name.is_empty() {
        return;
    }
    let mut file = TextFile::default();
    tree_to_file_l22(t, &mut file);
    std::fs::write(file_name, &file.data).expect("failed to write tree file");
}

#[track_caller]
pub fn tree_to_file_l22(t: &Tree, file: &mut TextFile) {
    if t.rooted {
        tree_to_file_node_rooted(t, file, t.root_node_index);
        text_file_put_string(file, ";\n");
        return;
    }

    let node_index = tree_get_any_non_leaf_node(t);
    text_file_put_string(file, "(\n");
    tree_to_file_node_unrooted(t, file, t.neighbor1[node_index as usize], node_index);
    text_file_put_string(file, ",\n");
    tree_to_file_node_unrooted(t, file, t.neighbor2[node_index as usize], node_index);
    text_file_put_string(file, ",\n");
    tree_to_file_node_unrooted(t, file, t.neighbor3[node_index as usize], node_index);
    text_file_put_string(file, ");\n");
}

#[track_caller]
pub fn tree_to_file_node_unrooted(t: &Tree, file: &mut TextFile, node_index: uint, parent: uint) {
    assert!(!t.rooted);
    let format_g = |d: f64| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let exp = d.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 6 {
            let raw = format!("{d:.5e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (5 - exp).max(0) as usize;
            format!("{d:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };

    let i = node_index as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    let group = !(t.node_count == 1 || neighbor_count == 1);
    if group {
        text_file_put_string(file, "(\n");
    }

    if t.node_count == 1 || neighbor_count == 1 {
        text_file_put_string(file, t.names[i].as_deref().unwrap_or(""));
    } else {
        tree_to_file_node_unrooted(
            t,
            file,
            tree_get_first_neighbor(t, node_index, parent),
            node_index,
        );
        text_file_put_string(file, ",\n");
        tree_to_file_node_unrooted(
            t,
            file,
            tree_get_second_neighbor(t, node_index, parent),
            node_index,
        );
    }

    if group {
        text_file_put_string(file, ")");
    }

    if tree_has_edge_length(t, node_index, parent) {
        text_file_put_string(
            file,
            &format!(":{}", format_g(tree_get_edge_length(t, node_index, parent))),
        );
    }
    text_file_put_string(file, "\n");
}

#[track_caller]
pub fn tree_to_file_node_rooted(t: &Tree, file: &mut TextFile, node_index: uint) {
    assert!(t.rooted);
    let format_g = |d: f64| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let exp = d.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 6 {
            let raw = format!("{d:.5e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (5 - exp).max(0) as usize;
            format!("{d:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };

    let i = node_index as usize;
    let neighbor_count = (t.neighbor1[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor2[i] != NULL_NEIGHBOR) as uint
        + (t.neighbor3[i] != NULL_NEIGHBOR) as uint;
    let is_leaf = t.node_count == 1 || neighbor_count == 1;
    let is_root = node_index == t.root_node_index;
    let group = !is_leaf || is_root;
    if group {
        text_file_put_string(file, "(\n");
    }

    if is_leaf {
        text_file_put_string(file, t.names[i].as_deref().unwrap_or(""));
    } else {
        tree_to_file_node_rooted(t, file, t.neighbor2[i]);
        text_file_put_string(file, ",\n");
        tree_to_file_node_rooted(t, file, t.neighbor3[i]);
    }

    if group {
        text_file_put_string(file, ")");
    }

    if !is_root {
        let parent = t.neighbor1[i];
        if tree_has_edge_length(t, node_index, parent) {
            text_file_put_string(
                file,
                &format!(":{}", format_g(tree_get_edge_length(t, node_index, parent))),
            );
        }
    }
    text_file_put_string(file, "\n");
}

#[track_caller]
pub fn delete_all_gap_columns(msa: &mut MultiSequence) {
    let seq_count = msa.seqs.len() as uint;
    let col_count = multi_sequence_get_col_count(msa);

    let mut keeps = Vec::new();
    let mut keep_count = 0;
    for col_index in 0..col_count {
        let keep = msa_get_gap_count(msa, col_index) < seq_count;
        keeps.push(keep);
        if keep {
            keep_count += 1;
        }
    }
    if keep_count == 0 {
        panic!("MSA is all gaps");
    }

    for seq_index in 0..seq_count {
        let mut new_row = Vec::with_capacity(keep_count as usize);
        for col_index in 0..col_count {
            let c = msa.seqs[seq_index as usize].char_vec[col_index as usize];
            if !keeps[col_index as usize] {
                assert!(c == '-' || c == '.');
                continue;
            }
            new_row.push(c);
        }
        assert_eq!(new_row.len(), keep_count as usize);
        msa.seqs[seq_index as usize].char_vec = new_row;
    }
}

#[track_caller]
pub fn trim_to_ref(test: &MultiSequence, ref_msa: &MultiSequence) -> MultiSequence {
    let test_seq_count = test.seqs.len() as uint;
    let test_col_count = multi_sequence_get_col_count(test);

    let ref_seq_count = test.seqs.len() as uint;
    let ref_col_count = multi_sequence_get_col_count(ref_msa);

    let (ref_labels, ref_label_to_seq_index) = msa_get_label_to_seq_index(ref_msa);
    let (test_labels, test_label_to_seq_index) = msa_get_label_to_seq_index(test);
    assert_eq!(ref_labels.len(), ref_seq_count as usize);
    assert_eq!(test_labels.len(), test_seq_count as usize);

    let mut labels = Vec::new();
    let mut ref_seq_indexes = Vec::new();
    for test_seq_index in 0..test_seq_count {
        let label = &test_labels[test_seq_index as usize];
        if let Some(ref_seq_index) = ref_label_to_seq_index.get(label).copied() {
            labels.push(label.clone());
            ref_seq_indexes.push(ref_seq_index);
        }
    }

    let trimmed_seq_count = ref_seq_indexes.len() as uint;
    let mut trimmed = MultiSequence::default();
    msa_set_size(&mut trimmed, trimmed_seq_count, test_col_count);
    for trimmed_seq_index in 0..trimmed_seq_count {
        let ref_seq_index = ref_seq_indexes[trimmed_seq_index as usize];
        let label = &labels[trimmed_seq_index as usize];
        trimmed.seqs[trimmed_seq_index as usize].label = label.clone();

        let mut pos_to_upper = Vec::new();
        for ref_col_index in 0..ref_col_count {
            let c = ref_msa.seqs[ref_seq_index as usize].char_vec[ref_col_index as usize];
            if c != '-' && c != '.' {
                pos_to_upper.push(c.is_ascii_uppercase());
            }
        }

        let test_seq_index = test_label_to_seq_index
            .get(label)
            .copied()
            .expect("trim_to_ref test label missing");
        let mut pos = 0usize;
        for test_col_index in 0..test_col_count {
            let mut c = test.seqs[test_seq_index as usize].char_vec[test_col_index as usize];
            if c != '-' && c != '.' {
                let upper = pos_to_upper[pos];
                pos += 1;
                if !upper {
                    c = '-';
                }
            }
            trimmed.seqs[trimmed_seq_index as usize].char_vec[test_col_index as usize] = c;
        }
        assert_eq!(pos, pos_to_upper.len());
    }
    delete_all_gap_columns(&mut trimmed);
    trimmed
}

#[track_caller]
pub fn cmd_trimtoref(
    test_file_name: &str,
    ref_file_name: &str,
    output_file_name: &str,
) -> MultiSequence {
    let test = msa_from_fasta_file_l95(test_file_name);
    let ref_msa = msa_from_fasta_file_preserve_case(ref_file_name);
    let trimmed = trim_to_ref(&test, &ref_msa);
    if !output_file_name.is_empty() {
        msa_to_fasta_file_l103(&trimmed, output_file_name);
    }
    trimmed
}

#[track_caller]
pub fn cmd_trimtoref_efa(
    efa_file_name: &str,
    ref_file_name: &str,
    output_file_name: &str,
) -> Ensemble {
    let mut e = Ensemble::default();
    ensemble_from_file(&mut e, efa_file_name);

    let ref_msa = msa_from_fasta_file_preserve_case(ref_file_name);

    let msa_count = e.msas.len() as uint;
    let mut out = String::new();
    let mut trimmed_ensemble = Ensemble::default();
    for msa_index in 0..msa_count {
        let msa_name = ensemble_get_msa_name(&e, msa_index);
        out.push('<');
        out.push_str(msa_name);
        out.push('\n');

        let test_msa = ensemble_get_msa(&e, msa_index);
        let trimmed_msa = trim_to_ref(test_msa, &ref_msa);
        out.push_str(&msa_to_fasta_file_l112(&trimmed_msa));
        trimmed_ensemble.msa_names.push(msa_name.to_string());
        trimmed_ensemble.msas.push(trimmed_msa);
    }

    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, out).expect("failed to write trimtoref_efa output");
    }
    trimmed_ensemble
}

#[track_caller]
pub fn u_clust_align_seq_pair<F>(
    u: &UClust,
    seq_index1: uint,
    seq_index2: uint,
    mut align_pair_flat: F,
) -> (f32, String)
where
    F: FnMut(&str, &str) -> (f32, String),
{
    let input_seqs = u
        .input_seqs
        .as_ref()
        .expect("UClust::AlignSeqPair null input seqs");
    let seq1 = &input_seqs.seqs[seq_index1 as usize];
    let seq2 = &input_seqs.seqs[seq_index2 as usize];
    let label1 = &seq1.label;
    let label2 = &seq2.label;
    align_pair_flat(label1, label2)
}

#[track_caller]
pub fn u_clust_add_seq_to_index(u: &mut UClust, seq_index: uint) {
    let input_seqs = u
        .input_seqs
        .as_ref()
        .expect("UClust::AddSeqToIndex null input seqs");
    let seq = &input_seqs.seqs[seq_index as usize];
    let byte_seq = sequence_get_seq_as_string(seq).into_bytes();
    u_sorter_add_seq(&mut u.us, &byte_seq, seq_index);
}

#[track_caller]
pub fn u_clust_search<F>(u: &UClust, seq_index: uint, mut align_pair_flat: F) -> (uint, String)
where
    F: FnMut(&str, &str) -> (f32, String),
{
    let input_seqs = u
        .input_seqs
        .as_ref()
        .expect("UClust::Search null input seqs");
    let seq = &input_seqs.seqs[seq_index as usize];
    let byte_seq = sequence_get_seq_as_string(seq).into_bytes();

    let (top_seq_indexes, top_word_counts) = u_sorter_search_seq(&u.us, &byte_seq);
    let mut top_count = top_seq_indexes.len();
    assert_eq!(top_word_counts.len(), top_count);
    if top_count == 0 {
        return (uint::MAX, String::new());
    }
    const MAX_REJECTS: usize = 8;
    if top_count > MAX_REJECTS {
        top_count = MAX_REJECTS;
    }

    let mut centroid_seq_index = uint::MAX;
    let mut found_path = String::new();
    for top_index in 0..top_count {
        let top_seq_index = top_seq_indexes[top_index];
        let (ea, path) = u_clust_align_seq_pair(u, seq_index, top_seq_index, |label1, label2| {
            align_pair_flat(label1, label2)
        });
        if ea >= u.min_ea {
            centroid_seq_index = top_seq_index;
            found_path = path;
            break;
        }
    }
    (centroid_seq_index, found_path)
}

#[track_caller]
pub fn u_clust_run<F>(
    u: &mut UClust,
    input_seqs: &MultiSequence,
    min_ea: f32,
    mut align_pair_flat: F,
) -> String
where
    F: FnMut(&str, &str) -> (f32, String),
{
    u.input_seqs = Some(input_seqs.clone());
    u.min_ea = min_ea;
    u_sorter_init(&mut u.us);

    let input_seq_count = input_seqs.seqs.len() as uint;
    let gsi_count = get_global_ms_seq_count();
    let mut gsi_to_input_seq_index = vec![uint::MAX; gsi_count as usize];
    for seq_index in 0..input_seq_count {
        let label = input_seqs.seqs[seq_index as usize].label.clone();
        let gsi = get_gsi_by_label(&label);
        assert!(gsi < gsi_count);
        assert_eq!(gsi_to_input_seq_index[gsi as usize], uint::MAX);
        gsi_to_input_seq_index[gsi as usize] = seq_index;
    }

    let mut centroid_count = 0;
    let mut member_count = 0;

    u.seq_index_to_centroid_seq_index.clear();
    u.seq_index_to_path.clear();
    u.seq_index_to_centroid_seq_index
        .resize(input_seq_count as usize, uint::MAX);
    u.seq_index_to_path
        .resize(input_seq_count as usize, String::new());

    let order = multi_sequence_get_length_order(input_seqs);
    let mut last_length = uint::MAX;
    let min_ee = 1.0 - u.min_ea;
    let mut out = String::new();
    for k in 0..input_seq_count {
        let seq_index = order[k as usize];
        assert!(seq_index < input_seq_count);
        let l = multi_sequence_get_seq_length(input_seqs, seq_index);
        assert!(l <= last_length);
        last_length = l;

        out.push_str(&format!(
            "UCLUST {input_seq_count} seqs EE<{min_ee:.2}, {centroid_count} centroids, {member_count} members\n"
        ));

        let (mut rep_seq_index, path) = u_clust_search(u, seq_index, |label1, label2| {
            align_pair_flat(label1, label2)
        });
        u.seq_index_to_path[seq_index as usize] = path;
        if rep_seq_index == uint::MAX {
            u.centroid_seq_indexes.push(seq_index);
            u_clust_add_seq_to_index(u, seq_index);
            centroid_count += 1;
            rep_seq_index = seq_index;
            u.seq_index_to_path[seq_index as usize].clear();
        } else {
            member_count += 1;
        }

        u.seq_index_to_centroid_seq_index[seq_index as usize] = rep_seq_index;
    }
    out
}

#[track_caller]
pub fn u_clust_get_centroid_seqs(u: &UClust, centroid_seqs: &mut MultiSequence) {
    let input_seqs = u
        .input_seqs
        .as_ref()
        .expect("UClust::GetCentroidSeqs null input seqs");
    let centroid_count = u.centroid_seq_indexes.len();
    for i in 0..centroid_count {
        let seq_index = u.centroid_seq_indexes[i];
        let seq = &input_seqs.seqs[seq_index as usize];
        centroid_seqs.seqs.push(seq.clone());
        centroid_seqs.owners.push(false);
    }
    assert_same_labels("uclust.cpp", 132, centroid_seqs);
}

#[track_caller]
pub fn u_clust_get_gs_is(u: &UClust) -> (Vec<uint>, Vec<uint>, Vec<uint>, Vec<String>) {
    let mut centroid_gs_is = Vec::<uint>::new();
    let mut member_gs_is = Vec::<uint>::new();
    let mut member_centroid_gs_is = Vec::<uint>::new();
    let mut gsi_to_member_centroid_path = Vec::<String>::new();

    let input_seqs = u
        .input_seqs
        .as_ref()
        .expect("UClust::GetGSIs null input seqs");
    let input_seq_count = input_seqs.seqs.len();
    let gsi_count = get_gsi_count();

    gsi_to_member_centroid_path.resize(gsi_count as usize, String::new());

    let cluster_count = u.centroid_seq_indexes.len();
    for cluster_index in 0..cluster_count {
        let centroid_seq_index = u.centroid_seq_indexes[cluster_index];
        let seq = &input_seqs.seqs[centroid_seq_index as usize];
        let centroid_gsi = get_gsi_by_label(&seq.label);
        centroid_gs_is.push(centroid_gsi);
    }

    assert_eq!(u.seq_index_to_centroid_seq_index.len(), input_seq_count);
    for member_seq_index in 0..input_seq_count {
        let centroid_seq_index = u.seq_index_to_centroid_seq_index[member_seq_index];
        if centroid_seq_index == member_seq_index as uint {
            continue;
        }

        let path = &u.seq_index_to_path[member_seq_index];
        let member_seq = &input_seqs.seqs[member_seq_index];
        let centroid_seq = &input_seqs.seqs[centroid_seq_index as usize];

        let member_gsi = get_gsi_by_label(&member_seq.label);
        let member_centroid_gsi = get_gsi_by_label(&centroid_seq.label);

        member_gs_is.push(member_gsi);
        member_centroid_gs_is.push(member_centroid_gsi);

        assert!(!path.is_empty());
        gsi_to_member_centroid_path[member_gsi as usize] = path.clone();
    }

    (
        centroid_gs_is,
        member_gs_is,
        member_centroid_gs_is,
        gsi_to_member_centroid_path,
    )
}

#[track_caller]
pub fn cmd_uclust<FAlignPairFlat>(
    input_file_name: &str,
    output_file_name: &str,
    min_ea: f32,
    mut align_pair_flat: FAlignPairFlat,
) -> (UClust, MultiSequence)
where
    FAlignPairFlat: FnMut(&str, &str) -> (f32, String),
{
    let mut input_seqs = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut input_seqs, input_file_name, true);
    set_global_input_ms(&input_seqs);

    let is_nucleo = multi_sequence_guess_is_nucleo(&input_seqs);
    if is_nucleo {
        set_alpha_l209(ALPHA::ALPHA_Nucleo);
    } else {
        set_alpha_l209(ALPHA::ALPHA_Amino);
    }

    let mut u = UClust::default();
    u_clust_run(&mut u, &input_seqs, min_ea, |label1, label2| {
        align_pair_flat(label1, label2)
    });

    let mut centroid_seqs = MultiSequence::default();
    u_clust_get_centroid_seqs(&u, &mut centroid_seqs);
    let mut out = String::new();
    for seq in &centroid_seqs.seqs {
        out.push_str(&seq_to_fasta_l2561(
            &sequence_get_seq_as_string(seq),
            &seq.label,
        ));
    }
    if !output_file_name.is_empty() {
        std::fs::write(output_file_name, out).expect("failed to write UClust centroids FASTA");
    }
    (u, centroid_seqs)
}

#[track_caller]
pub fn get_dp_mem_l17() -> XDPMem {
    let mut mems = UCLUST_PD_DP_MEMS.lock().unwrap();
    if mems.is_empty() {
        let n = get_requested_thread_count();
        assert!(n > 0);
        for _i in 0..n {
            mems.push(XDPMem::default());
        }
    }
    let thread_index = get_thread_index();
    assert!(thread_index < mems.len() as uint);
    mems[thread_index as usize].clone()
}

#[track_caller]
pub fn u_clust_pd_get_label(uc: &UClustPD, seq_index: uint) -> String {
    let input = uc.input_seqs.as_ref().expect("UClustPD input seqs not set");
    input.seqs[seq_index as usize].label.clone()
}

#[track_caller]
pub fn u_clust_pd_get_byte_seq(uc: &UClustPD, seq_index: uint) -> (Vec<byte>, uint) {
    let input = uc.input_seqs.as_ref().expect("UClustPD input seqs not set");
    let seq = &input.seqs[seq_index as usize];
    let bytes: Vec<byte> = sequence_get_seq_as_string(seq).into_bytes();
    let l = bytes.len() as uint;
    (bytes, l)
}

#[track_caller]
pub fn u_clust_pd_get_prot_dist_pair<FViterbi, FDist>(
    uc: &UClustPD,
    seq_indexi: uint,
    seq_indexj: uint,
    path: Option<&mut String>,
    mut viterbi_fast_mem: FViterbi,
    mut get_prot_dist: FDist,
) -> f64
where
    FViterbi: FnMut(&[byte], uint, &[byte], uint) -> PathInfo,
    FDist: FnMut(&str, &str, uint) -> f64,
{
    let (seqi, li) = u_clust_pd_get_byte_seq(uc, seq_indexi);
    let _labeli = u_clust_pd_get_label(uc, seq_indexi);
    let (seqj, lj) = u_clust_pd_get_byte_seq(uc, seq_indexj);
    let _labelj = u_clust_pd_get_label(uc, seq_indexj);

    get_prot_dist_seq_pair(
        &seqi,
        li,
        &seqj,
        lj,
        path,
        |seqi, li, seqj, lj| viterbi_fast_mem(seqi, li, seqj, lj),
        |row_x, row_y, col_count| get_prot_dist(row_x, row_y, col_count),
    )
}

#[track_caller]
pub fn u_clust_pd_search_all<F>(uc: &UClustPD, seq_index: uint, mut get_prot_dist_pair: F) -> uint
where
    F: FnMut(uint, uint) -> f64,
{
    let n = uc.subset_seq_indexes.len() as uint;
    let mut hit_count = 0;
    for i in 0..n {
        let seq_index2 = uc.subset_seq_indexes[i as usize];
        if seq_index2 == seq_index {
            continue;
        }
        let d = get_prot_dist_pair(seq_index, seq_index2);
        if d < uc.max_pd {
            hit_count += 1;
        }
    }
    hit_count
}

#[track_caller]
pub fn u_clust_pd_search<F>(
    uc: &UClustPD,
    seq_index: uint,
    centroids: &[uint],
    mut get_prot_dist_pair: F,
) -> (uint, f64)
where
    F: FnMut(uint, uint) -> f64,
{
    let n = centroids.len() as uint;
    let mut best_centroid_index = uint::MAX;
    let mut best_dist = f64::from(f32::MAX);
    for i in 0..n {
        let centroid_index = centroids[i as usize];
        assert!((centroid_index as usize) < uc.centroid_seq_indexes.len());
        let centroid_seq_index = uc.centroid_seq_indexes[centroid_index as usize];
        let d = get_prot_dist_pair(seq_index, centroid_seq_index);
        if d > uc.max_pd {
            continue;
        }
        if d < best_dist {
            best_dist = d;
            best_centroid_index = centroid_index;
        }
    }
    (best_centroid_index, best_dist)
}

#[track_caller]
pub fn u_clust_pd_centroids_to_fasta(uc: &UClustPD, file_name: &str) {
    if file_name.is_empty() {
        return;
    }
    let input = uc.input_seqs.as_ref().expect("UClustPD input seqs not set");
    let cluster_count = uc.centroid_seq_indexes.len();
    assert_eq!(uc.centroid_seq_indexes.len(), cluster_count);
    let mut out = String::new();
    for cluster_index in 0..cluster_count {
        let centroid_seq_index = uc.centroid_seq_indexes[cluster_index] as usize;
        let seq = &input.seqs[centroid_seq_index];
        out.push_str(&seq_to_fasta_l2561(
            &sequence_get_seq_as_string(seq),
            &seq.label,
        ));
    }
    std::fs::write(file_name, out).expect("failed to write UClustPD centroids FASTA");
}

#[track_caller]
pub fn u_clust_pd_run<F>(
    uc: &mut UClustPD,
    input_seqs: &MultiSequence,
    subset_seq_indexes: &[uint],
    max_pd: f64,
    thread_count: uint,
    mut search: F,
) -> String
where
    F: FnMut(&UClustPD, uint, &[uint]) -> (uint, f64),
{
    uc.thread_count = 1;
    uc.input_seqs = None;
    uc.subset_seq_indexes.clear();
    uc.max_pd = -1.0;
    uc.pending_subset_indexes.clear();
    uc.centroid_seq_indexes.clear();
    uc.centroid_index_to_member_subset_indexes.clear();
    uc.subset_index_to_centroid_index.clear();
    uc.subset_index_to_dist.clear();

    uc.thread_count = thread_count;
    uc.max_pd = max_pd;
    uc.input_seqs = Some(input_seqs.clone());
    uc.subset_seq_indexes = subset_seq_indexes.to_vec();

    let subset_size = uc.subset_seq_indexes.len() as uint;
    for i in 0..subset_size {
        uc.pending_subset_indexes.push(i);
    }

    uc.subset_index_to_centroid_index
        .resize(subset_size as usize, uint::MAX);
    uc.subset_index_to_dist.resize(subset_size as usize, 0.0);
    let format_g3 = |d: f64| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let exp = d.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 3 {
            let raw = format!("{d:.2e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (2 - exp).max(0) as usize;
            format!("{d:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };
    let mut iter = 0;
    let mut out = String::new();
    loop {
        iter += 1;
        let mut pending_count = uc.pending_subset_indexes.len() as uint;
        let done_count = subset_size - pending_count;
        let done_pct = if subset_size == 0 {
            0.0
        } else {
            100.0 * f64::from(done_count) / f64::from(subset_size)
        };
        let done_pct_s = format_g3(done_pct);
        out.push_str(&format!(
            "Iter [{iter}] {} clusters, (assigned {done_pct_s}%, remaining {pending_count})\n",
            uc.centroid_seq_indexes.len()
        ));
        let begin_size = uc.pending_subset_indexes.len() as uint;
        if begin_size == 0 {
            break;
        }

        let mut new_seeds = Vec::new();
        let mut done_vec1 = Vec::new();
        for p_index in 0..uc.pending_subset_indexes.len() {
            let subset_index = uc.pending_subset_indexes[p_index];
            assert!((subset_index as usize) < uc.subset_seq_indexes.len());
            let seq_index = uc.subset_seq_indexes[subset_index as usize];

            let (centroid_index, _d) = search(uc, seq_index, &new_seeds);
            if centroid_index == uint::MAX {
                let centroid_index = uc.centroid_seq_indexes.len() as uint;
                new_seeds.push(centroid_index);
                uc.subset_index_to_centroid_index[subset_index as usize] = centroid_index;
                uc.subset_index_to_dist[subset_index as usize] = 0.0;
                uc.centroid_seq_indexes.push(seq_index);

                uc.centroid_index_to_member_subset_indexes
                    .push(vec![subset_index]);
                assert_eq!(
                    uc.centroid_seq_indexes.len(),
                    uc.centroid_index_to_member_subset_indexes.len()
                );
                done_vec1.push(p_index);
            }
            if new_seeds.len() as uint >= uc.thread_count {
                break;
            }
        }
        assert!(!done_vec1.is_empty());
        if done_vec1.len() == uc.pending_subset_indexes.len() {
            uc.pending_subset_indexes.clear();
            break;
        }
        for i in done_vec1.iter().rev() {
            uc.pending_subset_indexes.remove(*i);
        }

        pending_count = uc.pending_subset_indexes.len() as uint;
        if pending_count == 0 {
            break;
        }

        let mut new_hit_count = 0;
        let mut done_vec2 = Vec::new();
        for p_index in 0..uc.pending_subset_indexes.len() {
            let subset_index = uc.pending_subset_indexes[p_index];
            assert!((subset_index as usize) < uc.subset_seq_indexes.len());
            let seq_index = uc.subset_seq_indexes[subset_index as usize];

            let (centroid_index, d) = search(uc, seq_index, &new_seeds);
            if centroid_index != uint::MAX {
                assert!((centroid_index as usize) < uc.centroid_seq_indexes.len());
                let centroid_seq_index = uc.centroid_seq_indexes[centroid_index as usize];
                let _label_q = u_clust_pd_get_label(uc, seq_index);
                let _label_c = u_clust_pd_get_label(uc, centroid_seq_index);
                uc.subset_index_to_centroid_index[subset_index as usize] = centroid_index;
                uc.subset_index_to_dist[subset_index as usize] = d;
                assert!(
                    (centroid_index as usize) < uc.centroid_index_to_member_subset_indexes.len()
                );
                uc.centroid_index_to_member_subset_indexes[centroid_index as usize]
                    .push(subset_index);
                new_hit_count += 1;
                done_vec2.push(p_index);
            }
        }
        let _ = new_hit_count;

        if done_vec2.len() == uc.pending_subset_indexes.len() {
            uc.pending_subset_indexes.clear();
            break;
        }
        for i in done_vec2.iter().rev() {
            uc.pending_subset_indexes.remove(*i);
        }
        let end_size = uc.pending_subset_indexes.len() as uint;
        assert!(end_size < begin_size);
    }
    out
}

#[track_caller]
pub fn u_clust_pd_get_cluster_size(uc: &UClustPD, cluster_index: uint) -> uint {
    assert!((cluster_index as usize) < uc.centroid_index_to_member_subset_indexes.len());
    uc.centroid_index_to_member_subset_indexes[cluster_index as usize].len() as uint
}

#[track_caller]
pub fn u_clust_pd_to_tsv_l260(uc: &UClustPD, file_name: &str) {
    if file_name.is_empty() {
        return;
    }
    std::fs::write(file_name, u_clust_pd_to_tsv_l269(uc)).expect("failed to write UClustPD TSV");
}

#[track_caller]
pub fn u_clust_pd_to_tsv_l269(uc: &UClustPD) -> String {
    let centroid_count = uc.centroid_seq_indexes.len();
    assert_eq!(
        uc.centroid_index_to_member_subset_indexes.len(),
        centroid_count
    );
    let subset_size = uc.subset_seq_indexes.len();
    assert_eq!(uc.subset_index_to_centroid_index.len(), subset_size);

    let mut out = String::new();
    let mut done_count = 0usize;
    for centroid_index in 0..centroid_count {
        let centroid_seq_index = uc.centroid_seq_indexes[centroid_index];
        let _centroid_label = u_clust_pd_get_label(uc, centroid_seq_index);
        let member_subset_indexes = &uc.centroid_index_to_member_subset_indexes[centroid_index];
        let n = member_subset_indexes.len();
        assert!(n > 0);
        for subset_index in member_subset_indexes {
            let subset_index = *subset_index as usize;
            let seq_index = uc.subset_seq_indexes[subset_index];
            assert!(subset_index < uc.subset_index_to_dist.len());
            let _d = uc.subset_index_to_dist[subset_index];
            let label = u_clust_pd_get_label(uc, seq_index);
            out.push_str(&format!("{centroid_index}\t{label}\n"));
        }
        done_count += n;
    }
    assert_eq!(done_count, subset_size);
    out
}

#[track_caller]
pub fn u_clust_pd_get_cluster_mfa(uc: &UClustPD, cluster_index: uint, mfa: &mut MultiSequence) {
    multi_sequence_clear(mfa);
    let input = uc.input_seqs.as_ref().expect("UClustPD input seqs not set");
    let cluster_size = u_clust_pd_get_cluster_size(uc, cluster_index);
    assert!((cluster_index as usize) < uc.centroid_index_to_member_subset_indexes.len());
    let subset_indexes = &uc.centroid_index_to_member_subset_indexes[cluster_index as usize];
    assert_eq!(subset_indexes.len() as uint, cluster_size);
    for i in 0..cluster_size {
        let subset_index = subset_indexes[i as usize] as usize;
        assert!(subset_index < uc.subset_seq_indexes.len());
        let seq_index = uc.subset_seq_indexes[subset_index] as usize;
        mfa.seqs.push(sequence_clone(&input.seqs[seq_index]));
        mfa.owners.push(false);
    }
}

#[track_caller]
pub fn u_clust_pd_get_cluster_mf_as(uc: &UClustPD) -> Vec<MultiSequence> {
    let mut mfas = Vec::new();
    let cluster_count = uc.centroid_seq_indexes.len() as uint;
    for cluster_index in 0..cluster_count {
        let mut cluster_mfa = MultiSequence::default();
        u_clust_pd_get_cluster_mfa(uc, cluster_index, &mut cluster_mfa);
        mfas.push(cluster_mfa);
    }
    mfas
}

#[track_caller]
pub fn u_clust_pd_get_cluster_sizes(uc: &UClustPD) -> Vec<uint> {
    let mut sizes = Vec::new();
    let cluster_count = uc.centroid_seq_indexes.len() as uint;
    for i in 0..cluster_count {
        sizes.push(u_clust_pd_get_cluster_size(uc, i));
    }
    sizes
}

#[track_caller]
pub fn u_clust_pd_log_stats(uc: &UClustPD) -> String {
    let cluster_count = uc.centroid_seq_indexes.len() as uint;
    let subset_size = uc.subset_seq_indexes.len() as uint;
    let avg_size = (subset_size / cluster_count) as f64;
    let cluster_sizes = u_clust_pd_get_cluster_sizes(uc);
    let mut singleton_count = 0;
    for i in 0..cluster_count {
        if cluster_sizes[i as usize] == 1 {
            singleton_count += 1;
        }
    }

    let mut order: Vec<uint> = (0..cluster_count).collect();
    if cluster_count > 0 {
        let mut stack = vec![(0_i32, cluster_count as i32 - 1)];
        while let Some((left, right)) = stack.pop() {
            let mut i = left;
            let mut j = right;
            let mid = (left + right) / 2;
            let pivot = cluster_sizes[order[mid as usize] as usize];
            while i <= j {
                while cluster_sizes[order[i as usize] as usize] > pivot {
                    i += 1;
                }
                while cluster_sizes[order[j as usize] as usize] < pivot {
                    j -= 1;
                }
                if i <= j {
                    order.swap(i as usize, j as usize);
                    i += 1;
                    j -= 1;
                }
            }
            if left < j {
                stack.push((left, j));
            }
            if i < right {
                stack.push((i, right));
            }
        }
    }
    let median_size = cluster_sizes[order[(cluster_count / 2) as usize] as usize];

    let mut out = String::new();
    out.push('\n');
    out.push_str(&format!(
        "{} seqs, {} clusters, avg size {:.1}, median {}, singletons {}\n",
        subset_size, cluster_count, avg_size, median_size, singleton_count
    ));
    for i in 0..std::cmp::min(10, cluster_count) {
        let k = order[i as usize];
        out.push_str(&format!(
            "    Cluster  [{:5}]   size {}\n",
            k, cluster_sizes[k as usize]
        ));
    }
    out
}

#[track_caller]
pub fn cmd_uclustpd<FGetProtDistPair>(
    input_file_name: &str,
    tsv_out_file_name: &str,
    max_pd: f64,
    thread_count: uint,
    mut get_prot_dist_pair: FGetProtDistPair,
) -> (UClustPD, String, String)
where
    FGetProtDistPair: FnMut(&UClustPD, uint, uint) -> f64,
{
    let mut input = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut input, input_file_name, true);

    let is_nucleo = multi_sequence_guess_is_nucleo(&input);
    set_alpha_l209(if is_nucleo {
        ALPHA::ALPHA_Nucleo
    } else {
        ALPHA::ALPHA_Amino
    });

    let seq_count = input.seqs.len() as uint;
    let mut all_seq_indexes = Vec::new();
    for i in 0..seq_count {
        all_seq_indexes.push(i);
    }

    let mut ud = UClustPD::default();
    let run_log = u_clust_pd_run(
        &mut ud,
        &input,
        &all_seq_indexes,
        max_pd,
        thread_count,
        |uc, seq_index, centroids| {
            u_clust_pd_search(uc, seq_index, centroids, |seq_indexi, seq_indexj| {
                get_prot_dist_pair(uc, seq_indexi, seq_indexj)
            })
        },
    );

    u_clust_pd_to_tsv_l260(&ud, tsv_out_file_name);
    let stats = u_clust_pd_log_stats(&ud);
    (ud, run_log, stats)
}

#[track_caller]
pub fn u_clust_pd_select_candidate_good_centroids<F>(uc: &UClustPD, mut search_all: F) -> Vec<uint>
where
    F: FnMut(&UClustPD, uint) -> uint,
{
    let mut subset_indexes = Vec::new();
    let mut unsorted_selected_indexes = Vec::new();
    let cluster_count = uc.centroid_seq_indexes.len() as uint;
    assert_eq!(
        uc.centroid_index_to_member_subset_indexes.len() as uint,
        cluster_count
    );
    let mut selected_hit_counts = Vec::new();
    for cluster_index in 0..cluster_count {
        let cluster_size = u_clust_pd_get_cluster_size(uc, cluster_index);
        if cluster_size < 8 {
            continue;
        }

        let member_subset_indexes =
            &uc.centroid_index_to_member_subset_indexes[cluster_index as usize];
        let n = (f64::from(cluster_size).log2() / 2.0) as uint;
        assert!(n >= 1);
        let mut sample_set = std::collections::BTreeSet::new();
        for _i in 0..2 * n {
            let r = randu32() % cluster_size;
            let subset_index = member_subset_indexes[r as usize];
            sample_set.insert(subset_index);
            if sample_set.len() as uint == n {
                break;
            }
        }

        let mut top_hit_count = 0;
        let mut top_subset_index = uint::MAX;
        for subset_index in sample_set {
            assert!((subset_index as usize) < uc.subset_seq_indexes.len());
            let _seq_index = uc.subset_seq_indexes[subset_index as usize];
            let hit_count = search_all(uc, subset_index);
            if hit_count > top_hit_count {
                top_hit_count = hit_count;
                top_subset_index = subset_index;
            }
        }
        if top_hit_count > cluster_size {
            unsorted_selected_indexes.push(top_subset_index);
            selected_hit_counts.push(top_hit_count);
        } else {
            let current_centroid =
                uc.centroid_index_to_member_subset_indexes[cluster_index as usize][0];
            unsorted_selected_indexes.push(current_centroid);
            selected_hit_counts.push(cluster_size);
        }
    }
    let n = unsorted_selected_indexes.len();
    let mut order: Vec<uint> = (0..n as uint).collect();
    order.sort_by(|a, b| {
        selected_hit_counts[*b as usize]
            .cmp(&selected_hit_counts[*a as usize])
            .then_with(|| a.cmp(b))
    });
    for k in 0..n {
        let i = order[k] as usize;
        let index = unsorted_selected_indexes[i];
        let _hit_count = selected_hit_counts[i];
        subset_indexes.push(index);
    }
    subset_indexes
}

#[track_caller]
pub fn cmd_uclustpd2<FGetProtDistPair, FSearchAll>(
    input_file_name: &str,
    output1_file_name: &str,
    output2_file_name: &str,
    centroids_file_name: &str,
    max_pd: f64,
    thread_count: uint,
    mut get_prot_dist_pair: FGetProtDistPair,
    mut search_all: FSearchAll,
) -> (
    UClustPD,
    Vec<uint>,
    Vec<uint>,
    String,
    String,
    String,
    String,
)
where
    FGetProtDistPair: FnMut(&UClustPD, uint, uint) -> f64,
    FSearchAll: FnMut(&UClustPD, uint) -> uint,
{
    let mut input = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut input, input_file_name, true);

    let is_nucleo = multi_sequence_guess_is_nucleo(&input);
    set_alpha_l209(if is_nucleo {
        ALPHA::ALPHA_Nucleo
    } else {
        ALPHA::ALPHA_Amino
    });

    let seq_count = input.seqs.len() as uint;
    let mut all_seq_indexes = Vec::new();
    for i in 0..seq_count {
        all_seq_indexes.push(i);
    }

    let mut ud = UClustPD::default();
    let run_log1 = u_clust_pd_run(
        &mut ud,
        &input,
        &all_seq_indexes,
        max_pd,
        thread_count,
        |uc, seq_index, centroids| {
            u_clust_pd_search(uc, seq_index, centroids, |seq_indexi, seq_indexj| {
                get_prot_dist_pair(uc, seq_indexi, seq_indexj)
            })
        },
    );
    let stats1 = u_clust_pd_log_stats(&ud);
    u_clust_pd_to_tsv_l260(&ud, output1_file_name);

    let sis = u_clust_pd_select_candidate_good_centroids(&ud, |uc, subset_index| {
        search_all(uc, subset_index)
    });

    let mut si_set = std::collections::BTreeSet::new();
    let mut all_seq_indexes2 = Vec::new();
    for index in &sis {
        let seq_index = all_seq_indexes[*index as usize];
        assert_eq!(*index, seq_index);
        si_set.insert(*index);
        all_seq_indexes2.push(seq_index);
    }
    for i in 0..seq_count {
        if !si_set.contains(&i) {
            all_seq_indexes2.push(i);
        }
    }

    let run_log2 = u_clust_pd_run(
        &mut ud,
        &input,
        &all_seq_indexes2,
        max_pd,
        thread_count,
        |uc, seq_index, centroids| {
            u_clust_pd_search(uc, seq_index, centroids, |seq_indexi, seq_indexj| {
                get_prot_dist_pair(uc, seq_indexi, seq_indexj)
            })
        },
    );
    let stats2 = u_clust_pd_log_stats(&ud);
    u_clust_pd_to_tsv_l260(&ud, output2_file_name);
    u_clust_pd_centroids_to_fasta(&ud, centroids_file_name);

    (
        ud,
        sis,
        all_seq_indexes2,
        run_log1,
        stats1,
        run_log2,
        stats2,
    )
}

#[track_caller]
pub fn avg(x: f32, y: f32) -> f32 {
    (x + y) / 2.0
}

#[track_caller]
pub fn upgma5_log_me(u: &UPGMA5) -> String {
    let triangle_subscript = |index1: uint, index2: uint| -> uint {
        let v = if index1 >= index2 {
            index2 + (index1 * (index1 - 1)) / 2
        } else {
            index1 + (index2 * (index2 - 1)) / 2
        };
        assert!(v < (u.leaf_count * (u.leaf_count - 1)) / 2);
        v
    };
    let format_g2 = |d: f32| -> String {
        if d == 0.0 {
            return "0".to_string();
        }
        if !d.is_finite() {
            return d.to_string();
        }
        let d64 = f64::from(d);
        let exp = d64.abs().log10().floor() as i32;
        let mut s = if exp < -4 || exp >= 2 {
            let raw = format!("{d64:.1e}");
            let (mantissa, exponent) = raw.split_once('e').unwrap();
            let mut mantissa = mantissa
                .trim_end_matches('0')
                .trim_end_matches('.')
                .to_string();
            if mantissa == "-0" {
                mantissa = "0".to_string();
            }
            let exp_value = exponent.parse::<i32>().unwrap();
            let sign = if exp_value >= 0 { '+' } else { '-' };
            format!("{mantissa}e{sign}{:02}", exp_value.abs())
        } else {
            let decimals = (1 - exp).max(0) as usize;
            format!("{d64:.decimals$}")
        };
        if !s.contains('e') && !s.contains('E') {
            s = s.trim_end_matches('0').trim_end_matches('.').to_string();
        }
        if s == "-0" {
            s = "0".to_string();
        }
        s
    };

    let mut out = String::new();
    out.push_str("Dist matrix\n");
    out.push_str("     ");
    for i in 0..u.leaf_count as usize {
        if u.node_index[i] == uint::MAX {
            continue;
        }
        out.push_str(&format!("  {:5}", u.node_index[i]));
    }
    out.push('\n');

    for i in 0..u.leaf_count as usize {
        if u.node_index[i] == uint::MAX {
            continue;
        }
        out.push_str(&format!("{:5}  ", u.node_index[i]));
        for j in 0..u.leaf_count as usize {
            if u.node_index[j] == uint::MAX {
                continue;
            }
            if i == j {
                out.push_str("       ");
            } else {
                let v = triangle_subscript(i as uint, j as uint);
                out.push_str(&format!("{:>5}  ", format_g2(u.dist[v as usize])));
            }
        }
        out.push_str(&format!("  {}", u.labels[i]));
        out.push('\n');
    }

    out.push('\n');
    out.push_str("    i   Node   NrNb      Dist\n");
    out.push_str("-----  -----  -----  --------\n");
    for i in 0..u.leaf_count as usize {
        if u.node_index[i] == uint::MAX {
            continue;
        }
        out.push_str(&format!(
            "{:5}  {:5}  {:5}  {:8.3}\n",
            i, u.node_index[i], u.nearest_neighbor[i], u.min_dist[i]
        ));
    }

    out.push('\n');
    out.push_str(" Node      L      R  Height  LLength  RLength\n");
    out.push_str("-----  -----  -----  ------  -------  -------\n");
    for i in 0..=u.internal_node_index as usize {
        out.push_str(&format!(
            "{:5}  {:5}  {:5}  {:>6}  {:>6}  {:>6}\n",
            i,
            u.left[i],
            u.right[i],
            format_g2(u.height[i]),
            format_g2(u.left_length[i]),
            format_g2(u.right_length[i])
        ));
    }
    out
}

#[track_caller]
pub fn upgma5_run_l75(u: &mut UPGMA5, linkage: &str, tree: &mut Tree) {
    match linkage {
        "min" | "max" | "avg" | "biased" => upgma5_run_l87(u, linkage, tree),
        _ => die(&format!("UPGMA5::Run(Linkage={linkage})")),
    }
}

#[track_caller]
pub fn upgma5_run_l87(u: &mut UPGMA5, linkage: &str, tree: &mut Tree) {
    u.leaf_count = u.labels.len() as uint;
    assert_eq!(u.dist_mx.len() as uint, u.leaf_count);
    for i in 0..u.leaf_count as usize {
        assert_eq!(u.dist_mx[i].len() as uint, u.leaf_count);
    }
    assert!(u.leaf_count >= 2);

    let triangle_subscript = |leaf_count: uint, index1: uint, index2: uint| -> uint {
        let v = if index1 >= index2 {
            index2 + (index1 * (index1 - 1)) / 2
        } else {
            index1 + (index2 * (index2 - 1)) / 2
        };
        assert!(v < (leaf_count * (leaf_count - 1)) / 2);
        v
    };

    u.triangle_size = (u.leaf_count * (u.leaf_count - 1)) / 2;
    u.internal_node_count = u.leaf_count - 1;
    u.dist = vec![0.0; u.triangle_size as usize];
    u.node_index = vec![uint::MAX; u.leaf_count as usize];
    u.nearest_neighbor = vec![uint::MAX; u.leaf_count as usize];
    u.min_dist = vec![f32::MAX; u.leaf_count as usize];
    let leaf_ids = (0..u.leaf_count).collect::<Vec<_>>();
    let leaf_names = u.labels.clone();
    u.left = vec![uint::MAX; u.internal_node_count as usize];
    u.right = vec![uint::MAX; u.internal_node_count as usize];
    u.height = vec![f32::MAX; u.internal_node_count as usize];
    u.left_length = vec![f32::MAX; u.internal_node_count as usize];
    u.right_length = vec![f32::MAX; u.internal_node_count as usize];

    for i in 0..u.leaf_count as usize {
        u.min_dist[i] = f32::MAX;
        u.node_index[i] = i as uint;
        u.nearest_neighbor[i] = uint::MAX;
    }

    for i in 1..u.leaf_count {
        let mut base = triangle_subscript(u.leaf_count, i, 0);
        for j in 0..i {
            let mut d = u.dist_mx[i as usize][j as usize];
            if d < 0.0 {
                d = 0.0;
                u.dist_mx[i as usize][j as usize] = 0.0;
                u.dist_mx[j as usize][i as usize] = 0.0;
            }
            u.dist[base as usize] = d;
            base += 1;
            if d < u.min_dist[i as usize] {
                u.min_dist[i as usize] = d;
                u.nearest_neighbor[i as usize] = j;
            }
            if d < u.min_dist[j as usize] {
                u.min_dist[j as usize] = d;
                u.nearest_neighbor[j as usize] = i;
            }
        }
        assert!(base <= u.triangle_size);
    }

    let join_count = u.leaf_count - 1;
    for internal_node_index in 0..join_count {
        u.internal_node_index = internal_node_index;
        let mut lmin = uint::MAX;
        let mut rmin = uint::MAX;
        let mut dt_min_dist = f32::MAX;
        for j in 0..u.leaf_count {
            if u.node_index[j as usize] == uint::MAX {
                continue;
            }
            let d = u.min_dist[j as usize];
            if d < dt_min_dist {
                dt_min_dist = d;
                lmin = j;
                rmin = u.nearest_neighbor[j as usize];
                assert_ne!(rmin, uint::MAX);
                assert_ne!(u.node_index[rmin as usize], uint::MAX);
            }
        }
        assert_ne!(lmin, uint::MAX);
        assert_ne!(rmin, uint::MAX);
        assert_ne!(dt_min_dist, f32::MAX);

        let mut dt_new_min_dist = f32::MAX;
        let mut new_nearest_neighbor = uint::MAX;
        for j in 0..u.leaf_count {
            if j == lmin || j == rmin {
                continue;
            }
            if u.node_index[j as usize] == uint::MAX {
                continue;
            }

            let vl = triangle_subscript(u.leaf_count, lmin, j);
            let vr = triangle_subscript(u.leaf_count, rmin, j);
            let dl = u.dist[vl as usize];
            let dr = u.dist[vr as usize];
            let dt_new_dist = match linkage {
                "avg" => avg(dl, dr),
                "min" => dl.min(dr),
                "max" => dl.max(dr),
                "biased" => 0.1 * avg(dl, dr) + (1.0 - 0.1) * dl.min(dr),
                _ => die(&format!("UPGMA5: Invalid LINKAGE_{linkage}")),
            };

            if u.nearest_neighbor[j as usize] == rmin {
                u.nearest_neighbor[j as usize] = lmin;
            }
            u.dist[vl as usize] = dt_new_dist;
            if dt_new_dist < dt_new_min_dist {
                dt_new_min_dist = dt_new_dist;
                new_nearest_neighbor = j;
            }
        }

        let v = triangle_subscript(u.leaf_count, lmin, rmin);
        let dlr = u.dist[v as usize];
        let height_new = dlr / 2.0;
        let left = u.node_index[lmin as usize];
        let right = u.node_index[rmin as usize];
        let height_left = if left < u.leaf_count {
            0.0
        } else {
            u.height[(left - u.leaf_count) as usize]
        };
        let height_right = if right < u.leaf_count {
            0.0
        } else {
            u.height[(right - u.leaf_count) as usize]
        };

        let ini = internal_node_index as usize;
        u.left[ini] = left;
        u.right[ini] = right;
        u.left_length[ini] = height_new - height_left;
        u.right_length[ini] = height_new - height_right;
        u.height[ini] = height_new;

        u.node_index[lmin as usize] = u.leaf_count + internal_node_index;
        u.nearest_neighbor[lmin as usize] = new_nearest_neighbor;
        u.min_dist[lmin as usize] = dt_new_min_dist;
        u.node_index[rmin as usize] = uint::MAX;
    }

    let root = u.leaf_count - 2;
    tree_create(
        tree,
        u.leaf_count,
        root,
        &u.left,
        &u.right,
        &u.left_length,
        &u.right_length,
        &leaf_ids,
        &leaf_names,
    );
}

#[track_caller]
pub fn upgma5_clear(u: &mut UPGMA5) {
    u.labels.clear();
    u.dist_mx.clear();
    u.label_to_index.clear();
}

#[track_caller]
pub fn upgma5_init(u: &mut UPGMA5, labels: &[String], dist_mx: &[Vec<f32>]) {
    upgma5_clear(u);
    u.dist_mx = dist_mx.to_vec();
    u.labels = labels.to_vec();
    for i in 0..labels.len() {
        let label = &labels[i];
        if u.label_to_index.contains_key(label) {
            die(&format!("UPGMA5::Init(), duplicate label >{label}"));
        }
        u.label_to_index.insert(label.clone(), i as uint);
    }
    u.leaf_count = u.labels.len() as uint;
}

#[track_caller]
pub fn upgma5_add_label(u: &mut UPGMA5, label: &str) {
    assert!(!label.is_empty());
    if u.label_to_index.contains_key(label) {
        return;
    }
    let index = u.labels.len() as uint;
    u.labels.push(label.to_string());
    u.label_to_index.insert(label.to_string(), index);
}

#[track_caller]
pub fn upgma5_get_label_index(u: &UPGMA5, label: &str) -> uint {
    *u.label_to_index
        .get(label)
        .expect("UPGMA5::GetLabelIndex label not found")
}

#[track_caller]
pub fn upgma5_read_dist_mx(u: &mut UPGMA5, file_name: &str) {
    let _ = progress("Reading dist mx...");
    let text = std::fs::read_to_string(file_name).unwrap();
    u.labels.clear();
    u.label_to_index.clear();
    for line in text.lines() {
        let fields = split(line.trim_end_matches('\r'), '\t');
        assert_eq!(fields.len(), 3);
        upgma5_add_label(u, &fields[0]);
        upgma5_add_label(u, &fields[1]);
    }

    u.leaf_count = u.labels.len() as uint;
    u.dist_mx = vec![vec![f32::MAX; u.leaf_count as usize]; u.leaf_count as usize];

    let mut line_nr = 0;
    for line in text.lines() {
        line_nr += 1;
        let fields = split(line.trim_end_matches('\r'), '\t');
        assert_eq!(fields.len(), 3);
        let index1 = upgma5_get_label_index(u, &fields[0]);
        let index2 = upgma5_get_label_index(u, &fields[1]);
        let dist = str_to_float_l1204(&fields[2], false) as f32;
        if index1 == index2 {
            die(&format!(
                "Line {line_nr} Index1={index1} Index2={index2} Label1='{}' Label2='{}'",
                fields[0], fields[1]
            ));
        }
        u.dist_mx[index1 as usize][index2 as usize] = dist;
        u.dist_mx[index2 as usize][index1 as usize] = dist;
    }
    let _ = progress(" done.\n");
}

#[track_caller]
pub fn upgma5_read_dist_mx2(u: &mut UPGMA5, file_name: &str) {
    let _ = progress("Reading dist mx (reseek format)...");
    let text = std::fs::read_to_string(file_name).unwrap();
    let mut lines = text.lines();

    let hdr = lines.next().expect("UPGMA5::ReadDistMx2 missing header");
    let hdr_fields = split(hdr.trim_end_matches('\r'), '\t');
    assert_eq!(hdr_fields.len(), 2);
    assert_eq!(hdr_fields[0], "distmx");
    u.leaf_count = str_to_uint_l1278(&hdr_fields[1], false);
    assert!(u.leaf_count > 2);

    u.labels.clear();
    u.label_to_index.clear();
    for idx in 0..u.leaf_count {
        let line = lines.next().expect("UPGMA5::ReadDistMx2 missing label");
        let fields = split(line.trim_end_matches('\r'), '\t');
        assert_eq!(fields.len(), 2);
        assert_eq!(str_to_uint_l1278(&fields[0], false), idx);
        upgma5_add_label(u, &fields[1]);
    }
    assert_eq!(u.labels.len(), u.leaf_count as usize);

    u.dist_mx = vec![vec![0.0; u.leaf_count as usize]; u.leaf_count as usize];
    let mut dist_count = 0;
    for line in lines {
        let fields = split(line.trim_end_matches('\r'), '\t');
        assert_eq!(fields.len(), 3);
        let index1 = str_to_uint_l1278(&fields[0], false);
        let index2 = str_to_uint_l1278(&fields[1], false);
        assert!(index1 < u.leaf_count);
        assert!(index2 < u.leaf_count);
        if index1 == index2 {
            continue;
        }
        let dist = str_to_float_l1204(&fields[2], false) as f32;
        u.dist_mx[index1 as usize][index2 as usize] = dist;
        u.dist_mx[index2 as usize][index1 as usize] = dist;
        dist_count += 1;
    }
    let _ = progress_log(&format!("{dist_count} pair-wise distances\n"));
    if dist_count < u.leaf_count {
        die("Distance matrix too sparse");
    }
    let _ = progress(" done.\n");
}

#[track_caller]
pub fn upgma5_fix_ea_dist_mx(u: &mut UPGMA5) {
    for i in 0..u.leaf_count as usize {
        u.dist_mx[i][i] = 0.0;
        for j in 0..i {
            let d = u.dist_mx[i][j];
            assert!((0.0..=1.0).contains(&d));
            let new_dist = 1.0 - d;
            u.dist_mx[i][j] = new_dist;
            u.dist_mx[j][i] = new_dist;
        }
    }
}

#[track_caller]
pub fn upgma5_scale_dist_mx(u: &mut UPGMA5, input_is_similarity: bool) {
    const SCALE: f32 = 10.0;
    let mut min_dist = u.dist_mx[0][1];
    let mut max_dist = u.dist_mx[0][1];
    for i in 0..u.leaf_count as usize {
        for j in 0..i {
            let d = u.dist_mx[i][j];
            assert_eq!(u.dist_mx[j][i], d);
            min_dist = min_dist.min(d);
            max_dist = max_dist.max(d);
        }
    }
    let _ = progress_log(&format!(
        "Re-scaling, min {min_dist:.4}, max {max_dist:.4}\n"
    ));

    let mut min_new_dist = f32::MAX;
    let mut max_new_dist = f32::MAX;
    for i in 0..u.leaf_count as usize {
        for j in 0..i {
            let d = u.dist_mx[i][j];
            let new_dist = if input_is_similarity {
                SCALE * (max_dist - d) / (max_dist - min_dist)
            } else {
                SCALE * (d - min_dist) / (max_dist - min_dist)
            };
            if min_new_dist == f32::MAX || new_dist < min_new_dist {
                min_new_dist = new_dist;
            }
            if max_new_dist == f32::MAX || new_dist > max_new_dist {
                max_new_dist = new_dist;
            }
            u.dist_mx[i][j] = new_dist;
            u.dist_mx[j][i] = new_dist;
        }
    }
    let _ = progress_log(&format!(
        "Scaled min dist {min_new_dist:.3}, max {max_new_dist:.3}. scale\n"
    ));
}

#[track_caller]
pub fn cmd_upgma5<FRunUpgma>(
    input_file_name: &str,
    output_file_name: &str,
    reseek: bool,
    scale_dist: bool,
    ea_dist: bool,
    linkage: Option<&str>,
    mut run_upgma: FRunUpgma,
) -> (UPGMA5, Tree, String)
where
    FRunUpgma: FnMut(&mut UPGMA5, &str) -> Tree,
{
    let mut u = UPGMA5::default();
    if reseek {
        upgma5_read_dist_mx2(&mut u, input_file_name);
        upgma5_scale_dist_mx(&mut u, false);
    } else {
        upgma5_read_dist_mx(&mut u, input_file_name);
        if scale_dist {
            upgma5_scale_dist_mx(&mut u, false);
        } else if ea_dist {
            upgma5_fix_ea_dist_mx(&mut u);
        }
    }

    let s_link = linkage.unwrap_or("avg");
    match s_link {
        "avg" | "min" | "max" | "biased" => {}
        _ => die(&format!("Invalid -linkage {s_link}")),
    }
    let mut log = format!("UPGMA5({s_link})\n");
    let tree = run_upgma(&mut u, s_link);
    tree_to_file_l13(&tree, output_file_name);
    log.push_str("All done.\n");
    (u, tree, log)
}

#[track_caller]
pub fn make_dist_mx<FDist>(
    aln: &MultiSequence,
    mut get_prot_dist: FDist,
) -> (Vec<Vec<f32>>, Vec<String>)
where
    FDist: FnMut(&str, &str, uint) -> f64,
{
    let seq_count = aln.seqs.len();
    let col_count = multi_sequence_get_col_count(aln);
    let mut dist_mx = vec![vec![f32::MAX; seq_count]; seq_count];
    let mut labels = Vec::with_capacity(seq_count);

    for i in 0..seq_count {
        dist_mx[i][i] = 0.0;
        labels.push(aln.seqs[i].label.clone());
    }

    let pair_count = (seq_count * (seq_count - 1)) / 2;
    let mut seq_indexi = uint::MAX;
    let mut seq_indexj = uint::MAX;
    for _pair_index in 0..pair_count {
        if seq_indexi == uint::MAX {
            seq_indexi = 1;
            seq_indexj = 0;
        } else {
            seq_indexj += 1;
            if seq_indexj == seq_indexi {
                seq_indexi += 1;
                seq_indexj = 0;
            }
        }

        let seqi = sequence_get_seq_as_string(&aln.seqs[seq_indexi as usize]);
        let seqj = sequence_get_seq_as_string(&aln.seqs[seq_indexj as usize]);
        let dij = get_prot_dist(&seqi, &seqj, col_count) as f32;
        dist_mx[seq_indexi as usize][seq_indexj as usize] = dij;
        dist_mx[seq_indexj as usize][seq_indexi as usize] = dij;
    }

    (dist_mx, labels)
}

#[track_caller]
pub fn cmd_upgma5_msa<FDist, FRunUpgma>(
    input_file_name: &str,
    output_file_name: &str,
    linkage: Option<&str>,
    mut get_prot_dist: FDist,
    mut run_upgma: FRunUpgma,
) -> (UPGMA5, Tree, String)
where
    FDist: FnMut(&str, &str, uint) -> f64,
    FRunUpgma: FnMut(&mut UPGMA5, &str) -> Tree,
{
    let mut aln = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut aln, input_file_name, false);
    let is_nucleo = multi_sequence_guess_is_nucleo(&aln);
    set_alpha_l209(if is_nucleo {
        ALPHA::ALPHA_Nucleo
    } else {
        ALPHA::ALPHA_Amino
    });

    let (dist_mx, labels) = make_dist_mx(&aln, |seqi, seqj, col_count| {
        get_prot_dist(seqi, seqj, col_count)
    });
    let mut u = UPGMA5::default();
    upgma5_init(&mut u, &labels, &dist_mx);

    let s_link = linkage.unwrap_or("avg");
    match s_link {
        "avg" | "min" | "max" | "biased" => {}
        _ => die(&format!("Invalid -linkage {s_link}")),
    }
    let mut log = format!("UPGMA5({s_link})\n");
    let tree = run_upgma(&mut u, s_link);
    tree_to_file_l13(&tree, output_file_name);
    log.push_str("All done.\n");
    (u, tree, log)
}

#[track_caller]
pub fn usage() -> String {
    help()
}

#[track_caller]
pub fn u_sorter_init(sorter: &mut USorter) {
    let state = ALPHA_STATE.lock().unwrap();
    assert!(state.alpha_size > 0);
    match state.alpha {
        ALPHA::ALPHA_Amino => {
            sorter.word_length = 3;
            sorter.dict_size = myipow(20, sorter.word_length);
        }
        ALPHA::ALPHA_Nucleo => {
            sorter.word_length = 8;
            sorter.dict_size = myipow(4, sorter.word_length);
        }
        _ => panic!("Invalid Alpha={:?}", state.alpha),
    }
    drop(state);
    sorter.rows.clear();
    sorter.rows.resize(sorter.dict_size as usize, Vec::new());
}

#[track_caller]
pub fn u_sorter_chars_to_word(sorter: &USorter, chars: &[byte]) -> uint {
    let alpha = ALPHA_STATE.lock().unwrap().alpha;
    match alpha {
        ALPHA::ALPHA_Amino => u_sorter_chars_to_word_amino(sorter, chars),
        ALPHA::ALPHA_Nucleo => u_sorter_chars_to_word_nucleo(sorter, chars),
        alpha => panic!("Invalid Alpha={alpha:?}"),
    }
}

#[track_caller]
pub fn u_sorter_chars_to_word_amino(sorter: &USorter, chars: &[byte]) -> uint {
    let state = ALPHA_STATE.lock().unwrap();
    let mut word = 0;
    for i in 0..sorter.word_length as usize {
        let c = chars[i] as usize;
        let letter = state.char_to_letter[c];
        if letter >= 20 {
            return uint::MAX;
        }
        word = word * 20 + letter;
    }
    word
}

#[track_caller]
pub fn u_sorter_chars_to_word_nucleo(sorter: &USorter, chars: &[byte]) -> uint {
    let state = ALPHA_STATE.lock().unwrap();
    let mut word = 0;
    for i in 0..sorter.word_length as usize {
        let c = chars[i] as usize;
        let letter = state.char_to_letter[c];
        if letter >= 4 {
            return uint::MAX;
        }
        word = word * 4 + letter;
    }
    word
}

#[track_caller]
pub fn u_sorter_add_seq(sorter: &mut USorter, seq: &[byte], seq_index: uint) {
    assert!(ALPHA_STATE.lock().unwrap().alpha_size > 0);
    let index = sorter.index_seq_indexes.len() as uint;
    if seq.len() < sorter.word_length as usize {
        return;
    }
    let word_count = seq.len() + 1 - sorter.word_length as usize;
    for i in 0..word_count {
        let word = u_sorter_chars_to_word(sorter, &seq[i..]);
        if word < sorter.dict_size {
            sorter.rows[word as usize].push(index);
        }
    }
    sorter.index_seq_indexes.push(seq_index);
}

#[track_caller]
pub fn u_sorter_search_seq(sorter: &USorter, seq: &[byte]) -> (Vec<uint>, Vec<uint>) {
    let mut top_seq_indexes = Vec::new();
    let mut top_word_counts = Vec::new();
    let index_size = sorter.index_seq_indexes.len();
    if index_size == 0 {
        return (top_seq_indexes, top_word_counts);
    }
    if seq.len() < sorter.word_length as usize {
        return (top_seq_indexes, top_word_counts);
    }
    let word_count = seq.len() + 1 - sorter.word_length as usize;
    let mut u: Vec<uint> = vec![0; index_size];
    for i in 0..word_count {
        let word = u_sorter_chars_to_word(sorter, &seq[i..]);
        if word >= sorter.dict_size {
            continue;
        }
        for &target_seq_index in &sorter.rows[word as usize] {
            assert!((target_seq_index as usize) < index_size);
            u[target_seq_index as usize] += 1;
        }
    }
    let mut order: Vec<usize> = (0..index_size).collect();
    order.sort_by(|&a, &b| u[b].cmp(&u[a]).then_with(|| a.cmp(&b)));
    let top_seq_index = order[0];
    let top_word_count = u[top_seq_index];
    let mut min_u = (top_word_count / 2).wrapping_sub(1);
    if min_u == 0 {
        min_u = 1;
    }
    let mut last_word_count = top_word_count;
    for index in order {
        let word_count = u[index];
        assert!(word_count <= last_word_count);
        last_word_count = word_count;
        if word_count < min_u {
            break;
        }
        top_seq_indexes.push(sorter.index_seq_indexes[index]);
        top_word_counts.push(word_count);
    }
    (top_seq_indexes, top_word_counts)
}

#[track_caller]
pub fn cmd_usorter(query_file_name: &str, db_file_name: &str) -> String {
    let mut query = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut query, query_file_name, false);

    let mut db = MultiSequence::default();
    multi_sequence_load_mfa_l8(&mut db, db_file_name, false);

    set_alpha_l209(ALPHA::ALPHA_Amino);

    let mut us = USorter::default();
    u_sorter_init(&mut us);
    let db_seq_count = db.seqs.len() as uint;
    for db_seq_index in 0..db_seq_count {
        let seq = &db.seqs[db_seq_index as usize];
        let seq_chars = sequence_get_seq_as_string(seq).into_bytes();
        u_sorter_add_seq(&mut us, &seq_chars, db_seq_index);
    }

    let mut out = String::new();
    let query_seq_count = query.seqs.len() as uint;
    for query_seq_index in 0..query_seq_count {
        let seq = &query.seqs[query_seq_index as usize];
        let seq_chars = sequence_get_seq_as_string(seq).into_bytes();
        let (top_seq_indexes, top_word_counts) = u_sorter_search_seq(&us, &seq_chars);

        let n = top_seq_indexes.len();
        assert_eq!(top_word_counts.len(), n);
        out.push('\n');
        out.push_str(&format!("Q>{}, {} hits\n", seq.label, n));
        for i in 0..n {
            let db_seq_index = top_seq_indexes[i];
            let count = top_word_counts[i];
            out.push_str(&format!(
                "  [{:4}]  {}\n",
                count, db.seqs[db_seq_index as usize].label
            ));
        }
    }
    out
}

#[track_caller]
pub fn viterbi_fast_mem(
    mem: &mut XDPMem,
    a: &[byte],
    la: uint,
    b: &[byte],
    lb: uint,
    pi: &mut PathInfo,
) -> f32 {
    const TRACEBITS_DM: byte = 0x01;
    const TRACEBITS_IM: byte = 0x02;
    const TRACEBITS_MD: byte = 0x04;
    const TRACEBITS_MI: byte = 0x08;

    if la * lb > 100 * 1000 * 1000 {
        die(&format!("ViterbiFastMem, seqs too long LA={la}, LB={lb}"));
    }
    assert!(a.len() >= la as usize);
    assert!(b.len() >= lb as usize);

    mem.max_la = la;
    mem.max_lb = lb;
    mem.buffer1 = vec![MINUS_INFINITY; lb as usize + 1];
    mem.buffer2 = vec![MINUS_INFINITY; lb as usize + 1];
    mem.tb_bit = vec![vec![0; lb as usize + 1]; la as usize + 1];
    mem.tb_bit_row_count = la + 1;
    mem.tb_bit_col_count = lb + 1;
    mem.tb_bit_allocated_row_count = la + 1;
    mem.tb_bit_allocated_col_count = lb + 1;
    path_info_alloc2(pi, la, lb);

    let mut open_a = -3.0_f32;
    let mut ext_a = -0.5_f32;
    let mut m0 = 0.0_f32;
    for i in 0..la {
        let aa = a[i as usize];
        let mut open_b = -3.0_f32;
        let mut ext_b = -0.5_f32;
        let mut i0 = MINUS_INFINITY;

        for j in 0..lb {
            let bb = b[j as usize];
            let mut trace_bits = 0;
            let saved_m0 = m0;

            let mut xm = m0;
            if mem.buffer2[j as usize] > xm {
                xm = mem.buffer2[j as usize];
                trace_bits = TRACEBITS_DM;
            }
            if i0 > xm {
                xm = i0;
                trace_bits = TRACEBITS_IM;
            }
            m0 = mem.buffer1[j as usize];
            mem.buffer1[j as usize] = xm + get_blosum_score_chars(aa, bb);

            let md = saved_m0 + open_b;
            mem.buffer2[j as usize] += ext_b;
            if md >= mem.buffer2[j as usize] {
                mem.buffer2[j as usize] = md;
                trace_bits |= TRACEBITS_MD;
            }

            let mi = saved_m0 + open_a;
            i0 += ext_a;
            if mi >= i0 {
                i0 = mi;
                trace_bits |= TRACEBITS_MI;
            }

            open_b = -3.0;
            ext_b = -0.5;
            mem.tb_bit[i as usize][j as usize] = trace_bits;
        }

        mem.tb_bit[i as usize][lb as usize] = 0;
        let md = m0 - 3.0;
        mem.buffer2[lb as usize] += -0.5;
        if md >= mem.buffer2[lb as usize] {
            mem.buffer2[lb as usize] = md;
            mem.tb_bit[i as usize][lb as usize] = TRACEBITS_MD;
        }

        m0 = MINUS_INFINITY;
        open_a = -3.0;
        ext_a = -0.5;
    }

    let mut i1 = MINUS_INFINITY;
    for j in 1..lb {
        mem.tb_bit[la as usize][j as usize] = 0;
        let mi = mem.buffer1[j as usize - 1] - 3.0;
        i1 += -0.5;
        if mi > i1 {
            i1 = mi;
            mem.tb_bit[la as usize][j as usize] = TRACEBITS_MI;
        }
    }

    let final_m = mem.buffer1[lb as usize - 1];
    let final_d = mem.buffer2[lb as usize];
    let final_i = i1;
    let mut score = final_m;
    let mut state = b'M';
    if final_d > score {
        score = final_d;
        state = b'D';
    }
    if final_i > score {
        score = final_i;
        state = b'I';
    }

    trace_back_bit_mem(mem, la, lb, state, pi);
    score
}

#[track_caller]
pub fn set_gaps(int_open: f32, int_ext: f32, term_open: f32, term_ext: f32) {
    let mut gaps = VITERBI_MEGA_GAPS.lock().unwrap();
    gaps.l_open_a = term_open;
    gaps.l_open_b = term_open;
    gaps.l_ext_a = term_ext;
    gaps.l_ext_b = term_ext;

    gaps.r_open_a = term_open;
    gaps.r_open_b = term_open;
    gaps.r_ext_a = term_ext;
    gaps.r_ext_b = term_ext;

    gaps.open_a = int_open;
    gaps.open_b = int_open;
    gaps.ext_a = int_ext;
    gaps.ext_b = int_ext;
}

#[track_caller]
pub fn viterbi_mega(
    mem: &mut XDPMem,
    prof_a: &[Vec<byte>],
    prof_b: &[Vec<byte>],
    pi: &mut PathInfo,
) -> f32 {
    const TRACEBITS_DM: byte = 0x01;
    const TRACEBITS_IM: byte = 0x02;
    const TRACEBITS_MD: byte = 0x04;
    const TRACEBITS_MI: byte = 0x08;

    let la = prof_a.len() as uint;
    let lb = prof_b.len() as uint;
    if la * lb > 100 * 1000 * 1000 {
        die(&format!("ViterbiMega, seqs too long LA={la}, LB={lb}"));
    }

    let gaps = *VITERBI_MEGA_GAPS.lock().unwrap();
    mem.max_la = la;
    mem.max_lb = lb;
    mem.buffer1 = vec![MINUS_INFINITY; lb as usize + 1];
    mem.buffer2 = vec![MINUS_INFINITY; lb as usize + 1];
    mem.tb_bit = vec![vec![0; lb as usize + 1]; la as usize + 1];
    mem.tb_bit_row_count = la + 1;
    mem.tb_bit_col_count = lb + 1;
    mem.tb_bit_allocated_row_count = la + 1;
    mem.tb_bit_allocated_col_count = lb + 1;
    path_info_alloc2(pi, la, lb);

    let mut open_a = gaps.l_open_a;
    let mut ext_a = gaps.l_ext_a;
    let mut m0 = 0.0_f32;
    for i in 0..la {
        let mut open_b = gaps.l_open_b;
        let mut ext_b = gaps.l_ext_b;
        let mut i0 = MINUS_INFINITY;

        for j in 0..lb {
            let mut trace_bits = 0;
            let saved_m0 = m0;

            let mut xm = m0;
            if mem.buffer2[j as usize] > xm {
                xm = mem.buffer2[j as usize];
                trace_bits = TRACEBITS_DM;
            }
            if i0 > xm {
                xm = i0;
                trace_bits = TRACEBITS_IM;
            }
            m0 = mem.buffer1[j as usize];
            let match_score = mega_get_match_score_log_odds(prof_a, i, prof_b, j);
            mem.buffer1[j as usize] = xm + match_score;

            let md = saved_m0 + open_b;
            mem.buffer2[j as usize] += ext_b;
            if md >= mem.buffer2[j as usize] {
                mem.buffer2[j as usize] = md;
                trace_bits |= TRACEBITS_MD;
            }

            let mi = saved_m0 + open_a;
            i0 += ext_a;
            if mi >= i0 {
                i0 = mi;
                trace_bits |= TRACEBITS_MI;
            }

            open_b = gaps.open_b;
            ext_b = gaps.ext_b;
            mem.tb_bit[i as usize][j as usize] = trace_bits;
        }

        mem.tb_bit[i as usize][lb as usize] = 0;
        let md = m0 + gaps.r_open_b;
        mem.buffer2[lb as usize] += gaps.r_ext_b;
        if md >= mem.buffer2[lb as usize] {
            mem.buffer2[lb as usize] = md;
            mem.tb_bit[i as usize][lb as usize] = TRACEBITS_MD;
        }

        m0 = MINUS_INFINITY;
        open_a = gaps.open_a;
        ext_a = gaps.ext_a;
    }

    let mut i1 = MINUS_INFINITY;
    for j in 1..lb {
        mem.tb_bit[la as usize][j as usize] = 0;
        let mi = mem.buffer1[j as usize - 1] + gaps.r_open_a;
        i1 += gaps.r_ext_a;
        if mi > i1 {
            i1 = mi;
            mem.tb_bit[la as usize][j as usize] = TRACEBITS_MI;
        }
    }

    let final_m = mem.buffer1[lb as usize - 1];
    let final_d = mem.buffer2[lb as usize];
    let final_i = i1;
    let mut score = final_m;
    let mut state = b'M';
    if final_d > score {
        score = final_d;
        state = b'D';
    }
    if final_i > score {
        score = final_i;
        state = b'I';
    }

    trace_back_bit_mem(mem, la, lb, state, pi);
    score
}

#[track_caller]
pub fn align_mega2(
    output_file_name: &str,
    gap_open: Option<f32>,
    gap_ext: Option<f32>,
    term_gap_open: Option<f32>,
    term_gap_ext: Option<f32>,
) -> (f32, PathInfo, Option<String>) {
    {
        let mut gaps = VITERBI_MEGA_GAPS.lock().unwrap();
        let int_open = -gap_open.unwrap_or(0.85);
        let int_ext = -gap_ext.unwrap_or(0.10);
        let term_open = -term_gap_open.unwrap_or(0.0);
        let term_ext = -term_gap_ext.unwrap_or(0.10);
        gaps.l_open_a = term_open;
        gaps.l_open_b = term_open;
        gaps.l_ext_a = term_ext;
        gaps.l_ext_b = term_ext;
        gaps.r_open_a = term_open;
        gaps.r_open_b = term_open;
        gaps.r_ext_a = term_ext;
        gaps.r_ext_b = term_ext;
        gaps.open_a = int_open;
        gaps.open_b = int_open;
        gaps.ext_a = int_ext;
        gaps.ext_b = int_ext;
    }

    let (prof_a, prof_b, seq_a, seq_b, label_a, label_b) = {
        let mega = MEGA_STATE.lock().unwrap();
        let profile_count = mega.profiles.len() as uint;
        if profile_count != 2 {
            die(&format!(
                "AlignMega2(): {profile_count} structures found, 2 required"
            ));
        }
        (
            mega.profiles[0].clone(),
            mega.profiles[1].clone(),
            mega.seqs[0].clone(),
            mega.seqs[1].clone(),
            mega.labels[0].clone(),
            mega.labels[1].clone(),
        )
    };

    let mut mem = XDPMem::default();
    let mut pi = PathInfo::default();
    let score = viterbi_mega(&mut mem, &prof_a, &prof_b, &mut pi);
    if output_file_name.is_empty() {
        return (score, pi, None);
    }

    let mut out = String::new();
    let mut pos_a = 0_usize;
    let mut pos_b = 0_usize;
    out.push_str(&format!(">{label_a}\n"));
    for c in pi.path.bytes() {
        if c == b'M' || c == b'D' {
            out.push(seq_a.as_bytes()[pos_a] as char);
            pos_a += 1;
        } else {
            out.push('-');
        }
    }
    out.push('\n');
    out.push_str(&format!(">{label_b}\n"));
    for c in pi.path.bytes() {
        if c == b'M' || c == b'I' {
            out.push(seq_b.as_bytes()[pos_b] as char);
            pos_b += 1;
        } else {
            out.push('-');
        }
    }
    out.push('\n');
    std::fs::write(output_file_name, &out).expect("failed to write AlignMega2 output");
    (score, pi, Some(out))
}

#[track_caller]
pub fn cmd_mega2(
    input_file_name: &str,
    output_file_name: &str,
    gap_open: Option<f32>,
    gap_ext: Option<f32>,
    term_gap_open: Option<f32>,
    term_gap_ext: Option<f32>,
) -> (f32, PathInfo, Option<String>) {
    mega_from_file(input_file_name);
    align_mega2(
        output_file_name,
        gap_open,
        gap_ext,
        term_gap_open,
        term_gap_ext,
    )
}

#[track_caller]
pub fn write_local_aln(
    label_a: &str,
    a: &[byte],
    label_b: &str,
    b: &[byte],
    loi: uint,
    loj: uint,
    path: &str,
) -> String {
    const BLOCK_SIZE: uint = 80;
    let col_lo = 0;
    let col_hi = path.len() as uint - 1;
    assert!(col_hi >= col_lo);

    let mut out = String::new();
    let mut pos_a = loi;
    let mut pos_b = loj;
    let mut col_from = col_lo;
    loop {
        if col_from > col_hi {
            break;
        }
        let mut col_to = col_from + BLOCK_SIZE - 1;
        if col_to > col_hi {
            col_to = col_hi;
        }

        let i0 = pos_a;
        let j0 = pos_b;
        let (a_row, new_pos_a) = write_a_row(a, path, pos_a, col_from, col_to, label_a);
        pos_a = new_pos_a;
        out.push_str(&a_row);
        out.push_str(&write_annot_row(a, b, path, i0, j0, col_from, col_to));
        let (b_row, new_pos_b) = write_b_row(b, path, pos_b, col_from, col_to, label_b);
        pos_b = new_pos_b;
        out.push_str(&b_row);
        out.push('\n');

        col_from += BLOCK_SIZE;
    }
    out
}

